/* QB_BIOLOGY — compact curated bank (source of truth). Row {i,g,u,d,t,q,o[4],c,e}. */
window.QB_BIOLOGY = [
  {"i":"bio-g11-cell-001","g":9,"u":"Cells","d":"easy","t":"definition","q":"Which organelle is described as the 'powerhouse of the cell'?","o":["Nucleus","Ribosome","Mitochondrion","Golgi apparatus"],"c":2,"e":"The mitochondrion is called the powerhouse because aerobic respiration there produces most of the cell's ATP."},
  {"i":"bio-g11-cell-002","g":9,"u":"Cells","d":"easy","t":"conceptual","q":"Which structure is present in plant cells but absent in animal cells?","o":["Cell membrane","Cell wall","Nucleus","Mitochondrion"],"c":1,"e":"Plant cells have a rigid cellulose cell wall outside the membrane; animal cells have only a cell membrane."},
  {"i":"bio-g11-cell-003","g":9,"u":"Cells","d":"easy","t":"definition","q":"The site of protein synthesis in a cell is the:","o":["Lysosome","Ribosome","Vacuole","Centriole"],"c":1,"e":"Ribosomes read mRNA and link amino acids into polypeptides, making them the site of protein synthesis."},
  {"i":"bio-g11-cell-004","g":9,"u":"Cells","d":"easy","t":"conceptual","q":"Which of the following is a prokaryotic organism?","o":["Bacterium","Amoeba","Yeast","Human liver cell"],"c":0,"e":"Bacteria lack a membrane-bound nucleus and organelles, which defines a prokaryote; the others are eukaryotes."},
  {"i":"bio-g11-cell-005","g":9,"u":"Cells","d":"easy","t":"definition","q":"Which organelle controls the activities of the cell and contains the genetic material?","o":["Chloroplast","Nucleus","Endoplasmic reticulum","Cytoplasm"],"c":1,"e":"The nucleus houses the DNA and directs cell activities through gene expression."},
  {"i":"bio-g11-bioc-001","g":11,"u":"Enzymes","d":"easy","t":"definition","q":"Enzymes are biological catalysts made mainly of:","o":["Lipids","Proteins","Carbohydrates","Nucleic acids"],"c":1,"e":"Almost all enzymes are proteins whose folded shape creates an active site that speeds reactions."},
  {"i":"bio-g11-bioc-002","g":11,"u":"Enzymes","d":"easy","t":"definition","q":"The specific region of an enzyme where the substrate binds is called the:","o":["Active site","Binding pocket of DNA","Receptor site","Reaction centre"],"c":0,"e":"The active site is the precisely shaped region that binds the substrate to catalyse the reaction."},
  {"i":"bio-g11-bioc-003","g":11,"u":"Enzymes","d":"easy","t":"conceptual","q":"Which monomers make up proteins?","o":["Glucose molecules","Amino acids","Nucleotides","Fatty acids"],"c":1,"e":"Proteins are polymers of amino acids joined by peptide bonds."},
  {"i":"bio-g11-bioc-004","g":11,"u":"Enzymes","d":"easy","t":"conceptual","q":"The basic structural unit (monomer) of carbohydrates such as starch is:","o":["Amino acid","Glycerol","Monosaccharide","Nucleotide"],"c":2,"e":"Starch is a polysaccharide built from many monosaccharide (glucose) units."},
  {"i":"bio-g12-gen-001","g":11,"u":"Genetics","d":"easy","t":"definition","q":"An organism with two identical alleles for a trait (e.g. TT or tt) is said to be:","o":["Heterozygous","Homozygous","Hemizygous","Recessive"],"c":1,"e":"Homozygous means both alleles for the gene are the same; heterozygous means they differ."},
  {"i":"bio-g12-gen-002","g":11,"u":"Genetics","d":"easy","t":"definition","q":"In DNA, adenine (A) always pairs with:","o":["Guanine","Cytosine","Thymine","Uracil"],"c":2,"e":"By complementary base pairing in DNA, adenine pairs with thymine (A–T) via two hydrogen bonds."},
  {"i":"bio-g12-gen-003","g":11,"u":"Genetics","d":"easy","t":"definition","q":"The observable physical characteristics of an organism are called its:","o":["Genotype","Phenotype","Karyotype","Allele"],"c":1,"e":"Phenotype is the expressed trait; genotype is the underlying allele combination."},
  {"i":"bio-g12-gen-004","g":11,"u":"Genetics","d":"easy","t":"definition","q":"DNA replication is described as semi-conservative because each new molecule contains:","o":["Two new strands","One old and one new strand","Two old strands","Only RNA strands"],"c":1,"e":"Each daughter DNA keeps one parental (template) strand and one newly made strand, hence semi-conservative."},
  {"i":"bio-g12-evo-001","g":12,"u":"Evolution","d":"easy","t":"definition","q":"Who proposed the theory of evolution by natural selection?","o":["Gregor Mendel","Charles Darwin","Louis Pasteur","Robert Hooke"],"c":1,"e":"Charles Darwin proposed natural selection as the mechanism of evolution in 'On the Origin of Species'."},
  {"i":"bio-g12-evo-002","g":12,"u":"Evolution","d":"easy","t":"definition","q":"Structures with a common evolutionary origin but different functions (e.g. a human arm and a whale flipper) are called:","o":["Analogous structures","Vestigial structures","Homologous structures","Convergent structures"],"c":2,"e":"Homologous structures share a common ancestral origin even when their functions differ."},
  {"i":"bio-g11-phys-001","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"Which blood vessels carry blood away from the heart?","o":["Veins","Arteries","Capillaries","Venules"],"c":1,"e":"Arteries carry blood away from the heart; veins return blood toward it."},
  {"i":"bio-g11-phys-002","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"The functional unit of the kidney is the:","o":["Neuron","Nephron","Alveolus","Villus"],"c":1,"e":"The nephron is the kidney's filtering unit that produces urine."},
  {"i":"bio-g11-phys-003","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"Which gas is taken into the blood at the alveoli of the lungs during breathing?","o":["Carbon dioxide","Nitrogen","Oxygen","Hydrogen"],"c":2,"e":"Oxygen diffuses from alveolar air into the blood, while carbon dioxide diffuses out."},
  {"i":"bio-g11-micro-001","g":12,"u":"Microorganisms","d":"easy","t":"definition","q":"Which microorganism is used to make bread rise and to ferment alcohol?","o":["Yeast","Virus","Algae","Protozoan"],"c":0,"e":"Yeast (a fungus) ferments sugars, releasing CO₂ that makes dough rise and ethanol in brewing."},
  {"i":"bio-g11-micro-002","g":12,"u":"Microorganisms","d":"easy","t":"conceptual","q":"Which of the following diseases is caused by a virus?","o":["Tuberculosis","Cholera","Influenza","Typhoid"],"c":2,"e":"Influenza (flu) is caused by a virus; tuberculosis, cholera and typhoid are bacterial diseases."},
  {"i":"bio-g12-energy-001","g":12,"u":"Energy Transformation","d":"easy","t":"definition","q":"In which organelle does photosynthesis take place?","o":["Mitochondrion","Chloroplast","Nucleus","Ribosome"],"c":1,"e":"Chloroplasts contain chlorophyll and carry out photosynthesis in plant cells."},
  {"i":"bio-g12-energy-002","g":12,"u":"Energy Transformation","d":"easy","t":"definition","q":"Which pigment absorbs light energy for photosynthesis?","o":["Haemoglobin","Melanin","Chlorophyll","Carotene only"],"c":2,"e":"Chlorophyll is the main pigment that absorbs light (mostly red and blue) to drive photosynthesis."},
  {"i":"bio-g12-energy-003","g":12,"u":"Energy Transformation","d":"easy","t":"conceptual","q":"What gas is released as a by-product of photosynthesis?","o":["Carbon dioxide","Oxygen","Nitrogen","Methane"],"c":1,"e":"Photosynthesis splits water and releases oxygen as a by-product while fixing CO₂ into sugar."},
  {"i":"bio-g12-eco-001","g":9,"u":"Ecology","d":"easy","t":"definition","q":"Organisms that make their own food using sunlight are called:","o":["Consumers","Decomposers","Producers","Parasites"],"c":2,"e":"Producers (autotrophs) such as green plants synthesise their own food via photosynthesis."},
  {"i":"bio-g12-eco-002","g":9,"u":"Ecology","d":"easy","t":"definition","q":"All the populations of different species living together in the same area form a:","o":["Population","Community","Species","Biome of one species"],"c":1,"e":"A community is all the interacting populations of different species in one area; a population is a single species."},
  {"i":"bio-g12-climate-001","g":12,"u":"Climate Change","d":"easy","t":"definition","q":"Which gas is the main contributor to the enhanced greenhouse effect from burning fossil fuels?","o":["Oxygen","Carbon dioxide","Nitrogen","Argon"],"c":1,"e":"Burning fossil fuels releases large amounts of carbon dioxide, the principal greenhouse gas driving warming."},
  {"i":"bio-g12-climate-002","g":12,"u":"Climate Change","d":"easy","t":"conceptual","q":"Which human activity most directly increases atmospheric carbon dioxide?","o":["Planting trees","Deforestation and burning coal","Using solar panels","Recycling paper"],"c":1,"e":"Burning coal releases CO₂ and deforestation removes the trees that absorb it, so both raise atmospheric CO₂."},
  {"i":"bio-g12-gen-005","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"In a cross between two heterozygous tall pea plants (Tt × Tt), what fraction of offspring are expected to be short (tt)?","o":["1/4","1/2","3/4","0"],"c":0,"e":"Tt × Tt gives 1 TT : 2 Tt : 1 tt, so 1 of 4 offspring (1/4) is the homozygous recessive short type."},
  {"i":"bio-g12-gen-006","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"A Tt × Tt monohybrid cross produces what phenotypic ratio of tall to short offspring?","o":["1:1","3:1","9:3:3:1","1:2:1"],"c":1,"e":"The 1 TT : 2 Tt : 1 tt genotype ratio gives 3 tall to 1 short, the classic 3:1 monohybrid phenotypic ratio."},
  {"i":"bio-g12-gen-007","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"A test cross of a heterozygous purple-flowered plant (Pp) with a white-flowered plant (pp) gives what phenotypic ratio?","o":["3 purple : 1 white","1 purple : 1 white","All purple","All white"],"c":1,"e":"Pp × pp yields 1/2 Pp (purple) and 1/2 pp (white), a 1:1 ratio — the hallmark of a test cross."},
  {"i":"bio-g12-gen-008","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"If one DNA strand reads 5'-ATGC-3', what is the sequence of the complementary strand (5'→3')?","o":["5'-TACG-3'","5'-GCAT-3'","5'-CGTA-3'","5'-ATGC-3'"],"c":1,"e":"Pair A–T and G–C antiparallel: the complement to 3'-TACG-5' read 5'→3' is GCAT."},
  {"i":"bio-g11-bioc-005","g":11,"u":"Enzymes","d":"medium","t":"conceptual","q":"Why does an enzyme stop working (denature) at very high temperatures?","o":["It runs out of substrate","Its active site shape is destroyed as the protein unfolds","It is converted into a carbohydrate","The substrate becomes too cold"],"c":1,"e":"High heat breaks the bonds holding the protein's 3-D shape, distorting the active site so substrate no longer fits."},
  {"i":"bio-g11-bioc-006","g":11,"u":"Enzymes","d":"medium","t":"conceptual","q":"As substrate concentration increases with a fixed amount of enzyme, the reaction rate eventually levels off because:","o":["The enzyme is used up permanently","All active sites become saturated with substrate","The substrate denatures the enzyme","The pH automatically rises"],"c":1,"e":"At saturation every active site is occupied, so adding more substrate cannot increase the rate until enzymes free up."},
  {"i":"bio-g11-bioc-007","g":11,"u":"Enzymes","d":"medium","t":"conceptual","q":"The 'lock and key' model of enzyme action proposes that:","o":["Any substrate fits any enzyme","The active site has a shape complementary to one specific substrate","Enzymes are permanently changed after the reaction","Substrates break enzymes apart to react"],"c":1,"e":"The lock-and-key model explains enzyme specificity: only a substrate matching the active-site shape can bind."},
  {"i":"bio-g12-energy-004","g":12,"u":"Energy Transformation","d":"medium","t":"conceptual","q":"Which statement correctly distinguishes the light reactions of photosynthesis?","o":["They occur in the stroma and fix CO₂","They occur in the thylakoid membranes and produce ATP and NADPH","They occur in mitochondria and make glucose","They release CO₂ in the dark only"],"c":1,"e":"Light reactions happen in the thylakoid membranes, using light to make ATP and NADPH and to split water."},
  {"i":"bio-g12-energy-005","g":12,"u":"Energy Transformation","d":"medium","t":"conceptual","q":"The Calvin cycle (dark reactions) takes place in the ____ and uses ____ to fix carbon.","o":["thylakoid; light directly","stroma; ATP and NADPH","mitochondrial matrix; oxygen","cytoplasm; chlorophyll"],"c":1,"e":"The Calvin cycle runs in the stroma, consuming the ATP and NADPH made by the light reactions to fix CO₂ into sugar."},
  {"i":"bio-g12-energy-006","g":12,"u":"Energy Transformation","d":"medium","t":"conceptual","q":"During which stage of aerobic respiration is the most ATP produced?","o":["Glycolysis","Link reaction","Krebs cycle","Oxidative phosphorylation (electron transport chain)"],"c":3,"e":"Oxidative phosphorylation in the electron transport chain produces the bulk (about 34) of the ~38 ATP per glucose."},
  {"i":"bio-g12-energy-007","g":12,"u":"Energy Transformation","d":"medium","t":"conceptual","q":"In humans, anaerobic respiration in muscle cells converts glucose mainly into:","o":["Ethanol and CO₂","Lactic acid","Carbon dioxide and water","Glycogen"],"c":1,"e":"Without oxygen, human muscle uses glycolysis followed by fermentation to lactic acid, yielding only 2 ATP per glucose."},
  {"i":"bio-g11-cell-006","g":9,"u":"Cells","d":"medium","t":"conceptual","q":"A red blood cell placed in pure (distilled) water will:","o":["Shrink as water leaves it","Swell and may burst as water enters by osmosis","Stay exactly the same","Turn into a plant cell"],"c":1,"e":"Water moves by osmosis from the dilute outside into the cell; lacking a wall, the animal cell swells and can lyse."},
  {"i":"bio-g11-cell-007","g":9,"u":"Cells","d":"medium","t":"conceptual","q":"Movement of molecules from a region of high concentration to low concentration without using ATP is called:","o":["Active transport","Diffusion","Endocytosis","Exocytosis"],"c":1,"e":"Diffusion is passive movement down a concentration gradient and requires no cellular energy (ATP)."},
  {"i":"bio-g11-cell-008","g":10,"u":"Cell Reproduction","d":"medium","t":"conceptual","q":"Which process produces two genetically identical daughter cells with the same chromosome number as the parent?","o":["Meiosis","Mitosis","Fertilisation","Binary fission of viruses"],"c":1,"e":"Mitosis yields two diploid daughter cells genetically identical to the parent; meiosis halves the chromosome number."},
  {"i":"bio-g11-phys-004","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"Which sequence correctly traces deoxygenated blood through the right side of the heart?","o":["Left atrium → left ventricle → aorta","Right atrium → right ventricle → pulmonary artery → lungs","Right ventricle → aorta → body","Pulmonary vein → right atrium → lungs"],"c":1,"e":"Deoxygenated blood enters the right atrium, passes to the right ventricle, and is pumped via the pulmonary artery to the lungs."},
  {"i":"bio-g11-phys-005","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"Insulin lowers blood glucose mainly by:","o":["Breaking down glycogen into glucose","Stimulating cells to take up glucose and store it as glycogen","Increasing glucose absorption from food","Stopping the kidney from filtering"],"c":1,"e":"Insulin from the pancreas promotes glucose uptake by cells and its storage as glycogen, reducing blood glucose."},
  {"i":"bio-g11-phys-006","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"The transmission of a nerve impulse along a neuron is mainly:","o":["A mechanical push of fluid","An electrochemical wave of membrane depolarisation","A flow of blood","Diffusion of oxygen"],"c":1,"e":"A nerve impulse is an action potential — a moving wave of membrane depolarisation driven by Na⁺ and K⁺ ion movement."},
  {"i":"bio-g12-evo-003","g":12,"u":"Evolution","d":"medium","t":"conceptual","q":"Wings of a bird and wings of an insect perform the same function but have different origins. They are an example of:","o":["Homologous structures","Analogous structures","Vestigial structures","Genetic drift"],"c":1,"e":"Analogous structures share function but not ancestry; they result from convergent evolution, unlike homologous structures."},
  {"i":"bio-g12-evo-004","g":12,"u":"Evolution","d":"medium","t":"conceptual","q":"The widespread survival of dark-coloured peppered moths on soot-darkened trees during industrialisation is an example of:","o":["Lamarckian inheritance","Natural selection","Genetic engineering","Random mutation with no effect"],"c":1,"e":"Camouflaged dark moths escaped predation and reproduced more, so selection by the environment shifted the population — natural selection."},
  {"i":"bio-g11-micro-003","g":12,"u":"Microorganisms","d":"medium","t":"conceptual","q":"Why are antibiotics ineffective against viral infections such as the common cold?","o":["Viruses are too large for antibiotics","Viruses lack the bacterial structures and metabolism that antibiotics target","Antibiotics only work in plants","Viruses are immune by producing their own antibiotics"],"c":1,"e":"Antibiotics target bacterial processes like cell-wall synthesis; viruses have none of these and replicate inside host cells."},
  {"i":"bio-g11-micro-004","g":12,"u":"Microorganisms","d":"medium","t":"conceptual","q":"In the nitrogen cycle, nitrogen-fixing bacteria in root nodules of legumes convert:","o":["Nitrates into nitrogen gas","Atmospheric nitrogen gas into ammonia/nitrogen compounds usable by plants","Ammonia into oxygen","Proteins into glucose"],"c":1,"e":"Nitrogen-fixing bacteria reduce inert N₂ gas into ammonia/usable nitrogen compounds, enriching the soil for plants."},
  {"i":"bio-g12-eco-003","g":9,"u":"Ecology","d":"medium","t":"conceptual","q":"In a food chain: grass → grasshopper → frog → snake, the frog is a:","o":["Primary producer","Primary consumer","Secondary consumer","Decomposer"],"c":2,"e":"The grasshopper (primary consumer) eats grass; the frog eats the grasshopper, making it a secondary consumer."},
  {"i":"bio-g12-eco-004","g":11,"u":"Population & Natural Resources","d":"medium","t":"conceptual","q":"Two species competing for exactly the same limited resource in the same niche typically leads to:","o":["Both increasing without limit","One outcompeting or excluding the other (competitive exclusion)","A predator–prey cycle","Mutualism"],"c":1,"e":"The competitive exclusion principle states two species cannot coexist indefinitely on the identical limiting resource; one prevails."},
  {"i":"bio-g12-climate-003","g":12,"u":"Climate Change","d":"medium","t":"conceptual","q":"How do greenhouse gases warm the Earth?","o":["They block sunlight from reaching the surface","They absorb and re-emit outgoing infrared (heat) radiation, trapping energy","They create a physical glass dome","They increase the Sun's output"],"c":1,"e":"Greenhouse gases let sunlight in but absorb the infrared radiated by the warmed surface and re-emit it, trapping heat."},
  {"i":"bio-g12-climate-004","g":12,"u":"Climate Change","d":"medium","t":"conceptual","q":"Which is a likely ecological consequence of global warming?","o":["Expansion of polar ice caps","Rising sea levels and shifting species ranges","A permanent drop in global temperatures","Increased atmospheric oxygen from melting ice"],"c":1,"e":"Warming melts land ice and expands seawater, raising sea levels, and forces species to shift ranges toward cooler areas."},
  {"i":"bio-g12-gen-009","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"In a dihybrid cross RrYy × RrYy (round/yellow dominant), what fraction of offspring are round AND yellow (R_Y_)?","o":["9/16","3/16","1/16","1/4"],"c":0,"e":"The 9:3:3:1 dihybrid ratio gives 9/16 showing both dominant traits (round, yellow)."},
  {"i":"bio-g12-gen-010","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"From a dihybrid cross RrYy × RrYy, what fraction of offspring show both recessive traits (wrinkled and green, rryy)?","o":["9/16","3/16","1/16","1/8"],"c":2,"e":"Only the rryy class is fully recessive; in the 9:3:3:1 ratio it is 1/16 (1/4 rr × 1/4 yy)."},
  {"i":"bio-g12-gen-011","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"A colour-blind man (XᶜY) marries a woman who is a carrier (XᴬXᶜ). What is the probability that a son is colour-blind?","o":["1/4","1/2","3/4","1"],"c":1,"e":"Sons get Y from father and one X from mother; she gives Xᴬ or Xᶜ with equal chance, so 1/2 of sons (XᶜY) are colour-blind."},
  {"i":"bio-g12-gen-012","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"Two parents are both blood group AB (genotype IᴬIᴮ). What proportion of their children are expected to be blood group AB?","o":["1/4","1/2","3/4","All"],"c":1,"e":"IᴬIᴮ × IᴬIᴮ gives 1 IᴬIᴬ (A) : 2 IᴬIᴮ (AB) : 1 IᴮIᴮ (B), so 2/4 = 1/2 are AB (codominance)."},
  {"i":"bio-g12-gen-013","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"In snapdragons, red (RR) × white (WW) gives all pink (RW) due to incomplete dominance. What phenotypic ratio results from crossing two pink plants (RW × RW)?","o":["3 red : 1 white","1 red : 2 pink : 1 white","All pink","1 red : 1 white"],"c":1,"e":"With incomplete dominance the heterozygote is pink, so RW × RW gives genotype 1:2:1, which is 1 red : 2 pink : 1 white phenotypically."},
  {"i":"bio-g12-energy-008","g":12,"u":"Energy Transformation","d":"hard","t":"calculation","q":"In the complete aerobic oxidation of one glucose molecule, glycolysis and the Krebs cycle together yield only a small net ATP directly. Approximately how many ATP come from oxidative phosphorylation out of the ~38 total?","o":["About 2","About 4","About 34","About 38"],"c":2,"e":"Substrate-level phosphorylation gives ~4 ATP (net 2 in glycolysis + 2 in Krebs); the remaining ~34 come from the electron transport chain."},
  {"i":"bio-g12-energy-009","g":12,"u":"Energy Transformation","d":"hard","t":"conceptual","q":"If a poison blocks the electron transport chain in mitochondria, why does ATP production fall sharply even though glycolysis still runs?","o":["Glycolysis needs the chain to start","Without the chain, NADH/FADH₂ are not re-oxidised, halting oxidative phosphorylation, the main ATP source","Glucose can no longer enter the cell","Oxygen is converted into glucose"],"c":1,"e":"Blocking the chain stops NADH/FADH₂ from being re-oxidised, so the proton gradient and oxidative phosphorylation collapse, removing ~90% of ATP."},
  {"i":"bio-g12-energy-010","g":12,"u":"Energy Transformation","d":"hard","t":"conceptual","q":"In the light reactions, the oxygen released by a plant comes from:","o":["Carbon dioxide","Glucose","The splitting (photolysis) of water","ATP breakdown"],"c":2,"e":"Photolysis splits water (H₂O) at photosystem II, supplying electrons and protons and releasing O₂; the CO₂ oxygen ends up in sugar, not O₂."},
  {"i":"bio-g11-bioc-008","g":11,"u":"Enzymes","d":"hard","t":"conceptual","q":"A competitive inhibitor reduces enzyme activity, but adding a large excess of substrate restores the rate. This is because the inhibitor:","o":["Binds the active site reversibly and competes with substrate","Permanently denatures the enzyme","Binds a site far from the active site and cannot be displaced","Increases the substrate concentration"],"c":0,"e":"A competitive inhibitor binds the active site reversibly; flooding with substrate outcompetes it, so the maximum rate is regained."},
  {"i":"bio-g11-bioc-009","g":11,"u":"Enzymes","d":"hard","t":"conceptual","q":"An enzyme has an optimum pH of 2 (as in the stomach). Placing it at pH 8 sharply lowers its activity mainly because:","o":["Substrate concentration drops","Changed charge interactions distort the active site, lowering substrate binding","The enzyme is diluted","Temperature automatically rises"],"c":1,"e":"Moving far from optimum pH alters the ionisation of side chains, disrupting bonds that maintain the active-site shape and reducing binding."},
  {"i":"bio-g11-cell-009","g":9,"u":"Cells","d":"hard","t":"conceptual","q":"A plant cell placed in a strong salt solution becomes plasmolysed. This happens because:","o":["Water enters the cell and bursts it","Water leaves the cell by osmosis, so the membrane pulls away from the cell wall","The cell wall dissolves","Salt is actively pumped in, swelling the cell"],"c":1,"e":"In a hypertonic solution water leaves by osmosis; the protoplast shrinks and the membrane detaches from the wall — plasmolysis."},
  {"i":"bio-g11-cell-010","g":10,"u":"Cell Reproduction","d":"hard","t":"conceptual","q":"A diploid cell with 2n = 8 undergoes meiosis. How many chromosomes are in each resulting gamete, and how many gametes form from one cell?","o":["8 chromosomes; 2 gametes","4 chromosomes; 4 gametes","16 chromosomes; 4 gametes","4 chromosomes; 2 gametes"],"c":1,"e":"Meiosis halves the chromosome number (8 → 4) and one diploid cell produces four haploid gametes."},
  {"i":"bio-g11-phys-007","g":11,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"When blood glucose rises after a meal and then falls back to normal, this restoration is an example of:","o":["Positive feedback amplifying the change","Negative feedback restoring the set point","Active transport across the gut","Diffusion of glucose into bone"],"c":1,"e":"Insulin counters the rise and returns glucose toward the set point; correcting a deviation is negative feedback homeostasis."},
  {"i":"bio-g11-phys-008","g":11,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"In a kidney nephron, useful glucose that was filtered at the glomerulus is normally returned to the blood by:","o":["Ultrafiltration in the glomerulus","Selective reabsorption (active transport) in the proximal tubule","Secretion in the collecting duct","Osmosis in the loop of Henle only"],"c":1,"e":"Glucose is filtered but then completely reabsorbed by active transport in the proximal convoluted tubule, so healthy urine has no glucose."},
  {"i":"bio-g12-evo-005","g":12,"u":"Evolution","d":"hard","t":"conceptual","q":"A small population is wiped out by a random flood, leaving survivors with allele frequencies different from the original by chance. This change is best described as:","o":["Natural selection","Genetic drift (bottleneck effect)","Gene flow","Directional mutation"],"c":1,"e":"Random loss of individuals (not based on fitness) that shifts allele frequencies in a small population is genetic drift — here a bottleneck."},
  {"i":"bio-g12-evo-006","g":12,"u":"Evolution","d":"hard","t":"conceptual","q":"Overuse of antibiotics leads to resistant bacterial populations. The best evolutionary explanation is that antibiotics:","o":["Cause bacteria to deliberately mutate to survive","Select for pre-existing resistant variants, which then reproduce and dominate","Teach bacteria to become resistant during their lifetime","Make all bacteria immortal"],"c":1,"e":"Random mutations create some resistant bacteria; the antibiotic kills the susceptible ones, so resistant survivors reproduce — selection, not directed change."},
  {"i":"bio-g11-micro-005","g":12,"u":"Microorganisms","d":"hard","t":"conceptual","q":"A vaccine protects against a disease primarily by:","o":["Killing the pathogen directly with antibiotics in the injection","Exposing the immune system to a harmless antigen so memory cells form for a fast future response","Providing the body with ready-made glucose","Replacing the patient's white blood cells"],"c":1,"e":"A vaccine presents antigens that trigger an immune response and memory cells, so a later real infection is destroyed quickly."},
  {"i":"bio-g11-micro-006","g":12,"u":"Microorganisms","d":"hard","t":"calculation","q":"A bacterium divides by binary fission every 20 minutes. Starting from one cell, how many bacteria are present after 2 hours (ideal conditions)?","o":["6","12","64","120"],"c":2,"e":"2 hours = 120 min = 6 divisions; 1 × 2⁶ = 64 bacteria."},
  {"i":"bio-g12-eco-005","g":11,"u":"Population & Natural Resources","d":"hard","t":"calculation","q":"If producers in an ecosystem capture 10,000 kJ of energy and only ~10% transfers between trophic levels, roughly how much energy reaches the secondary consumers?","o":["1000 kJ","100 kJ","10 kJ","5000 kJ"],"c":1,"e":"Producers 10,000 → primary consumers 1000 (10%) → secondary consumers 100 kJ (10% of 1000)."},
  {"i":"bio-g12-eco-006","g":11,"u":"Population & Natural Resources","d":"hard","t":"conceptual","q":"Why are food chains rarely longer than four or five trophic levels?","o":["Predators refuse to eat more than four times","About 90% of energy is lost at each level, so little remains to support higher levels","There are not enough species names","Decomposers stop the chain at level four"],"c":1,"e":"Only ~10% of energy passes up each level, so after several transfers too little energy remains to sustain another level."},
  {"i":"bio-g12-climate-005","g":12,"u":"Climate Change","d":"hard","t":"conceptual","q":"Large-scale deforestation contributes to climate change by BOTH:","o":["Releasing stored carbon when trees are burned and removing a CO₂-absorbing carbon sink","Increasing photosynthesis and cooling the planet","Producing more oxygen and less CO₂","Reducing rainfall only, with no effect on carbon"],"c":0,"e":"Burning/clearing forests releases their stored carbon as CO₂ and simultaneously removes the trees that would have absorbed atmospheric CO₂."},
  {"i":"bio-g12-climate-006","g":12,"u":"Climate Change","d":"hard","t":"conceptual","q":"Melting Arctic sea ice can accelerate warming through a positive feedback because:","o":["Open dark ocean absorbs more sunlight than reflective ice, warming further and melting more ice","Ice melting cools the surrounding water permanently","Less ice means more CO₂ is absorbed by the sea","Melting ice blocks sunlight"],"c":0,"e":"Ice reflects sunlight (high albedo); when it melts, darker ocean absorbs more heat, causing more melting — a self-reinforcing positive feedback."},
  {"i":"bio-g12-gen-014","g":11,"u":"Genetics","d":"impossible","t":"calculation","q":"In a trihybrid cross AaBbCc × AaBbCc (all independently assorting, simple dominance), what fraction of offspring are homozygous recessive at all three loci (aabbcc)?","o":["1/8","1/16","1/32","1/64"],"c":3,"e":"Each locus gives 1/4 homozygous recessive; independent assortment multiplies: (1/4)³ = 1/64."},
  {"i":"bio-g12-gen-015","g":11,"u":"Genetics","d":"impossible","t":"calculation","q":"In a dihybrid cross AaBb × AaBb, what fraction of offspring are heterozygous at BOTH genes (AaBb)?","o":["1/16","1/8","1/4","9/16"],"c":2,"e":"P(Aa) = 1/2 and P(Bb) = 1/2; independent, so P(AaBb) = 1/2 × 1/2 = 1/4 (the 4 of 16 double-heterozygotes)."},
  {"i":"bio-g12-gen-016","g":11,"u":"Genetics","d":"impossible","t":"calculation","q":"Two parents are heterozygous for an autosomal recessive disease (Aa × Aa). Given that a child is unaffected (shows the dominant phenotype), what is the probability that this child is a carrier (Aa)?","o":["1/2","1/4","2/3","3/4"],"c":2,"e":"Aa × Aa gives 1 AA : 2 Aa : 1 aa; among the 3 unaffected (AA, Aa, Aa), 2 are carriers, so the conditional probability is 2/3."},
  {"i":"bio-g12-gen-017","g":11,"u":"Genetics","d":"impossible","t":"calculation","q":"In sweet peas, two gene pairs control flower colour: at least one dominant allele at BOTH genes (C_P_) gives purple, otherwise white (complementary gene interaction). What purple:white ratio results from CcPp × CcPp?","o":["9 purple : 7 white","9 purple : 3 : 3 : 1","3 purple : 1 white","13 purple : 3 white"],"c":0,"e":"Only the 9/16 C_P_ class is purple; the 3 + 3 + 1 = 7/16 lacking a dominant at either gene are white, giving the 9:7 epistatic ratio."},
  {"i":"bio-g12-gen-018","g":11,"u":"Genetics","d":"impossible","t":"calculation","q":"Two genes are linked 20 map units apart. A dihybrid AaBb (cis arrangement, AB/ab) is test-crossed with aabb. What percentage of offspring are recombinant?","o":["10%","20%","40%","50%"],"c":1,"e":"Map distance equals percent recombination, so 20 map units means 20% recombinant offspring (10% each recombinant class)."},
  {"i":"bio-g12-energy-011","g":12,"u":"Energy Transformation","d":"impossible","t":"conceptual","q":"A scientist supplies a plant with water labelled with heavy oxygen (H₂¹⁸O) but normal CO₂. Where does the ¹⁸O label first appear?","o":["In the glucose produced","In the oxygen gas (O₂) released","In the carbon dioxide taken up","In the ATP phosphate groups"],"c":1,"e":"Photolysis splits water, so the released O₂ comes from water; therefore the ¹⁸O label appears in the evolved oxygen gas, not in glucose."},
  {"i":"bio-g12-energy-012","g":12,"u":"Energy Transformation","d":"impossible","t":"conceptual","q":"A chemical makes the inner mitochondrial membrane freely permeable to protons (an 'uncoupler'). The immediate effect is that the cell:","o":["Makes more ATP than normal","Continues electron transport and oxygen use but makes little ATP, releasing energy as heat","Stops glycolysis entirely","Begins photosynthesis"],"c":1,"e":"An uncoupler dissipates the proton gradient, so ATP synthase has no gradient to drive it; electron transport and O₂ use continue but energy is lost as heat."},
  {"i":"bio-g12-energy-013","g":12,"u":"Energy Transformation","d":"impossible","t":"conceptual","q":"Both oxidative phosphorylation in mitochondria and the light reactions in chloroplasts share which core mechanism for making ATP?","o":["Direct transfer of a phosphate from glucose","Chemiosmosis: a proton gradient across a membrane drives ATP synthase","Fixation of carbon dioxide","Breakdown of lactic acid"],"c":1,"e":"Both use chemiosmosis — an electron transport chain pumps protons to form a gradient whose flow through ATP synthase makes ATP."},
  {"i":"bio-g11-bioc-010","g":11,"u":"Enzymes","d":"impossible","t":"conceptual","q":"An enzyme is studied with a non-competitive inhibitor. Compared with no inhibitor, the maximum rate (Vmax) and the substrate level for half-maximal rate (Km) change how?","o":["Vmax decreases; Km unchanged","Vmax unchanged; Km increases","Vmax increases; Km decreases","Both Vmax and Km increase"],"c":0,"e":"A non-competitive inhibitor binds away from the active site and cannot be outcompeted, so Vmax falls while substrate affinity (Km) is unchanged."},
  {"i":"bio-g11-bioc-011","g":11,"u":"Enzymes","d":"impossible","t":"conceptual","q":"In a metabolic pathway A→B→C→D, the end product D binds the first enzyme and slows it. This feedback inhibition is most precisely an example of:","o":["Competitive inhibition at the active site for substrate A","Allosteric (end-product) inhibition regulating pathway flux","Denaturation of enzyme 1","Substrate-level phosphorylation"],"c":1,"e":"The product binds a regulatory (allosteric) site on the first enzyme, throttling the whole pathway — classic allosteric feedback inhibition."},
  {"i":"bio-g11-cell-011","g":10,"u":"Cell Reproduction","d":"impossible","t":"conceptual","q":"A drug stops microtubule spindle fibres from functioning during cell division. The most direct consequence is that cells:","o":["Cannot replicate their DNA in S phase","Arrest in mitosis because chromosomes cannot be separated to the poles","Skip mitosis and divide faster","Stop making proteins"],"c":1,"e":"Spindle microtubules pull sister chromatids apart in anaphase; blocking them halts cells in mitosis with chromosomes unable to segregate."},
  {"i":"bio-g11-cell-012","g":9,"u":"Cells","d":"impossible","t":"conceptual","q":"Mitochondria and chloroplasts have their own circular DNA and double membranes. This is the central evidence for which idea?","o":["Spontaneous generation","The endosymbiotic theory (they descend from engulfed prokaryotes)","That they are made by the Golgi","That they are viruses"],"c":1,"e":"Their prokaryote-like circular DNA, ribosomes and double membrane support endosymbiosis: ancestral cells engulfed bacteria that became these organelles."},
  {"i":"bio-g11-phys-009","g":11,"u":"The Human Body Systems","d":"impossible","t":"conceptual","q":"At high altitude with low oxygen, the body increases red blood cell production over weeks. The correct hormonal pathway is:","o":["Insulin from the pancreas stimulates bone marrow","Low oxygen triggers the kidneys to release erythropoietin, stimulating bone marrow to make red cells","The lungs directly manufacture red blood cells","Adrenaline destroys old cells to free oxygen"],"c":1,"e":"Sensing low O₂, the kidneys secrete erythropoietin (EPO), which stimulates bone marrow to produce more red blood cells, raising oxygen-carrying capacity."},
  {"i":"bio-g11-phys-010","g":11,"u":"The Human Body Systems","d":"impossible","t":"conceptual","q":"During heavy exercise, why does CO₂ rising in the blood increase the breathing rate even before oxygen drops much?","o":["CO₂ is directly toxic to the lungs","CO₂ forms carbonic acid, lowering blood pH; chemoreceptors detect this and signal faster breathing","CO₂ binds haemoglobin better than O₂ and suffocates cells","Muscles store CO₂ as glycogen"],"c":1,"e":"Dissolved CO₂ forms carbonic acid, lowering pH; chemoreceptors detect the acidity and drive the respiratory centre to increase breathing to expel CO₂."},
  {"i":"bio-g12-evo-007","g":12,"u":"Evolution","d":"impossible","t":"calculation","q":"In a population at Hardy–Weinberg equilibrium, the recessive disorder affects 1 in 100 people (q² = 0.01). What fraction of the population are carriers (heterozygotes)?","o":["0.10","0.18","0.81","0.01"],"c":1,"e":"q = 0.1, p = 0.9; carrier frequency 2pq = 2(0.9)(0.1) = 0.18, i.e. 18% of the population."},
  {"i":"bio-g12-evo-008","g":12,"u":"Evolution","d":"impossible","t":"conceptual","q":"A single mountain range splits one beetle species into two groups that, over time, can no longer interbreed. This is best described as:","o":["Sympatric speciation","Allopatric speciation by geographic isolation","Convergent evolution","Artificial selection"],"c":1,"e":"A physical barrier geographically isolates populations, which then diverge until reproductively incompatible — allopatric speciation."},
  {"i":"bio-g11-micro-007","g":12,"u":"Microorganisms","d":"impossible","t":"conceptual","q":"A retrovirus like HIV is unusual because it:","o":["Has no genetic material","Uses reverse transcriptase to copy its RNA into DNA that integrates into the host genome","Is a type of bacterium with a nucleus","Reproduces only outside living cells"],"c":1,"e":"Retroviruses carry RNA and the enzyme reverse transcriptase, which makes DNA from that RNA; the DNA then inserts into the host's chromosomes."},
  {"i":"bio-g11-micro-008","g":12,"u":"Microorganisms","d":"impossible","t":"conceptual","q":"Decomposer bacteria are essential to ecosystems mainly because they:","o":["Add new energy to the ecosystem","Recycle nutrients by breaking dead matter into inorganic forms that producers can reuse","Photosynthesise to feed consumers","Fix all the carbon dioxide in the air"],"c":1,"e":"Decomposers release locked-up nutrients (N, P, etc.) from dead organisms back into the soil/water for producers; energy still flows in only from the Sun."},
  {"i":"bio-g12-eco-007","g":11,"u":"Population & Natural Resources","d":"impossible","t":"calculation","q":"A population of 500 has a per-capita birth rate of 0.30/year and death rate of 0.10/year, with no migration. What is the population's growth (number added) in one year under exponential growth?","o":["50","100","150","200"],"c":1,"e":"Growth rate r = 0.30 − 0.10 = 0.20/yr; ΔN = rN = 0.20 × 500 = 100 individuals added."},
  {"i":"bio-g12-eco-008","g":11,"u":"Population & Natural Resources","d":"impossible","t":"conceptual","q":"Why do persistent toxins like DDT reach their highest concentrations in top predators (biomagnification)?","o":["Top predators produce the toxin themselves","The toxin is not excreted and accumulates, becoming more concentrated at each higher trophic level","Producers absorb most of the toxin and pass none on","Toxins are diluted as they move up the chain"],"c":1,"e":"Fat-soluble toxins resist excretion, so each consumer accumulates the toxin from all its prey, concentrating it further at every trophic level."},
  {"i":"bio-g12-climate-007","g":12,"u":"Climate Change","d":"impossible","t":"conceptual","q":"Ocean acidification, a consequence of rising CO₂, harms coral and shellfish because dissolved CO₂:","o":["Raises seawater pH, dissolving plankton","Forms carbonic acid that lowers pH and reduces carbonate ions needed to build calcium carbonate shells","Adds oxygen that corrodes shells","Heats the water so shells melt"],"c":1,"e":"CO₂ dissolves to form carbonic acid, lowering pH and depleting carbonate ions, so organisms struggle to build/maintain their CaCO₃ shells and skeletons."},
  {"i":"bio-g12-climate-008","g":12,"u":"Climate Change","d":"impossible","t":"conceptual","q":"Thawing permafrost is considered a dangerous climate feedback mainly because it:","o":["Reflects more sunlight back to space","Releases stored methane and CO₂, greenhouse gases that cause further warming and more thawing","Absorbs atmospheric CO₂ permanently","Cools the Arctic by exposing soil"],"c":1,"e":"Frozen soil holds vast organic carbon; thawing lets microbes release methane and CO₂, intensifying warming that thaws still more permafrost — a positive feedback."},
  {"i":"bio-b3-0001","g":9,"u":"Introduction to Biology","d":"easy","t":"definition","q":"The branch of biology that deals specifically with the study of fungi is called:","o":["Mycology","Virology","Entomology","Ornithology"],"c":0,"e":"Mycology is the study of fungi; virology studies viruses, entomology insects, and ornithology birds."},
  {"i":"bio-b3-0002","g":9,"u":"Introduction to Biology","d":"easy","t":"conceptual","q":"In the correct sequence of the scientific method, what immediately follows forming a hypothesis?","o":["Designing and performing an experiment","Stating the conclusion","Making the first observation","Publishing the result"],"c":0,"e":"After a testable hypothesis is formed, the next step is to design and carry out an experiment to test it."},
  {"i":"bio-b3-0003","g":9,"u":"Introduction to Biology","d":"easy","t":"definition","q":"A magnifying tool that uses two sets of lenses (objective and eyepiece) to view very small specimens is the:","o":["Compound light microscope","Hand lens","Telescope","Periscope"],"c":0,"e":"A compound light microscope uses an objective lens plus an eyepiece lens, giving much higher magnification than a single-lens hand lens."},
  {"i":"bio-b3-0004","g":9,"u":"Characteristics & Classification of Organisms","d":"easy","t":"conceptual","q":"Which of the following is NOT one of the basic characteristics shared by all living things?","o":["Having a backbone","Reproduction","Growth","Response to stimuli"],"c":0,"e":"Reproduction, growth, and responsiveness are universal life characteristics; having a backbone applies only to vertebrates, not all organisms."},
  {"i":"bio-b3-0005","g":9,"u":"Characteristics & Classification of Organisms","d":"easy","t":"definition","q":"In the binomial system of naming, the first word of a species name represents the organism's:","o":["Genus","Species","Family","Kingdom"],"c":0,"e":"In binomial nomenclature the first (capitalized) word is the genus and the second is the species (specific epithet)."},
  {"i":"bio-b3-0006","g":9,"u":"Characteristics & Classification of Organisms","d":"easy","t":"conceptual","q":"Which taxonomic rank contains the greatest number of different organisms?","o":["Kingdom","Genus","Species","Family"],"c":0,"e":"Kingdom is the broadest rank, so it contains the most diverse organisms; species is the narrowest."},
  {"i":"bio-b3-0007","g":9,"u":"Characteristics & Classification of Organisms","d":"easy","t":"application","q":"Bacteria are placed in which kingdom because their cells lack a true membrane-bound nucleus?","o":["Monera","Fungi","Protista","Plantae"],"c":0,"e":"Bacteria are prokaryotes lacking a true nucleus, so in the five-kingdom system they belong to Kingdom Monera."},
  {"i":"bio-b3-0008","g":9,"u":"Cells","d":"easy","t":"definition","q":"The structure that controls which substances enter and leave the cell is the:","o":["Cell membrane","Nucleolus","Vacuole","Cell wall"],"c":0,"e":"The cell (plasma) membrane is selectively permeable and regulates the movement of substances into and out of the cell."},
  {"i":"bio-b3-0009","g":9,"u":"Cells","d":"easy","t":"conceptual","q":"Which organelle is correctly described as the site where most ATP is produced and is often called the powerhouse of the cell?","o":["Mitochondrion","Ribosome","Golgi apparatus","Lysosome"],"c":0,"e":"Mitochondria carry out aerobic respiration to produce most of the cell's ATP, earning the name powerhouse of the cell."},
  {"i":"bio-b3-0010","g":9,"u":"Cells","d":"easy","t":"conceptual","q":"Which feature is present in a typical plant cell but absent in a typical animal cell?","o":["Cellulose cell wall","Cell membrane","Nucleus","Cytoplasm"],"c":0,"e":"Plant cells have a rigid cellulose cell wall outside the membrane; animal cells have only a cell membrane, no cell wall."},
  {"i":"bio-b3-0011","g":9,"u":"Cells","d":"easy","t":"definition","q":"The net movement of water molecules across a selectively permeable membrane from a region of higher to lower water concentration is called:","o":["Osmosis","Active transport","Phagocytosis","Respiration"],"c":0,"e":"Osmosis is the diffusion of water across a selectively permeable membrane down its concentration gradient, requiring no energy."},
  {"i":"bio-b3-0012","g":9,"u":"Cells","d":"easy","t":"conceptual","q":"Green plant cells can make their own food because they contain the pigment-bearing organelle called the:","o":["Chloroplast","Mitochondrion","Centriole","Lysosome"],"c":0,"e":"Chloroplasts contain chlorophyll and are the site of photosynthesis, allowing plant cells to make their own food."},
  {"i":"bio-b3-0013","g":9,"u":"Cells","d":"easy","t":"definition","q":"The jelly-like fluid that fills the cell and surrounds the organelles is the:","o":["Cytoplasm","Nucleus","Cell wall","Membrane"],"c":0,"e":"Cytoplasm is the gel-like substance between the membrane and nucleus in which the organelles are suspended."},
  {"i":"bio-b3-0014","g":9,"u":"Reproduction","d":"easy","t":"definition","q":"A type of asexual reproduction in which a small outgrowth detaches from the parent to form a new organism, as seen in yeast, is called:","o":["Budding","Fragmentation","Binary fission","Pollination"],"c":0,"e":"In budding, a small bud grows on the parent (e.g., yeast) and separates to become a new individual; it is asexual."},
  {"i":"bio-b3-0015","g":9,"u":"Reproduction","d":"easy","t":"conceptual","q":"Offspring produced by asexual reproduction are best described as being:","o":["Genetically identical to the parent","Always larger than the parent","A mixture of two parents' genes","Unable to grow"],"c":0,"e":"Asexual reproduction involves one parent and mitosis, so offspring are genetically identical (clones) of the parent."},
  {"i":"bio-b3-0016","g":9,"u":"Reproduction","d":"easy","t":"application","q":"In flowering plants, the transfer of pollen from an anther to a stigma is called:","o":["Pollination","Fertilization","Germination","Respiration"],"c":0,"e":"Pollination is the transfer of pollen from anther to stigma; fertilization is the later fusion of male and female gametes."},
  {"i":"bio-b3-0017","g":9,"u":"Reproduction","d":"easy","t":"conceptual","q":"The cell division that produces gametes and halves the chromosome number is:","o":["Meiosis","Mitosis","Binary fission","Budding"],"c":0,"e":"Meiosis reduces the chromosome number by half, producing haploid gametes for sexual reproduction."},
  {"i":"bio-b3-0018","g":9,"u":"Human Health, Nutrition & Disease","d":"easy","t":"conceptual","q":"A disease caused by a serious deficiency of vitamin C in the diet is:","o":["Scurvy","Rickets","Goitre","Night blindness"],"c":0,"e":"Vitamin C deficiency causes scurvy; rickets is from vitamin D, goitre from iodine, and night blindness from vitamin A deficiency."},
  {"i":"bio-b3-0019","g":9,"u":"Human Health, Nutrition & Disease","d":"easy","t":"application","q":"A person whose diet lacks iodine is most likely to develop:","o":["Goitre","Scurvy","Anaemia","Beri-beri"],"c":0,"e":"Iodine is needed by the thyroid gland; its deficiency causes the thyroid to enlarge, a condition called goitre."},
  {"i":"bio-b3-0020","g":9,"u":"Human Health, Nutrition & Disease","d":"easy","t":"conceptual","q":"Malaria, a major communicable disease in lowland Ethiopia, is transmitted to humans through the bite of the:","o":["Female Anopheles mosquito","Tsetse fly","Housefly","Female Aedes mosquito"],"c":0,"e":"Malaria is caused by Plasmodium and transmitted by the bite of an infected female Anopheles mosquito."},
  {"i":"bio-b3-0021","g":9,"u":"Human Health, Nutrition & Disease","d":"easy","t":"definition","q":"A balanced diet is best defined as one that contains:","o":["All nutrients in correct proportions","Only proteins and fats","The largest possible amount of food","Only carbohydrates for energy"],"c":0,"e":"A balanced diet supplies carbohydrates, proteins, fats, vitamins, minerals, water and fibre in the correct proportions for health."},
  {"i":"bio-b3-0022","g":9,"u":"Ecology","d":"easy","t":"definition","q":"All the populations of different species living and interacting in the same area form a:","o":["Community","Population","Species","Biome"],"c":0,"e":"A community is all the interacting populations of different species in an area; a population is members of just one species."},
  {"i":"bio-b3-0023","g":9,"u":"Cells","d":"easy","t":"definition","q":"In a typical plant cell, which organelle is the site where light energy is captured to make food?","o":["Mitochondrion","Chloroplast","Ribosome","Vacuole"],"c":1,"e":"Chloroplasts contain chlorophyll, which absorbs light energy for photosynthesis. Mitochondria release energy by respiration, ribosomes build proteins, and the vacuole stores cell sap."},
  {"i":"bio-b3-0024","g":9,"u":"Introduction to Biology","d":"easy","t":"definition","q":"The branch of biology that deals specifically with the study of plants is called:","o":["Zoology","Botany","Ecology","Microbiology"],"c":1,"e":"Botany is the study of plants. Zoology studies animals, ecology studies organisms and their environment, and microbiology studies microorganisms."},
  {"i":"bio-b3-0025","g":9,"u":"Characteristics & Classification of Organisms","d":"easy","t":"conceptual","q":"In the binomial naming system, the scientific name of an organism is made up of which two parts in order?","o":["Kingdom then phylum","Genus then species","Family then order","Species then genus"],"c":1,"e":"Binomial nomenclature gives each organism a two-part Latin name: the genus (capitalized) followed by the species, for example Homo sapiens."},
  {"i":"bio-b3-0026","g":9,"u":"Ecology","d":"easy","t":"application","q":"In a simple Ethiopian grassland food chain — grass → grasshopper → lizard → hawk — the grasshopper is best described as a:","o":["Producer","Primary consumer","Secondary consumer","Decomposer"],"c":1,"e":"The grasshopper eats the grass (the producer), so it is the primary consumer. The lizard that eats the grasshopper is the secondary consumer."},
  {"i":"bio-b3-0027","g":9,"u":"Introduction to Biology","d":"medium","t":"conceptual","q":"A student observes a pond sample, formulates the idea that algae release oxygen in light, then sets up jars in light and dark and measures gas produced. Which step of the scientific method is the light/dark jar comparison?","o":["Forming a hypothesis","Designing a controlled experiment","Stating the problem","Drawing a conclusion"],"c":1,"e":"Comparing a treatment (light) against a control (dark) while keeping other factors equal is a controlled experiment; the hypothesis was already stated before the jars were set up."},
  {"i":"bio-b3-0028","g":9,"u":"Introduction to Biology","d":"medium","t":"application","q":"In a microscope, the eyepiece magnifies 10× and the high-power objective magnifies 40×. A learner viewing onion cells under high power records the total magnification. What is it?","o":["50×","400×","4×","140×"],"c":1,"e":"Total magnification = eyepiece × objective = 10 × 40 = 400×."},
  {"i":"bio-b3-0029","g":9,"u":"Introduction to Biology","d":"medium","t":"definition","q":"A biologist studies how acacia trees, dik-diks and soil bacteria interact and cycle nutrients in an area of the Rift Valley. Which branch of biology best describes this work?","o":["Genetics","Ecology","Histology","Taxonomy"],"c":1,"e":"Ecology is the study of interactions among organisms and between organisms and their non-living environment, including nutrient cycling."},
  {"i":"bio-b3-0030","g":9,"u":"Characteristics & Classification of Organisms","d":"medium","t":"conceptual","q":"An organism is multicellular, has cells with walls of chitin, lacks chlorophyll, and absorbs nutrients from dead matter. To which kingdom does it most likely belong?","o":["Plantae","Fungi","Protista","Monera"],"c":1,"e":"Chitin cell walls plus heterotrophic absorption of nutrients from dead organic matter are defining features of Kingdom Fungi, not photosynthetic plants."},
  {"i":"bio-b3-0031","g":9,"u":"Characteristics & Classification of Organisms","d":"medium","t":"application","q":"Using binomial nomenclature, the coffee plant of Ethiopia is written Coffea arabica. In this name, what does the word 'Coffea' represent?","o":["The species","The genus","The family","The kingdom"],"c":1,"e":"In binomial nomenclature the first capitalised word is the genus and the second lowercase word is the species epithet."},
  {"i":"bio-b3-0032","g":9,"u":"Characteristics & Classification of Organisms","d":"medium","t":"conceptual","q":"A prokaryotic cell and a plant cell are compared. Which structure is present in the plant cell but ABSENT in the prokaryote?","o":["Cell membrane","Membrane-bound nucleus","Cytoplasm","Ribosomes"],"c":1,"e":"Prokaryotes lack a membrane-bound nucleus (their DNA lies free in the cytoplasm); membrane, cytoplasm and ribosomes occur in both."},
  {"i":"bio-b3-0033","g":9,"u":"Cells","d":"medium","t":"application","q":"A plant cell is placed in pure (distilled) water. Compared with the cell sap, the water outside is hypotonic. What happens to the cell?","o":["It shrinks (plasmolyses)","Water enters and it becomes turgid","Water leaves and it bursts","No net water movement occurs"],"c":1,"e":"Water moves by osmosis from the hypotonic outside into the cell; the rigid wall prevents bursting, so the cell becomes turgid."},
  {"i":"bio-b3-0034","g":9,"u":"Cells","d":"medium","t":"conceptual","q":"During photosynthesis the light-dependent reactions in the chloroplast split water. Which two products of this water-splitting are correctly paired?","o":["Carbon dioxide and glucose","Oxygen and hydrogen ions (with electrons)","Nitrogen and ATP","Glucose and water"],"c":1,"e":"Photolysis of water (2H₂O → 4H⁺ + 4e⁻ + O₂) releases oxygen as a by-product and supplies hydrogen ions and electrons; glucose forms later in the light-independent stage."},
  {"i":"bio-b3-0035","g":9,"u":"Cells","d":"medium","t":"conceptual","q":"A muscle cell working hard with too little oxygen carries out anaerobic respiration. Which product, building up in the muscle, is correctly identified?","o":["Ethanol and CO₂","Lactic acid","Glucose","Oxygen"],"c":1,"e":"In animal (human muscle) anaerobic respiration glucose is broken down to lactic acid, which accumulates and causes fatigue; ethanol/CO₂ is the yeast/plant pathway."},
  {"i":"bio-b3-0036","g":9,"u":"Cells","d":"medium","t":"conceptual","q":"An enzyme that digests starch works best at pH 7 and 37 °C. A sample is heated to 70 °C and activity stops permanently even after cooling. The best explanation is that the enzyme has been:","o":["Used up as a reactant","Denatured, changing its active site shape","Converted into its substrate","Made more specific"],"c":1,"e":"High temperature breaks the bonds holding the enzyme's 3-D shape, permanently altering the active site (denaturation); enzymes are catalysts and are not used up."},
  {"i":"bio-b3-0037","g":9,"u":"Cells","d":"medium","t":"calculation","q":"A cell undergoing mitosis starts with 24 chromosomes. After one complete mitotic division, how many chromosomes are in EACH daughter cell?","o":["12","24","48","6"],"c":1,"e":"Mitosis is conservative for chromosome number: each daughter cell receives the same number as the parent, so 24."},
  {"i":"bio-b3-0038","g":9,"u":"Cells","d":"medium","t":"calculation","q":"A human cell has a diploid number of 46. After meiosis produces gametes, how many chromosomes are in each gamete?","o":["46","23","92","22"],"c":1,"e":"Meiosis halves the chromosome number, so a gamete from a 2n = 46 cell is haploid with 46 ÷ 2 = 23 chromosomes."},
  {"i":"bio-b3-0039","g":9,"u":"Reproduction","d":"medium","t":"calculation","q":"In garden pea, tall (T) is dominant to short (t). A heterozygous tall plant (Tt) is crossed with a short plant (tt). What fraction of the offspring are expected to be short?","o":["0","1/4","1/2","3/4"],"c":2,"e":"Tt × tt gives genotypes 1 Tt : 1 tt, so 1/2 are tt (short)."},
  {"i":"bio-b3-0040","g":9,"u":"Reproduction","d":"medium","t":"calculation","q":"In a monohybrid cross of two heterozygous purple-flowered pea plants (Pp × Pp), purple (P) is dominant to white. What fraction of offspring are expected to be white-flowered?","o":["1/4","3/4","1/2","0"],"c":0,"e":"Pp × Pp gives 1 PP : 2 Pp : 1 pp; only pp (1/4) is white."},
  {"i":"bio-b3-0041","g":9,"u":"Reproduction","d":"medium","t":"calculation","q":"A man with blood group AB (genotype I^A I^B) and a woman with group O (ii) have children. What is the probability a child has blood group A?","o":["0","1/4","1/2","3/4"],"c":2,"e":"I^A I^B × ii gives 1/2 I^A i (group A) and 1/2 I^B i (group B); so the chance of group A is 1/2."},
  {"i":"bio-b3-0042","g":9,"u":"Reproduction","d":"medium","t":"calculation","q":"Red-green colour blindness is X-linked recessive. A carrier mother (X^B X^b) and a normal father (X^B Y) have a son. What is the probability that the son is colour-blind?","o":["0","1/4","1/2","1"],"c":2,"e":"Sons get X from the mother: 1/2 X^B (normal) and 1/2 X^b (colour-blind), so among sons the probability is 1/2."},
  {"i":"bio-b3-0043","g":9,"u":"Reproduction","d":"medium","t":"conceptual","q":"A farmer propagates a banana plant using suckers, producing offspring genetically identical to the parent. Which feature of asexual reproduction does this best illustrate?","o":["Offspring show high genetic variation","Offspring are clones of the single parent","Two gametes fuse to form a zygote","Meiosis halves the chromosome number"],"c":1,"e":"Asexual reproduction involves one parent and mitosis only, so the offspring (suckers) are genetically identical clones with no new variation."},
  {"i":"bio-b3-0044","g":9,"u":"Human Health, Nutrition & Disease","d":"medium","t":"application","q":"A child in a rural community shows a swollen neck (goitre). Which dietary mineral deficiency is the most likely cause, and what is a common preventive measure?","o":["Iron deficiency; eat more meat","Iodine deficiency; use iodised salt","Calcium deficiency; drink more milk","Vitamin C deficiency; eat citrus"],"c":1,"e":"Goitre (enlarged thyroid) is classically caused by dietary iodine deficiency; iodising salt is the standard public-health prevention used in Ethiopia."},
  {"i":"bio-b3-0045","g":9,"u":"Human Health, Nutrition & Disease","d":"medium","t":"conceptual","q":"Malaria, caused by Plasmodium and spread by the female Anopheles mosquito, is common in low-lying Ethiopian areas. Sleeping under an insecticide-treated net mainly breaks the disease cycle by:","o":["Killing the Plasmodium inside the body","Preventing the vector mosquito from biting","Boosting white blood cell numbers","Providing immunity through antibodies"],"c":1,"e":"The net acts on the transmission route by stopping the Anopheles vector from biting at night, interrupting spread rather than treating the parasite already present."},
  {"i":"bio-b3-0046","g":9,"u":"Human Health, Nutrition & Disease","d":"medium","t":"definition","q":"A person eats only injera (mainly carbohydrate) with little legume, meat or vegetables. Which nutrient class, needed for growth and repair of tissues, is most likely lacking?","o":["Carbohydrate","Protein","Water","Fibre"],"c":1,"e":"Proteins supply the amino acids needed for building and repairing tissues; a cereal-only diet low in legumes/meat is typically protein-deficient."},
  {"i":"bio-b3-0047","g":9,"u":"Ecology","d":"medium","t":"calculation","q":"In a grassland food chain grass → grasshopper → lizard → hawk, energy roughly follows the 10% rule. If the grass fixes 10,000 kJ, about how much energy is available to the lizard (third level)?","o":["1,000 kJ","100 kJ","10 kJ","1,000,000 kJ"],"c":1,"e":"Each transfer passes ~10%: 10,000 → 1,000 (grasshopper) → 100 kJ at the lizard level."},
  {"i":"bio-b3-0048","g":9,"u":"Ecology","d":"medium","t":"conceptual","q":"In a lake, plant nutrients from fertiliser runoff cause algae to bloom, then decompose, and fish die from low oxygen. This sequence best illustrates:","o":["The carbon cycle returning carbon to rock","Eutrophication reducing dissolved oxygen","Nitrogen fixation by root bacteria","Primary succession on bare rock"],"c":1,"e":"Nutrient enrichment drives an algal bloom whose later decomposition by bacteria consumes dissolved oxygen, killing fish — the defining pattern of eutrophication."},
  {"i":"bio-b3-0049","g":9,"u":"Cells","d":"medium","t":"calculation","q":"A plant cell is placed in a solution and observed to lose water until its cytoplasm pulls away from the cell wall (plasmolysis). Compared with the cell's interior, the surrounding solution must be:","o":["Hypotonic to the cell","Hypertonic to the cell","Isotonic with the cell","Identical in solute concentration to the cell"],"c":1,"e":"Water leaves a cell only when the outside solution has a higher solute (lower water) concentration, i.e. is hypertonic; plasmolysis is the sign of net water loss by osmosis."},
  {"i":"bio-b3-0050","g":9,"u":"Cells","d":"medium","t":"conceptual","q":"A scientist removes all the mitochondria from an actively respiring muscle cell but keeps every other organelle intact. The most direct consequence is that the cell can no longer efficiently:","o":["Synthesize proteins on ribosomes","Produce large amounts of ATP through aerobic respiration","Store genetic information in the nucleus","Control what enters through the cell membrane"],"c":1,"e":"Mitochondria are the site of aerobic respiration, where most ATP is produced; removing them cripples efficient ATP generation while leaving protein synthesis, the nucleus and the membrane intact."},
  {"i":"bio-b3-0051","g":9,"u":"Reproduction","d":"medium","t":"calculation","q":"In garden peas, tall (T) is dominant over short (t). A heterozygous tall plant (Tt) is crossed with a short plant (tt). What fraction of the offspring is expected to be short?","o":["0 (none)","1/4","1/2","3/4"],"c":2,"e":"Tt × tt gives genotypes 1 Tt : 1 tt, so 1/2 are tt (short). This is a test-cross ratio of 1 tall : 1 short."},
  {"i":"bio-b3-0052","g":9,"u":"Reproduction","d":"medium","t":"calculation","q":"In humans, a colour-blind allele is recessive and X-linked. A carrier mother (XᴬXᵃ) has children with a father who has normal vision (XᴬY). What fraction of their SONS is expected to be colour-blind?","o":["0","1/4","1/2","3/4"],"c":2,"e":"Sons get Xᴬ or Xᵃ from the carrier mother and Y from the father; half of sons are XᵃY (colour-blind). Among all children it would be 1/4, but among sons specifically it is 1/2."},
  {"i":"bio-b3-0053","g":9,"u":"Characteristics & Classification of Organisms","d":"medium","t":"application","q":"A biologist finds a single-celled organism with no true nucleus and no membrane-bound organelles, with its DNA free in the cytoplasm. Into which group does it best fit?","o":["Fungi","Protista","Bacteria (prokaryote)","Plantae"],"c":2,"e":"Lacking a true (membrane-bound) nucleus and organelles is the defining feature of prokaryotes such as bacteria; fungi, protists and plants are all eukaryotes with a true nucleus."},
  {"i":"bio-b3-0054","g":9,"u":"Human Health, Nutrition & Disease","d":"medium","t":"application","q":"A child in a rural Ethiopian community shows poor growth, muscle wasting and swelling (oedema) due to a diet very low in one class of nutrient. The deficiency is most directly of:","o":["Carbohydrates","Proteins","Vitamin C","Dietary fibre"],"c":1,"e":"Kwashiorkor is caused by severe protein deficiency, producing oedema and muscle wasting even when energy intake is not the main shortfall; vitamin C deficiency causes scurvy instead."},
  {"i":"bio-b3-0055","g":9,"u":"Human Health, Nutrition & Disease","d":"medium","t":"conceptual","q":"Malaria, common in lowland areas of Ethiopia, is caused by a Plasmodium parasite. Controlling the disease often targets mosquito populations because the mosquito acts as the:","o":["Definitive host that is harmed by the parasite","Vector that transmits the parasite between people","Pathogen that directly causes the symptoms","Decomposer of the parasite"],"c":1,"e":"The Anopheles mosquito is the vector that carries Plasmodium from person to person; reducing the vector breaks transmission, while the pathogen itself is the protozoan Plasmodium."},
  {"i":"bio-b3-0056","g":9,"u":"Ecology","d":"medium","t":"application","q":"In a grassland food chain: grass → grasshopper → lizard → hawk, roughly 10% of energy passes to each next level. If the grass stores 10,000 kJ, about how much energy is available to the hawk?","o":["1,000 kJ","100 kJ","10 kJ","1 kJ"],"c":2,"e":"At ~10% transfer per level: grass 10,000 → grasshopper 1,000 → lizard 100 → hawk 10 kJ. Most energy is lost as heat at each trophic step."},
  {"i":"bio-b3-0057","g":9,"u":"Introduction to Biology","d":"medium","t":"definition","q":"A student tests whether light affects bean seedling growth, growing some seedlings in light and others in darkness while keeping water, soil and temperature the same. The factor she deliberately changes (light) is the:","o":["Dependent variable","Independent variable","Controlled variable","Measured outcome"],"c":1,"e":"The independent variable is the factor the investigator deliberately changes (light); the seedling growth that is measured is the dependent variable, and the kept-constant factors are controlled variables."},
  {"i":"bio-b3-0058","g":9,"u":"Cells","d":"hard","t":"calculation","q":"A spherical cell has its radius reduced to one-third of the original. By what factor does its surface-area-to-volume ratio (SA:V) change, and what does this imply for exchange efficiency?","o":["SA:V increases 3×, improving exchange","SA:V decreases 3×, worsening exchange","SA:V stays the same","SA:V increases 9×, improving exchange"],"c":0,"e":"SA:V for a sphere is 3/r, so reducing r to r/3 makes the ratio 3/(r/3)=9/r, which is 3× larger; a higher SA:V means faster exchange relative to volume."},
  {"i":"bio-b3-0059","g":9,"u":"Cells","d":"hard","t":"conceptual","q":"A plant cell and an animal cell are both placed in distilled water. Why does the plant cell NOT burst while the animal cell does?","o":["The plant cell has a rigid cell wall that resists turgor pressure","The plant cell lacks a cell membrane","The animal cell pumps water out faster","The plant cell is impermeable to water"],"c":0,"e":"Water enters both by osmosis, but the plant cell wall withstands the resulting turgor pressure, whereas the animal cell, lacking a wall, lyses."},
  {"i":"bio-b3-0060","g":9,"u":"Cells","d":"hard","t":"application","q":"During an experiment, a respiratory poison stops mitochondria from making ATP. Which active process would FIRST be directly affected?","o":["Active transport of mineral ions into a root cell","Osmosis of water into a cell","Simple diffusion of oxygen across the membrane","Settling of starch grains by gravity"],"c":0,"e":"Active transport requires ATP, so it stops first; osmosis and diffusion are passive and need no ATP."},
  {"i":"bio-b3-0061","g":9,"u":"Reproduction","d":"hard","t":"calculation","q":"In garden peas, tall (T) is dominant to short (t). A heterozygous tall plant is crossed with a short plant. What fraction of the offspring are expected to be short?","o":["1/2","1/4","3/4","0"],"c":0,"e":"Tt × tt gives Tt, Tt, tt, tt — half are tt (short), so 1/2."},
  {"i":"bio-b3-0062","g":9,"u":"Reproduction","d":"hard","t":"calculation","q":"In a dihybrid cross between two plants heterozygous for both seed shape (Round R dominant) and seed colour (Yellow Y dominant), what fraction of offspring show both recessive traits (wrinkled, green)?","o":["1/16","9/16","3/16","1/4"],"c":0,"e":"RrYy × RrYy gives a 9:3:3:1 ratio; the double-recessive (rryy) is 1/16."},
  {"i":"bio-b3-0063","g":9,"u":"Reproduction","d":"hard","t":"calculation","q":"In humans, red-green colour blindness is X-linked recessive. A carrier mother crosses with a normal-vision father. What proportion of their SONS are expected to be colour blind?","o":["1/2","1/4","0","All"],"c":0,"e":"Mother X^B X^b × father X^B Y; sons receive X^B (normal) or X^b (colour blind) from the mother with equal chance, so 1/2 of sons are affected."},
  {"i":"bio-b3-0064","g":9,"u":"Reproduction","d":"hard","t":"conceptual","q":"A cross between two plants with red flowers and white flowers gives all pink offspring. When the pink plants are self-crossed, the ratio is 1 red : 2 pink : 1 white. This pattern is best explained by:","o":["Incomplete dominance","Complete dominance of red","Sex linkage","Codominance producing spotted flowers"],"c":0,"e":"The heterozygote shows an intermediate (pink) phenotype and the F2 genotype ratio 1:2:1 equals the phenotype ratio — the signature of incomplete dominance."},
  {"i":"bio-b3-0065","g":9,"u":"Reproduction","d":"hard","t":"calculation","q":"In a large randomly mating population, the recessive allele for a trait has frequency q = 0.2. Using Hardy–Weinberg, what percentage of the population are expected to be heterozygous carriers?","o":["32%","4%","16%","64%"],"c":0,"e":"p = 0.8, so 2pq = 2(0.8)(0.2) = 0.32, i.e. 32%."},
  {"i":"bio-b3-0066","g":9,"u":"Reproduction","d":"hard","t":"calculation","q":"A diploid organism has 12 chromosomes in its body cells. How many chromosomes are present in each cell at the end of meiosis I (per daughter cell)?","o":["6","12","24","3"],"c":0,"e":"Meiosis I is reductional: homologous pairs separate, so each daughter cell has half the chromosome number, 12/2 = 6 (each still as two chromatids)."},
  {"i":"bio-b3-0067","g":9,"u":"Characteristics & Classification of Organisms","d":"hard","t":"application","q":"An organism is unicellular, has no membrane-bound nucleus, and a peptidoglycan cell wall. In the five-kingdom system, it belongs to:","o":["Monera","Protista","Fungi","Plantae"],"c":0,"e":"Lack of a true nucleus (prokaryotic) plus a peptidoglycan wall identifies it as a bacterium in Kingdom Monera."},
  {"i":"bio-b3-0068","g":9,"u":"Characteristics & Classification of Organisms","d":"hard","t":"conceptual","q":"Two organisms share the genus name but have different species names. Which statement is the most reliable conclusion?","o":["They are closely related but cannot normally interbreed to give fertile offspring","They are identical species","They belong to different families","They cannot share any physical features"],"c":0,"e":"A shared genus indicates close relationship, while different species names mean they are distinct species, normally reproductively isolated."},
  {"i":"bio-b3-0069","g":9,"u":"Characteristics & Classification of Organisms","d":"hard","t":"definition","q":"In the hierarchy of classification, which sequence is correctly ordered from the most inclusive (largest) to the least inclusive (smallest) group?","o":["Kingdom, Phylum, Class, Order, Family, Genus, Species","Species, Genus, Family, Order, Class, Phylum, Kingdom","Kingdom, Class, Phylum, Family, Order, Genus, Species","Phylum, Kingdom, Class, Order, Family, Species, Genus"],"c":0,"e":"The standard taxonomic hierarchy runs Kingdom → Phylum → Class → Order → Family → Genus → Species, broadest to narrowest."},
  {"i":"bio-b3-0070","g":9,"u":"Human Health, Nutrition & Disease","d":"hard","t":"calculation","q":"A balanced diet provides 2,000 kcal per day, with 50% of energy from carbohydrate. If carbohydrate supplies 4 kcal per gram, how many grams of carbohydrate does the person consume daily?","o":["250 g","100 g","500 g","125 g"],"c":0,"e":"Carbohydrate energy = 50% of 2,000 = 1,000 kcal; grams = 1,000 ÷ 4 = 250 g."},
  {"i":"bio-b3-0071","g":9,"u":"Human Health, Nutrition & Disease","d":"hard","t":"application","q":"A child in a rural area shows swollen abdomen, oedema, and stunted growth despite eating mainly enset and cereals. The most likely nutritional deficiency is:","o":["Protein (kwashiorkor)","Vitamin C","Iron only","Excess fat"],"c":0,"e":"Oedema with adequate calories but a starch-dominated, protein-poor diet is characteristic of kwashiorkor, a protein-energy deficiency."},
  {"i":"bio-b3-0072","g":9,"u":"Human Health, Nutrition & Disease","d":"hard","t":"conceptual","q":"Why is a course of antibiotics ineffective against a common cold but effective against bacterial pneumonia?","o":["Colds are caused by viruses, which lack the bacterial structures antibiotics target","Antibiotics only work in cold weather","Viruses are larger than bacteria and resist drugs","Pneumonia is caused by a virus"],"c":0,"e":"Antibiotics act on bacterial-specific structures (e.g. cell walls, ribosomes); viruses, which cause colds, lack these, so antibiotics do not work on them."},
  {"i":"bio-b3-0073","g":9,"u":"Human Health, Nutrition & Disease","d":"hard","t":"application","q":"In Ethiopia, malaria is transmitted by the female Anopheles mosquito. Breaking which step would MOST directly reduce transmission across a whole community?","o":["Eliminating stagnant-water breeding sites for mosquito larvae","Treating only people who already recovered","Boiling drinking water","Vaccinating cattle against the parasite"],"c":0,"e":"Removing larval breeding sites cuts the vector population at source, reducing transmission community-wide; the Plasmodium parasite is not water-borne nor carried by cattle."},
  {"i":"bio-b3-0074","g":9,"u":"Ecology","d":"hard","t":"calculation","q":"In a grassland food chain, grass fixes 10,000 kJ of energy. Applying the ~10% energy-transfer rule, approximately how much energy is available to a secondary consumer (e.g. a snake eating grasshoppers)?","o":["100 kJ","1,000 kJ","10 kJ","5,000 kJ"],"c":0,"e":"Grass 10,000 kJ → primary consumer ~1,000 kJ → secondary consumer ~100 kJ (10% at each transfer)."},
  {"i":"bio-b3-0075","g":9,"u":"Ecology","d":"hard","t":"conceptual","q":"Removing nearly all the top predators from a lake ecosystem most plausibly leads first to:","o":["A rise in herbivore numbers, then a decline in producer biomass","An immediate increase in producers and herbivores together","No change because predators are few","A permanent rise in predator prey"],"c":0,"e":"Without predators, herbivore populations rise and graze down producers — a trophic cascade — though real ecosystems can show exceptions."},
  {"i":"bio-b3-0076","g":9,"u":"Ecology","d":"hard","t":"application","q":"In the nitrogen cycle, a farmer ploughs in legume plants such as faba beans (baqela) to improve soil fertility. The benefit comes mainly because legumes:","o":["Host nitrogen-fixing bacteria in root nodules that enrich the soil with usable nitrogen","Directly absorb nitrogen gas through their leaves for the soil","Kill all denitrifying bacteria","Add large amounts of phosphorus only"],"c":0,"e":"Legume root nodules contain symbiotic Rhizobium bacteria that fix atmospheric N₂ into compounds plants can use, raising soil nitrogen."},
  {"i":"bio-b3-0077","g":9,"u":"Ecology","d":"hard","t":"calculation","q":"A population of 500 rabbits has a birth rate of 120 and a death rate of 40 over one year, with no migration. What is the percentage growth of the population for that year?","o":["16%","8%","24%","32%"],"c":0,"e":"Net increase = 120 − 40 = 80; growth = 80/500 × 100 = 16%."},
  {"i":"bio-b3-0078","g":9,"u":"Introduction to Biology","d":"hard","t":"application","q":"A student tests the hypothesis that light affects plant growth. She grows identical seedlings, varying only light, and measures height. Which is the dependent variable?","o":["Plant height (the measured outcome)","The amount of light given","The type of seed used","The size of the pot"],"c":0,"e":"The dependent variable is what is measured in response to the manipulated (independent) variable; here that is plant height, while light is the independent variable."},
  {"i":"bio-b3-0079","g":9,"u":"Introduction to Biology","d":"hard","t":"conceptual","q":"A new microscope improves resolution but not magnification. Practically, this means the instrument can now:","o":["Distinguish two close structures as separate that previously looked like one","Make every image appear larger only","See through opaque metal","Replace the need for staining entirely"],"c":0,"e":"Resolution is the ability to tell two nearby points apart; better resolution reveals previously merged details, independent of mere magnification."},
  {"i":"bio-b3-0080","g":9,"u":"Cells","d":"impossible","t":"conceptual","q":"A G9 student examines a prokaryotic cell and a plant cell under a microscope. Both are alive and metabolizing. Which single structural feature, present in the plant cell but absent in the prokaryote, is the one whose absence forces the prokaryote to carry out ALL of transcription and translation in the same compartment at the same time?","o":["A cell wall","A plasma membrane","A membrane-bound nucleus","Ribosomes"],"c":2,"e":"Prokaryotes lack a nuclear membrane, so DNA sits free in the cytoplasm and transcription and translation occur together; the cell wall, plasma membrane and ribosomes are present in both, so only the nucleus explains the coupling."},
  {"i":"bio-b3-0081","g":9,"u":"Reproduction","d":"impossible","t":"calculation","q":"In a certain plant, round seed (R) is dominant to wrinkled (r) and tall (T) is dominant to short (t), genes assorting independently. A dihybrid plant (RrTt) is crossed with a fully recessive plant (rrtt). Of 320 offspring, how many are expected to be round AND short?","o":["80","20","160","240"],"c":0,"e":"A testcross of RrTt × rrtt gives a 1:1:1:1 ratio, so round-short (R_tt) = 1/4 of offspring; 1/4 × 320 = 80."},
  {"i":"bio-b3-0082","g":9,"u":"Characteristics & Classification of Organisms","d":"impossible","t":"conceptual","q":"A newly found organism is multicellular, has cells with walls made of chitin, lacks chlorophyll, and absorbs nutrients from decaying matter after secreting digestive enzymes onto it. In which kingdom does the Ethiopian classification scheme place it, and what is the decisive single feature?","o":["Plantae, because it is multicellular with cell walls","Fungi, because of chitin walls and extracellular heterotrophic absorption","Monera, because it decomposes organic matter","Animalia, because it lacks chlorophyll"],"c":1,"e":"Chitinous walls combined with heterotrophic absorptive nutrition by secreted enzymes is unique to Fungi; plants have cellulose walls and are autotrophic, and Monera are unicellular prokaryotes."},
  {"i":"bio-b3-0083","g":9,"u":"Human Health, Nutrition & Disease","d":"impossible","t":"calculation","q":"Colour blindness is X-linked recessive. A woman who is a carrier (XᴬXᵃ) marries a man with normal colour vision (XᴬY). Considering only their SONS, what fraction are expected to be colour blind?","o":["1/4","0","1/2","1"],"c":2,"e":"Sons get Y from the father and one X from the mother; half the mother's X chromosomes carry the recessive allele, so 1/2 of sons are colour blind (this is 1/4 of all children, but half of the sons)."},
  {"i":"bio-b3-0084","g":9,"u":"Cells","d":"impossible","t":"application","q":"A plant cell with a solute concentration giving an internal water potential lower than its surroundings is placed in distilled water. Which sequence correctly describes what happens, and what structure ultimately prevents the cell from bursting?","o":["Water leaves, cell becomes flaccid; vacuole prevents lysis","Water enters by osmosis, cell becomes turgid; the cell wall prevents bursting","Water enters by active transport; the membrane prevents bursting","No net movement occurs because the cell is isotonic"],"c":1,"e":"Distilled water has higher water potential, so water enters by osmosis until the cell is turgid; the rigid cellulose cell wall resists further expansion and stops the cell bursting (unlike an animal cell)."},
  {"i":"bio-b3-0085","g":9,"u":"Introduction to Biology","d":"impossible","t":"conceptual","q":"A student claims a burning candle is alive because it 'moves, needs oxygen, releases heat and grows a soot trail.' Using the recognized characteristics of living things, which single property a candle truly LACKS is the strongest disqualifier?","o":["It uses oxygen","It releases energy as heat","It reproduces and is built from cells that grow by assimilation","It changes over time"],"c":2,"e":"A flame mimics movement, respiration-like oxygen use and apparent growth, but it cannot reproduce nor is it made of cells that grow by assimilating materials into living structure, which decisively excludes it from life."},
  {"i":"bio-b3-0086","g":9,"u":"Human Health, Nutrition & Disease","d":"impossible","t":"application","q":"A community in Ethiopia relies almost entirely on polished cereals and lacks dietary variety. Several people develop weakness, poor wound healing, and bleeding gums. Distinguishing this from a protein-energy disorder, which deficiency best fits the gum/bleeding sign, and why is the reasoning specific?","o":["Vitamin A, because it affects vision and epithelia","Vitamin C, because it is needed for collagen synthesis affecting gums and wound healing","Iron, because it causes general weakness","Iodine, because it affects metabolism"],"c":1,"e":"Bleeding gums plus poor wound healing point to impaired collagen formation, which requires vitamin C (scurvy); iron and iodine cause anaemia and goitre respectively, and vitamin A affects vision/skin, not collagen."},
  {"i":"bio-b3-0087","g":9,"u":"Ecology","d":"impossible","t":"conceptual","q":"Nitrogen-fixing bacteria in the root nodules of a leguminous Ethiopian crop convert atmospheric N₂ into a usable form. Identify the precise role the bacteria play and the immediate product they make available, distinguishing fixation from nitrification.","o":["They convert ammonia to nitrate (nitrification), the form plants absorb","They fix N₂ into ammonia/ammonium, which can then enter the plant or be nitrified","They release N₂ back to the air (denitrification)","They directly let plants absorb gaseous N₂"],"c":1,"e":"Nitrogen fixation converts inert N₂ into ammonia/ammonium; nitrification (a separate step by other bacteria) later turns ammonium into nitrate, and denitrification returns N₂ to the air, so only option B describes fixation correctly."},
  {"i":"bio-b3-0088","g":10,"u":"Sub-fields of Biology","d":"easy","t":"definition","q":"Which sub-field of biology is concerned mainly with the study of fungi?","o":["Mycology","Ornithology","Entomology","Virology"],"c":0,"e":"Mycology is the branch of biology that studies fungi; ornithology studies birds, entomology insects, and virology viruses."},
  {"i":"bio-b3-0089","g":10,"u":"Sub-fields of Biology","d":"easy","t":"definition","q":"The sub-field of biology that deals with the classification and naming of living organisms is called:","o":["Taxonomy","Ecology","Physiology","Genetics"],"c":0,"e":"Taxonomy is the science of classifying and naming organisms into groups based on shared characteristics."},
  {"i":"bio-b3-0090","g":10,"u":"Sub-fields of Biology","d":"easy","t":"conceptual","q":"A scientist who studies the structure and function of microorganisms such as bacteria works mainly in:","o":["Microbiology","Botany","Zoology","Palaeontology"],"c":0,"e":"Microbiology is the study of microscopic organisms such as bacteria, while botany studies plants and zoology studies animals."},
  {"i":"bio-b3-0091","g":10,"u":"Plants","d":"easy","t":"definition","q":"In flowering plants, the male gametes are produced inside the:","o":["Pollen grains","Ovules","Sepals","Stigma"],"c":0,"e":"Pollen grains carry the male gametes; ovules contain the female gametes (egg cells) within the ovary."},
  {"i":"bio-b3-0092","g":10,"u":"Plants","d":"easy","t":"conceptual","q":"Which tissue in a plant is mainly responsible for transporting water and dissolved minerals from the roots upward?","o":["Xylem","Phloem","Epidermis","Cambium"],"c":0,"e":"Xylem transports water and minerals upward from roots, while phloem transports manufactured food (sugars) throughout the plant."},
  {"i":"bio-b3-0093","g":10,"u":"Plants","d":"easy","t":"application","q":"During photosynthesis, green plants use light energy mainly to convert carbon dioxide and water into:","o":["Glucose and oxygen","Protein and water","Starch and nitrogen","Lipid and carbon dioxide"],"c":0,"e":"Photosynthesis converts CO₂ and water into glucose (a sugar) and releases oxygen, using light energy trapped by chlorophyll."},
  {"i":"bio-b3-0094","g":10,"u":"Plants","d":"easy","t":"conceptual","q":"The small pores on the underside of a leaf through which gases are exchanged are called:","o":["Stomata","Lenticels","Trichomes","Root hairs"],"c":0,"e":"Stomata are tiny leaf pores, each bordered by guard cells, that allow gas exchange (CO₂ in, O₂ out) and water loss by transpiration."},
  {"i":"bio-b3-0095","g":10,"u":"Biochemical Molecules","d":"easy","t":"definition","q":"The building blocks (monomers) from which proteins are made are:","o":["Amino acids","Fatty acids","Monosaccharides","Nucleotides"],"c":0,"e":"Proteins are polymers of amino acids; monosaccharides build carbohydrates and nucleotides build nucleic acids."},
  {"i":"bio-b3-0096","g":10,"u":"Biochemical Molecules","d":"easy","t":"application","q":"A student adds Benedict's solution to a sugar solution and heats it, and it turns brick-red. This shows the presence of a:","o":["Reducing sugar","Protein","Lipid","Starch"],"c":0,"e":"Benedict's solution turns brick-red on heating when a reducing sugar such as glucose is present; starch instead gives a blue-black colour with iodine."},
  {"i":"bio-b3-0097","g":10,"u":"Biochemical Molecules","d":"easy","t":"conceptual","q":"Enzymes are biological catalysts that speed up reactions mainly by:","o":["Lowering the activation energy","Raising the activation energy","Increasing the body temperature","Adding extra energy to reactants"],"c":0,"e":"Enzymes lower the activation energy required for a reaction, speeding it up without being used up themselves."},
  {"i":"bio-b3-0098","g":10,"u":"Biochemical Molecules","d":"easy","t":"conceptual","q":"Most enzymes in the human body work best (have an optimum activity) at about:","o":["37 °C","0 °C","60 °C","100 °C"],"c":0,"e":"Human enzymes have an optimum temperature of about 37 °C (body temperature); much higher temperatures denature them."},
  {"i":"bio-b3-0099","g":10,"u":"Cell Reproduction","d":"easy","t":"definition","q":"The type of cell division that produces two genetically identical daughter cells for growth and repair is:","o":["Mitosis","Meiosis","Binary fission","Fertilization"],"c":0,"e":"Mitosis produces two daughter cells identical to the parent cell; meiosis produces four genetically varied gametes."},
  {"i":"bio-b3-0100","g":10,"u":"Cell Reproduction","d":"easy","t":"calculation","q":"A human body cell has 46 chromosomes. After meiosis, each gamete (sex cell) produced contains how many chromosomes?","o":["23","46","92","12"],"c":0,"e":"Meiosis halves the chromosome number, so a gamete from a 46-chromosome cell has 46 ÷ 2 = 23 chromosomes."},
  {"i":"bio-b3-0101","g":10,"u":"Cell Reproduction","d":"easy","t":"conceptual","q":"Which process increases genetic variation by exchanging segments between homologous chromosomes during meiosis?","o":["Crossing over","Replication","Cytokinesis","Denaturation"],"c":0,"e":"Crossing over swaps segments between paired homologous chromosomes during prophase I of meiosis, increasing genetic variation."},
  {"i":"bio-b3-0102","g":10,"u":"Cell Reproduction","d":"easy","t":"calculation","q":"In pea plants, tall (T) is dominant over short (t). A cross Tt × tt gives what fraction of short offspring?","o":["1/2","1/4","3/4","0"],"c":0,"e":"Tt × tt gives Tt, Tt, tt, tt — half (1/2) are short (tt). This is the classic 1:1 test-cross ratio."},
  {"i":"bio-b3-0103","g":10,"u":"Cell Reproduction","d":"easy","t":"calculation","q":"A monohybrid cross between two heterozygous parents (Rr × Rr), where R is dominant, gives what ratio of dominant to recessive phenotypes?","o":["3 : 1","1 : 1","9 : 3 : 3 : 1","1 : 2 : 1"],"c":0,"e":"Rr × Rr gives RR, Rr, Rr, rr — three showing the dominant trait to one recessive, a 3:1 phenotypic ratio."},
  {"i":"bio-b3-0104","g":10,"u":"Cell Reproduction","d":"easy","t":"definition","q":"An organism that carries two different alleles for a gene, such as Bb, is described as:","o":["Heterozygous","Homozygous dominant","Homozygous recessive","Haploid"],"c":0,"e":"An organism with two different alleles (Bb) is heterozygous; two identical alleles (BB or bb) make it homozygous."},
  {"i":"bio-b3-0105","g":10,"u":"Human Biology","d":"easy","t":"conceptual","q":"In the human breathing system, the actual exchange of oxygen and carbon dioxide with the blood takes place in the:","o":["Alveoli","Trachea","Bronchi","Larynx"],"c":0,"e":"Gas exchange occurs across the thin walls of the alveoli (air sacs) in the lungs, which are surrounded by capillaries."},
  {"i":"bio-b3-0106","g":10,"u":"Human Biology","d":"easy","t":"definition","q":"Which component of human blood is mainly responsible for carrying oxygen?","o":["Red blood cells","White blood cells","Platelets","Plasma proteins"],"c":0,"e":"Red blood cells contain haemoglobin, which binds and transports oxygen; white blood cells defend against disease."},
  {"i":"bio-b3-0107","g":10,"u":"Human Biology","d":"easy","t":"application","q":"A person infected with HIV gradually becomes vulnerable to many infections because the virus mainly destroys:","o":["White blood cells of the immune system","Red blood cells","Platelets","Liver cells"],"c":0,"e":"HIV attacks white blood cells (especially helper T-cells) of the immune system, weakening the body's defence against infections."},
  {"i":"bio-b3-0108","g":10,"u":"Human Biology","d":"easy","t":"conceptual","q":"In the human digestive system, most absorption of digested nutrients into the blood occurs in the:","o":["Small intestine","Stomach","Large intestine","Oesophagus"],"c":0,"e":"The small intestine, with its many villi, is the main site where digested nutrients are absorbed into the bloodstream."},
  {"i":"bio-b3-0109","g":10,"u":"Ecological Interaction","d":"easy","t":"definition","q":"In a food chain, organisms such as green plants that make their own food are called:","o":["Producers","Primary consumers","Decomposers","Secondary consumers"],"c":0,"e":"Producers (autotrophs) such as green plants make their own food by photosynthesis and form the base of every food chain."},
  {"i":"bio-b3-0110","g":10,"u":"Sub-fields of Biology","d":"easy","t":"definition","q":"Which sub-field of biology is concerned mainly with the study of heredity and how traits are passed from parents to offspring?","o":["Ecology","Genetics","Taxonomy","Physiology"],"c":1,"e":"Genetics is the branch of biology that studies genes, heredity, and the inheritance of traits across generations."},
  {"i":"bio-b3-0111","g":10,"u":"Sub-fields of Biology","d":"easy","t":"conceptual","q":"A scientist who studies the structure and function of microorganisms such as bacteria and viruses works in the field of:","o":["Botany","Zoology","Microbiology","Palaeontology"],"c":2,"e":"Microbiology is the study of microscopic organisms including bacteria, viruses, fungi, and protozoa."},
  {"i":"bio-b3-0112","g":10,"u":"Sub-fields of Biology","d":"easy","t":"definition","q":"Which applied sub-field uses living cells or organisms to make useful products such as vaccines, enzymes, and improved crops?","o":["Biotechnology","Histology","Ecology","Anatomy"],"c":0,"e":"Biotechnology applies biological systems and living organisms to develop products like medicines, enzymes, and genetically improved crops."},
  {"i":"bio-b3-0113","g":10,"u":"Plants","d":"easy","t":"conceptual","q":"In flowering plants, which tissue is mainly responsible for transporting water and dissolved minerals from the roots upward?","o":["Phloem","Xylem","Cambium","Epidermis"],"c":1,"e":"Xylem conducts water and mineral salts upward from the roots to the stems and leaves."},
  {"i":"bio-b3-0114","g":10,"u":"Plants","d":"easy","t":"conceptual","q":"During photosynthesis in green plants, the gas taken in from the atmosphere and the gas released are, respectively:","o":["Oxygen in, carbon dioxide out","Carbon dioxide in, oxygen out","Nitrogen in, oxygen out","Carbon dioxide in, nitrogen out"],"c":1,"e":"Photosynthesis absorbs carbon dioxide and releases oxygen as a by-product of splitting water."},
  {"i":"bio-b3-0115","g":10,"u":"Plants","d":"easy","t":"definition","q":"The green pigment in plant leaves that absorbs light energy for photosynthesis is called:","o":["Carotene","Haemoglobin","Chlorophyll","Melanin"],"c":2,"e":"Chlorophyll, found in chloroplasts, absorbs light energy (mainly red and blue) to drive photosynthesis."},
  {"i":"bio-b3-0116","g":10,"u":"Plants","d":"easy","t":"application","q":"The transfer of pollen from the anther to the stigma of a flower is known as:","o":["Fertilization","Germination","Pollination","Transpiration"],"c":2,"e":"Pollination is the transfer of pollen grains from the anther (male part) to the stigma (female part)."},
  {"i":"bio-b3-0117","g":10,"u":"Biochemical Molecules","d":"easy","t":"definition","q":"Which biochemical molecule serves as the main long-term energy store in many oil-bearing seeds such as Ethiopian noug (Guizotia)?","o":["Protein","Lipid","Nucleic acid","Cellulose"],"c":1,"e":"Lipids (oils and fats) provide a concentrated long-term energy store, which is why noug seeds are pressed for oil."},
  {"i":"bio-b3-0118","g":10,"u":"Biochemical Molecules","d":"easy","t":"conceptual","q":"The basic building-block (monomer) units that join together to form proteins are:","o":["Amino acids","Monosaccharides","Fatty acids","Nucleotides"],"c":0,"e":"Proteins are polymers made of amino acid monomers linked by peptide bonds."},
  {"i":"bio-b3-0119","g":10,"u":"Biochemical Molecules","d":"easy","t":"definition","q":"Enzymes are biological catalysts that speed up reactions. Chemically, the great majority of enzymes are:","o":["Lipids","Carbohydrates","Proteins","Mineral salts"],"c":2,"e":"Most enzymes are proteins whose specific shape lets them bind a substrate and lower the activation energy."},
  {"i":"bio-b3-0120","g":10,"u":"Biochemical Molecules","d":"easy","t":"conceptual","q":"Which test reagent turns from blue to brick-red on heating in the presence of a reducing sugar such as glucose?","o":["Iodine solution","Benedict's solution","Biuret reagent","Limewater"],"c":1,"e":"Benedict's solution changes from blue to brick-red precipitate when heated with reducing sugars like glucose."},
  {"i":"bio-b3-0121","g":10,"u":"Cell Reproduction","d":"easy","t":"calculation","q":"A human body cell has 46 chromosomes. After meiosis, how many chromosomes will each gamete contain?","o":["92","46","23","12"],"c":2,"e":"Meiosis halves the chromosome number (46 ÷ 2 = 23), so each gamete is haploid with 23 chromosomes."},
  {"i":"bio-b3-0122","g":10,"u":"Cell Reproduction","d":"easy","t":"conceptual","q":"During which stage of mitosis do the chromosomes line up along the equator (middle) of the cell?","o":["Prophase","Metaphase","Anaphase","Telophase"],"c":1,"e":"In metaphase the chromosomes align at the cell's equatorial plate before the sister chromatids separate."},
  {"i":"bio-b3-0123","g":10,"u":"Cell Reproduction","d":"easy","t":"conceptual","q":"Meiosis is important in sexually reproducing organisms mainly because it:","o":["Doubles the chromosome number each generation","Keeps the chromosome number constant across generations","Produces identical daughter cells for growth","Repairs damaged body tissues"],"c":1,"e":"By halving chromosomes in gametes, meiosis ensures that fertilization restores the normal number, keeping it constant."},
  {"i":"bio-b3-0124","g":10,"u":"Human Biology","d":"easy","t":"conceptual","q":"In the human circulatory system, which chamber of the heart pumps oxygenated blood out to the whole body through the aorta?","o":["Right atrium","Right ventricle","Left atrium","Left ventricle"],"c":3,"e":"The left ventricle has the thickest muscular wall and pumps oxygenated blood into the aorta to the body."},
  {"i":"bio-b3-0125","g":10,"u":"Human Biology","d":"easy","t":"definition","q":"Which component of human blood is mainly responsible for transporting oxygen because it contains haemoglobin?","o":["White blood cells","Red blood cells","Platelets","Plasma"],"c":1,"e":"Red blood cells contain haemoglobin, which binds oxygen and carries it from the lungs to the tissues."},
  {"i":"bio-b3-0126","g":10,"u":"Human Biology","d":"easy","t":"conceptual","q":"In humans, sex is determined by sex chromosomes. A normal human female cell carries which sex-chromosome combination?","o":["XY","XX","XO","YY"],"c":1,"e":"Females are XX and males are XY; the female gametes therefore always carry an X chromosome."},
  {"i":"bio-b3-0127","g":10,"u":"Human Biology","d":"easy","t":"application","q":"Which part of the human digestive system is the main site where most digested nutrients are absorbed into the blood?","o":["Stomach","Large intestine","Small intestine","Oesophagus"],"c":2,"e":"The small intestine, lined with villi, is the main site of absorption of digested nutrients into the bloodstream."},
  {"i":"bio-b3-0128","g":10,"u":"Ecological Interaction","d":"easy","t":"conceptual","q":"In a grassland food chain — grass → grasshopper → lizard → hawk — the grass is best described as the:","o":["Producer","Primary consumer","Secondary consumer","Decomposer"],"c":0,"e":"Grass makes its own food by photosynthesis, so it is the producer at the base of the food chain."},
  {"i":"bio-b3-0129","g":10,"u":"Ecological Interaction","d":"easy","t":"definition","q":"The close relationship in which one organism (a parasite) benefits while the host is harmed is called:","o":["Mutualism","Commensalism","Parasitism","Competition"],"c":2,"e":"In parasitism the parasite gains nourishment at the expense of its host, which is harmed by the relationship."},
  {"i":"bio-b3-0130","g":10,"u":"Sub-fields of Biology","d":"easy","t":"definition","q":"Which sub-field of biology is concerned mainly with the study of heredity and how traits pass from parents to offspring?","o":["Ecology","Genetics","Taxonomy","Physiology"],"c":1,"e":"Genetics is the branch of biology that studies heredity and variation, including how genes transmit traits from one generation to the next."},
  {"i":"bio-b3-0131","g":10,"u":"Sub-fields of Biology","d":"easy","t":"definition","q":"A scientist who studies the structure, growth and uses of fungi is working in which sub-field of biology?","o":["Mycology","Virology","Entomology","Ornithology"],"c":0,"e":"Mycology is the study of fungi. Virology studies viruses, entomology insects, and ornithology birds."},
  {"i":"bio-b3-0132","g":10,"u":"Plants","d":"easy","t":"conceptual","q":"In which part of a leaf cell does photosynthesis mainly take place?","o":["Mitochondrion","Chloroplast","Nucleus","Vacuole"],"c":1,"e":"Chloroplasts contain chlorophyll, which traps light energy used to make glucose; they are the site of photosynthesis."},
  {"i":"bio-b3-0133","g":10,"u":"Plants","d":"easy","t":"conceptual","q":"Which tissue in a plant transports water and dissolved minerals upward from the roots to the leaves?","o":["Phloem","Xylem","Cambium","Epidermis"],"c":1,"e":"Xylem conducts water and minerals upward from roots to shoots, while phloem transports manufactured food (sugars)."},
  {"i":"bio-b3-0134","g":10,"u":"Plants","d":"easy","t":"definition","q":"The tiny pores on the underside of a leaf through which gases are exchanged are called:","o":["Lenticels","Stomata","Root hairs","Guard cells"],"c":1,"e":"Stomata are pores (each bordered by two guard cells) that allow CO₂ in and O₂ and water vapour out during gas exchange."},
  {"i":"bio-b3-0135","g":10,"u":"Biochemical Molecules","d":"easy","t":"definition","q":"Which biochemical molecule is the main long-term energy storage compound and provides about twice the energy per gram compared with carbohydrates?","o":["Proteins","Lipids","Nucleic acids","Vitamins"],"c":1,"e":"Lipids (fats) store roughly twice the energy per gram of carbohydrates, making them the body's main long-term energy reserve."},
  {"i":"bio-b3-0136","g":10,"u":"Biochemical Molecules","d":"easy","t":"conceptual","q":"The basic building-block (monomer) units that join together to form a protein are:","o":["Glucose molecules","Amino acids","Fatty acids","Nucleotides"],"c":1,"e":"Proteins are polymers of amino acids linked by peptide bonds; nucleotides build nucleic acids and glucose builds polysaccharides."},
  {"i":"bio-b3-0137","g":10,"u":"Cell Reproduction","d":"easy","t":"conceptual","q":"Which type of cell division produces two genetically identical daughter cells used for growth and repair?","o":["Meiosis","Mitosis","Binary fission","Fertilization"],"c":1,"e":"Mitosis yields two daughter cells with the same chromosome number as the parent, used for growth and tissue repair."},
  {"i":"bio-b3-0138","g":10,"u":"Cell Reproduction","d":"easy","t":"calculation","q":"If a human body cell has 46 chromosomes, how many chromosomes will each gamete (sex cell) contain after meiosis?","o":["46","92","23","12"],"c":2,"e":"Meiosis halves the chromosome number, so a diploid cell of 46 produces haploid gametes with 23 chromosomes each."},
  {"i":"bio-b3-0139","g":10,"u":"Cell Reproduction","d":"easy","t":"calculation","q":"In a monohybrid cross between two heterozygous tall pea plants (Tt × Tt), what fraction of the offspring is expected to be short (tt)?","o":["1/4","1/2","3/4","All"],"c":0,"e":"The Tt × Tt Punnett square gives TT : Tt : tt = 1 : 2 : 1, so tt (short) is 1/4 of the offspring."},
  {"i":"bio-b3-0140","g":10,"u":"Human Biology","d":"easy","t":"conceptual","q":"Which component of human blood is mainly responsible for carrying oxygen around the body?","o":["White blood cells","Platelets","Red blood cells","Plasma proteins"],"c":2,"e":"Red blood cells contain haemoglobin, which binds and transports oxygen from the lungs to body tissues."},
  {"i":"bio-b3-0141","g":10,"u":"Human Biology","d":"easy","t":"definition","q":"The muscular tube through which food passes from the mouth to the stomach is the:","o":["Trachea","Oesophagus","Duodenum","Larynx"],"c":1,"e":"The oesophagus carries swallowed food from the pharynx to the stomach by peristalsis; the trachea carries air."},
  {"i":"bio-b3-0142","g":10,"u":"Ecological Interaction","d":"easy","t":"definition","q":"In a food chain, organisms such as green plants that make their own food are best described as:","o":["Producers","Primary consumers","Decomposers","Predators"],"c":0,"e":"Producers (autotrophs) such as green plants make their own food by photosynthesis and form the base of the food chain."},
  {"i":"bio-b3-0143","g":10,"u":"Ecological Interaction","d":"easy","t":"conceptual","q":"A relationship in which one organism lives on or in a host and harms it while benefiting itself is called:","o":["Mutualism","Commensalism","Parasitism","Competition"],"c":2,"e":"In parasitism one partner (the parasite) benefits while the other (the host) is harmed, unlike mutualism where both benefit."},
  {"i":"bio-b3-0144","g":10,"u":"Cell Reproduction","d":"medium","t":"calculation","q":"A diploid plant cell has 24 chromosomes. After one complete mitotic division, how many chromosomes are present in each of the two daughter cells?","o":["12","24","48","6"],"c":1,"e":"Mitosis is conservative: each daughter cell receives the same chromosome number as the parent, so each has 24."},
  {"i":"bio-b3-0145","g":10,"u":"Cell Reproduction","d":"medium","t":"calculation","q":"A cell with diploid number 2n = 16 undergoes meiosis. How many chromosomes does each resulting gamete contain?","o":["32","16","8","4"],"c":2,"e":"Meiosis halves the chromosome number, so each gamete is haploid: 16 ÷ 2 = 8."},
  {"i":"bio-b3-0146","g":10,"u":"Biochemical Molecules","d":"medium","t":"conceptual","q":"An enzyme that normally works fastest at 37 °C shows almost no activity at 70 °C. The best explanation is that at 70 °C the enzyme has most likely been:","o":["Denatured, so its active site changed shape","Used up as a reactant in the reaction","Converted permanently into its substrate","Saturated with excess substrate"],"c":0,"e":"High temperature breaks the bonds holding the enzyme's 3-D shape, denaturing it and distorting the active site; enzymes are catalysts, not consumed."},
  {"i":"bio-b3-0147","g":10,"u":"Biochemical Molecules","d":"medium","t":"definition","q":"Which pair correctly matches a biochemical molecule with one of its monomers?","o":["Protein — fatty acid","Polysaccharide — glucose","Nucleic acid — glycerol","Lipid — amino acid"],"c":1,"e":"Polysaccharides such as starch are polymers of glucose monomers; proteins are made of amino acids and nucleic acids of nucleotides."},
  {"i":"bio-b3-0148","g":10,"u":"Plants","d":"medium","t":"conceptual","q":"In the light-dependent stage of photosynthesis, water is split. Which products of this splitting are used directly in the same overall process?","o":["Oxygen released and hydrogen ions/electrons used to make ATP and NADPH","Carbon dioxide fixed and glucose released","Nitrogen fixed and proteins built","Carbon dioxide released and oxygen absorbed"],"c":0,"e":"Photolysis of water releases O₂ as waste and provides H⁺ and electrons used to generate ATP and NADPH for the light-independent stage."},
  {"i":"bio-b3-0149","g":10,"u":"Plants","d":"medium","t":"application","q":"A farmer near Bahir Dar covers part of a leaf with foil and tests the whole leaf for starch after a sunny day. The covered region shows no blue-black colour with iodine. This best demonstrates that:","o":["Chlorophyll is not needed for photosynthesis","Light is needed for photosynthesis","Carbon dioxide is released by leaves","Water is the only requirement for starch"],"c":1,"e":"Only the illuminated region made starch; the foil-covered part received no light and made none, showing light is required."},
  {"i":"bio-b3-0150","g":10,"u":"Human Biology","d":"medium","t":"calculation","q":"In humans, ability to roll the tongue (R) is dominant to non-rolling (r). Two heterozygous (Rr) parents have children. What fraction of the offspring is expected to be unable to roll the tongue?","o":["1/2","3/4","1/4","0"],"c":2,"e":"Rr × Rr gives 1 RR : 2 Rr : 1 rr. Only rr (1/4) cannot roll the tongue."},
  {"i":"bio-b3-0151","g":10,"u":"Human Biology","d":"medium","t":"calculation","q":"A man with blood group AA marries a woman with blood group OO. What blood group(s) are possible in their children?","o":["Only A","Only O","A or O in equal numbers","A, B, AB or O"],"c":0,"e":"Father AA gives only A alleles, mother OO gives only O alleles; all children are AO, which expresses group A."},
  {"i":"bio-b3-0152","g":10,"u":"Human Biology","d":"medium","t":"calculation","q":"Red–green colour blindness is X-linked recessive. A carrier mother (XᴬXᵃ) and a normal father (XᴬY) have sons. What fraction of the SONS is expected to be colour blind?","o":["0","1/4","1/2","All"],"c":2,"e":"Sons get Y from father and either Xᴬ or Xᵃ from mother. Half of sons are XᵃY and colour blind, so 1/2 of sons."},
  {"i":"bio-b3-0153","g":10,"u":"Human Biology","d":"medium","t":"calculation","q":"In a large population at Hardy–Weinberg equilibrium, the recessive homozygous genotype (aa) has frequency 0.16. What is the frequency of the dominant allele (A)?","o":["0.4","0.6","0.84","0.36"],"c":1,"e":"q² = 0.16 so q = 0.4; therefore p = 1 − 0.4 = 0.6 for allele A."},
  {"i":"bio-b3-0154","g":10,"u":"Human Biology","d":"medium","t":"calculation","q":"Using the same population where q = 0.4 for a recessive allele at Hardy–Weinberg equilibrium, what proportion of individuals are expected to be heterozygous carriers?","o":["0.16","0.36","0.48","0.24"],"c":2,"e":"Heterozygotes = 2pq = 2 × 0.6 × 0.4 = 0.48."},
  {"i":"bio-b3-0155","g":10,"u":"Human Biology","d":"medium","t":"conceptual","q":"In a dihybrid cross between two individuals heterozygous for both genes (RrYy × RrYy), the offspring show a 9:3:3:1 phenotype ratio. The '1' class represents individuals that are:","o":["Heterozygous for both genes","Homozygous recessive for both genes","Homozygous dominant for both genes","Heterozygous for one gene only"],"c":1,"e":"In a 9:3:3:1 ratio the smallest (1) class shows both recessive traits, so it is homozygous recessive for both genes (rryy)."},
  {"i":"bio-b3-0156","g":10,"u":"Human Biology","d":"medium","t":"application","q":"After a meal rich in injera, blood glucose rises. The pancreas responds by releasing insulin, which lowers blood glucose, and the lowered glucose then reduces further insulin release. This control pattern is an example of:","o":["Positive feedback","Negative feedback","An irreversible reflex","Passive diffusion only"],"c":1,"e":"The output (lowered glucose) feeds back to reduce the original stimulus for insulin release, which is negative feedback that restores balance."},
  {"i":"bio-b3-0157","g":10,"u":"Human Biology","d":"medium","t":"conceptual","q":"During strenuous exercise when oxygen supply to muscles is limited, human muscle cells carry out anaerobic respiration, producing:","o":["Ethanol and carbon dioxide","Lactic acid","Glucose and oxygen","Only carbon dioxide and water"],"c":1,"e":"In humans, anaerobic respiration in muscle converts glucose (via pyruvate) to lactic acid; ethanol and CO₂ are the yeast/plant fermentation products."},
  {"i":"bio-b3-0158","g":10,"u":"Human Biology","d":"medium","t":"conceptual","q":"In the human breathing system, gas exchange between air and blood occurs across the:","o":["Trachea","Bronchi","Alveoli","Pleural membrane"],"c":2,"e":"Alveoli are thin-walled air sacs with a large surface area and rich capillary supply, where O₂ and CO₂ diffuse between air and blood."},
  {"i":"bio-b3-0159","g":10,"u":"Sub-fields of Biology","d":"medium","t":"definition","q":"A scientist studies how genes are passed from Ethiopian highland cattle to their offspring and how traits are inherited. Which sub-field of biology does this work belong to?","o":["Ecology","Genetics","Taxonomy","Histology"],"c":1,"e":"Genetics is the study of inheritance and variation of traits across generations; ecology, taxonomy and histology address other questions."},
  {"i":"bio-b3-0160","g":10,"u":"Sub-fields of Biology","d":"medium","t":"definition","q":"Which sub-field of biology is most directly concerned with the study of bacteria and viruses, including those involved in making 'ergo' (fermented milk)?","o":["Microbiology","Botany","Zoology","Entomology"],"c":0,"e":"Microbiology studies microorganisms such as bacteria and viruses; botany studies plants, zoology animals, and entomology insects."},
  {"i":"bio-b3-0161","g":10,"u":"Sub-fields of Biology","d":"medium","t":"application","q":"A researcher uses bacteria to produce a useful human protein by inserting a human gene into the bacterial DNA. This application is best classified under:","o":["Palaeontology","Biotechnology","Taxonomy","Ornithology"],"c":1,"e":"Using and modifying living organisms (here genetically engineered bacteria) to make useful products is biotechnology."},
  {"i":"bio-b3-0162","g":10,"u":"Ecological Interaction","d":"medium","t":"application","q":"In a grassland near Awash, grass is eaten by grasshoppers, which are eaten by lizards, which are eaten by hawks. If 10000 kJ of energy is stored in the grass, roughly how much is expected to reach the hawks, assuming about 10% transfer at each step?","o":["1000 kJ","100 kJ","10 kJ","1 kJ"],"c":2,"e":"Energy ~10% per trophic step: grass 10000 → grasshopper 1000 → lizard 100 → hawk 10 kJ."},
  {"i":"bio-b3-0163","g":10,"u":"Ecological Interaction","d":"medium","t":"conceptual","q":"Lichens are formed by a fungus and an alga living together, where the alga makes food by photosynthesis and the fungus provides shelter and absorbs water; both benefit. This relationship is best described as:","o":["Parasitism","Mutualism","Predation","Competition"],"c":1,"e":"Both partners benefit from living together, which defines mutualism; in parasitism one organism is harmed."},
  {"i":"bio-b3-0164","g":10,"u":"Ecological Interaction","d":"medium","t":"conceptual","q":"In the nitrogen cycle, certain soil bacteria convert ammonia/ammonium into nitrates that plants can absorb. This process is called:","o":["Denitrification","Nitrification","Nitrogen fixation","Decomposition"],"c":1,"e":"Nitrification is the bacterial conversion of ammonium to nitrites and then nitrates; nitrogen fixation turns N₂ gas into ammonia, and denitrification returns N₂ to the air."},
  {"i":"bio-b3-0165","g":10,"u":"Cell Reproduction","d":"medium","t":"conceptual","q":"Compared with mitosis, meiosis increases genetic variation in offspring mainly because it includes:","o":["Crossing over and independent assortment of chromosomes","A single division producing two identical cells","Copying of DNA without any errors","Fusion of two body cells"],"c":0,"e":"Meiosis introduces variation through crossing over between homologous chromosomes and independent assortment, producing genetically different gametes."},
  {"i":"bio-b3-0166","g":10,"u":"Sub-fields of Biology","d":"medium","t":"application","q":"A scientist studies how genes are passed from one generation of teff plants to the next and predicts the proportion of offspring carrying a disease-resistance allele. Which sub-field of biology does this work belong to?","o":["Ecology","Genetics","Taxonomy","Physiology"],"c":1,"e":"Genetics is the sub-field concerned with heredity and the transmission of traits and alleles between generations, which is exactly what predicting allele proportions in offspring involves."},
  {"i":"bio-b3-0167","g":10,"u":"Sub-fields of Biology","d":"medium","t":"conceptual","q":"A researcher at the Ethiopian Public Health Institute identifies a new bacterial strain and studies its structure and how it causes disease. Which two sub-fields are MOST directly combined in this work?","o":["Botany and ecology","Microbiology and pathology","Zoology and genetics","Taxonomy and physiology"],"c":1,"e":"Studying a bacterium (a microorganism) is microbiology, and investigating how it causes disease is pathology; together they cover identifying the strain and its disease mechanism."},
  {"i":"bio-b3-0168","g":10,"u":"Sub-fields of Biology","d":"medium","t":"definition","q":"Which sub-field of biology would a worker use to name and classify newly collected plant specimens from the Bale Mountains into a hierarchy of groups?","o":["Taxonomy","Embryology","Ethology","Histology"],"c":0,"e":"Taxonomy is the science of naming, describing, and classifying organisms into ordered groups such as kingdom, phylum, and species."},
  {"i":"bio-b3-0169","g":10,"u":"Plants","d":"medium","t":"conceptual","q":"In a leaf, the guard cells close the stomata during a hot, dry afternoon. The MOST direct benefit of this response to the plant is to:","o":["increase the rate of photosynthesis","reduce water loss by transpiration","speed up mineral uptake from the soil","increase oxygen entry for respiration"],"c":1,"e":"Closing stomata reduces the surface for water vapour to escape, lowering transpiration and conserving water during hot, dry conditions, even though it also slows gas exchange."},
  {"i":"bio-b3-0170","g":10,"u":"Plants","d":"medium","t":"application","q":"A potted plant is placed near a window so that light reaches it from one side only. After several days the shoot tip bends toward the window. This growth response is caused mainly by uneven distribution of which hormone?","o":["Ethylene","Abscisic acid","Auxin","Cytokinin"],"c":2,"e":"Auxin accumulates on the shaded side of the shoot, causing those cells to elongate more, so the shoot bends toward the light (positive phototropism)."},
  {"i":"bio-b3-0171","g":10,"u":"Plants","d":"medium","t":"conceptual","q":"Water moves up the xylem from the roots to the leaves of a tall eucalyptus tree mainly because:","o":["xylem cells actively pump water upward using ATP","transpiration from leaves creates a pull through cohesive water columns","root pressure alone lifts water the full height","phloem pushes water into the xylem under pressure"],"c":1,"e":"The transpiration-pull (cohesion-tension) mechanism dominates: water evaporating from leaves pulls a continuous, cohesive column of water up the xylem; xylem cells are dead and do not pump."},
  {"i":"bio-b3-0172","g":10,"u":"Plants","d":"medium","t":"application","q":"A farmer notices that seeds soaked in water before planting germinate faster than dry seeds. The water is needed FIRST to:","o":["provide minerals for the seedling","activate enzymes that mobilise stored food","supply chlorophyll for photosynthesis","increase the temperature of the seed"],"c":1,"e":"Imbibed water rehydrates the seed and activates hydrolytic enzymes, which break down stored starch and protein into soluble forms the embryo can use to begin growth."},
  {"i":"bio-b3-0173","g":10,"u":"Biochemical Molecules","d":"medium","t":"application","q":"An enzyme that digests starch works best at pH 7 and 37 degrees Celsius. If the temperature is raised to 60 degrees Celsius, the reaction rate falls sharply. The MOST likely reason is that the enzyme:","o":["has used up all its substrate","has been denatured, changing its active site shape","has switched to a different substrate","has been converted into a competitive inhibitor"],"c":1,"e":"High temperature disrupts the bonds holding the enzyme's tertiary structure, denaturing it; the active site changes shape so substrate can no longer bind, sharply lowering the rate."},
  {"i":"bio-b3-0174","g":10,"u":"Biochemical Molecules","d":"medium","t":"conceptual","q":"A food sample turns brick-red when heated with Benedict's solution but stays blue with iodine solution. The sample most likely contains:","o":["starch but no reducing sugar","reducing sugar but no starch","protein but no sugar","lipid but no starch"],"c":1,"e":"A brick-red colour with Benedict's solution indicates a reducing sugar is present, while iodine staying blue (not turning blue-black) means no starch is present."},
  {"i":"bio-b3-0175","g":10,"u":"Biochemical Molecules","d":"medium","t":"definition","q":"Which statement BEST describes the relationship between amino acids and proteins?","o":["Proteins are single large amino acids","Amino acids are joined by peptide bonds to form proteins","Proteins break down into glucose units","Amino acids are a type of fatty acid"],"c":1,"e":"Proteins are polymers of many amino acids linked by peptide bonds; the sequence and folding of these amino acids determine the protein's structure and function."},
  {"i":"bio-b3-0176","g":10,"u":"Biochemical Molecules","d":"medium","t":"calculation","q":"A short section of DNA has 30 adenine (A) bases out of 100 total bases. Using Chargaff's base-pairing rule, how many cytosine (C) bases does this section contain?","o":["20","30","40","70"],"c":0,"e":"By base pairing A = T = 30, so A + T = 60, leaving 40 bases as G + C. Since G = C, each equals 40 divided by 2 = 20 cytosine bases."},
  {"i":"bio-b3-0177","g":10,"u":"Cell Reproduction","d":"medium","t":"calculation","q":"A human body (somatic) cell contains 46 chromosomes. After one normal mitotic division, each of the two daughter cells contains how many chromosomes?","o":["23","46","69","92"],"c":1,"e":"Mitosis produces two daughter cells genetically identical to the parent, each keeping the full diploid number; 46 chromosomes give two cells of 46 each."},
  {"i":"bio-b3-0178","g":10,"u":"Cell Reproduction","d":"medium","t":"calculation","q":"A primary cell with 12 chromosomes (diploid number 2n = 12) completes meiosis. How many chromosomes does each resulting gamete contain?","o":["3","6","12","24"],"c":1,"e":"Meiosis halves the chromosome number, so each haploid gamete has n = 6 (that is 12 divided by 2 = 6) chromosomes."},
  {"i":"bio-b3-0179","g":10,"u":"Cell Reproduction","d":"medium","t":"conceptual","q":"During which event of meiosis does the exchange of segments between homologous chromosomes (crossing over) increase genetic variation?","o":["Prophase I","Anaphase II","Telophase I","Metaphase II"],"c":0,"e":"Crossing over occurs in prophase I when homologous chromosomes pair up as bivalents and exchange segments at chiasmata, creating new allele combinations."},
  {"i":"bio-b3-0180","g":10,"u":"Cell Reproduction","d":"medium","t":"conceptual","q":"Mitosis differs from meiosis mainly in that mitosis:","o":["produces four genetically varied cells","reduces the chromosome number by half","produces two cells identical to the parent cell","occurs only in reproductive organs"],"c":2,"e":"Mitosis produces two diploid daughter cells genetically identical to the parent, whereas meiosis produces four genetically varied haploid cells."},
  {"i":"bio-b3-0181","g":10,"u":"Human Biology","d":"medium","t":"calculation","q":"In humans, the ability to roll the tongue (R) is dominant to the inability to roll it (r). Two heterozygous (Rr) parents have children. What fraction of their children is expected to be unable to roll the tongue?","o":["1/4","1/2","3/4","0"],"c":0,"e":"The cross Rr x Rr gives genotype ratio 1 RR : 2 Rr : 1 rr. Only rr cannot roll the tongue, so 1 out of 4 children, that is 1/4."},
  {"i":"bio-b3-0182","g":10,"u":"Human Biology","d":"medium","t":"calculation","q":"A man with blood group AB marries a woman with blood group O. What blood groups are possible among their children?","o":["A and B only","AB and O only","A, B, AB and O","O only"],"c":0,"e":"The father is genotype I^A I^B and the mother is ii. Children receive I^A or I^B from the father and i from the mother, giving I^A i (group A) or I^B i (group B) only."},
  {"i":"bio-b3-0183","g":10,"u":"Human Biology","d":"medium","t":"calculation","q":"Red-green colour blindness is X-linked recessive. A carrier mother (X^N X^n) and a normal-vision father (X^N Y) have a son. What is the probability that the son is colour blind?","o":["0","1/4","1/2","1"],"c":2,"e":"Sons receive Y from the father and either X^N or X^n from the mother with equal chance. Half the sons get X^n Y and are colour blind, so the probability is 1/2."},
  {"i":"bio-b3-0184","g":10,"u":"Human Biology","d":"medium","t":"application","q":"In the human breathing system, gas exchange between air and blood happens across the:","o":["walls of the trachea","walls of the alveoli","lining of the bronchi","surface of the diaphragm"],"c":1,"e":"Alveoli are thin-walled, moist, and surrounded by capillaries, providing the large surface area where oxygen and carbon dioxide diffuse between air and blood."},
  {"i":"bio-b3-0185","g":10,"u":"Ecological Interaction","d":"medium","t":"application","q":"In a grassland food chain: grass to grasshopper to lizard to hawk, the grasshopper occupies which trophic level?","o":["First trophic level (producer)","Second trophic level (primary consumer)","Third trophic level (secondary consumer)","Fourth trophic level (tertiary consumer)"],"c":1,"e":"Grass is the producer (first level); the grasshopper eats the producer, making it the primary consumer at the second trophic level."},
  {"i":"bio-b3-0186","g":10,"u":"Ecological Interaction","d":"medium","t":"conceptual","q":"Rhizobium bacteria live inside the root nodules of bean plants, fixing nitrogen the plant uses while receiving sugars from the plant. This relationship is BEST described as:","o":["parasitism","mutualism","commensalism","predation"],"c":1,"e":"Both partners benefit: the plant gains usable nitrogen and the bacteria gain sugars and shelter, which defines mutualism (a mutually beneficial symbiosis)."},
  {"i":"bio-b3-0187","g":10,"u":"Ecological Interaction","d":"medium","t":"calculation","q":"In an energy pyramid, only about 10 percent of energy passes to the next trophic level. If producers store 20,000 kJ, approximately how much energy is available to the secondary consumers?","o":["2,000 kJ","200 kJ","20 kJ","2 kJ"],"c":1,"e":"Producers 20,000 kJ; primary consumers get 10 percent = 2,000 kJ; secondary consumers get 10 percent of that = 200 kJ."},
  {"i":"bio-b3-0188","g":10,"u":"Sub-fields of Biology","d":"medium","t":"application","q":"A scientist studies how a strain of nitrogen-fixing bacteria in teff soils responds to changing acidity and shares its genus with related species. Which two sub-fields of biology are MOST directly combined in this work?","o":["Microbiology and taxonomy","Histology and palaeontology","Embryology and virology","Mycology and entomology"],"c":0,"e":"Studying bacteria is microbiology; grouping them into a genus with related species is taxonomy (classification). The other pairs do not fit bacteria or naming."},
  {"i":"bio-b3-0189","g":10,"u":"Sub-fields of Biology","d":"medium","t":"conceptual","q":"A research team measures gene-frequency changes in a population of Ethiopian wolves across generations. The sub-field whose definition BEST matches this study is the one concerned with:","o":["the structure of tissues under a microscope","heredity and variation in populations","the chemical reactions inside a single cell","the naming and ranking of organisms"],"c":1,"e":"Tracking gene frequencies over generations is genetics, defined as the study of heredity and variation. Tissue structure is histology, cell reactions are biochemistry/cell biology, and naming is taxonomy."},
  {"i":"bio-b3-0190","g":10,"u":"Sub-fields of Biology","d":"medium","t":"definition","q":"During an outbreak, a health officer in Bahir Dar traces how a disease spreads through a community and which groups are most affected. This work falls under the sub-field that studies:","o":["the distribution and control of diseases in populations","the internal anatomy of one patient","the fossils of extinct organisms","the behaviour of single animals in the wild"],"c":0,"e":"Studying disease distribution, spread and control in populations is epidemiology. Anatomy is one body, palaeontology is fossils, and ethology is animal behaviour."},
  {"i":"bio-b3-0191","g":10,"u":"Plants","d":"medium","t":"conceptual","q":"A maize leaf is kept in darkness for 48 hours, then one half is exposed to light for several hours and tested for starch with iodine. The dark-kept half shows no blue-black colour MAINLY because:","o":["chlorophyll was destroyed by darkness","no light was available to drive photosynthesis","the stomata permanently closed","starch is only made at night"],"c":1,"e":"Starch forms only where photosynthesis occurred, which needs light; the shaded half made no glucose to store as starch, so iodine stays brown. Chlorophyll is not destroyed by short darkness."},
  {"i":"bio-b3-0192","g":10,"u":"Plants","d":"medium","t":"application","q":"A farmer notices that on a hot, dry, windy afternoon his bean plants wilt even though the soil is moist. The MOST direct cause is that:","o":["transpiration exceeds water uptake by the roots","photosynthesis stopped completely","the roots stopped respiring","phloem transport reversed direction"],"c":0,"e":"Hot, dry, windy conditions raise transpiration; when water loss from leaves exceeds root uptake, cells lose turgor and the plant wilts. Photosynthesis slowing does not cause wilting directly."},
  {"i":"bio-b3-0193","g":10,"u":"Plants","d":"medium","t":"conceptual","q":"Water rises from the roots to the top of a tall eucalyptus tree mainly through xylem. The pulling force at the top is generated chiefly by:","o":["active pumping by xylem cells","root pressure alone","transpiration pull plus cohesion of water","translocation of sugars in phloem"],"c":2,"e":"Evaporation from leaf surfaces creates transpiration pull, and cohesion between water molecules transmits this tension down a continuous xylem column. Xylem cells are dead and do not pump; root pressure is too weak for tall trees."},
  {"i":"bio-b3-0194","g":10,"u":"Plants","d":"medium","t":"application","q":"A ring of bark (containing phloem) is removed all the way around a tree trunk. Over time the region ABOVE the ring swells with stored sugars. This best demonstrates that phloem:","o":["transports water upward only","carries dissolved sugars away from the leaves","conducts only mineral ions","is made of dead hollow cells"],"c":1,"e":"Sugars made in leaves move down through phloem; blocking it traps sugars above the ring, causing swelling. This shows phloem transports organic food, while xylem (still intact) carries water."},
  {"i":"bio-b3-0195","g":10,"u":"Biochemical Molecules","d":"medium","t":"calculation","q":"A polypeptide is built from amino acids joined by peptide bonds. If a chain contains 60 amino acid residues fully linked in a single line, how many peptide bonds and how many water molecules were released during its formation?","o":["60 bonds and 60 water molecules","59 bonds and 59 water molecules","61 bonds and 60 water molecules","59 bonds and 60 water molecules"],"c":1,"e":"Joining n amino acids in one chain needs (n-1) peptide bonds, and each bond is a condensation releasing one water. So 60 residues give 59 bonds and 59 water molecules."},
  {"i":"bio-b3-0196","g":10,"u":"Biochemical Molecules","d":"medium","t":"application","q":"An enzyme that digests starch works best at 37 °C and pH 7. When the solution is heated to 70 °C, the reaction stops and does not restart on cooling. The BEST explanation is that the enzyme has:","o":["used up all its substrate","been denatured, losing its active-site shape","reached its optimum temperature","turned into a different enzyme"],"c":1,"e":"High temperature breaks the bonds holding the enzyme's 3-D shape, permanently distorting the active site (denaturation), so activity is not recovered on cooling. The substrate is unrelated to this loss."},
  {"i":"bio-b3-0197","g":10,"u":"Biochemical Molecules","d":"medium","t":"conceptual","q":"A food sample turns brick-red with Benedict's solution after heating but stays blue with iodine. The sample most likely contains:","o":["starch but no sugar","a reducing sugar but little or no starch","protein only","lipids only"],"c":1,"e":"Brick-red with Benedict's indicates a reducing sugar; iodine staying blue (not blue-black) means little or no starch is present. The two tests detect different molecules."},
  {"i":"bio-b3-0198","g":10,"u":"Biochemical Molecules","d":"medium","t":"conceptual","q":"Compared with one gram of carbohydrate, one gram of lipid releases roughly twice the energy on full oxidation. The main structural reason is that lipids:","o":["contain more nitrogen atoms","are more highly reduced (richer in C–H bonds)","dissolve easily in water","are made of amino acids"],"c":1,"e":"Lipids have many C-H bonds and are more reduced than carbohydrates, so their oxidation releases more energy per gram. Nitrogen and amino acids belong to proteins, not lipids."},
  {"i":"bio-b3-0199","g":10,"u":"Cell Reproduction","d":"medium","t":"calculation","q":"A diploid plant cell has 24 chromosomes. After one complete mitotic division, each daughter cell contains how many chromosomes, and after one meiotic division producing gametes, each gamete contains how many?","o":["12 after mitosis and 24 in gametes","24 after mitosis and 12 in gametes","48 after mitosis and 24 in gametes","24 after mitosis and 24 in gametes"],"c":1,"e":"Mitosis keeps the chromosome number constant, so daughter cells have 24. Meiosis halves it, so gametes have 24 ÷ 2 = 12 chromosomes."},
  {"i":"bio-b3-0200","g":10,"u":"Cell Reproduction","d":"medium","t":"conceptual","q":"During meiosis, crossing over occurs in prophase I when homologous chromosomes exchange segments. Its MAIN biological significance is that it:","o":["doubles the chromosome number","increases genetic variation among gametes","repairs all DNA damage","prevents the cell from dividing"],"c":1,"e":"Crossing over recombines maternal and paternal alleles on homologous chromosomes, producing new allele combinations and increasing variation. It does not change chromosome number."},
  {"i":"bio-b3-0201","g":10,"u":"Cell Reproduction","d":"medium","t":"application","q":"A cell that has completed DNA replication enters mitosis with sister chromatids joined at the centromere. At which stage do the sister chromatids separate and move to opposite poles?","o":["Prophase","Metaphase","Anaphase","Telophase"],"c":2,"e":"In anaphase the centromeres split and sister chromatids are pulled to opposite poles. Metaphase only aligns them at the equator; prophase condenses them."},
  {"i":"bio-b3-0202","g":10,"u":"Cell Reproduction","d":"medium","t":"calculation","q":"In a pea plant, a heterozygous tall (Tt) is crossed with a short (tt) plant, where tall (T) is dominant. Of 200 offspring, about how many are expected to be short?","o":["About 50","About 100","About 150","About 0"],"c":1,"e":"Tt × tt gives 1 Tt : 1 tt, so half the offspring are short. Half of 200 is about 100 short plants."},
  {"i":"bio-b3-0203","g":10,"u":"Cell Reproduction","d":"medium","t":"calculation","q":"Two heterozygous parents (Bb × Bb) are crossed, where B (brown) is dominant over b (white). In a dihybrid-free monohybrid cross, what fraction of the offspring are expected to be homozygous recessive (white)?","o":["1/4","1/2","3/4","1/16"],"c":0,"e":"Bb × Bb gives genotypes 1 BB : 2 Bb : 1 bb, so the bb (white) fraction is 1/4. The 3/4 figure is the brown phenotype, not white."},
  {"i":"bio-b3-0204","g":10,"u":"Human Biology","d":"medium","t":"calculation","q":"In humans, red-green colour blindness is X-linked recessive. A carrier mother (XᴬXᵃ) marries a man with normal vision (XᴬY). What fraction of their SONS are expected to be colour blind?","o":["0","1/4 of all children","1/2 of the sons","All of the sons"],"c":2,"e":"Sons get Y from father and either Xᴬ or Xᵃ from the carrier mother, so half the sons are XᵃY (colour blind). Among all children that is 1/4, but among sons it is 1/2."},
  {"i":"bio-b3-0205","g":10,"u":"Human Biology","d":"medium","t":"application","q":"A person donates blood and is found to be blood group O, Rh-negative. Considering ABO antigens only, this person can safely DONATE red cells to recipients of which ABO groups?","o":["Only group O","Groups A and B only","All ABO groups (A, B, AB and O)","Only group AB"],"c":2,"e":"Group O red cells carry neither A nor B antigen, so they are not attacked by anti-A or anti-B antibodies and can be given to all ABO groups (O is the universal red-cell donor)."},
  {"i":"bio-b3-0206","g":10,"u":"Human Biology","d":"medium","t":"conceptual","q":"After eating injera with wot, a person's blood glucose rises. The pancreas responds by releasing insulin, which lowers blood glucose. This is an example of:","o":["positive feedback amplifying the change","negative feedback restoring the set point","a reflex arc through the spinal cord","an inherited Mendelian trait"],"c":1,"e":"Insulin opposes the rise in glucose and returns it toward normal, which is negative feedback (control by reversing a deviation). Positive feedback would amplify the rise instead."},
  {"i":"bio-b3-0207","g":10,"u":"Human Biology","d":"medium","t":"application","q":"In the human gas-exchange system, oxygen moves from the alveoli into the blood capillaries. The MAIN reason oxygen diffuses in this direction is that:","o":["the alveoli actively pump oxygen into blood","oxygen partial pressure is higher in alveoli than in deoxygenated blood","blood is warmer than the alveolar air","carbon dioxide carries oxygen with it"],"c":1,"e":"Diffusion follows the partial-pressure gradient; alveolar air has higher oxygen partial pressure than the returning deoxygenated blood, so oxygen moves into the blood. No active pumping is involved."},
  {"i":"bio-b3-0208","g":10,"u":"Ecological Interaction","d":"medium","t":"application","q":"In a grassland food chain, grass is eaten by grasshoppers, which are eaten by frogs, which are eaten by snakes. If only about 10% of energy passes to each next level and the grass fixes 10,000 kJ, roughly how much energy reaches the snakes?","o":["1,000 kJ","100 kJ","10 kJ","1 kJ"],"c":2,"e":"Energy at each step is 10% of the previous: grasshoppers 1,000 kJ, frogs 100 kJ, snakes 10 kJ. So snakes (the fourth level) receive about 10 kJ."},
  {"i":"bio-b3-0209","g":10,"u":"Ecological Interaction","d":"medium","t":"conceptual","q":"Acacia trees in Ethiopian savanna house ants that attack browsing animals, while the ants gain shelter and food from the tree. Both partners benefit. This relationship is BEST described as:","o":["parasitism","mutualism","commensalism","predation"],"c":1,"e":"When both organisms benefit from living together, the interaction is mutualism. Parasitism harms one partner, and commensalism benefits only one without affecting the other."},
  {"i":"bio-b3-0210","g":10,"u":"Cell Reproduction","d":"medium","t":"calculation","q":"In peas, seed shape (R = round, dominant; r = wrinkled) and seed colour (Y = yellow, dominant; y = green) assort independently. Two plants of genotype RrYy are crossed. What fraction of the offspring are expected to be wrinkled AND green?","o":["1/16","3/16","9/16","1/4"],"c":0,"e":"Each gene gives a 3:1 ratio, so the homozygous recessive (rr) is 1/4 and (yy) is 1/4. By independent assortment, 1/4 × 1/4 = 1/16 wrinkled-green."},
  {"i":"bio-b3-0211","g":10,"u":"Human Biology","d":"medium","t":"calculation","q":"A father with blood group A (genotype IAi) and a mother with blood group B (genotype IBi) have children. What is the probability that a given child has blood group O?","o":["1/4","1/2","0","3/4"],"c":0,"e":"The cross IAi × IBi gives IAIB (AB), IAi (A), IBi (B) and ii (O), each at probability 1/4. Group O needs genotype ii, so the probability is 1/4."},
  {"i":"bio-b3-0212","g":10,"u":"Plants","d":"medium","t":"application","q":"Using the balanced equation 6CO₂ + 6H₂O → C₆H₁₂O₆ + 6O₂, if a leaf consumes 12 molecules of CO₂ during photosynthesis, how many molecules of O₂ are released, assuming water is not limiting?","o":["12","6","24","2"],"c":0,"e":"The equation shows CO₂ and O₂ in a 6:6 (that is 1:1) ratio. For 12 CO₂ consumed, 12 O₂ molecules are released."},
  {"i":"bio-b3-0213","g":10,"u":"Cell Reproduction","d":"hard","t":"calculation","q":"A diploid plant cell with 2n = 24 undergoes meiosis. After meiosis I is complete, how many chromosomes (counted as structures) are present in EACH of the two daughter cells, and how many chromatids does each of those cells contain?","o":["12 chromosomes, 24 chromatids","12 chromosomes, 12 chromatids","24 chromosomes, 48 chromatids","6 chromosomes, 12 chromatids"],"c":0,"e":"Meiosis I separates homologous pairs, so each daughter has 12 chromosomes (haploid), but each is still made of 2 sister chromatids (24 chromatids); sisters separate only in meiosis II."},
  {"i":"bio-b3-0214","g":10,"u":"Cell Reproduction","d":"hard","t":"calculation","q":"Starting from a single diploid cell, one round of mitosis is followed by each resulting cell completing meiosis. How many haploid cells are ultimately produced?","o":["8","4","2","16"],"c":0,"e":"One mitosis gives 2 diploid cells; each then completes meiosis producing 4 haploid cells, so 2 × 4 = 8 haploid cells."},
  {"i":"bio-b3-0215","g":10,"u":"Human Biology","d":"hard","t":"calculation","q":"In humans, colour-blindness is X-linked recessive. A carrier woman marries a man with normal vision. Of their SONS only, what fraction is expected to be colour-blind?","o":["1/2","1/4","0","1"],"c":0,"e":"Sons receive their X from the mother (X^A X^a) and a Y from the father; half the sons inherit X^a and are colour-blind, so among sons the fraction is 1/2."},
  {"i":"bio-b3-0216","g":10,"u":"Human Biology","d":"hard","t":"calculation","q":"A man with blood group AB marries a woman with blood group O. Considering the ABO system only, what proportion of their children are expected to have blood group O?","o":["0","1/2","1/4","All"],"c":0,"e":"Father is I^A I^B, mother is ii; children are I^A i (group A) or I^B i (group B). None can be ii, so the proportion with group O is 0."},
  {"i":"bio-b3-0217","g":10,"u":"Human Biology","d":"hard","t":"calculation","q":"In a dihybrid cross between two organisms heterozygous for both genes (RrYy × RrYy) showing independent assortment, what fraction of the offspring are expected to be homozygous recessive for BOTH traits?","o":["1/16","9/16","3/16","1/4"],"c":0,"e":"P(rr) = 1/4 and P(yy) = 1/4; by independent assortment P(rryy) = 1/4 × 1/4 = 1/16."},
  {"i":"bio-b3-0218","g":10,"u":"Human Biology","d":"hard","t":"application","q":"A couple, both carriers for albinism (autosomal recessive), already have two albino children. What is the probability that their NEXT child is also albino?","o":["1/4","1/16","3/4","0"],"c":0,"e":"Each conception is independent of previous children; for Aa × Aa the chance of an albino (aa) child remains 1/4 every time."},
  {"i":"bio-b3-0219","g":10,"u":"Plants","d":"hard","t":"conceptual","q":"During photosynthesis, the products of the light-dependent reactions that are consumed by the Calvin cycle (light-independent reactions) are:","o":["ATP and NADPH","ATP and oxygen","Carbon dioxide and water","NADPH and carbon dioxide"],"c":0,"e":"The light reactions produce ATP and NADPH (releasing O2 as a by-product); the Calvin cycle uses ATP and NADPH to fix CO2 into sugar."},
  {"i":"bio-b3-0220","g":10,"u":"Plants","d":"hard","t":"application","q":"A potted plant is sealed in a clear chamber in bright light. While photosynthesis exceeds respiration over several hours, the chamber air will MOST likely show which net change?","o":["O2 rises and CO2 falls","O2 falls and CO2 rises","Both O2 and CO2 rise","Both O2 and CO2 fall"],"c":0,"e":"When photosynthesis exceeds respiration, there is net consumption of CO2 and net release of O2, so O2 rises and CO2 falls."},
  {"i":"bio-b3-0221","g":10,"u":"Plants","d":"hard","t":"conceptual","q":"In a typical dicot leaf, most photosynthesis occurs in the palisade mesophyll. Which feature BEST explains why this tissue is more photosynthetically productive than the spongy mesophyll?","o":["Tightly packed, chloroplast-rich cells just below the upper surface","Large air spaces that maximise gas diffusion","A thick waxy cuticle that traps light","Absence of chloroplasts that lets light pass through"],"c":0,"e":"Palisade cells are densely packed, column-shaped and chloroplast-rich beneath the upper epidermis, capturing maximal incoming light; spongy mesophyll specialises in gas exchange."},
  {"i":"bio-b3-0222","g":10,"u":"Plants","d":"hard","t":"application","q":"A farmer near Bahir Dar notices that on a hot, dry afternoon his maize leaves' stomata close. The MOST direct immediate consequence for the leaf is:","o":["A decline in photosynthesis as CO2 entry is restricted","An increase in transpiration","A rise in internal CO2 concentration","Faster water uptake by the roots"],"c":0,"e":"Closed stomata reduce CO2 entry, so the Calvin cycle slows and photosynthesis declines; transpiration also drops, but the direct effect on photosynthesis is CO2 limitation."},
  {"i":"bio-b3-0223","g":10,"u":"Biochemical Molecules","d":"hard","t":"conceptual","q":"An enzyme-catalysed reaction is run with fixed enzyme amount while substrate concentration is increased. The rate rises then plateaus. The plateau is BEST explained by:","o":["All enzyme active sites being saturated with substrate","The enzyme being denatured by the substrate","Substrate molecules running out","A fall in temperature during the reaction"],"c":0,"e":"At high substrate concentration every active site is occupied as fast as products are released, so adding more substrate cannot raise the rate, giving a plateau (Vmax)."},
  {"i":"bio-b3-0224","g":10,"u":"Biochemical Molecules","d":"hard","t":"calculation","q":"One DNA strand reads 5'-A T G C C G T A-3'. Written 5' to 3', what is the sequence of its complementary strand?","o":["5'-T A C G G C A T-3'","5'-A T G C C G T A-3'","5'-T A T G C C G T-3'","5'-U A C G G C A U-3'"],"c":0,"e":"The base-by-base complement of ATGCCGTA is TACGGCAT; read antiparallel and written 5'→3', the complementary strand is 5'-TACGGCAT-3'."},
  {"i":"bio-b3-0225","g":10,"u":"Biochemical Molecules","d":"hard","t":"conceptual","q":"Proteins differ from carbohydrates and lipids in containing which element as a defining component of their monomers?","o":["Nitrogen","Carbon","Oxygen","Hydrogen"],"c":0,"e":"Amino acids contain an amino group (-NH2), so nitrogen is characteristic of proteins; carbohydrates and lipids are essentially only C, H and O."},
  {"i":"bio-b3-0226","g":10,"u":"Biochemical Molecules","d":"hard","t":"application","q":"A student boils a leaf, removes its chlorophyll, then adds iodine solution and sees blue-black colour only where the leaf had been exposed to light. The blue-black colour indicates the presence of:","o":["Starch","Reducing sugar","Protein","Lipid"],"c":0,"e":"Iodine turns blue-black with starch; starch forms only in illuminated regions where photosynthesis occurred, showing that light is needed."},
  {"i":"bio-b3-0227","g":10,"u":"Human Biology","d":"hard","t":"application","q":"Blood entering the left atrium differs from blood entering the right atrium mainly in that it has:","o":["Higher oxygen and lower carbon dioxide content","Lower oxygen and higher carbon dioxide content","Higher carbon dioxide and higher oxygen content","Identical gas content but higher pressure"],"c":0,"e":"Pulmonary veins return oxygenated blood from the lungs to the left atrium (high O2, low CO2); the right atrium receives deoxygenated blood from the body (low O2, high CO2)."},
  {"i":"bio-b3-0228","g":10,"u":"Human Biology","d":"hard","t":"conceptual","q":"In the human digestive system, protein digestion BEGINS in the stomach. The enzyme and the condition responsible are:","o":["Pepsin acting in acidic conditions","Amylase acting in alkaline conditions","Lipase acting in acidic conditions","Trypsin acting in acidic conditions"],"c":0,"e":"Gastric glands secrete pepsin, which works best in the acidic environment created by hydrochloric acid; trypsin acts later in the alkaline small intestine."},
  {"i":"bio-b3-0229","g":10,"u":"Human Biology","d":"hard","t":"conceptual","q":"In a spinal reflex arc, the correct order of signal transmission after a stimulus is detected is:","o":["Sensory neuron → interneuron (spinal cord) → motor neuron → effector","Motor neuron → sensory neuron → effector → interneuron","Effector → motor neuron → sensory neuron → receptor","Sensory neuron → motor neuron → brain → effector"],"c":0,"e":"A reflex travels from the receptor along the sensory neuron to an interneuron in the spinal cord, then out via the motor neuron to the effector, giving a rapid response without waiting for the brain."},
  {"i":"bio-b3-0230","g":10,"u":"Ecological Interaction","d":"hard","t":"calculation","q":"In a grassland food chain the producers fix 20,000 kJ of energy. Assuming about 10% energy transfer between trophic levels, approximately how much energy reaches the secondary consumers?","o":["200 kJ","2,000 kJ","20 kJ","2 kJ"],"c":0,"e":"Primary consumers receive ~10% of 20,000 = 2,000 kJ; secondary consumers receive ~10% of that = 200 kJ."},
  {"i":"bio-b3-0231","g":10,"u":"Ecological Interaction","d":"hard","t":"conceptual","q":"In an Ethiopian acacia woodland, an oxpecker bird removes ticks from a buffalo's hide, gaining food while the buffalo is relieved of parasites. This relationship is BEST classified as:","o":["Mutualism","Commensalism","Parasitism","Predation"],"c":0,"e":"Both organisms benefit—the bird gets food and the buffalo gets cleaned—which defines mutualism."},
  {"i":"bio-b3-0232","g":10,"u":"Ecological Interaction","d":"hard","t":"application","q":"In the nitrogen cycle, atmospheric N2 is converted into a form usable by plants mainly through:","o":["Nitrogen fixation by bacteria such as those in legume root nodules","Photosynthesis in leaf chloroplasts","Transpiration through stomata","Denitrification by fungi"],"c":0,"e":"Nitrogen-fixing bacteria (e.g. Rhizobium in legume nodules) convert inert N2 into ammonia/nitrate that plants can absorb; denitrification does the reverse."},
  {"i":"bio-b3-0233","g":10,"u":"Sub-fields of Biology","d":"hard","t":"application","q":"A scientist engineers a strain of bacteria to produce human insulin for treating diabetes. This work belongs MOST specifically to which sub-field of biology?","o":["Biotechnology (genetic engineering)","Taxonomy","Ecology","Palaeontology"],"c":0,"e":"Manipulating an organism's genes to make a useful product (insulin) is biotechnology/genetic engineering; taxonomy classifies organisms and ecology studies interactions."},
  {"i":"bio-b3-0234","g":10,"u":"Sub-fields of Biology","d":"hard","t":"definition","q":"A researcher identifies newly collected highland plants and groups them into a naming hierarchy. The sub-field of biology directly concerned with naming and classifying organisms is:","o":["Taxonomy","Physiology","Genetics","Microbiology"],"c":0,"e":"Taxonomy is the science of identifying, naming and classifying organisms into groups; physiology studies function and genetics studies inheritance."},
  {"i":"bio-b3-0235","g":10,"u":"Cell Reproduction","d":"hard","t":"calculation","q":"A pure-breeding tall purple-flowered pea (TTPP) is crossed with a short white-flowered pea (ttpp); the genes assort independently. If 320 F₂ offspring are produced, approximately how many are expected to be short AND purple?","o":["20","60","180","240"],"c":1,"e":"F₂ dihybrid ratio is 9:3:3:1; short-purple (ttP_) is the 3/16 class, so 3/16 × 320 = 60."},
  {"i":"bio-b3-0236","g":10,"u":"Cell Reproduction","d":"hard","t":"calculation","q":"In humans, red-green colour blindness is X-linked recessive. A woman whose father was colour-blind marries a man with normal vision. What fraction of ALL their children is expected to be colour-blind?","o":["0","1/4","1/2","3/4"],"c":1,"e":"The woman is a carrier (XᶜX) since her father gave her Xᶜ; cross XᶜX × XY gives XᶜX, XX, XᶜY, XY, so 1/4 of all children (the sons receiving Xᶜ) are colour-blind."},
  {"i":"bio-b3-0237","g":10,"u":"Cell Reproduction","d":"hard","t":"calculation","q":"A cell with a diploid number of 2n = 12 undergoes meiosis. How many chromatids are present in a single cell at the start of metaphase I, and how many chromosomes are in each cell at the end of meiosis II?","o":["24 chromatids; 6 chromosomes","12 chromatids; 12 chromosomes","24 chromatids; 12 chromosomes","12 chromatids; 6 chromosomes"],"c":0,"e":"After S-phase each of the 12 chromosomes has 2 sister chromatids = 24 chromatids at metaphase I; meiosis II halves to n = 6 chromosomes per gamete."},
  {"i":"bio-b3-0238","g":10,"u":"Cell Reproduction","d":"hard","t":"calculation","q":"Two parents with normal pigmentation each have one albino child (albinism is autosomal recessive). If they have three more children, what is the probability that all three are unaffected?","o":["27/64","1/64","9/16","3/4"],"c":0,"e":"Both parents must be Aa, so each child has a 3/4 chance of being unaffected; for three independent children (3/4)³ = 27/64."},
  {"i":"bio-b3-0239","g":10,"u":"Cell Reproduction","d":"hard","t":"application","q":"In Mirror sheep on an Ethiopian farm, coat colour shows incomplete dominance: black (BB) × white (bb) gives grey (Bb). If two grey sheep are mated, what phenotypic ratio is expected among the offspring?","o":["3 black : 1 white","1 black : 2 grey : 1 white","All grey","9 black : 3 grey : 4 white"],"c":1,"e":"With incomplete dominance the heterozygote (Bb) is grey, so Bb × Bb gives 1 BB : 2 Bb : 1 bb = 1 black : 2 grey : 1 white, the genotype ratio showing directly as phenotype."},
  {"i":"bio-b3-0240","g":10,"u":"Cell Reproduction","d":"hard","t":"calculation","q":"In a large population at Hardy–Weinberg equilibrium, a recessive disorder affects 1 in 400 individuals. What proportion of the population is expected to be heterozygous carriers?","o":["0.0475","0.05","0.095","0.9025"],"c":2,"e":"q² = 1/400 so q = 0.05 and p = 0.95; carrier frequency = 2pq = 2 × 0.95 × 0.05 = 0.095."},
  {"i":"bio-b3-0241","g":10,"u":"Cell Reproduction","d":"hard","t":"application","q":"A man with blood type AB marries a woman with blood type O. Which statement about their children is correct?","o":["Children can be type A, B, AB or O","Children can be only type AB","Children can be type A or B but never AB or O","All children will be type O"],"c":2,"e":"AB (IᴬIᴮ) × O (ii) gives Iᴬi (type A) and Iᴮi (type B) only; neither AB nor O is possible because the O parent contributes only i and the AB parent never contributes i."},
  {"i":"bio-b3-0242","g":10,"u":"Cell Reproduction","d":"hard","t":"conceptual","q":"During which stage of mitosis would a non-disjunction event MOST directly produce two daughter cells with unequal chromosome numbers, and what is the immediate consequence?","o":["Prophase; chromosomes fail to condense","Anaphase; sister chromatids fail to separate so one cell gains and one loses a chromosome","Metaphase; spindle fibres fail to form so the cell arrests","Telophase; the nuclear envelope reforms too early"],"c":1,"e":"Non-disjunction is failure of sister chromatids to separate at anaphase; both copies move to one pole, giving one daughter cell an extra chromosome and the other one fewer."},
  {"i":"bio-b3-0243","g":10,"u":"Biochemical Molecules","d":"hard","t":"calculation","q":"A short mRNA contains 90 nucleotides, including the start and stop codons. Assuming no introns, what is the maximum number of amino acids in the resulting polypeptide?","o":["30","29","45","27"],"c":1,"e":"90 nucleotides ÷ 3 = 30 codons; one codon is the stop codon (not translated into an amino acid), so the polypeptide has at most 29 amino acids."},
  {"i":"bio-b3-0244","g":10,"u":"Biochemical Molecules","d":"hard","t":"conceptual","q":"An enzyme-catalysed reaction proceeds quickly at 37 °C but stops almost completely at 70 °C, and adding more substrate at 70 °C does not restart it. What is the best explanation?","o":["High temperature increased the activation energy","The enzyme was denatured, distorting its active site irreversibly","The substrate evaporated at 70 °C","The enzyme was used up as a reactant"],"c":1,"e":"Above its optimum the enzyme's tertiary structure unfolds (denaturation), permanently altering the active site so substrate can no longer bind; enzymes are not consumed, so 'used up' is wrong."},
  {"i":"bio-b3-0245","g":10,"u":"Biochemical Molecules","d":"hard","t":"conceptual","q":"Maltose is hydrolysed by maltase, and a similar disaccharide is split by a different enzyme but not by maltase. Which property of enzymes does this BEST illustrate?","o":["Enzymes lower activation energy","Enzymes are specific to their substrate because of active-site shape","Enzymes work fastest at high pH","Enzymes are permanently changed by the reaction"],"c":1,"e":"That maltase acts on maltose but not a structurally similar disaccharide shows substrate specificity arising from the complementary shape of the active site (lock-and-key / induced fit)."},
  {"i":"bio-b3-0246","g":10,"u":"Biochemical Molecules","d":"hard","t":"calculation","q":"In a double-stranded DNA sample, 30% of the bases are adenine. Using Chargaff's rules, what percentage of the bases are guanine?","o":["30%","20%","70%","40%"],"c":1,"e":"A = T = 30%, so A + T = 60%, leaving G + C = 40%; since G = C, guanine = 20%."},
  {"i":"bio-b3-0247","g":10,"u":"Plants","d":"hard","t":"calculation","q":"A leaf carries out photosynthesis. If the overall equation is 6CO₂ + 6H₂O → C₆H₁₂O₆ + 6O₂, how many molecules of carbon dioxide must be fixed to build 5 molecules of glucose?","o":["6","11","30","5"],"c":2,"e":"Each glucose requires 6 CO₂; for 5 glucose molecules, 5 × 6 = 30 CO₂ molecules are fixed."},
  {"i":"bio-b3-0248","g":10,"u":"Plants","d":"hard","t":"conceptual","q":"A variegated leaf (green and white patches) is destarched, exposed to light, then tested with iodine. Which result and conclusion are correct?","o":["Whole leaf turns blue-black; light is needed","Only green areas turn blue-black; chlorophyll is needed for starch synthesis","Only white areas turn blue-black; chlorophyll blocks starch","No part turns blue-black; CO₂ was absent"],"c":1,"e":"Only the chlorophyll-containing green areas photosynthesise and store starch, turning blue-black with iodine; the white areas lack chlorophyll and stay brown, showing chlorophyll is required."},
  {"i":"bio-b3-0249","g":10,"u":"Plants","d":"hard","t":"application","q":"A potted plant is kept in darkness for 48 hours and then one leaf is partly covered with foil before the plant is illuminated. After iodine testing, why does the foil-covered region fail to turn blue-black?","o":["The covered region lacked chlorophyll","The covered region received no light, so no photosynthesis or starch formation occurred","Iodine cannot penetrate foil-covered tissue","The covered region lost its starch to respiration only"],"c":1,"e":"The dark pre-treatment destarches the leaf; the foil excludes light from one region, so that region cannot photosynthesise and forms no starch, giving a negative (brown) iodine result."},
  {"i":"bio-b3-0250","g":10,"u":"Plants","d":"hard","t":"conceptual","q":"In the cells lining the spongy mesophyll of a leaf, both photosynthesis and respiration occur during the day. At the light compensation point, which statement is true?","o":["Net oxygen output is at its maximum","The rate of photosynthesis equals the rate of respiration, so net gas exchange is zero","Respiration has completely stopped","Carbon dioxide is released faster than it is taken in"],"c":1,"e":"At the compensation point the oxygen produced by photosynthesis exactly matches that used in respiration (and CO₂ likewise), so there is no net gas exchange with the surroundings."},
  {"i":"bio-b3-0251","g":10,"u":"Human Biology","d":"hard","t":"application","q":"A person with type B blood (genotype IᴮIᴮ) needs a transfusion. Which donor blood can be received safely, considering antigens and antibodies?","o":["Type A only","Type B or type O","Type AB only","Any type, because B is a universal recipient"],"c":1,"e":"A type-B recipient has anti-A antibodies, so any donor blood carrying the A antigen (A or AB) would be agglutinated; only type B and type O (no A antigen) are safe."},
  {"i":"bio-b3-0252","g":10,"u":"Human Biology","d":"hard","t":"conceptual","q":"During strenuous exercise a sprinter's muscle cells switch partly to anaerobic respiration. Compared with aerobic respiration of one glucose molecule, anaerobic respiration in muscle yields:","o":["More ATP and produces ethanol","Less ATP and produces lactic acid","The same ATP and produces carbon dioxide and water","More ATP and produces carbon dioxide only"],"c":1,"e":"Anaerobic respiration in human muscle produces only about 2 ATP per glucose (versus much more aerobically) and forms lactic acid, not ethanol (which forms in yeast)."},
  {"i":"bio-b3-0253","g":10,"u":"Human Biology","d":"hard","t":"application","q":"Blood leaving an active muscle and entering a kidney differs in composition along the way. Which sequence of changes is correct for blood passing first through the lungs and then a respiring muscle?","o":["Gains CO₂ in lungs, gains O₂ in muscle","Gains O₂ in lungs, gains CO₂ in muscle","Loses O₂ in lungs, loses CO₂ in muscle","Gains O₂ in both lungs and muscle"],"c":1,"e":"In the lungs blood loads O₂ and unloads CO₂; in a respiring muscle it delivers O₂ and picks up the CO₂ produced by respiration, so it gains O₂ at the lungs and gains CO₂ at the muscle."},
  {"i":"bio-b3-0254","g":10,"u":"Sub-fields of Biology","d":"hard","t":"application","q":"A scientist studies how Anopheles mosquito populations transmit malaria across the lowland regions of Ethiopia, tracking infection spread in human communities. Which two sub-fields of biology are MOST directly combined in this work?","o":["Genetics and botany","Entomology and epidemiology","Mycology and taxonomy","Histology and palaeontology"],"c":1,"e":"Studying the mosquito (an insect) is entomology, and tracking the spread of disease in populations is epidemiology; together they describe this malaria-transmission study."},
  {"i":"bio-b3-0255","g":10,"u":"Ecological Interaction","d":"hard","t":"application","q":"In a grassland food chain, grass (10,000 kJ) → grasshopper → bird → hawk, roughly 10% of energy passes to each next level. Approximately how much energy is available at the hawk level, and why so little?","o":["1,000 kJ; energy is created at each level","10 kJ; energy is lost as heat in respiration at each transfer","100 kJ; only producers lose energy","1 kJ; matter is destroyed at each level"],"c":1,"e":"Applying 10% three times: 10,000 → 1,000 → 100 → 10 kJ at the hawk; the loss occurs because most energy is used in respiration and lost as heat at each trophic transfer."},
  {"i":"bio-b3-0256","g":10,"u":"Cell Reproduction","d":"hard","t":"calculation","q":"In a certain Ethiopian highland barley line, plant height (T = tall dominant) and awn colour (B = black dominant) assort independently. Two plants heterozygous for both genes (TtBb) are crossed. What fraction of the offspring are expected to be tall with white awns (recessive awn colour)?","o":["1/16","3/16","9/16","3/8"],"c":1,"e":"TtBb × TtBb gives a 9:3:3:1 ratio. Tall-and-white = T_bb = (3/4 tall) × (1/4 white) = 3/16."},
  {"i":"bio-b3-0257","g":10,"u":"Human Biology","d":"hard","t":"calculation","q":"Haemophilia is X-linked recessive. A woman who is a carrier (XᴴXʰ) marries a man with normal clotting (XᴴY). Considering all of their children together, what proportion are expected to be haemophiliac, and of what sex?","o":["1/2 of all children, both sexes","1/4 of all children, all of them male","1/4 of all children, all of them female","1/2 of all children, all male"],"c":1,"e":"Children: XᴴXᴴ, XᴴXʰ, XᴴY, XʰY in equal quarters. Only XʰY (a son) is affected = 1/4 of all children, and every affected child is male."},
  {"i":"bio-b3-0258","g":10,"u":"Ecological Interaction","d":"hard","t":"calculation","q":"In a large, randomly-mating Ethiopian population at Hardy–Weinberg equilibrium, an autosomal recessive disorder affects 1 in 10 000 people. What percentage of the population are expected to be unaffected carriers (heterozygotes)?","o":["0.01%","1.98%","2.00%","9.99%"],"c":1,"e":"q² = 1/10 000 so q = 0.01 and p = 0.99. Carriers = 2pq = 2(0.99)(0.01) = 0.0198 = 1.98%."},
  {"i":"bio-b3-0259","g":10,"u":"Plants","d":"hard","t":"conceptual","q":"A teff plant is kept in continuous bright light but the air around it is depleted of CO₂. Which statement best predicts the short-term effect on its chloroplasts?","o":["The light-dependent reactions stop immediately because they need CO₂","NADPH and ATP accumulate because the Calvin cycle slows for lack of CO₂","Oxygen release rises sharply as the Calvin cycle speeds up","Glucose output is unchanged because light alone drives carbon fixation"],"c":1,"e":"The light reactions still split water and make ATP/NADPH, but without CO₂ the Calvin (light-independent) cycle cannot consume them, so NADPH and ATP build up and fixation slows."},
  {"i":"bio-b3-0260","g":10,"u":"Biochemical Molecules","d":"hard","t":"application","q":"A student measures the rate of an enzyme-catalysed reaction at 25 °C, 37 °C and 60 °C, and finds the rate is highest at 37 °C and almost zero at 60 °C. Which explanation is most consistent with the curriculum view of enzyme behaviour?","o":["At 60 °C the enzyme's active site is denatured, losing its specific shape","At 60 °C the substrate is used up faster than it can be replaced","At 37 °C the enzyme is permanently consumed, lowering later rates","At 60 °C the enzyme gains a permanent new active site"],"c":0,"e":"Rate rises with temperature up to an optimum (~37 °C in humans), but high temperature breaks the bonds maintaining the enzyme's tertiary shape, denaturing the active site so catalysis nearly stops."},
  {"i":"bio-b3-0261","g":10,"u":"Biochemical Molecules","d":"impossible","t":"calculation","q":"A linear DNA fragment of 1500 base pairs is analyzed. Of its bases, adenine accounts for 18% of all nucleotides. According to Chargaff's rules, how many cytosine bases are present in the entire double-stranded fragment?","o":["540","960","1080","270"],"c":1,"e":"A = T = 18%, so A+T = 36%; therefore G+C = 64% and C = 32%. Total nucleotides = 2 × 1500 = 3000, so cytosine = 0.32 × 3000 = 960."},
  {"i":"bio-b3-0262","g":10,"u":"Cell Reproduction","d":"impossible","t":"calculation","q":"A diploid Ethiopian highland barley cell has 2n = 14. A single primary spermatocyte (in an analogous animal model) completes meiosis I and II. Considering both products of meiosis I, what is the total number of chromatids present across all cells at the moment metaphase II begins?","o":["28","14","56","7"],"c":0,"e":"After meiosis I each of the 2 cells has n = 7 chromosomes, each still as 2 sister chromatids = 14 chromatids per cell; across both cells = 28 chromatids."},
  {"i":"bio-b3-0263","g":10,"u":"Biochemical Molecules","d":"impossible","t":"calculation","q":"During cellular respiration of one glucose molecule, the theoretical maximum yield is often quoted as 38 ATP. If glycolysis and the Krebs cycle together contribute 4 ATP by substrate-level phosphorylation, what fraction of the total is generated by oxidative phosphorylation?","o":["2/19","17/19","4/38 exactly","19/38"],"c":1,"e":"Oxidative phosphorylation supplies 38 − 4 = 34 ATP, so the fraction is 34/38 = 17/19."},
  {"i":"bio-b3-0264","g":10,"u":"Human Biology","d":"impossible","t":"calculation","q":"A man heterozygous for a recessive autosomal allele (Aa) marries a woman who is also Aa. Of their unaffected children, what is the probability that a randomly chosen one is a heterozygous carrier?","o":["1/2","2/3","1/4","1/3"],"c":1,"e":"The cross Aa × Aa gives 1 AA : 2 Aa : 1 aa. Among unaffected children (AA and Aa, total 3 parts), carriers (Aa) are 2 parts, so 2/3."},
  {"i":"bio-b3-0265","g":10,"u":"Human Biology","d":"impossible","t":"calculation","q":"In humans, red-green colour blindness is X-linked recessive. A carrier mother and a colour-blind father have children. What proportion of their daughters are expected to be colour-blind?","o":["0","1/2","1/4","All"],"c":1,"e":"Mother XᴬXᵃ × father XᵃY. Daughters get Xᵃ from father and either Xᴬ or Xᵃ from mother: 1/2 XᴬXᵃ (carrier) and 1/2 XᵃXᵃ (colour-blind), so 1/2 of daughters are colour-blind."},
  {"i":"bio-b3-0266","g":10,"u":"Human Biology","d":"impossible","t":"calculation","q":"In an Ethiopian population at Hardy-Weinberg equilibrium, an autosomal recessive disorder affects 1 in 400 newborns. What is the approximate frequency of heterozygous carriers in the population?","o":["About 1 in 400","About 1 in 20","About 1 in 10","About 1 in 200"],"c":2,"e":"q² = 1/400, so q = 0.05 and p = 0.95. Carrier frequency 2pq = 2 × 0.95 × 0.05 = 0.095, which is roughly 1 in 10."},
  {"i":"bio-b3-0267","g":10,"u":"Human Biology","d":"impossible","t":"calculation","q":"Blood type frequencies follow the ABO system with codominance of Iᴬ and Iᴮ. If allele frequencies are Iᴬ = 0.3, Iᴮ = 0.1, and i = 0.6, what is the expected frequency of individuals with blood group O?","o":["0.36","0.6","0.09","0.42"],"c":0,"e":"Group O is genotype ii, frequency = i² = 0.6² = 0.36."},
  {"i":"bio-b3-0268","g":10,"u":"Plants","d":"impossible","t":"calculation","q":"A tall pea plant of unknown genotype is test-crossed. The offspring are 50% tall and 50% dwarf (tall dominant). A second tall plant test-crossed gives all tall offspring. What were the two unknown genotypes, respectively?","o":["TT and Tt","Tt and TT","Tt and Tt","TT and TT"],"c":1,"e":"A 1:1 tall:dwarf ratio from a test cross (× tt) means the parent was Tt; all-tall offspring means the parent contributed only T, so it was TT."},
  {"i":"bio-b3-0269","g":10,"u":"Plants","d":"impossible","t":"conceptual","q":"In a C3 plant such as Ethiopian wheat, on a hot dry afternoon stomata partially close. This raises the relative concentration of O2 versus CO2 inside the leaf. Which immediate consequence best explains the resulting drop in net carbon fixation?","o":["RuBisCO increasingly fixes O2 in photorespiration, reducing sugar yield","The light-dependent reactions stop producing ATP entirely","Chlorophyll is denatured by the higher oxygen level","Water splitting in photosystem II is reversed by oxygen"],"c":0,"e":"RuBisCO is a dual-function enzyme; a low CO2-to-O2 ratio favours oxygenation (photorespiration), which consumes energy and releases CO2, lowering net fixation."},
  {"i":"bio-b3-0270","g":10,"u":"Plants","d":"impossible","t":"application","q":"A dihybrid pea cross RrYy × RrYy (round/yellow dominant) is performed. Out of 320 offspring, approximately how many are expected to show the recessive phenotype for BOTH traits (wrinkled, green)?","o":["20","60","80","180"],"c":0,"e":"The double-recessive class is 1/16 of a 9:3:3:1 ratio; 1/16 × 320 = 20."},
  {"i":"bio-b3-0271","g":10,"u":"Cell Reproduction","d":"impossible","t":"conceptual","q":"A drug blocks the assembly of the spindle apparatus during mitosis. A cell exposed to it after DNA replication but before division would most likely arrest at, and show, which outcome?","o":["Metaphase, with chromosomes unable to align and separate","Interphase, with DNA replication halted","Telophase, with two complete nuclei already formed","G1 phase, before any chromosome condensation"],"c":0,"e":"Spindle fibres align and pull chromosomes; without them the cell cannot pass the spindle checkpoint, arresting at metaphase with chromosomes condensed but unseparated."},
  {"i":"bio-b3-0272","g":10,"u":"Biochemical Molecules","d":"impossible","t":"conceptual","q":"A competitive inhibitor and the substrate compete for the same active site of an enzyme. As substrate concentration is greatly increased while inhibitor concentration is held constant, what happens to the reaction rate compared with the uninhibited reaction?","o":["It approaches the same maximum velocity as without inhibitor","It plateaus permanently below the uninhibited maximum","It exceeds the uninhibited maximum velocity","It falls to zero regardless of substrate"],"c":0,"e":"A competitive inhibitor raises the apparent Km but does not change Vmax; enough substrate outcompetes the inhibitor, so the rate approaches the normal maximum velocity."},
  {"i":"bio-b3-0273","g":10,"u":"Human Biology","d":"impossible","t":"application","q":"A person hyperventilates, exhaling excess CO2 rapidly. Using the equilibrium CO2 + H2O ⇌ H2CO3 ⇌ H⁺ + HCO3⁻, what is the immediate effect on blood pH, and the body's compensatory respiratory tendency?","o":["pH rises; breathing rate is reduced to retain CO2","pH falls; breathing rate increases further","pH rises; breathing rate increases further","pH is unchanged; no compensation occurs"],"c":0,"e":"Losing CO2 shifts the equilibrium left, lowering H⁺ so pH rises (alkalosis); the body compensates by slowing breathing to retain CO2 and restore H⁺."},
  {"i":"bio-b3-0274","g":10,"u":"Human Biology","d":"impossible","t":"conceptual","q":"A vaccine introduces a harmless antigen. On a SECOND exposure to the real pathogen years later, the secondary immune response is faster and stronger mainly because of which cell type generated during the first response?","o":["Memory B and T lymphocytes","Mature red blood cells","Neutrophils stored in marrow","Plasma proteins from the liver"],"c":0,"e":"The primary response produces long-lived memory B and T cells; on re-exposure these rapidly proliferate and differentiate, giving a quicker, larger antibody response."},
  {"i":"bio-b3-0275","g":10,"u":"Sub-fields of Biology","d":"impossible","t":"definition","q":"A researcher in Ethiopia studies the molecular techniques used to insert a desired gene into a bacterium so it produces human insulin. This work falls most precisely within which sub-field of biology?","o":["Genetic engineering (biotechnology)","Taxonomy","Paleontology","Ethology"],"c":0,"e":"Inserting a gene into an organism to manufacture a protein is recombinant DNA technology, a core technique of genetic engineering within biotechnology."},
  {"i":"bio-b3-0276","g":10,"u":"Sub-fields of Biology","d":"impossible","t":"application","q":"A scientist tracks how a fungal pathogen spreads through an Ethiopian teff farming community, models infection rates, and recommends control measures. Which combination of sub-fields BEST describes this integrated work?","o":["Microbiology and epidemiology","Botany and embryology","Histology and cytology","Genetics and biochemistry"],"c":0,"e":"Studying the disease-causing microbe is microbiology; tracking how the disease spreads through a population and its control is epidemiology."},
  {"i":"bio-b3-0277","g":10,"u":"Ecological Interaction","d":"impossible","t":"calculation","q":"In a grassland food chain, grass fixes 10000 kJ of energy. Following the 10% ecological efficiency rule, how much energy is available to a secondary consumer (e.g., a serval) two trophic levels above the grass?","o":["100 kJ","1000 kJ","10 kJ","500 kJ"],"c":0,"e":"At each transfer only ~10% passes on: 10000 → 1000 (primary consumer) → 100 kJ (secondary consumer), so 100 kJ."},
  {"i":"bio-b3-0278","g":10,"u":"Ecological Interaction","d":"impossible","t":"conceptual","q":"In the nitrogen cycle, two microbial processes act in opposite directions on soil fertility. Which pairing correctly matches the process to its effect on plant-available nitrogen?","o":["Nitrification increases nitrate; denitrification decreases available nitrogen","Nitrification decreases nitrate; denitrification increases it","Both nitrification and denitrification add nitrate to soil","Both remove nitrogen from soil as ammonia"],"c":0,"e":"Nitrifying bacteria convert ammonia to nitrate (plant-usable), increasing availability; denitrifying bacteria convert nitrate to N2 gas lost to the air, decreasing it."},
  {"i":"bio-b3-0279","g":10,"u":"Ecological Interaction","d":"impossible","t":"conceptual","q":"Two species of birds in an Ethiopian forest feed on insects at different heights of the same tree, reducing direct competition. This partitioning of resources to allow coexistence best illustrates which ecological principle?","o":["Niche differentiation (resource partitioning)","Mutualism","Competitive exclusion eliminating one species","Parasitism"],"c":0,"e":"By using different parts of the same habitat the species occupy distinct realized niches, reducing overlap and allowing coexistence — niche differentiation, the alternative to competitive exclusion."},
  {"i":"bio-b3-0280","g":10,"u":"Ecological Interaction","d":"impossible","t":"application","q":"A population of Ethiopian wolves shows a recessive lethal allele. Natural selection acts against homozygous recessive individuals each generation, while heterozygotes survive and reproduce. Over many generations, why does the recessive allele persist rather than disappearing completely?","o":["Heterozygotes carry and pass on the allele without expressing the lethal phenotype","Selection cannot act on lethal alleles at all","The allele mutates back faster than it is removed","Homozygous recessives always survive to reproduce"],"c":0,"e":"Selection removes only the visible homozygous recessives; the allele is sheltered in phenotypically normal heterozygous carriers, so it is removed slowly and persists at low frequency."},
  {"i":"bio-b3-0281","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"In a human cell, which organelle is the main site of aerobic respiration, where most ATP is produced?","o":["Ribosome","Mitochondrion","Golgi apparatus","Lysosome"],"c":1,"e":"The mitochondrion carries out the Krebs cycle and oxidative phosphorylation, producing most of the cell's ATP through aerobic respiration."},
  {"i":"bio-b3-0282","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"Which part of a neuron receives signals and conducts impulses toward the cell body?","o":["Axon","Dendrite","Myelin sheath","Synaptic knob"],"c":1,"e":"Dendrites are branched extensions that receive impulses and carry them toward the cell body; the axon carries impulses away."},
  {"i":"bio-b3-0283","g":11,"u":"The Human Body Systems","d":"easy","t":"conceptual","q":"In humans, oxygen-rich blood returns from the lungs to the heart through which vessels?","o":["Pulmonary veins","Pulmonary arteries","Venae cavae","The aorta"],"c":0,"e":"The pulmonary veins carry oxygenated blood from the lungs to the left atrium; pulmonary arteries carry deoxygenated blood to the lungs."},
  {"i":"bio-b3-0284","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"Which structures are the functional filtration units of the human kidney?","o":["Alveoli","Villi","Nephrons","Neurons"],"c":2,"e":"Each kidney contains about a million nephrons, which filter blood and form urine."},
  {"i":"bio-b3-0285","g":11,"u":"The Human Body Systems","d":"easy","t":"conceptual","q":"Most chemical digestion and absorption of nutrients in humans occurs in the:","o":["Stomach","Small intestine","Large intestine","Oesophagus"],"c":1,"e":"The small intestine, with its villi and digestive enzymes, is the main site of chemical digestion and nutrient absorption."},
  {"i":"bio-b3-0286","g":11,"u":"Enzymes","d":"easy","t":"definition","q":"Enzymes increase the rate of a biochemical reaction mainly by:","o":["Raising the activation energy","Lowering the activation energy","Increasing the temperature of cells","Being used up in the reaction"],"c":1,"e":"Enzymes are biological catalysts that lower the activation energy of a reaction without being consumed."},
  {"i":"bio-b3-0287","g":11,"u":"Enzymes","d":"easy","t":"conceptual","q":"Which factor will most directly denature a human enzyme and stop its activity?","o":["A temperature near 37 °C","A pH near its optimum","A temperature far above its optimum","Adding more substrate"],"c":2,"e":"Temperatures well above the optimum break the bonds holding the enzyme's 3-D shape, denaturing it and destroying the active site."},
  {"i":"bio-b3-0288","g":11,"u":"Enzymes","d":"easy","t":"definition","q":"The reactant molecule that an enzyme acts upon is called the:","o":["Product","Substrate","Coenzyme","Inhibitor"],"c":1,"e":"The substrate is the specific molecule on which the enzyme acts, converting it into product."},
  {"i":"bio-b3-0289","g":11,"u":"Genetics","d":"easy","t":"calculation","q":"In pea plants tall (T) is dominant to short (t). Crossing two heterozygous tall plants (Tt × Tt) gives what fraction of short offspring?","o":["1/4","1/2","3/4","0"],"c":0,"e":"Tt × Tt gives genotype ratio 1 TT : 2 Tt : 1 tt, so 1/4 (tt) are short."},
  {"i":"bio-b3-0290","g":11,"u":"Genetics","d":"easy","t":"calculation","q":"A monohybrid cross between two heterozygotes (Aa × Aa) gives what phenotypic ratio of dominant to recessive?","o":["1:1","3:1","9:3:3:1","1:2:1"],"c":1,"e":"Aa × Aa yields 3 showing the dominant trait to 1 showing the recessive trait, a 3:1 phenotypic ratio."},
  {"i":"bio-b3-0291","g":11,"u":"Genetics","d":"easy","t":"calculation","q":"A standard dihybrid cross between two double heterozygotes (RrYy × RrYy) gives which phenotypic ratio?","o":["3:1","1:1:1:1","9:3:3:1","1:2:1"],"c":2,"e":"Independent assortment of two heterozygous gene pairs produces the classic 9:3:3:1 phenotypic ratio."},
  {"i":"bio-b3-0292","g":11,"u":"Genetics","d":"easy","t":"application","q":"In humans, red-green colour blindness is X-linked recessive. A carrier mother (XᴮXᵇ) and a normal father (XᴮY) have sons. What fraction of their sons are expected to be colour blind?","o":["0","1/4","1/2","All"],"c":2,"e":"Sons receive XᴮY or XᵇY in equal numbers; half inherit the Xᵇ from the carrier mother and are colour blind."},
  {"i":"bio-b3-0293","g":11,"u":"Genetics","d":"easy","t":"definition","q":"An organism with two identical alleles for a trait, such as TT or tt, is described as:","o":["Heterozygous","Homozygous","Hemizygous","Codominant"],"c":1,"e":"Homozygous means both alleles for the gene are the same; heterozygous means they differ."},
  {"i":"bio-b3-0294","g":11,"u":"Genetics","d":"easy","t":"definition","q":"The molecule that carries the genetic code in the chromosomes of human cells is:","o":["DNA","ATP","Glycogen","Cellulose"],"c":0,"e":"DNA (deoxyribonucleic acid) stores hereditary information in its base sequence within chromosomes."},
  {"i":"bio-b3-0295","g":11,"u":"Characteristics of Animals","d":"easy","t":"definition","q":"Animals that maintain a constant internal body temperature regardless of the environment are best described as:","o":["Ectothermic","Endothermic","Poikilothermic","Anaerobic"],"c":1,"e":"Endothermic (warm-blooded) animals, such as mammals and birds, regulate body temperature internally and keep it relatively constant."},
  {"i":"bio-b3-0296","g":11,"u":"Characteristics of Animals","d":"easy","t":"conceptual","q":"Which feature is characteristic of all chordates at some stage of their life?","o":["A backbone of bone","A notochord","An exoskeleton","Radial symmetry"],"c":1,"e":"All chordates possess a notochord at some life stage; not all chordates have a bony backbone (e.g. lampreys)."},
  {"i":"bio-b3-0297","g":11,"u":"Characteristics of Animals","d":"easy","t":"definition","q":"Arthropods such as insects are characterised by having:","o":["A soft unsegmented body","Jointed appendages and an exoskeleton","An internal bony skeleton","No body segmentation"],"c":1,"e":"Arthropods have a chitinous exoskeleton and jointed appendages, the defining features of the phylum."},
  {"i":"bio-b3-0298","g":11,"u":"Biology & Technology","d":"easy","t":"definition","q":"The use of living organisms or their products to make useful goods, such as injera fermentation or antibiotic production, is called:","o":["Biotechnology","Taxonomy","Histology","Cytology"],"c":0,"e":"Biotechnology applies living organisms or their components to produce useful products; fermentation by microbes is a classic example."},
  {"i":"bio-b3-0299","g":11,"u":"Biology & Technology","d":"easy","t":"application","q":"Which microorganism is responsible for the fermentation that makes bread dough and tella rise by producing carbon dioxide?","o":["Yeast","Rhizobium","Influenza virus","Amoeba"],"c":0,"e":"Yeast (a fungus) ferments sugars anaerobically, releasing carbon dioxide that causes dough and brews to rise."},
  {"i":"bio-b3-0300","g":11,"u":"Population & Natural Resources","d":"easy","t":"definition","q":"All the individuals of a single species living together in the same area at the same time make up a:","o":["Community","Population","Ecosystem","Biome"],"c":1,"e":"A population is one species in a defined area at a given time; a community includes all species together."},
  {"i":"bio-b3-0301","g":11,"u":"Population & Natural Resources","d":"easy","t":"conceptual","q":"In a grassland food chain, the organisms that capture sunlight and make their own food are the:","o":["Producers","Primary consumers","Decomposers","Tertiary consumers"],"c":0,"e":"Producers (green plants) carry out photosynthesis, converting light energy into chemical energy that supports the rest of the food chain."},
  {"i":"bio-b3-0302","g":11,"u":"Genetics","d":"easy","t":"calculation","q":"In pea plants, tall (T) is dominant over short (t). A cross between two heterozygous tall plants (Tt × Tt) is made. What fraction of the offspring are expected to be short?","o":["1/4","1/2","3/4","0"],"c":0,"e":"Tt × Tt gives genotypes 1 TT : 2 Tt : 1 tt. Only tt (1 out of 4) is short, so the short fraction is 1/4."},
  {"i":"bio-b3-0303","g":11,"u":"Genetics","d":"easy","t":"calculation","q":"A monohybrid cross between two heterozygotes (Aa × Aa) produces 240 offspring. Approximately how many are expected to show the dominant phenotype?","o":["60","120","180","240"],"c":2,"e":"The dominant-to-recessive phenotype ratio is 3:1, so 3/4 show the dominant trait. 3/4 × 240 = 180."},
  {"i":"bio-b3-0304","g":11,"u":"Genetics","d":"easy","t":"conceptual","q":"In a standard dihybrid cross between two plants heterozygous for both genes (RrYy × RrYy), what is the expected phenotypic ratio of the offspring?","o":["9:3:3:1","3:1","1:2:1","1:1:1:1"],"c":0,"e":"A dihybrid cross of two double heterozygotes yields the classic 9:3:3:1 phenotypic ratio for two independently assorting genes."},
  {"i":"bio-b3-0305","g":11,"u":"Genetics","d":"easy","t":"definition","q":"Which term describes the specific position that a gene occupies on a chromosome?","o":["Allele","Locus","Genotype","Phenotype"],"c":1,"e":"A locus is the fixed physical location of a gene on a chromosome; alleles are alternative forms of that gene."},
  {"i":"bio-b3-0306","g":11,"u":"Genetics","d":"easy","t":"calculation","q":"In a population in Hardy–Weinberg equilibrium, the recessive allele frequency q = 0.2. What is the frequency of the dominant allele p?","o":["0.2","0.4","0.64","0.8"],"c":3,"e":"Since p + q = 1, p = 1 − 0.2 = 0.8."},
  {"i":"bio-b3-0307","g":11,"u":"Genetics","d":"easy","t":"definition","q":"An organism that carries two identical alleles for a particular gene is described as:","o":["Heterozygous","Homozygous","Hemizygous","Hybrid"],"c":1,"e":"Homozygous means both alleles at a locus are identical (e.g. AA or aa); heterozygous means they differ."},
  {"i":"bio-b3-0308","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"Which blood cells are mainly responsible for transporting oxygen from the lungs to body tissues?","o":["White blood cells","Platelets","Red blood cells","Plasma cells"],"c":2,"e":"Red blood cells (erythrocytes) contain haemoglobin, which binds oxygen and carries it to the tissues."},
  {"i":"bio-b3-0309","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"In the human breathing system, what is the main site of gas exchange between air and blood?","o":["Trachea","Bronchi","Alveoli","Larynx"],"c":2,"e":"The alveoli are thin-walled air sacs surrounded by capillaries where oxygen and carbon dioxide are exchanged by diffusion."},
  {"i":"bio-b3-0310","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"Which part of the human digestive system is the main site for the absorption of digested nutrients into the blood?","o":["Stomach","Small intestine","Large intestine","Oesophagus"],"c":1,"e":"The small intestine, with its villi, is the main site where digested nutrients are absorbed into the bloodstream."},
  {"i":"bio-b3-0311","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"Which functional unit of the kidney is responsible for filtering blood and forming urine?","o":["Neuron","Nephron","Alveolus","Villus"],"c":1,"e":"The nephron is the structural and functional unit of the kidney that filters blood and produces urine."},
  {"i":"bio-b3-0312","g":11,"u":"The Human Body Systems","d":"easy","t":"conceptual","q":"Which chamber of the human heart pumps oxygenated blood out to the whole body through the aorta?","o":["Right atrium","Right ventricle","Left atrium","Left ventricle"],"c":3,"e":"The left ventricle has the thickest muscular wall and pumps oxygenated blood into the aorta to supply the entire body."},
  {"i":"bio-b3-0313","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"Which type of neuron carries impulses from sense organs toward the central nervous system?","o":["Motor neuron","Sensory neuron","Relay neuron","Effector neuron"],"c":1,"e":"Sensory (afferent) neurons carry impulses from receptors and sense organs toward the central nervous system."},
  {"i":"bio-b3-0314","g":11,"u":"Enzymes","d":"easy","t":"definition","q":"Enzymes increase the rate of biochemical reactions mainly by:","o":["Raising the activation energy","Lowering the activation energy","Increasing the temperature of cells","Being used up in the reaction"],"c":1,"e":"Enzymes are biological catalysts that speed up reactions by lowering the activation energy needed, without being consumed."},
  {"i":"bio-b3-0315","g":11,"u":"Enzymes","d":"easy","t":"conceptual","q":"What generally happens to most human enzymes when the temperature rises well above 40 °C?","o":["They work faster permanently","They become denatured and lose activity","They turn into substrate","Their active sites multiply"],"c":1,"e":"High temperatures break the bonds holding the enzyme's shape, denaturing it so the active site no longer fits the substrate and activity is lost."},
  {"i":"bio-b3-0316","g":11,"u":"Enzymes","d":"easy","t":"application","q":"The enzyme amylase, found in human saliva, begins the chemical digestion of which nutrient?","o":["Proteins","Fats","Starch","Vitamins"],"c":2,"e":"Salivary amylase breaks down starch into smaller sugars such as maltose, beginning carbohydrate digestion in the mouth."},
  {"i":"bio-b3-0317","g":11,"u":"Characteristics of Animals","d":"easy","t":"definition","q":"Animals that maintain a relatively constant internal body temperature regardless of the surroundings are described as:","o":["Ectothermic","Endothermic","Poikilothermic","Cold-blooded"],"c":1,"e":"Endothermic (warm-blooded) animals, such as mammals and birds, generate internal heat to keep body temperature stable."},
  {"i":"bio-b3-0318","g":11,"u":"Characteristics of Animals","d":"easy","t":"definition","q":"Which group of animals is characterized by having a backbone (vertebral column)?","o":["Arthropods","Vertebrates","Molluscs","Annelids"],"c":1,"e":"Vertebrates are animals that possess a backbone or vertebral column; the listed alternatives are invertebrate groups."},
  {"i":"bio-b3-0319","g":11,"u":"Characteristics of Animals","d":"easy","t":"conceptual","q":"Which feature is a typical characteristic shared by all mammals?","o":["Laying shelled eggs only","Having feathers","Producing milk from mammary glands","Breathing only through gills"],"c":2,"e":"A defining characteristic of mammals is the presence of mammary glands that produce milk to nourish their young."},
  {"i":"bio-b3-0320","g":11,"u":"Biology & Technology","d":"easy","t":"application","q":"In biotechnology, which group of organisms is used to ferment milk into yoghurt and the traditional Ethiopian fermented milk 'ergo'?","o":["Viruses","Bacteria","Protozoa","Algae"],"c":1,"e":"Lactic acid bacteria ferment the lactose in milk, souring and thickening it to form yoghurt and traditional fermented milk such as ergo."},
  {"i":"bio-b3-0321","g":11,"u":"Population & Natural Resources","d":"easy","t":"definition","q":"In an ecosystem, organisms such as bacteria and fungi that break down dead organic matter and return nutrients to the soil are called:","o":["Producers","Primary consumers","Decomposers","Predators"],"c":2,"e":"Decomposers (mainly bacteria and fungi) break down dead organisms and waste, recycling nutrients back into the ecosystem."},
  {"i":"bio-b3-0322","g":11,"u":"Genetics","d":"easy","t":"calculation","q":"A heterozygous purple-flowered plant (Pp) is crossed with a white-flowered plant (pp), where purple is dominant. What ratio of purple to white offspring is expected?","o":["3:1","1:1","2:1","All purple"],"c":1,"e":"A test cross Pp × pp yields 1 Pp (purple) : 1 pp (white), a 1:1 phenotypic ratio."},
  {"i":"bio-b3-0323","g":11,"u":"Genetics","d":"easy","t":"calculation","q":"In humans, red-green colour blindness is X-linked recessive. A carrier mother (XᴺXⁿ) and a normal-vision father (XᴺY) have children. What fraction of their SONS are expected to be colour blind?","o":["0","1/4","1/2","All"],"c":2,"e":"Sons get Y from father and either Xᴺ or Xⁿ from the carrier mother. Half receive Xⁿ and are colour blind, so 1/2 of sons."},
  {"i":"bio-b3-0324","g":11,"u":"Genetics","d":"easy","t":"definition","q":"What term describes the specific position that a gene occupies on a chromosome?","o":["Allele","Locus","Genome","Genotype"],"c":1,"e":"A locus is the fixed location of a gene on a chromosome. Alleles are alternative forms of the gene found at that locus."},
  {"i":"bio-b3-0325","g":11,"u":"Genetics","d":"easy","t":"calculation","q":"In a dihybrid cross between two plants heterozygous for both traits (RrYy × RrYy), what phenotypic ratio is expected in the F2 generation?","o":["3:1","1:1:1:1","9:3:3:1","9:7"],"c":2,"e":"A standard dihybrid cross of two doubly heterozygous parents with independent assortment gives the classic 9:3:3:1 phenotypic ratio."},
  {"i":"bio-b3-0326","g":11,"u":"Enzymes","d":"easy","t":"definition","q":"What is the name given to the specific reactant molecule on which an enzyme acts?","o":["Substrate","Product","Coenzyme","Inhibitor"],"c":0,"e":"The substrate is the molecule an enzyme binds and acts upon at its active site, converting it into product(s)."},
  {"i":"bio-b3-0327","g":11,"u":"Enzymes","d":"easy","t":"conceptual","q":"How do enzymes speed up biochemical reactions?","o":["By raising the temperature of the cell","By lowering the activation energy of the reaction","By being consumed during the reaction","By adding extra energy to the reactants"],"c":1,"e":"Enzymes are biological catalysts that lower the activation energy required, allowing reactions to proceed faster without being used up."},
  {"i":"bio-b3-0328","g":11,"u":"Enzymes","d":"easy","t":"conceptual","q":"The enzyme salivary amylase in the mouth works best at near-neutral pH. What is MOST likely to happen to its activity in the strongly acidic stomach?","o":["Its activity greatly increases","Its activity is unaffected","It becomes denatured and stops working","It turns into pepsin"],"c":2,"e":"Outside its optimum pH, the acidic stomach denatures salivary amylase, altering its active site so it can no longer function."},
  {"i":"bio-b3-0329","g":11,"u":"Enzymes","d":"easy","t":"definition","q":"What is the term for the region of an enzyme where the substrate binds and the reaction occurs?","o":["Active site","Allosteric ridge","Binding pole","Catalytic shell"],"c":0,"e":"The active site is the specific region of an enzyme that binds the substrate and catalyses its conversion to product."},
  {"i":"bio-b3-0330","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"Which blood vessels carry oxygenated blood away from the heart to the body tissues (with the exception of the pulmonary artery)?","o":["Veins","Capillaries","Arteries","Venules"],"c":2,"e":"Arteries carry blood away from the heart. Most carry oxygenated blood; the pulmonary artery is the noted exception carrying deoxygenated blood."},
  {"i":"bio-b3-0331","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"What is the functional unit of the kidney responsible for filtering blood and forming urine?","o":["Nephron","Alveolus","Neuron","Villus"],"c":0,"e":"The nephron is the microscopic functional unit of the kidney where blood is filtered and urine is produced."},
  {"i":"bio-b3-0332","g":11,"u":"The Human Body Systems","d":"easy","t":"conceptual","q":"In the human gas-exchange system, where does the actual exchange of oxygen and carbon dioxide between air and blood take place?","o":["Trachea","Bronchi","Alveoli","Larynx"],"c":2,"e":"The alveoli are thin-walled air sacs with a rich capillary supply; their large surface area allows efficient O₂ and CO₂ exchange with the blood."},
  {"i":"bio-b3-0333","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"Which chamber of the human heart pumps oxygenated blood out to the entire body through the aorta?","o":["Right atrium","Left atrium","Right ventricle","Left ventricle"],"c":3,"e":"The left ventricle has the thickest muscular wall and pumps oxygenated blood into the aorta for distribution to the whole body."},
  {"i":"bio-b3-0334","g":11,"u":"The Human Body Systems","d":"easy","t":"conceptual","q":"Which hormone, secreted by the pancreas, lowers blood glucose by promoting its uptake into cells?","o":["Glucagon","Insulin","Adrenaline","Thyroxine"],"c":1,"e":"Insulin from the pancreatic beta cells lowers blood glucose by stimulating cells to absorb glucose and the liver to store it as glycogen."},
  {"i":"bio-b3-0335","g":11,"u":"Characteristics of Animals","d":"easy","t":"definition","q":"Which group of animals is characterised by having a backbone (vertebral column)?","o":["Arthropods","Molluscs","Vertebrates","Annelids"],"c":2,"e":"Vertebrates are animals possessing a backbone or vertebral column, including fish, amphibians, reptiles, birds and mammals."},
  {"i":"bio-b3-0336","g":11,"u":"Characteristics of Animals","d":"easy","t":"conceptual","q":"Which feature is characteristic of mammals and distinguishes them from other vertebrate classes?","o":["Laying shelled eggs on land","Presence of mammary glands and body hair","Breathing only through gills","Having scales covering the body"],"c":1,"e":"Mammals are uniquely defined by mammary glands that produce milk for their young and by the presence of hair or fur."},
  {"i":"bio-b3-0337","g":11,"u":"Biology & Technology","d":"easy","t":"definition","q":"What is the term for the use of living organisms or their products to make useful goods such as bread, beer, and injera?","o":["Biotechnology","Genetics","Taxonomy","Ecology"],"c":0,"e":"Biotechnology is the application of living organisms or their products to make useful items; fermentation in injera and beer brewing are everyday Ethiopian examples."},
  {"i":"bio-b3-0338","g":11,"u":"Biology & Technology","d":"easy","t":"conceptual","q":"In the traditional Ethiopian preparation of injera, the rising and sour flavour of the fermenting teff batter is mainly produced by the action of:","o":["Viruses","Microorganisms such as yeasts and bacteria","Soil minerals","Enzymes from teff seeds only"],"c":1,"e":"Fermentation of teff batter by yeasts and bacteria produces gas (causing the eyes/bubbles) and acids that give injera its characteristic sour taste."},
  {"i":"bio-b3-0339","g":11,"u":"Population & Natural Resources","d":"easy","t":"definition","q":"What term describes the maximum population size of a species that a particular environment can support sustainably?","o":["Biotic potential","Carrying capacity","Population density","Birth rate"],"c":1,"e":"Carrying capacity is the largest population an environment can sustain indefinitely given its available resources such as food, water and space."},
  {"i":"bio-b3-0340","g":11,"u":"Population & Natural Resources","d":"easy","t":"conceptual","q":"Cutting down large areas of Ethiopia's highland forests for farmland and fuelwood most directly leads to which environmental problem?","o":["Increased soil fertility","Soil erosion and loss of biodiversity","More groundwater storage","Cooler regional climate"],"c":1,"e":"Deforestation removes the plant cover that holds soil, leading to soil erosion and destruction of habitats, which reduces biodiversity."},
  {"i":"bio-b3-0341","g":11,"u":"Enzymes","d":"easy","t":"definition","q":"What type of biological molecule are most enzymes?","o":["Proteins","Lipids","Carbohydrates","Nucleic acids"],"c":0,"e":"Most enzymes are globular proteins whose specific three-dimensional shape gives them catalytic activity."},
  {"i":"bio-b3-0342","g":11,"u":"Enzymes","d":"easy","t":"conceptual","q":"How does an enzyme speed up a chemical reaction?","o":["By raising the temperature of the cell","By lowering the activation energy","By increasing the substrate concentration","By becoming part of the final product"],"c":1,"e":"Enzymes act as catalysts by lowering the activation energy needed for a reaction, so it proceeds faster without being used up."},
  {"i":"bio-b3-0343","g":11,"u":"Enzymes","d":"easy","t":"definition","q":"The specific substance on which an enzyme acts is called the:","o":["Product","Substrate","Coenzyme","Inhibitor"],"c":1,"e":"The substrate is the reactant molecule that binds to the enzyme's active site and is converted into product."},
  {"i":"bio-b3-0344","g":11,"u":"Enzymes","d":"easy","t":"application","q":"Most human enzymes work fastest (optimum activity) at a temperature of about:","o":["0 °C","25 °C","37 °C","60 °C"],"c":2,"e":"Human enzymes have an optimum near normal body temperature, about 37 °C; much higher temperatures denature them."},
  {"i":"bio-b3-0345","g":11,"u":"Genetics","d":"easy","t":"definition","q":"An organism with two identical alleles for a gene (for example TT or tt) is described as:","o":["Heterozygous","Homozygous","Hemizygous","Codominant"],"c":1,"e":"Homozygous means both alleles for a trait are the same; heterozygous means they differ (Tt)."},
  {"i":"bio-b3-0346","g":11,"u":"Genetics","d":"easy","t":"calculation","q":"In a cross Tt × Tt (T = tall, dominant over t = short), what fraction of offspring are expected to be short?","o":["1/4","1/2","3/4","0"],"c":0,"e":"Tt × Tt gives 1 TT : 2 Tt : 1 tt. Only tt (1/4) is short, so 1/4 of offspring are short."},
  {"i":"bio-b3-0347","g":11,"u":"Genetics","d":"easy","t":"calculation","q":"A cross between a homozygous tall pea plant (TT) and a short plant (tt) produces F1 offspring that are all:","o":["Short","Tall","Half tall, half short","Intermediate height"],"c":1,"e":"All F1 are Tt; since T (tall) is dominant, every offspring is tall."},
  {"i":"bio-b3-0348","g":11,"u":"Genetics","d":"easy","t":"calculation","q":"In a monohybrid cross of two heterozygotes (Aa × Aa), the expected phenotypic ratio of dominant to recessive is:","o":["1:1","3:1","9:3:3:1","1:2:1"],"c":1,"e":"Aa × Aa yields 3 showing the dominant phenotype to 1 showing the recessive, the classic 3:1 ratio."},
  {"i":"bio-b3-0349","g":11,"u":"Genetics","d":"easy","t":"definition","q":"The observable physical characteristics of an organism make up its:","o":["Genotype","Phenotype","Karyotype","Genome"],"c":1,"e":"Phenotype is the set of observable traits; genotype is the underlying allele combination."},
  {"i":"bio-b3-0350","g":11,"u":"Genetics","d":"easy","t":"application","q":"In humans, a child receives a Y chromosome from the father. The child's sex is:","o":["Female","Male","Cannot be determined","Depends on the mother"],"c":1,"e":"A sperm carrying a Y chromosome produces an XY zygote, which develops as male; the mother always contributes an X."},
  {"i":"bio-b3-0351","g":11,"u":"Genetics","d":"easy","t":"calculation","q":"In a dihybrid cross between two organisms heterozygous for both genes (RrYy × RrYy), the expected phenotypic ratio is:","o":["3:1","1:1:1:1","9:3:3:1","1:2:1"],"c":2,"e":"Two independently assorting heterozygous gene pairs give the classic 9:3:3:1 dihybrid phenotypic ratio."},
  {"i":"bio-b3-0352","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"The functional unit of the kidney that filters blood and forms urine is the:","o":["Nephron","Alveolus","Neuron","Villus"],"c":0,"e":"The nephron is the microscopic filtering unit of the kidney; each kidney contains about a million of them."},
  {"i":"bio-b3-0353","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"In the human lungs, gas exchange between air and blood takes place across the:","o":["Bronchi","Trachea","Alveoli","Pleura"],"c":2,"e":"The alveoli are tiny air sacs with thin walls and a rich blood supply, the actual surface for oxygen and carbon dioxide exchange."},
  {"i":"bio-b3-0354","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"The basic structural and functional unit of the nervous system is the:","o":["Nephron","Neuron","Alveolus","Sarcomere"],"c":1,"e":"The neuron (nerve cell) is the basic unit that transmits electrical impulses in the nervous system."},
  {"i":"bio-b3-0355","g":11,"u":"The Human Body Systems","d":"easy","t":"application","q":"Which chamber of the human heart pumps oxygenated blood to the whole body?","o":["Right atrium","Right ventricle","Left atrium","Left ventricle"],"c":3,"e":"The thick-walled left ventricle pumps oxygenated blood into the aorta and on to the body; the right ventricle sends blood to the lungs."},
  {"i":"bio-b3-0356","g":11,"u":"Characteristics of Animals","d":"easy","t":"definition","q":"Animals that have a backbone (vertebral column) belong to the group called:","o":["Invertebrates","Vertebrates","Arthropods","Molluscs"],"c":1,"e":"Vertebrates possess an internal backbone; this group includes fish, amphibians, reptiles, birds and mammals."},
  {"i":"bio-b3-0357","g":11,"u":"Characteristics of Animals","d":"easy","t":"application","q":"The Walia ibex of the Ethiopian Simien Mountains feeds its young on milk and has hair. It is best classified as a:","o":["Reptile","Bird","Mammal","Amphibian"],"c":2,"e":"Producing milk (mammary glands) and having hair are defining mammalian characteristics, so the Walia ibex is a mammal."},
  {"i":"bio-b3-0358","g":11,"u":"Biology & Technology","d":"easy","t":"definition","q":"The use of living organisms or their products to make useful goods, such as making injera dough rise, is called:","o":["Biotechnology","Geology","Pharmacology","Taxonomy"],"c":0,"e":"Biotechnology applies living organisms or their products to human use; fermentation in injera making is a traditional example."},
  {"i":"bio-b3-0359","g":11,"u":"Biology & Technology","d":"easy","t":"application","q":"Which microorganism is responsible for the fermentation that makes injera batter (and bread dough) rise?","o":["Yeast","Virus","Algae","Protozoan"],"c":0,"e":"Yeast ferments sugars and releases carbon dioxide gas, which creates bubbles that make the dough rise."},
  {"i":"bio-b3-0360","g":11,"u":"Population & Natural Resources","d":"easy","t":"definition","q":"All the organisms of the same species living together in one area at one time form a:","o":["Community","Population","Ecosystem","Biome"],"c":1,"e":"A population is a group of individuals of a single species in a given area; many populations together form a community."},
  {"i":"bio-b3-0361","g":11,"u":"Enzymes","d":"easy","t":"definition","q":"Most enzymes are made of which class of macromolecule?","o":["Lipids","Proteins","Carbohydrates","Nucleic acids"],"c":1,"e":"Enzymes are biological catalysts, and the large majority are globular proteins whose specific 3-D shape forms an active site (a few exceptions, ribozymes, are RNA)."},
  {"i":"bio-b3-0362","g":11,"u":"The Human Body Systems","d":"easy","t":"definition","q":"In the human respiratory system, gas exchange between air and blood occurs in which structures?","o":["Bronchi","Trachea","Alveoli","Larynx"],"c":2,"e":"The alveoli are tiny thin-walled air sacs surrounded by capillaries; their large surface area allows oxygen and carbon dioxide to diffuse between air and blood."},
  {"i":"bio-b3-0363","g":11,"u":"Biology & Technology","d":"easy","t":"application","q":"In genetic engineering, which type of enzyme is used to cut DNA at specific base sequences?","o":["DNA ligase","Restriction enzyme","DNA polymerase","Amylase"],"c":1,"e":"Restriction enzymes (restriction endonucleases) recognise and cut DNA at specific sequences, while DNA ligase joins fragments together."},
  {"i":"bio-b3-0364","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"In a Punnett cross between two pea plants heterozygous for round (Rr) seeds, where round (R) is dominant over wrinkled (r), what fraction of the offspring are expected to be heterozygous?","o":["1/4","1/2","3/4","1"],"c":1,"e":"Rr × Rr gives 1 RR : 2 Rr : 1 rr. The heterozygous (Rr) class is 2 of 4, i.e. 1/2."},
  {"i":"bio-b3-0365","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"A dihybrid cross AaBb × AaBb (both genes showing complete dominance with independent assortment) is performed. What fraction of offspring show both recessive traits?","o":["9/16","3/16","1/16","1/4"],"c":2,"e":"For both recessive (aabb) the probability is (1/4 aa) × (1/4 bb) = 1/16."},
  {"i":"bio-b3-0366","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"In a population at Hardy–Weinberg equilibrium, the recessive allele frequency q = 0.3 for a two-allele locus. What is the expected frequency of heterozygotes?","o":["0.09","0.21","0.42","0.49"],"c":2,"e":"p = 1 − 0.3 = 0.7. Heterozygote frequency = 2pq = 2(0.7)(0.3) = 0.42."},
  {"i":"bio-b3-0367","g":11,"u":"Genetics","d":"medium","t":"application","q":"A man with blood group AB marries a woman with blood group O. Which blood group is IMPOSSIBLE among their children?","o":["Group A","Group B","Group AB","Both A and B are possible"],"c":2,"e":"AB (IᴬIᴮ) × O (ii) gives Iᴬi (group A) and Iᴮi (group B) only; no child can be AB or O."},
  {"i":"bio-b3-0368","g":11,"u":"Genetics","d":"medium","t":"conceptual","q":"During meiosis, the physical exchange of segments between homologous chromosomes that increases genetic variation is called:","o":["Crossing over","Independent assortment","Nondisjunction","Replication"],"c":0,"e":"Crossing over occurs at chiasmata in prophase I, exchanging segments between homologues and producing recombinant chromatids."},
  {"i":"bio-b3-0369","g":11,"u":"Enzymes","d":"medium","t":"conceptual","q":"An enzyme lowers the activation energy of a reaction primarily by:","o":["Increasing the energy of the substrate","Providing an alternative reaction pathway via the active site","Changing the overall energy released by the reaction","Raising the temperature of the cell"],"c":1,"e":"Enzymes bind substrate at the active site, stabilising the transition state and offering a lower-energy pathway; they do not alter the net energy change (ΔG)."},
  {"i":"bio-b3-0370","g":11,"u":"Enzymes","d":"medium","t":"application","q":"A digestive enzyme works fastest at pH 2 and loses activity at pH 7. This enzyme most likely functions in the:","o":["Mouth","Stomach","Small intestine","Large intestine"],"c":1,"e":"Pepsin, the stomach protease, has an optimum near pH 2 because gastric HCl creates a strongly acidic environment; neutral pH denatures it."},
  {"i":"bio-b3-0371","g":11,"u":"Enzymes","d":"medium","t":"conceptual","q":"A competitive inhibitor reduces enzyme activity because it:","o":["Binds the active site, competing with the substrate","Binds a site away from the active site, changing enzyme shape","Permanently destroys the enzyme","Lowers the substrate concentration"],"c":0,"e":"A competitive inhibitor resembles the substrate and binds the active site; its effect can be overcome by raising substrate concentration."},
  {"i":"bio-b3-0372","g":11,"u":"Enzymes","d":"medium","t":"application","q":"When temperature is raised well above an enzyme's optimum, reaction rate falls sharply mainly because:","o":["Substrate molecules move too slowly","The enzyme's tertiary structure denatures","The pH automatically rises","Activation energy increases"],"c":1,"e":"Excess heat breaks the bonds maintaining the enzyme's 3-D shape, distorting the active site so substrate can no longer bind (denaturation)."},
  {"i":"bio-b3-0373","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"In the human nephron, most reabsorption of glucose and amino acids back into the blood occurs at the:","o":["Glomerulus","Proximal convoluted tubule","Loop of Henle","Collecting duct"],"c":1,"e":"The proximal convoluted tubule reabsorbs nearly all filtered glucose and amino acids by active transport into surrounding capillaries."},
  {"i":"bio-b3-0374","g":11,"u":"The Human Body Systems","d":"medium","t":"application","q":"During strenuous exercise, breathing rate rises mainly in response to a blood increase in:","o":["Oxygen","Carbon dioxide","Glucose","Water"],"c":1,"e":"Rising CO₂ lowers blood pH; chemoreceptors detect this and the medulla increases breathing rate to expel CO₂."},
  {"i":"bio-b3-0375","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"Which sequence correctly traces blood from the body back through the heart to the lungs?","o":["Right atrium → right ventricle → pulmonary artery","Left atrium → left ventricle → aorta","Right ventricle → left atrium → pulmonary vein","Left ventricle → right atrium → vena cava"],"c":0,"e":"Deoxygenated blood enters the right atrium, passes to the right ventricle, then leaves via the pulmonary artery to the lungs."},
  {"i":"bio-b3-0376","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"At a chemical synapse, the neurotransmitter is released from the presynaptic neuron when an impulse triggers the influx of:","o":["Na⁺ ions only","Ca²⁺ ions","K⁺ ions","Cl⁻ ions"],"c":1,"e":"Depolarisation opens voltage-gated Ca²⁺ channels; Ca²⁺ entry causes synaptic vesicles to fuse and release neurotransmitter."},
  {"i":"bio-b3-0377","g":11,"u":"The Human Body Systems","d":"medium","t":"application","q":"A person's blood glucose rises after a meal. Which hormone is released to lower it, and from where?","o":["Glucagon from the liver","Insulin from the pancreas","Adrenaline from the adrenal gland","Thyroxine from the thyroid"],"c":1,"e":"Beta cells of the pancreatic islets release insulin, which promotes glucose uptake and storage as glycogen, lowering blood glucose."},
  {"i":"bio-b3-0378","g":11,"u":"Characteristics of Animals","d":"medium","t":"conceptual","q":"Animals such as Hydra and jellyfish, which have stinging cells and a body built around two tissue layers, belong to the phylum:","o":["Porifera","Cnidaria","Platyhelminthes","Annelida"],"c":1,"e":"Cnidarians are diploblastic with radial symmetry and possess cnidocytes (stinging cells); Hydra and jellyfish are classic examples."},
  {"i":"bio-b3-0379","g":11,"u":"Characteristics of Animals","d":"medium","t":"conceptual","q":"Which feature is shared by ALL chordates at some stage of their life?","o":["A bony vertebral column","A notochord","Feathers","A four-chambered heart"],"c":1,"e":"A notochord (a flexible dorsal rod) is present at some stage in every chordate; bone, feathers and a four-chambered heart occur only in certain groups."},
  {"i":"bio-b3-0380","g":11,"u":"Characteristics of Animals","d":"medium","t":"application","q":"An invertebrate has a segmented body, a hard exoskeleton of chitin and jointed legs. It belongs to the phylum:","o":["Mollusca","Arthropoda","Echinodermata","Nematoda"],"c":1,"e":"A chitinous exoskeleton, segmentation and jointed appendages are defining features of Arthropoda (insects, crustaceans, arachnids)."},
  {"i":"bio-b3-0381","g":11,"u":"Biology & Technology","d":"medium","t":"application","q":"In producing the local fermented flatbread injera from teff, the sour taste and gas bubbles are mainly produced by the action of:","o":["Yeasts and bacteria during fermentation","Enzymes added by the cook","Heat from the mitad alone","Salt breaking down the dough"],"c":0,"e":"Microorganisms (wild yeasts and lactic-acid bacteria) ferment the teff batter, producing CO₂ (bubbles) and organic acids (sour taste)."},
  {"i":"bio-b3-0382","g":11,"u":"Biology & Technology","d":"medium","t":"conceptual","q":"In genetic engineering, the enzymes used to cut DNA at specific recognition sequences are called:","o":["DNA polymerases","Restriction enzymes","Ligases","Helicases"],"c":1,"e":"Restriction enzymes (endonucleases) recognise specific sequences and cut DNA there, often leaving sticky ends used to insert genes."},
  {"i":"bio-b3-0383","g":11,"u":"Biology & Technology","d":"medium","t":"application","q":"Insulin for treating diabetes can now be mass-produced cheaply by inserting the human insulin gene into bacteria. This technique is best described as:","o":["Natural selection","Recombinant DNA technology","Selective breeding","Tissue culture"],"c":1,"e":"Inserting a human gene into a bacterial plasmid so the bacterium makes the protein is recombinant DNA technology (genetic engineering)."},
  {"i":"bio-b3-0384","g":11,"u":"Population & Natural Resources","d":"medium","t":"calculation","q":"In a food chain, a plant captures 10,000 kJ of energy. If only about 10% passes to each next trophic level, roughly how much energy reaches a secondary consumer?","o":["1,000 kJ","100 kJ","10 kJ","5,000 kJ"],"c":1,"e":"Producer 10,000 kJ → primary consumer 1,000 kJ (10%) → secondary consumer 100 kJ (10% again)."},
  {"i":"bio-b3-0385","g":11,"u":"Population & Natural Resources","d":"medium","t":"conceptual","q":"Clearing forest on steep highland slopes for farming most directly increases the risk of:","o":["Soil erosion and loss of fertility","Higher atmospheric oxygen","Increased groundwater storage","Greater biodiversity"],"c":0,"e":"Removing tree cover and roots exposes soil to rain and runoff, accelerating erosion and loss of topsoil fertility on steep slopes."},
  {"i":"bio-b3-0386","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"In Ethiopian highland cattle, polled (hornless, P) is dominant over horned (p). A heterozygous polled bull is crossed with a horned cow. What fraction of the calves is expected to be horned?","o":["1/4","1/2","3/4","0"],"c":1,"e":"Cross Pp x pp gives 1 Pp : 1 pp, so 1/2 are pp (horned). This is a test-cross ratio of 1:1."},
  {"i":"bio-b3-0387","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"Two plants heterozygous for seed colour (Yy, yellow dominant) and seed shape (Rr, round dominant) are crossed (YyRr x YyRr). What fraction of offspring is expected to be yellow and wrinkled?","o":["9/16","3/16","1/16","6/16"],"c":1,"e":"Dihybrid 9:3:3:1 gives yellow-round 9, yellow-wrinkled 3, green-round 3, green-wrinkled 1; yellow-wrinkled = 3/16."},
  {"i":"bio-b3-0388","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"Colour-blindness is X-linked recessive. A carrier woman marries a man with normal colour vision. What fraction of their SONS is expected to be colour-blind?","o":["1/4","1/2","0","3/4"],"c":1,"e":"Mother X^A X^a x father X^A Y. Sons get X from mother only: 1/2 X^A Y (normal), 1/2 X^a Y (colour-blind). So 1/2 of sons are affected."},
  {"i":"bio-b3-0389","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"In a large population at Hardy-Weinberg equilibrium, the recessive allele frequency q = 0.3. What is the expected frequency of heterozygous carriers?","o":["0.09","0.42","0.49","0.21"],"c":1,"e":"p = 1 − 0.3 = 0.7. Heterozygotes = 2pq = 2(0.7)(0.3) = 0.42."},
  {"i":"bio-b3-0390","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"In humans, blood group is determined by alleles I^A, I^B (codominant) and i (recessive). A mother with genotype I^A i and a father with genotype I^B i have a child. What is the chance the child has blood group O?","o":["1/4","1/2","3/4","0"],"c":0,"e":"I^A i x I^B i gives I^A I^B, I^A i, I^B i, ii in equal parts; only ii (1/4) is group O."},
  {"i":"bio-b3-0391","g":11,"u":"Genetics","d":"medium","t":"conceptual","q":"A man whose father was haemophilic (X-linked recessive) but who is himself unaffected marries an unaffected non-carrier woman. Regarding haemophilia, what is true of their children?","o":["Half the daughters will be haemophilic","None of the children will be haemophilic","All sons will be haemophilic","All daughters will be carriers"],"c":1,"e":"The unaffected man is X^H Y (he did not inherit the disease allele from his father; sons get their father's Y, not X). With a non-carrier mother, no child receives X^h, so none are affected."},
  {"i":"bio-b3-0392","g":11,"u":"Enzymes","d":"medium","t":"conceptual","q":"A student measures the rate of an enzyme-catalysed reaction as temperature rises from 20 to 50 degrees C. The rate increases up to about 37 degrees C, then falls sharply. The fall above 37 degrees C is best explained by which change to the enzyme?","o":["The substrate is used up","The active site is denatured by loss of tertiary structure","The pH suddenly becomes acidic","More competitive inhibitor binds"],"c":1,"e":"Above the optimum, heat disrupts hydrogen and other bonds holding the enzyme's tertiary structure, altering the active site shape so substrate no longer fits."},
  {"i":"bio-b3-0393","g":11,"u":"Enzymes","d":"medium","t":"conceptual","q":"A non-competitive inhibitor binds to a site other than the active site. Compared with the uninhibited reaction, adding excess substrate to a non-competitively inhibited reaction will most likely do what?","o":["Fully restore the maximum rate","Not restore the maximum rate","Increase enzyme concentration","Lower the activation energy further"],"c":1,"e":"A non-competitive inhibitor changes the active site via a separate site, so adding more substrate cannot out-compete it; maximum rate stays reduced."},
  {"i":"bio-b3-0394","g":11,"u":"Enzymes","d":"medium","t":"application","q":"Salivary amylase works best near pH 7 but is inactivated in the stomach. Which factor in the stomach most directly stops amylase activity?","o":["The very low (acidic) pH","The high substrate concentration","The body temperature of 37 degrees C","The presence of bile salts"],"c":0,"e":"Stomach pH is about 1.5-2; this is far below amylase's optimum (about 7) and denatures it, halting starch digestion."},
  {"i":"bio-b3-0395","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"During inhalation in humans, which combination of events allows air to enter the lungs?","o":["Diaphragm relaxes (domes up) and thoracic volume falls","Diaphragm contracts (flattens) and thoracic volume rises","External intercostals relax and ribs move down","Lung pressure rises above atmospheric pressure"],"c":1,"e":"The diaphragm contracts and flattens while external intercostals lift the ribs; thoracic volume rises, lung pressure drops below atmospheric, so air flows in."},
  {"i":"bio-b3-0396","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"In the human nephron, most reabsorption of glucose back into the blood occurs at which region, and is normally complete in a healthy person?","o":["Glomerulus","Proximal convoluted tubule","Collecting duct","Loop of Henle descending limb"],"c":1,"e":"Glucose is reabsorbed by active transport in the proximal convoluted tubule; in a healthy person essentially all filtered glucose is recovered, so urine is glucose-free."},
  {"i":"bio-b3-0397","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"A signal travelling along a motor neuron reaches the axon terminal. What is the correct immediate sequence at the synapse?","o":["Neurotransmitter released, then Ca2+ enters, then receptors bind","Ca2+ enters, vesicles fuse and release neurotransmitter, receptors on next cell bind it","Receptors bind first, then Ca2+ leaves the cell","Neurotransmitter is reabsorbed before it crosses the cleft"],"c":1,"e":"Depolarisation opens Ca2+ channels; Ca2+ entry triggers vesicle fusion and neurotransmitter release into the cleft, where it binds receptors on the postsynaptic membrane."},
  {"i":"bio-b3-0398","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"In the human heart, the sino-atrial (SA) node sets the heartbeat. After the SA node fires, a brief delay before the ventricles contract is caused mainly by which structure?","o":["The atrioventricular (AV) node","The aortic semilunar valve","The pulmonary vein","The bundle of His tip in Purkinje fibres"],"c":0,"e":"The AV node delays the impulse, allowing atria to finish emptying into the ventricles before the ventricles contract."},
  {"i":"bio-b3-0399","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"Which statement best describes why arteries (compared with veins) have thick, elastic, muscular walls?","o":["They carry deoxygenated blood only","They must withstand and smooth high pressure from the heart","They contain valves along their entire length","They carry blood more slowly than capillaries"],"c":1,"e":"Arteries receive blood pumped at high pressure; thick elastic muscular walls withstand the pressure and recoil to keep blood flowing smoothly."},
  {"i":"bio-b3-0400","g":11,"u":"The Human Body Systems","d":"medium","t":"application","q":"After a carbohydrate-rich injera meal, blood glucose rises. Which hormonal response in a healthy person lowers it back toward normal?","o":["Glucagon stimulates glycogen breakdown","Insulin promotes glucose uptake and glycogen storage","Adrenaline raises blood glucose","ADH increases water reabsorption"],"c":1,"e":"High blood glucose stimulates pancreatic beta cells to release insulin, which promotes cellular glucose uptake and storage as glycogen, lowering blood glucose."},
  {"i":"bio-b3-0401","g":11,"u":"Characteristics of Animals","d":"medium","t":"conceptual","q":"Insects such as locusts, which periodically swarm in parts of Ethiopia, exchange gases without lungs. Which structures deliver oxygen directly to their tissues?","o":["Gills","Tracheae and tracheoles","Moist skin surface","Book lungs only"],"c":1,"e":"Insects use a tracheal system: air enters through spiracles and travels through tracheae and fine tracheoles that deliver oxygen straight to the cells."},
  {"i":"bio-b3-0402","g":11,"u":"Characteristics of Animals","d":"medium","t":"conceptual","q":"A student groups animals by symmetry. Which feature is characteristic of bilaterally symmetrical animals compared with radially symmetrical ones?","o":["A single body axis with identical halves all around","Distinct anterior (head) and posterior ends with cephalization","No definite front or back end","Body parts arranged around a central point only"],"c":1,"e":"Bilateral symmetry gives a defined head end where sense organs and nerve tissue concentrate (cephalization), unlike radial symmetry's circular arrangement."},
  {"i":"bio-b3-0403","g":11,"u":"Characteristics of Animals","d":"medium","t":"conceptual","q":"Amphibians such as frogs are described as having incomplete double circulation. Which heart feature is responsible for some mixing of oxygenated and deoxygenated blood?","o":["A single atrium and single ventricle","Two atria but a single undivided ventricle","Four fully separate chambers","No heart, only open sinuses"],"c":1,"e":"The amphibian heart has two atria but only one ventricle, so oxygenated and deoxygenated blood partly mix in that single ventricle."},
  {"i":"bio-b3-0404","g":11,"u":"Biology & Technology","d":"medium","t":"conceptual","q":"In genetic engineering, a restriction enzyme and DNA ligase are both used to make recombinant DNA. What is the role of DNA ligase in this process?","o":["It cuts DNA at specific recognition sequences","It joins the sugar-phosphate backbones of DNA fragments","It copies RNA into DNA","It separates the two DNA strands"],"c":1,"e":"Restriction enzymes cut DNA; DNA ligase seals the fragments by forming phosphodiester bonds, joining the gene of interest into the vector."},
  {"i":"bio-b3-0405","g":11,"u":"Biology & Technology","d":"medium","t":"application","q":"In the production of injera, the batter is fermented before baking. The sourness and bubbles are produced mainly by which biotechnological activity?","o":["Microbial fermentation producing acids and CO2","Photosynthesis in the grain","Denaturation of starch by heat","Enzyme-free oxidation of fat"],"c":0,"e":"Microorganisms (including yeasts and lactic acid bacteria) ferment the teff batter, producing CO2 gas (bubbles) and acids (sour taste)."},
  {"i":"bio-b3-0406","g":11,"u":"Biology & Technology","d":"medium","t":"conceptual","q":"The polymerase chain reaction (PCR) amplifies DNA in repeated cycles. During the denaturation step of each cycle, what happens?","o":["Primers bind to the template strands","The double-stranded DNA is heated to separate into single strands","Taq polymerase adds new nucleotides","The new DNA strands are ligated together"],"c":1,"e":"Denaturation heats DNA (about 94-95 degrees C) to break hydrogen bonds and separate the strands, so primers can bind in the next step."},
  {"i":"bio-b3-0407","g":11,"u":"Population & Natural Resources","d":"medium","t":"calculation","q":"In a grassland food chain, grass fixes 50000 kJ of energy. Assuming about 10 percent energy transfer between trophic levels, roughly how much energy is available to a secondary consumer?","o":["5000 kJ","500 kJ","50 kJ","5 kJ"],"c":1,"e":"Grass 50000 to primary consumer 5000 (10%), then to secondary consumer 500 kJ (another 10%)."},
  {"i":"bio-b3-0408","g":11,"u":"Population & Natural Resources","d":"medium","t":"conceptual","q":"A population of grazing animals shows logistic growth in a reserve. As the population approaches the carrying capacity (K), what happens to the population growth rate?","o":["It keeps rising exponentially","It slows and approaches zero","It becomes negative immediately","It is unaffected by resources"],"c":1,"e":"As numbers near K, limited resources and competition reduce per-capita growth, so the growth rate slows and approaches zero, giving an S-shaped curve."},
  {"i":"bio-b3-0409","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"In garden pea, tall (T) is dominant to short (t). A heterozygous tall plant is crossed with a short plant. What fraction of the offspring are expected to be tall?","o":["1/4","1/2","3/4","All"],"c":1,"e":"Tt × tt gives 1 Tt : 1 tt, so 1/2 are tall (Tt) and 1/2 are short. A test cross of a heterozygote yields a 1:1 ratio."},
  {"i":"bio-b3-0410","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"Two heterozygous black guinea pigs (Bb) are crossed. Among the offspring, what is the expected ratio of black to white coat colour?","o":["1:1","2:1","3:1","9:7"],"c":2,"e":"Bb × Bb gives 1 BB : 2 Bb : 1 bb. Three carry at least one dominant B (black) to one bb (white), so the phenotypic ratio is 3:1."},
  {"i":"bio-b3-0411","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"In a dihybrid cross between two plants heterozygous for both seed shape and seed colour (RrYy × RrYy), what fraction of offspring show both recessive traits?","o":["1/16","3/16","9/16","1/4"],"c":0,"e":"For independently assorting genes, recessive at both loci is 1/4 × 1/4 = 1/16. This is the rryy class of the classic 9:3:3:1 ratio."},
  {"i":"bio-b3-0412","g":11,"u":"Genetics","d":"medium","t":"application","q":"Colour blindness is X-linked recessive. A carrier mother (XᴬXᵃ) and a normal-vision father (XᴬY) have children. What is the probability that a son is colour blind?","o":["0","1/4","1/2","1"],"c":2,"e":"Sons receive Y from father and either Xᴬ or Xᵃ from the carrier mother, with equal chance. Half the sons inherit Xᵃ and are colour blind, so the probability is 1/2."},
  {"i":"bio-b3-0413","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"In a population at Hardy–Weinberg equilibrium, the recessive phenotype (aa) occurs in 16% of individuals. What is the frequency of the dominant allele A?","o":["0.4","0.6","0.16","0.84"],"c":1,"e":"q² = 0.16 so q = 0.4, and p = 1 − q = 0.6. The dominant allele A has frequency 0.6."},
  {"i":"bio-b3-0414","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"For the same population where q = 0.4 and p = 0.6, what percentage of individuals are heterozygous carriers (Aa)?","o":["16%","24%","36%","48%"],"c":3,"e":"Heterozygote frequency = 2pq = 2 × 0.6 × 0.4 = 0.48, i.e. 48% of the population."},
  {"i":"bio-b3-0415","g":11,"u":"Genetics","d":"medium","t":"conceptual","q":"During which phase of meiosis does the random separation of homologous chromosomes (independent assortment) physically occur?","o":["Prophase I","Anaphase I","Anaphase II","Telophase II"],"c":1,"e":"At anaphase I homologous chromosomes of each bivalent are pulled to opposite poles independently of other pairs, which is the cellular basis of independent assortment."},
  {"i":"bio-b3-0416","g":11,"u":"Enzymes","d":"medium","t":"conceptual","q":"An enzyme-catalysed reaction is run at increasing substrate concentrations while enzyme amount is fixed. Beyond a certain point the rate stops increasing. The best explanation is that:","o":["The substrate has been denatured","All active sites are saturated with substrate","The pH has become too acidic","The enzyme has been used up permanently"],"c":1,"e":"At high substrate concentration every active site is occupied, so the enzyme works at maximum velocity (Vmax). Adding more substrate cannot speed it up because no free active sites remain."},
  {"i":"bio-b3-0417","g":11,"u":"Enzymes","d":"medium","t":"conceptual","q":"A competitive inhibitor and the substrate both bind the same active site. Increasing the substrate concentration in the presence of a competitive inhibitor will:","o":["Have no effect on reaction rate","Reduce the maximum rate permanently","Help overcome the inhibition","Denature the enzyme"],"c":2,"e":"Because they compete for the same site, raising substrate concentration out-competes the inhibitor and can restore the rate toward Vmax. This is the defining feature of competitive inhibition."},
  {"i":"bio-b3-0418","g":11,"u":"Enzymes","d":"medium","t":"application","q":"Human salivary amylase works best near pH 7, while pepsin in the stomach works best near pH 2. If salivary amylase is swallowed into the stomach, its activity will most likely:","o":["Increase sharply","Stay the same","Fall to nearly zero","Switch to digesting protein"],"c":2,"e":"Each enzyme has an optimum pH; far from it the enzyme is denatured. The strongly acidic stomach (pH 2) is well below amylase's optimum, so its activity drops to almost zero."},
  {"i":"bio-b3-0419","g":11,"u":"Enzymes","d":"medium","t":"conceptual","q":"According to the induced-fit model, when a substrate binds an enzyme:","o":["The active site is already a perfect rigid match","The active site changes shape to fit the substrate","The substrate changes into the enzyme","No change in shape occurs at all"],"c":1,"e":"The induced-fit model proposes that substrate binding causes the active site to adjust its shape slightly to grip the substrate more tightly, unlike the rigid lock-and-key view."},
  {"i":"bio-b3-0420","g":11,"u":"The Human Body Systems","d":"medium","t":"application","q":"In the human nephron, most reabsorption of glucose, amino acids and water back into the blood occurs at the:","o":["Glomerulus","Proximal convoluted tubule","Collecting duct","Bowman's capsule"],"c":1,"e":"Filtration occurs at the glomerulus/Bowman's capsule, but selective reabsorption of useful solutes such as glucose and amino acids occurs mainly in the proximal convoluted tubule."},
  {"i":"bio-b3-0421","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"Oxygenated blood returning from the lungs enters which chamber of the human heart first?","o":["Right atrium","Right ventricle","Left atrium","Left ventricle"],"c":2,"e":"Pulmonary veins carry oxygenated blood from the lungs into the left atrium, which then passes it to the left ventricle for systemic circulation."},
  {"i":"bio-b3-0422","g":11,"u":"The Human Body Systems","d":"medium","t":"application","q":"After a high-carbohydrate injera meal, blood glucose rises. Which hormone is released to lower it, and by what main action?","o":["Glucagon; breaks down glycogen","Insulin; promotes glucose uptake by cells","Adrenaline; raises heart rate","Thyroxine; speeds metabolism"],"c":1,"e":"Rising blood glucose stimulates the pancreatic beta cells to release insulin, which promotes glucose uptake and storage as glycogen, lowering blood glucose toward normal."},
  {"i":"bio-b3-0423","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"At a synapse, the arrival of a nerve impulse at the axon terminal triggers the release of:","o":["Hormones into the blood","Neurotransmitters into the synaptic cleft","Antibodies into the cleft","Enzymes that cut the neuron"],"c":1,"e":"When the impulse reaches the axon terminal, neurotransmitter molecules are released into the synaptic cleft and diffuse across to receptors on the next neuron, passing the signal."},
  {"i":"bio-b3-0424","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"During strenuous exercise when oxygen supply is limited, human muscle cells obtain ATP by anaerobic respiration, producing:","o":["Ethanol and carbon dioxide","Lactic acid","Glucose and oxygen","Carbon dioxide and water only"],"c":1,"e":"In animal/muscle anaerobic respiration, glucose is partially broken down to lactic acid (not ethanol, which is the yeast pathway), yielding a small amount of ATP."},
  {"i":"bio-b3-0425","g":11,"u":"Characteristics of Animals","d":"medium","t":"conceptual","q":"Animals such as Hydra and jellyfish belong to phylum Cnidaria. A defining feature of this phylum is:","o":["A true coelom and segmented body","Stinging cells (cnidocytes) and radial symmetry","A jointed exoskeleton","A backbone made of cartilage"],"c":1,"e":"Cnidarians are radially symmetric and possess specialised stinging cells called cnidocytes (with nematocysts) used for capturing prey and defence."},
  {"i":"bio-b3-0426","g":11,"u":"Characteristics of Animals","d":"medium","t":"conceptual","q":"Which feature distinguishes arthropods such as insects and crustaceans from annelids such as earthworms?","o":["Presence of a jointed exoskeleton and limbs","Presence of a closed circulatory system","Lack of any body segmentation","Absence of a nervous system"],"c":0,"e":"Arthropods are characterised by a hard jointed exoskeleton of chitin and jointed appendages. Annelids are segmented but soft-bodied without jointed limbs."},
  {"i":"bio-b3-0427","g":11,"u":"Characteristics of Animals","d":"medium","t":"application","q":"A newly described aquatic animal has a notochord, a dorsal hollow nerve cord and pharyngeal gill slits at some stage of life. It is best classified in phylum:","o":["Mollusca","Echinodermata","Chordata","Platyhelminthes"],"c":2,"e":"A notochord, dorsal hollow nerve cord and pharyngeal slits are the diagnostic features of phylum Chordata, present at least during some stage of development."},
  {"i":"bio-b3-0428","g":11,"u":"Biology & Technology","d":"medium","t":"application","q":"In recombinant DNA technology, restriction enzymes are used because they:","o":["Join DNA fragments together","Cut DNA at specific recognition sequences","Copy RNA into protein","Translate genes into amino acids"],"c":1,"e":"Restriction enzymes (restriction endonucleases) recognise specific base sequences and cut DNA there, producing fragments that can later be joined by DNA ligase during gene cloning."},
  {"i":"bio-b3-0429","g":11,"u":"Population & Natural Resources","d":"medium","t":"application","q":"In a grassland food chain (grass → grasshopper → bird → hawk), if the grass stores 10000 kJ of energy, roughly how much energy is available to the bird, assuming about 10% transfer between levels?","o":["1000 kJ","100 kJ","10 kJ","1 kJ"],"c":1,"e":"About 10% passes to each next level: grass 10000 → grasshopper 1000 → bird 100 kJ. So roughly 100 kJ reaches the bird."},
  {"i":"bio-b3-0430","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"In garden pea, tall (T) is dominant to dwarf (t). A heterozygous tall plant is crossed with a dwarf plant. What fraction of the offspring is expected to be dwarf?","o":["1/4","1/2","3/4","All tall"],"c":1,"e":"Tt × tt gives gametes T,t from one parent and t,t from the other, producing 1 Tt : 1 tt, so 1/2 are dwarf (tt)."},
  {"i":"bio-b3-0431","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"A dihybrid cross between two plants heterozygous for both seed shape (Rr) and seed colour (Yy) is performed. What fraction of the offspring shows both recessive traits?","o":["9/16","3/16","1/16","1/4"],"c":2,"e":"In a RrYy × RrYy cross the double-recessive (rryy) probability is 1/4 × 1/4 = 1/16."},
  {"i":"bio-b3-0432","g":11,"u":"Genetics","d":"medium","t":"application","q":"In humans, red-green colour blindness is X-linked recessive. A carrier mother and a normal-vision father have children. What proportion of their SONS is expected to be colour blind?","o":["0","1/4","1/2","All"],"c":2,"e":"Mother X^B X^b passes X^b to half her sons; X^b Y sons are colour blind, so 1/2 of sons are affected."},
  {"i":"bio-b3-0433","g":11,"u":"Genetics","d":"medium","t":"conceptual","q":"A man with blood group AB marries a woman with blood group O. Which blood groups are possible among their children?","o":["A and B only","AB and O only","A, B, AB and O","O only"],"c":0,"e":"Father is I^A I^B and mother is ii; children are I^A i (group A) or I^B i (group B), so only A and B are possible."},
  {"i":"bio-b3-0434","g":11,"u":"Genetics","d":"medium","t":"application","q":"Two parents who can both roll their tongue (a dominant trait) have a child who cannot roll the tongue. What are the genotypes of the parents?","o":["Both homozygous dominant","Both heterozygous","One homozygous dominant, one recessive","Both homozygous recessive"],"c":1,"e":"A non-roller child is recessive (rr), so each parent contributed a recessive allele; both rollers must therefore be heterozygous (Rr)."},
  {"i":"bio-b3-0435","g":11,"u":"Enzymes","d":"medium","t":"conceptual","q":"Enzyme activity rises with temperature up to an optimum, then falls sharply above it. The sharp fall above the optimum is mainly because the enzyme is:","o":["Used up as a reactant","Denatured, changing its active-site shape","Converted into substrate","Diluted by the product"],"c":1,"e":"Above the optimum, heat breaks bonds maintaining the tertiary structure, denaturing the enzyme so the active site no longer fits the substrate."},
  {"i":"bio-b3-0436","g":11,"u":"Enzymes","d":"medium","t":"conceptual","q":"A competitive inhibitor and the substrate compete for the same site on an enzyme. Increasing the substrate concentration while inhibitor is present will:","o":["Have no effect on reaction rate","Reduce the maximum rate permanently","Help overcome the inhibition and raise the rate","Denature the enzyme"],"c":2,"e":"Because a competitive inhibitor binds the active site reversibly, adding more substrate outcompetes it and the rate can approach the normal maximum."},
  {"i":"bio-b3-0437","g":11,"u":"Enzymes","d":"medium","t":"definition","q":"Which statement best describes why most enzymes act on only one or very few substrates?","o":["They are made of carbohydrate","The active site has a specific shape complementary to the substrate","They work only at high temperature","They are permanently changed after reacting"],"c":1,"e":"Enzyme specificity arises because the active site's shape and chemistry are complementary to a particular substrate, as in the induced-fit model."},
  {"i":"bio-b3-0438","g":11,"u":"Enzymes","d":"medium","t":"application","q":"The enzyme catalase breaks down hydrogen peroxide. If liver tissue is first boiled and then added to hydrogen peroxide, what is the most likely result?","o":["Faster bubbling than fresh liver","No or very little bubbling","Identical bubbling to fresh liver","The peroxide turns solid"],"c":1,"e":"Boiling denatures catalase, destroying its active site, so little or no oxygen is released and bubbling is minimal."},
  {"i":"bio-b3-0439","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"After a meal rich in injera and bread, blood glucose rises. Which hormone is released to lower it by promoting glucose uptake into cells?","o":["Glucagon","Insulin","Adrenaline","Thyroxine"],"c":1,"e":"Beta cells of the pancreas release insulin, which increases glucose uptake by cells and glycogen storage in the liver, lowering blood glucose."},
  {"i":"bio-b3-0440","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"During inhalation, the diaphragm and external intercostal muscles contract. The immediate effect on the thoracic cavity and lung pressure is:","o":["Volume decreases, pressure rises","Volume increases, pressure falls","Volume and pressure both rise","No change in volume or pressure"],"c":1,"e":"Contraction enlarges the thoracic cavity, increasing lung volume and lowering internal pressure below atmospheric, so air flows in."},
  {"i":"bio-b3-0441","g":11,"u":"The Human Body Systems","d":"medium","t":"application","q":"In the nephron, glucose normally appears in the filtrate but not in the final urine of a healthy person. This is mainly because glucose is:","o":["Never filtered at the glomerulus","Reabsorbed in the proximal tubule","Secreted into the collecting duct","Broken down in the bladder"],"c":1,"e":"Glucose is freely filtered, then almost completely reabsorbed by active transport in the proximal convoluted tubule, so healthy urine contains none."},
  {"i":"bio-b3-0442","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"A person is given an injection of antibodies obtained from another individual to fight a snakebite venom. This type of immunity is:","o":["Active natural","Active artificial","Passive artificial","Innate"],"c":2,"e":"Receiving ready-made antibodies (antiserum) from an external source gives immediate but short-lived protection, which is passive artificial immunity."},
  {"i":"bio-b3-0443","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"In the human heart, blood returning from the body enters which chamber first before being sent to the lungs?","o":["Left atrium","Left ventricle","Right atrium","Right ventricle"],"c":2,"e":"Deoxygenated blood from the body enters the right atrium via the venae cavae, then the right ventricle pumps it to the lungs."},
  {"i":"bio-b3-0444","g":11,"u":"Characteristics of Animals","d":"medium","t":"conceptual","q":"Animals such as Hydra and jellyfish have a body plan organised around a central axis so that any cut through the centre gives mirror halves. This symmetry is described as:","o":["Bilateral","Radial","Asymmetrical","Spherical only"],"c":1,"e":"Cnidarians show radial symmetry: body parts are arranged around a central axis, and many planes through the centre produce mirror-image halves."},
  {"i":"bio-b3-0445","g":11,"u":"Characteristics of Animals","d":"medium","t":"conceptual","q":"Which feature is shared by all chordates at some stage of their life cycle?","o":["A bony backbone","A dorsal hollow nerve cord","Jointed legs","An exoskeleton of chitin"],"c":1,"e":"All chordates possess, at some life stage, a notochord, dorsal hollow nerve cord, pharyngeal slits and a post-anal tail; a bony backbone is only in vertebrates."},
  {"i":"bio-b3-0446","g":11,"u":"Characteristics of Animals","d":"medium","t":"application","q":"A small aquatic animal exchanges gases directly across its thin, moist body surface without specialised lungs or gills. This is most efficient when the animal is:","o":["Large with thick skin","Small with a high surface-area-to-volume ratio","Covered by a dry exoskeleton","Endothermic and large"],"c":1,"e":"Direct diffusion suffices only when the diffusion distance is short and surface area relative to volume is high, which is true of small, thin-bodied animals."},
  {"i":"bio-b3-0447","g":11,"u":"Population & Natural Resources","d":"medium","t":"calculation","q":"A population of 4,000 has 120 births and 40 deaths in one year, with no migration. What is the annual growth rate as a percentage?","o":["1%","2%","3%","4%"],"c":1,"e":"Net increase = 120 − 40 = 80; rate = 80/4000 × 100 = 2% per year."},
  {"i":"bio-b3-0448","g":11,"u":"Population & Natural Resources","d":"medium","t":"conceptual","q":"In an Ethiopian highland grassland food chain, grass → grasshopper → bird → hawk, roughly what percentage of energy is typically transferred from one trophic level to the next?","o":["About 1%","About 10%","About 50%","About 90%"],"c":1,"e":"On average only about 10% of the energy at one trophic level is passed to the next, the rest being lost mainly as heat in respiration."},
  {"i":"bio-b3-0449","g":11,"u":"Population & Natural Resources","d":"medium","t":"application","q":"Repeated removal of trees on steep Ethiopian highlands without replanting most directly leads to which environmental problem?","o":["Increased soil fertility","Accelerated soil erosion","Higher groundwater recharge","Greater biodiversity"],"c":1,"e":"Tree roots bind soil and reduce runoff; removing them exposes slopes so rain washes topsoil away, accelerating soil erosion."},
  {"i":"bio-b3-0450","g":11,"u":"Biology & Technology","d":"medium","t":"conceptual","q":"In producing genetically modified insulin, the human insulin gene is inserted into a bacterial plasmid before the bacteria are cultured. The plasmid here functions as a:","o":["Restriction enzyme","Vector that carries the gene into the host","Source of energy","Type of antibody"],"c":1,"e":"A plasmid is a vector: a carrier that delivers the desired gene into the bacterial host so it can be expressed and the protein mass-produced."},
  {"i":"bio-b3-0451","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"Two plants heterozygous for seed colour (Yy, yellow dominant) are crossed. Of 240 offspring, about how many are expected to show the recessive green phenotype?","o":["60","120","180","240"],"c":0,"e":"Yy × Yy → 3 yellow : 1 green, so 1/4 are green. 1/4 × 240 = 60."},
  {"i":"bio-b3-0452","g":11,"u":"Genetics","d":"medium","t":"application","q":"A woman with normal vision whose father was red-green colour-blind marries a man with normal vision. What percentage of their SONS is expected to be colour-blind? (Colour blindness is X-linked recessive.)","o":["0%","25%","50%","100%"],"c":2,"e":"The woman is a carrier (XᴬXᵃ) since her father gave her Xᵃ; father normal is XᴬY. Sons are XᴬY or XᵃY, so 1/2 of sons are colour-blind = 50%."},
  {"i":"bio-b3-0453","g":11,"u":"Genetics","d":"medium","t":"calculation","q":"In a population in Hardy–Weinberg equilibrium, the recessive allele frequency q = 0.3. What is the expected frequency of heterozygous individuals?","o":["0.09","0.21","0.42","0.49"],"c":2,"e":"p = 1 − 0.3 = 0.7. Heterozygotes = 2pq = 2(0.7)(0.3) = 0.42."},
  {"i":"bio-b3-0454","g":11,"u":"Enzymes","d":"medium","t":"conceptual","q":"A student measures the rate of an enzyme-catalysed reaction as substrate concentration increases at constant enzyme amount. Why does the rate eventually level off at a maximum?","o":["The enzyme is permanently denatured by the substrate","All active sites become saturated with substrate","The substrate is fully used up at every concentration","The pH rises sharply at high substrate levels"],"c":1,"e":"At high substrate concentration every enzyme active site is occupied, so adding more substrate cannot increase the rate; the reaction is enzyme-saturated (Vmax)."},
  {"i":"bio-b3-0455","g":11,"u":"Enzymes","d":"medium","t":"application","q":"An enzyme from the human stomach works best at pH 2, while one from the small intestine works best at about pH 8. If both are placed at pH 7, what is the most likely outcome?","o":["Both work at maximum rate","The stomach enzyme works well, the intestinal one poorly","The intestinal enzyme works near its best, the stomach enzyme poorly","Both are permanently destroyed"],"c":2,"e":"Each enzyme has an optimum pH. At pH 7 the intestinal enzyme (optimum ~8) is near its best, while the stomach enzyme (optimum 2) is far from optimum and works slowly."},
  {"i":"bio-b3-0456","g":11,"u":"Enzymes","d":"medium","t":"conceptual","q":"A competitive inhibitor binds the active site of an enzyme. Which change to reaction conditions would most reduce its inhibitory effect?","o":["Lowering the temperature","Increasing substrate concentration","Adding more inhibitor","Lowering the pH below optimum"],"c":1,"e":"A competitive inhibitor competes with substrate for the active site. Raising substrate concentration shifts the competition in favour of substrate, reducing inhibition."},
  {"i":"bio-b3-0457","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"After a meal rich in carbohydrate, blood glucose rises. Which hormone is released and what is its main effect?","o":["Glucagon; it raises blood glucose","Insulin; it promotes glucose uptake by cells, lowering blood glucose","Adrenaline; it stores glucose as fat","Insulin; it breaks down glycogen to glucose"],"c":1,"e":"Rising blood glucose triggers insulin from the pancreas, which promotes glucose uptake into cells and glycogen storage, lowering blood glucose."},
  {"i":"bio-b3-0458","g":11,"u":"The Human Body Systems","d":"medium","t":"application","q":"During strenuous exercise, muscle cells run short of oxygen. What is produced by anaerobic respiration in these cells, causing fatigue?","o":["Ethanol and carbon dioxide","Lactic acid","Pyruvate only","Carbon dioxide and water"],"c":1,"e":"In oxygen shortage, human muscle cells respire anaerobically, converting pyruvate to lactic acid, whose build-up contributes to fatigue."},
  {"i":"bio-b3-0459","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"In the human nephron, useful substances such as glucose are reabsorbed back into the blood. In which part does most selective reabsorption of glucose occur?","o":["Glomerulus","Proximal convoluted tubule","Collecting duct","Bowman's capsule"],"c":1,"e":"After filtration in the glomerulus, glucose and most useful solutes are selectively reabsorbed into the blood mainly in the proximal convoluted tubule."},
  {"i":"bio-b3-0460","g":11,"u":"The Human Body Systems","d":"medium","t":"application","q":"A person breathes in air. Tracing one oxygen molecule, which sequence correctly shows its path to the blood?","o":["Trachea → bronchi → alveoli → blood capillary","Bronchi → trachea → alveoli → blood capillary","Alveoli → trachea → bronchi → blood capillary","Trachea → alveoli → bronchi → blood capillary"],"c":0,"e":"Air passes the trachea, then bronchi, into the alveoli, where oxygen diffuses across the thin alveolar wall into the surrounding blood capillaries."},
  {"i":"bio-b3-0461","g":11,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"Why is the wall of the left ventricle of the human heart thicker and more muscular than that of the right ventricle?","o":["It pumps blood only to the lungs","It must pump blood at higher pressure to the whole body","It receives deoxygenated blood","It holds a much larger volume of blood"],"c":1,"e":"The left ventricle pumps oxygenated blood through the aorta to the whole body, requiring higher pressure, so its wall is thicker than the right ventricle, which pumps only to the lungs."},
  {"i":"bio-b3-0462","g":11,"u":"Characteristics of Animals","d":"medium","t":"definition","q":"Animals are grouped into vertebrates and invertebrates. Which feature best defines a vertebrate?","o":["Presence of an exoskeleton","Presence of a backbone (vertebral column)","Having jointed legs","Reproducing by spores"],"c":1,"e":"Vertebrates are animals possessing a backbone or vertebral column of bone or cartilage; invertebrates lack this structure."},
  {"i":"bio-b3-0463","g":11,"u":"Characteristics of Animals","d":"medium","t":"conceptual","q":"A newly observed animal is ectothermic, has moist skin used in gas exchange, and lays eggs in water that hatch into larvae with gills. To which vertebrate class does it most likely belong?","o":["Reptilia","Amphibia","Mammalia","Aves"],"c":1,"e":"Moist skin used for gas exchange, water-laid eggs and gilled larvae (tadpoles) are hallmark features of amphibians."},
  {"i":"bio-b3-0464","g":11,"u":"Biology & Technology","d":"medium","t":"application","q":"In a biotechnology lab, a desired human gene is inserted into a bacterial plasmid so the bacteria produce a human protein. Which enzymes are used to cut the DNA and to join the gene into the plasmid, respectively?","o":["DNA polymerase and helicase","Restriction enzyme and DNA ligase","Ligase and restriction enzyme","Amylase and protease"],"c":1,"e":"Restriction enzymes cut DNA at specific sites, and DNA ligase joins the gene into the plasmid, forming recombinant DNA."},
  {"i":"bio-b3-0465","g":11,"u":"Biology & Technology","d":"medium","t":"conceptual","q":"In the traditional Ethiopian production of injera, teff batter is left to ferment for a few days before baking. Which microorganisms and product are mainly responsible for the sour taste and rising of the batter?","o":["Viruses producing oxygen","Yeasts and bacteria producing carbon dioxide and acids","Protozoa producing lactic acid only","Algae producing starch"],"c":1,"e":"Fermentation of teff batter by yeasts and bacteria releases carbon dioxide (which causes rising) and organic acids that give injera its characteristic sour taste."},
  {"i":"bio-b3-0466","g":11,"u":"Population & Natural Resources","d":"medium","t":"application","q":"In a grassland food chain: grass → grasshopper → lizard → hawk, only about 10% of energy passes to each next level. If the grass stores 100,000 kJ, roughly how much energy is available to the hawk?","o":["10,000 kJ","1,000 kJ","100 kJ","10 kJ"],"c":2,"e":"Energy: grass 100,000 → grasshopper 10,000 → lizard 1,000 → hawk 100 kJ, losing ~90% at each transfer (10% rule)."},
  {"i":"bio-b3-0467","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"In a population of 10,000 Ethiopians at Hardy–Weinberg equilibrium for an autosomal recessive trait, 400 individuals express the recessive phenotype. What is the expected number of heterozygous carriers?","o":["3,200","4,200","1,600","2,400"],"c":0,"e":"q² = 400/10000 = 0.04, so q = 0.2 and p = 0.8. Heterozygotes = 2pq = 2(0.8)(0.2) = 0.32, i.e. 0.32 × 10,000 = 3,200."},
  {"i":"bio-b3-0468","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"A man with haemophilia (X-linked recessive) marries a carrier woman. What proportion of ALL their children (both sexes pooled) are expected to be affected?","o":["1/2","1/4","3/4","1/8"],"c":0,"e":"Cross XʰY × XᴴXʰ gives XᴴXʰ, XʰXʰ, XᴴY, XʰY. Two of four offspring (XʰXʰ daughter and XʰY son) are affected = 1/2."},
  {"i":"bio-b3-0469","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"In a dihybrid cross AaBb × AaBb where both genes assort independently, what fraction of the offspring are homozygous at BOTH loci (any combination)?","o":["1/4","1/16","1/8","9/16"],"c":0,"e":"At each locus the chance of being homozygous (AA or aa) is 1/2. For both loci independently: 1/2 × 1/2 = 1/4."},
  {"i":"bio-b3-0470","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"Two heterozygous black, short-haired guinea pigs (BbSs, both dominant) are crossed. What is the probability of an offspring that is black AND long-haired (recessive ss)?","o":["3/16","9/16","1/16","3/4"],"c":0,"e":"Black = 3/4, long hair (ss) = 1/4. Independent: 3/4 × 1/4 = 3/16."},
  {"i":"bio-b3-0471","g":11,"u":"Genetics","d":"hard","t":"application","q":"A woman with blood type AB marries a man with type O. Which statement about their children is correct?","o":["Children are either type A or type B; none can be O or AB","All children are type AB like the mother","Half the children are expected to be type O","Children can be any of the four ABO types"],"c":0,"e":"Mother IᴬIᴮ × father ii gives Iᴬi (type A) and Iᴮi (type B) only, each 1/2. No O or AB is possible."},
  {"i":"bio-b3-0472","g":11,"u":"Genetics","d":"hard","t":"conceptual","q":"In a test cross of an organism heterozygous for two linked genes, the offspring ratio deviates sharply from 1:1:1:1, with parental types far exceeding recombinants. The best explanation is that the two genes are:","o":["Close together on the same chromosome, so crossing over between them is rare","On different chromosomes and assort independently","Both lethal in the homozygous recessive state","Subject to incomplete dominance"],"c":0,"e":"Excess of parental combinations indicates linkage; the closer two loci are, the lower the recombination frequency, so recombinants are few."},
  {"i":"bio-b3-0473","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"In maize, the recombination frequency between gene P and gene Q is 12%. Out of 500 test-cross offspring, approximately how many are expected to be recombinant types?","o":["60","120","440","30"],"c":0,"e":"Recombinant fraction = 12% of 500 = 0.12 × 500 = 60 offspring."},
  {"i":"bio-b3-0474","g":11,"u":"Genetics","d":"hard","t":"application","q":"Sickle-cell trait persists at high frequency in some malaria-endemic Ethiopian lowlands. The heterozygote advantage example shows that natural selection here favours:","o":["The heterozygote, maintaining both alleles in the population","Elimination of the recessive allele within a few generations","Only the homozygous recessive individuals","The dominant allele becoming fixed at frequency 1"],"c":0,"e":"Balancing selection (overdominance): heterozygotes resist malaria better than either homozygote, so both alleles are retained in the population."},
  {"i":"bio-b3-0475","g":11,"u":"Enzymes","d":"hard","t":"conceptual","q":"Adding a competitive inhibitor to an enzyme-catalysed reaction changes the kinetics such that:","o":["The maximum rate (Vmax) is unchanged but more substrate is needed to reach it","Both Vmax and the affinity for substrate fall together","Vmax falls but the apparent affinity is unchanged","The enzyme is permanently denatured"],"c":0,"e":"A competitive inhibitor competes for the active site; excess substrate outcompetes it, so Vmax is reached eventually (unchanged) but apparent Km rises."},
  {"i":"bio-b3-0476","g":11,"u":"Enzymes","d":"hard","t":"conceptual","q":"A digestive enzyme from the human stomach has optimum activity near pH 2, while one from the small intestine peaks near pH 8. The most accurate reason is that:","o":["Each enzyme's active-site shape and charge are stabilised at its native pH; far from it, bonds shift and activity drops","Stomach enzymes are made of fats and intestinal ones of protein","Low pH speeds all reactions while high pH slows them","Only temperature, not pH, affects enzyme shape"],"c":0,"e":"pH alters ionisation of active-site and substrate groups, changing 3-D conformation; pepsin is adapted to acidic, trypsin to alkaline conditions."},
  {"i":"bio-b3-0477","g":11,"u":"Enzymes","d":"hard","t":"application","q":"A student boils an amylase solution, cools it back to 37 °C, then adds starch. No breakdown occurs. The best explanation is that boiling:","o":["Denatured the enzyme by disrupting its tertiary structure irreversibly","Lowered the substrate concentration below threshold","Used up all the enzyme as a reactant","Changed the starch into a non-substrate"],"c":0,"e":"Enzymes are not consumed; high temperature breaks the weak bonds holding the active-site shape, denaturing amylase so it cannot bind starch even after cooling."},
  {"i":"bio-b3-0478","g":11,"u":"Enzymes","d":"hard","t":"conceptual","q":"Which statement best describes why a small amount of enzyme can convert a large amount of substrate over time?","o":["The enzyme is released unchanged after each catalytic cycle and reused","Each enzyme molecule binds one substrate permanently","The enzyme increases the energy released by the reaction","The enzyme raises the activation energy of the reaction"],"c":0,"e":"Enzymes lower activation energy and are regenerated after catalysis, so one molecule turns over many substrate molecules."},
  {"i":"bio-b3-0479","g":11,"u":"The Human Body Systems","d":"hard","t":"application","q":"A person at high altitude in the Ethiopian highlands (e.g. Bale Mountains) shows, over weeks, an increased red blood cell count. The most direct trigger for this acclimatisation is:","o":["Low oxygen partial pressure stimulating erythropoietin release from the kidneys","Higher carbon dioxide directly building new haemoglobin","Reduced air temperature thickening the blood","Increased dietary iron forcing extra cell production"],"c":0,"e":"Hypoxia at altitude stimulates kidney release of erythropoietin (EPO), which drives the bone marrow to produce more red blood cells, improving oxygen carriage."},
  {"i":"bio-b3-0480","g":11,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"During strenuous exercise when oxygen supply to muscle is limited, the muscle cells generate ATP and produce lactic acid. This pathway, compared with full aerobic respiration of one glucose, yields:","o":["Far less ATP (about 2 vs about 36–38) but continues without oxygen","More ATP but requires oxygen","The same ATP yield with carbon dioxide as the only product","No ATP at all until oxygen returns"],"c":0,"e":"Anaerobic glycolysis to lactate yields only ~2 ATP per glucose, versus ~36–38 from complete aerobic oxidation, but it proceeds without oxygen."},
  {"i":"bio-b3-0481","g":11,"u":"The Human Body Systems","d":"hard","t":"application","q":"In a healthy nephron, glucose appears in the filtrate but not in the urine. Glucose in the urine of a diabetic patient indicates that:","o":["Blood glucose exceeds the renal threshold, saturating the tubular reabsorption carriers","The glomerulus has stopped filtering glucose","The kidney is actively secreting glucose into urine","Glucose has been converted to protein in the tubule"],"c":0,"e":"Normally all filtered glucose is reabsorbed; when blood glucose is very high the carrier proteins saturate, so excess glucose spills into the urine (glycosuria)."},
  {"i":"bio-b3-0482","g":11,"u":"Characteristics of Animals","d":"hard","t":"conceptual","q":"An animal is bilaterally symmetrical, triploblastic, segmented, and has a true coelom and closed circulation. It most likely belongs to the phylum:","o":["Annelida","Cnidaria","Platyhelminthes","Nematoda"],"c":0,"e":"Segmentation plus a true coelom and closed circulation are hallmarks of Annelida (e.g. earthworm); cnidarians are diploblastic, flatworms acoelomate, roundworms pseudocoelomate."},
  {"i":"bio-b3-0483","g":11,"u":"Characteristics of Animals","d":"hard","t":"conceptual","q":"Which combination of features correctly distinguishes mammals from the other vertebrate classes?","o":["Hair/fur, mammary glands, and a diaphragm for breathing","Feathers, a four-chambered heart, and lungs","Scales, external fertilisation, and gills","Moist skin, a three-chambered heart, and metamorphosis"],"c":0,"e":"Hair, milk-producing mammary glands, and a muscular diaphragm are defining mammalian traits; feathers belong to birds, the rest describe fish or amphibians."},
  {"i":"bio-b3-0484","g":11,"u":"Biology & Technology","d":"hard","t":"application","q":"In recombinant DNA technology, a specific restriction enzyme and DNA ligase are used together so that a human gene can be inserted into a bacterial plasmid because the enzyme:","o":["Cuts both the gene and the plasmid at the same sequence, leaving matching sticky ends that ligase joins","Copies the human gene many times before insertion","Translates the gene into protein inside the bacterium","Removes all introns from the bacterial DNA"],"c":0,"e":"A restriction enzyme cuts at its specific recognition site producing complementary sticky ends on gene and plasmid; DNA ligase then seals the matching ends, forming recombinant DNA."},
  {"i":"bio-b3-0485","g":11,"u":"Biology & Technology","d":"hard","t":"calculation","q":"The polymerase chain reaction (PCR) amplifies a DNA segment through repeated cycles. If a sample starts with 1 target molecule, after 4 ideal cycles the number of copies is:","o":["16","8","4","32"],"c":0,"e":"Each cycle doubles the DNA, so after n cycles copies = 2ⁿ. After 4 cycles: 2⁴ = 16."},
  {"i":"bio-b3-0486","g":11,"u":"Population & Natural Resources","d":"hard","t":"calculation","q":"A population of 2,000 grows at a constant 3% per year. Assuming exponential growth, the number ADDED during the first year is:","o":["60","600","2,060","200"],"c":0,"e":"Increase = r × N = 0.03 × 2,000 = 60 individuals added in the first year."},
  {"i":"bio-b3-0487","g":11,"u":"Population & Natural Resources","d":"hard","t":"application","q":"In a grassland food chain (grass → grasshopper → bird → hawk), only about 10% of energy passes to each next level. If the grass fixes 100,000 kJ, the energy available to the hawk (4th level) is approximately:","o":["100 kJ","1,000 kJ","10 kJ","10,000 kJ"],"c":0,"e":"Each transfer keeps ~10%: 100,000 → 10,000 (grasshopper) → 1,000 (bird) → 100 kJ (hawk)."},
  {"i":"bio-b3-0488","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"In a sample of teff plants, the recessive allele for a non-functional flowering gene is at frequency q = 0.3 in Hardy–Weinberg equilibrium. What proportion of the population is expected to be heterozygous carriers?","o":["0.09","0.21","0.42","0.49"],"c":2,"e":"With q = 0.3, p = 0.7. Heterozygotes = 2pq = 2(0.7)(0.3) = 0.42."},
  {"i":"bio-b3-0489","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"A man with haemophilia (X-linked recessive) marries a woman who is a carrier. Considering only their sons, what fraction of the SONS are expected to be affected?","o":["1/4","1/2","3/4","1"],"c":1,"e":"Mother XᴴXʰ gives ½ Xᴴ and ½ Xʰ to sons; sons get Y from father. So ½ of sons are XʰY (affected). Among sons only the answer is 1/2."},
  {"i":"bio-b3-0490","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"In a dihybrid cross AaBb × AaBb with independent assortment, what fraction of offspring are homozygous at BOTH loci (any combination of homozygous genotypes)?","o":["1/16","1/8","1/4","9/16"],"c":2,"e":"Each locus is homozygous (AA or aa) with probability 1/2. Both loci homozygous = 1/2 × 1/2 = 1/4."},
  {"i":"bio-b3-0491","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"Two organisms heterozygous for a single incompletely dominant trait are crossed (RR = red, RW = pink, WW = white). A pink × pink cross is made. What fraction of the offspring will NOT be pink?","o":["1/4","1/2","3/4","1"],"c":1,"e":"RW × RW gives 1 RR : 2 RW : 1 WW. Non-pink (RR + WW) = 1/4 + 1/4 = 1/2."},
  {"i":"bio-b3-0492","g":11,"u":"Genetics","d":"hard","t":"application","q":"A coat-colour gene shows codominance: allele Cᴮ (black) and Cᵂ (white) give roan when together. A roan bull is crossed with a white cow. What phenotypic ratio is expected among the calves?","o":["All roan","1 black : 1 white","1 roan : 1 white","3 roan : 1 white"],"c":2,"e":"CᴮCᵂ × CᵂCᵂ gives ½ CᴮCᵂ (roan) and ½ CᵂCᵂ (white): a 1 roan : 1 white ratio."},
  {"i":"bio-b3-0493","g":11,"u":"Enzymes","d":"hard","t":"calculation","q":"An enzyme-catalysed reaction has Vmax = 80 µmol/min and Km = 4 mmol/L. According to the Michaelis–Menten relationship, what is the reaction rate when substrate concentration equals 12 mmol/L?","o":["20 µmol/min","40 µmol/min","60 µmol/min","75 µmol/min"],"c":2,"e":"v = Vmax[S]/(Km+[S]) = 80×12/(4+12) = 960/16 = 60 µmol/min."},
  {"i":"bio-b3-0494","g":11,"u":"Enzymes","d":"hard","t":"conceptual","q":"A competitive inhibitor is added to an enzyme assay. Compared with the uninhibited reaction, how are the apparent kinetic constants changed?","o":["Km increases, Vmax unchanged","Km unchanged, Vmax decreases","Both Km and Vmax decrease","Km decreases, Vmax increases"],"c":0,"e":"A competitive inhibitor competes for the active site, raising the apparent Km (more substrate needed to reach half Vmax) but Vmax is unchanged because high substrate outcompetes the inhibitor."},
  {"i":"bio-b3-0495","g":11,"u":"Enzymes","d":"hard","t":"application","q":"The enzyme amylase from human saliva works best near pH 7 and 37 °C. A student runs starch digestion at 60 °C and finds almost no product. What is the most likely explanation?","o":["The substrate was used up instantly","Heat denatured the enzyme, distorting its active site","Higher temperature always lowers reaction rate","Amylase needs a pH above 9 at high temperature"],"c":1,"e":"Above its optimum, heat disrupts the bonds maintaining tertiary structure, denaturing amylase and destroying the active site shape, so almost no starch is broken down."},
  {"i":"bio-b3-0496","g":11,"u":"Enzymes","d":"hard","t":"conceptual","q":"In the induced-fit model of enzyme action, why is this model favoured over the older lock-and-key model?","o":["It assumes the active site is perfectly rigid","It explains how substrate binding reshapes the active site to strain bonds","It removes the need for a substrate altogether","It shows enzymes are consumed in the reaction"],"c":1,"e":"Induced fit proposes the active site changes shape on binding, moulding around the substrate and straining its bonds to lower activation energy — something a rigid lock-and-key cannot explain."},
  {"i":"bio-b3-0497","g":11,"u":"Characteristics of Animals","d":"hard","t":"conceptual","q":"A newly described aquatic animal has radial symmetry, two tissue layers (diploblastic), a single gastrovascular opening, and stinging cells. To which phylum does it most likely belong?","o":["Porifera","Cnidaria","Platyhelminthes","Annelida"],"c":1,"e":"Radial symmetry, diploblastic body, one gut opening and cnidocytes (stinging cells) are defining features of phylum Cnidaria."},
  {"i":"bio-b3-0498","g":11,"u":"Characteristics of Animals","d":"hard","t":"application","q":"An animal is bilaterally symmetrical, triploblastic, segmented, has a true coelom and a closed circulatory system, and breathes through moist skin. Which group fits best?","o":["Flatworms (Platyhelminthes)","Roundworms (Nematoda)","Segmented worms (Annelida)","Arthropoda"],"c":2,"e":"Segmentation, a true coelom, a closed circulatory system and cutaneous gas exchange (as in earthworms) are characteristic of phylum Annelida."},
  {"i":"bio-b3-0499","g":11,"u":"Characteristics of Animals","d":"hard","t":"conceptual","q":"Among chordates, which combination of features is present at SOME stage in ALL members of the phylum?","o":["Bony skeleton, lungs, four limbs","Notochord, dorsal hollow nerve cord, pharyngeal slits, post-anal tail","Exoskeleton, jointed legs, compound eyes","Scales, gills throughout life, fins"],"c":1,"e":"All chordates share, at least during development, a notochord, a dorsal hollow nerve cord, pharyngeal slits and a post-anal tail — bones, lungs and limbs are not universal."},
  {"i":"bio-b3-0500","g":11,"u":"The Human Body Systems","d":"hard","t":"application","q":"During strenuous exercise in a highland runner, muscle cells lacking sufficient oxygen continue to make ATP. Which process operates and what end product builds up?","o":["Aerobic respiration; carbon dioxide","Lactic acid fermentation; lactate","Alcoholic fermentation; ethanol","Photosynthesis; glucose"],"c":1,"e":"When oxygen is limited, human muscle cells use lactic acid fermentation, regenerating NAD⁺ from glycolysis and accumulating lactate, which contributes to muscle fatigue."},
  {"i":"bio-b3-0501","g":11,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"In the human nephron, glucose is fully present in the filtrate but absent from normal urine. Which process and location best explain this?","o":["Filtration at the collecting duct","Selective reabsorption at the proximal convoluted tubule","Secretion at the loop of Henle","Osmosis at the glomerulus"],"c":1,"e":"Glucose is freely filtered at the glomerulus but is actively reabsorbed back into the blood at the proximal convoluted tubule, so normal urine contains none."},
  {"i":"bio-b3-0502","g":11,"u":"The Human Body Systems","d":"hard","t":"application","q":"A person rapidly inhales and exhales (hyperventilates), lowering blood CO₂. How does this most directly affect blood pH and the body's compensatory response?","o":["pH falls; breathing rate increases","pH rises; breathing rate decreases","pH unchanged; heart rate rises only","pH rises; kidneys add more CO₂"],"c":1,"e":"Removing CO₂ lowers carbonic acid, so blood pH rises (becomes more alkaline). The respiratory centre responds by slowing breathing to let CO₂ build back up."},
  {"i":"bio-b3-0503","g":11,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"Blood leaving the left ventricle of the human heart enters which vessel, and how does its oxygen content compare with blood in the pulmonary artery?","o":["Pulmonary vein; less oxygenated","Aorta; more oxygenated","Vena cava; equally oxygenated","Aorta; less oxygenated"],"c":1,"e":"The left ventricle pumps oxygenated blood into the aorta. The pulmonary artery carries deoxygenated blood to the lungs, so aortic blood is more oxygenated."},
  {"i":"bio-b3-0504","g":11,"u":"The Human Body Systems","d":"hard","t":"application","q":"After a meal rich in injera, blood glucose rises. Which hormonal response restores normal levels, and through what main action?","o":["Glucagon; stimulates glycogen breakdown","Insulin; promotes glucose uptake and glycogen storage","Adrenaline; increases blood glucose further","Thyroxine; lowers metabolic rate"],"c":1,"e":"Rising blood glucose triggers insulin release from pancreatic β-cells, which promotes cellular glucose uptake and conversion of glucose to glycogen in the liver, lowering blood glucose."},
  {"i":"bio-b3-0505","g":11,"u":"Biology & Technology","d":"hard","t":"application","q":"In genetic engineering, a human insulin gene is to be inserted into a bacterial plasmid. Which pair of tools is essential to cut both DNA pieces compatibly and then join them?","o":["DNA polymerase and helicase","Restriction enzyme and DNA ligase","Amylase and lipase","Reverse transcriptase and protease"],"c":1,"e":"A restriction enzyme cuts both the plasmid and the gene at the same recognition site (producing matching sticky ends), and DNA ligase seals the inserted gene into the plasmid."},
  {"i":"bio-b3-0506","g":11,"u":"Biology & Technology","d":"hard","t":"conceptual","q":"In the polymerase chain reaction (PCR), what is the purpose of the high-temperature (about 95 °C) denaturation step?","o":["To activate the primers","To separate the two DNA strands by breaking hydrogen bonds","To allow DNA polymerase to extend strands","To join Okazaki fragments"],"c":1,"e":"At about 95 °C the hydrogen bonds between complementary bases break, separating the double helix into single strands so primers can bind in the next step."},
  {"i":"bio-b3-0507","g":11,"u":"Biology & Technology","d":"hard","t":"application","q":"A biotechnologist uses a heat-stable DNA polymerase in PCR rather than ordinary human DNA polymerase. Why is this enzyme choice essential?","o":["It works only below 20 °C","It survives the repeated near-boiling denaturation steps without denaturing","It removes the need for primers","It synthesises RNA instead of DNA"],"c":1,"e":"PCR cycles repeatedly to about 95 °C; a heat-stable polymerase (e.g. Taq) is not denatured by these temperatures, so fresh enzyme need not be added each cycle."},
  {"i":"bio-b3-0508","g":11,"u":"Population & Natural Resources","d":"hard","t":"calculation","q":"A grassland has a deer population of 200. The birth rate is 30 per year, deaths 10 per year, immigration 5 and emigration 15. What is the net annual change in population size?","o":["+10","+20","+30","−10"],"c":0,"e":"Change = (births + immigration) − (deaths + emigration) = (30+5) − (10+15) = 35 − 25 = +10 individuals per year."},
  {"i":"bio-b3-0509","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"In a Hardy–Weinberg population, 16% of individuals show a recessive trait. Assuming equilibrium, what fraction of the population are heterozygous carriers?","o":["0.16","0.36","0.48","0.24"],"c":2,"e":"q² = 0.16 so q = 0.4 and p = 0.6. Heterozygotes = 2pq = 2(0.6)(0.4) = 0.48."},
  {"i":"bio-b3-0510","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"A dihybrid cross AaBb × AaBb (independent assortment, complete dominance) is made. What fraction of offspring are homozygous recessive at BOTH loci?","o":["1/16","9/16","3/16","1/4"],"c":0,"e":"aabb requires aa (1/4) and bb (1/4); 1/4 × 1/4 = 1/16."},
  {"i":"bio-b3-0511","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"A colour-blind father and a carrier mother (X-linked recessive) have children. What proportion of their SONS are expected to be colour-blind?","o":["1/4","1/2","3/4","All"],"c":1,"e":"Sons get Y from father and either Xᴬ or Xᵃ from the carrier mother, so 1/2 of sons receive Xᵃ and are affected."},
  {"i":"bio-b3-0512","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"In maize, kernel colour shows incomplete dominance: RR = red, Rr = pink, rr = white. Crossing two pink plants, what fraction of the F1 are pink?","o":["1/4","1/2","3/4","All"],"c":1,"e":"Rr × Rr gives 1 RR : 2 Rr : 1 rr, so 2/4 = 1/2 are pink (Rr)."},
  {"i":"bio-b3-0513","g":11,"u":"Genetics","d":"hard","t":"application","q":"A man with blood group AB marries a woman with group O. Which blood groups are possible among their children?","o":["A and B only","AB and O only","A, B, AB and O","O only"],"c":0,"e":"Father is IᴬIᴮ, mother is ii. Children get Iᴬ or Iᴮ from father plus i from mother, giving group A or group B only."},
  {"i":"bio-b3-0514","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"Two genes are 20 map units apart on the same chromosome. From a testcross of a dihybrid, what percentage of offspring are recombinant?","o":["10%","20%","40%","80%"],"c":1,"e":"Map distance in centimorgans equals recombination frequency, so 20 m.u. = 20% recombinant offspring."},
  {"i":"bio-b3-0515","g":11,"u":"Genetics","d":"hard","t":"conceptual","q":"A pedigree shows an affected daughter with two unaffected parents, and the trait appears equally in both sexes. Which inheritance pattern best fits?","o":["X-linked recessive","Autosomal recessive","Y-linked","Autosomal dominant"],"c":1,"e":"Two unaffected parents producing an affected child indicates recessive; equal sex distribution rules out X-linkage, so autosomal recessive fits best."},
  {"i":"bio-b3-0516","g":11,"u":"Enzymes","d":"hard","t":"conceptual","q":"A competitive inhibitor is added to an enzyme reaction. Compared with the uninhibited reaction, how do Vmax and Km change?","o":["Vmax unchanged, Km increases","Vmax decreases, Km unchanged","Both decrease","Vmax increases, Km decreases"],"c":0,"e":"A competitive inhibitor can be outcompeted by excess substrate, so Vmax is unchanged, but more substrate is needed to reach half-Vmax, so Km increases."},
  {"i":"bio-b3-0517","g":11,"u":"Enzymes","d":"hard","t":"application","q":"An enzyme works best at 37 °C and pH 7. Raising the temperature to 60 °C sharply lowers activity mainly because","o":["substrate concentration falls","the enzyme is denatured, distorting the active site","pH rises automatically","activation energy increases"],"c":1,"e":"High temperature breaks the bonds maintaining tertiary structure, denaturing the enzyme and distorting its active site so substrate no longer binds."},
  {"i":"bio-b3-0518","g":11,"u":"Enzymes","d":"hard","t":"conceptual","q":"In the induced-fit model, how does the active site behave when substrate approaches?","o":["It stays perfectly rigid","It changes shape to mould around the substrate","It permanently breaks apart","It binds any molecule equally"],"c":1,"e":"The induced-fit model proposes the active site is flexible and changes shape slightly to fit closely around the specific substrate."},
  {"i":"bio-b3-0519","g":11,"u":"Enzymes","d":"hard","t":"application","q":"A non-competitive inhibitor binds an enzyme's allosteric site. Increasing substrate concentration will","o":["fully restore the original Vmax","not restore the original Vmax","increase Km only","convert it to a competitive inhibitor"],"c":1,"e":"A non-competitive inhibitor binds away from the active site and is not displaced by substrate, so adding more substrate cannot restore the original Vmax."},
  {"i":"bio-b3-0520","g":11,"u":"The Human Body Systems","d":"hard","t":"application","q":"At a systemic capillary, oxygen leaves blood and enters tissue. The main driving force for this movement is","o":["active transport using ATP","the partial-pressure (concentration) gradient of oxygen","bulk flow of plasma proteins","osmosis of water"],"c":1,"e":"Oxygen diffuses passively from high partial pressure in blood to low partial pressure in respiring tissue, down its concentration gradient."},
  {"i":"bio-b3-0521","g":11,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"In the nephron, the glomerulus filters blood mainly by which process?","o":["Active secretion","Selective reabsorption","Pressure (ultra)filtration","Facilitated diffusion of glucose"],"c":2,"e":"High hydrostatic pressure in the glomerular capillaries forces water and small solutes through the filtration barrier, an ultrafiltration process."},
  {"i":"bio-b3-0522","g":11,"u":"The Human Body Systems","d":"hard","t":"application","q":"During strenuous exercise muscles respire anaerobically. The resulting build-up that contributes to fatigue is","o":["ethanol","lactic acid","carbon dioxide only","urea"],"c":1,"e":"In humans anaerobic respiration in muscle converts pyruvate to lactic acid, whose accumulation is associated with muscle fatigue."},
  {"i":"bio-b3-0523","g":11,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"After eating, blood glucose rises. The pancreatic hormone secreted to lower it promotes which response?","o":["Glycogen breakdown in the liver","Glucose uptake by cells and glycogen synthesis","Increased glucose release from the liver","Reduced glucose uptake by muscle"],"c":1,"e":"Insulin lowers blood glucose by stimulating cellular glucose uptake and conversion of glucose to glycogen in the liver and muscle."},
  {"i":"bio-b3-0524","g":11,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"At a chemical synapse, transmission across the synaptic cleft depends directly on","o":["direct electrical contact of membranes","release of neurotransmitter triggered by Ca²⁺ influx","myelin in the cleft","reverse flow of the action potential"],"c":1,"e":"Depolarization opens voltage-gated Ca²⁺ channels; Ca²⁺ influx triggers vesicles to release neurotransmitter, which diffuses across the cleft to the next neuron."},
  {"i":"bio-b3-0525","g":11,"u":"Characteristics of Animals","d":"hard","t":"conceptual","q":"An animal is bilaterally symmetrical, triploblastic, and has a true coelom and segmented body. Which group fits best?","o":["Cnidaria","Platyhelminthes","Annelida","Porifera"],"c":2,"e":"Annelids (e.g. earthworms) are bilaterally symmetrical, triploblastic, truly coelomate and conspicuously segmented; the others lack one or more of these features."},
  {"i":"bio-b3-0526","g":11,"u":"Characteristics of Animals","d":"hard","t":"conceptual","q":"Which combination of features is unique to mammals among vertebrates?","o":["Four-chambered heart and warm blood","Mammary glands and hair/fur","Internal fertilization and lungs","Closed circulation and a backbone"],"c":1,"e":"Mammary glands that produce milk plus body hair/fur are diagnostic of mammals; the other traits are shared with birds or other vertebrates."},
  {"i":"bio-b3-0527","g":11,"u":"Biology & Technology","d":"hard","t":"application","q":"To produce human insulin using bacteria, the human insulin gene is inserted into a bacterial plasmid. The enzyme used to seal the gene into the cut plasmid is","o":["DNA polymerase","restriction endonuclease","DNA ligase","helicase"],"c":2,"e":"Restriction enzymes cut the DNA, but DNA ligase joins the insulin gene into the plasmid by forming the phosphodiester bonds that seal it."},
  {"i":"bio-b3-0528","g":11,"u":"Biology & Technology","d":"hard","t":"conceptual","q":"In the polymerase chain reaction (PCR), the purpose of the denaturation step at about 95 °C is to","o":["join primers to the strands","extend new DNA strands","separate the two DNA strands","activate the ligase"],"c":2,"e":"Heating to roughly 95 °C breaks hydrogen bonds between the two strands, separating the double helix so primers can later anneal to single strands."},
  {"i":"bio-b3-0529","g":11,"u":"Population & Natural Resources","d":"hard","t":"calculation","q":"A grass population stores 10,000 kJ/m². If roughly 10% of energy passes to each higher trophic level, how much energy is available to a secondary consumer?","o":["1000 kJ/m²","100 kJ/m²","10 kJ/m²","900 kJ/m²"],"c":1,"e":"Primary consumer gets 10% of 10,000 = 1000 kJ/m²; secondary consumer gets 10% of 1000 = 100 kJ/m²."},
  {"i":"bio-b3-0530","g":11,"u":"Population & Natural Resources","d":"hard","t":"conceptual","q":"A population grows rapidly then levels off near the environment's carrying capacity. This pattern is best described as","o":["exponential (J-shaped) growth","logistic (S-shaped) growth","linear growth","negative growth"],"c":1,"e":"When growth slows as resources become limiting and the population stabilizes near carrying capacity, the curve is S-shaped (logistic) growth."},
  {"i":"bio-b3-0531","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"In an Ethiopian highland community, albinism (an autosomal recessive condition) occurs in about 1 in 10 000 newborns. Assuming Hardy–Weinberg equilibrium, what is the approximate frequency of unaffected carriers in this population?","o":["About 0.0001","About 0.0198","About 0.01","About 0.99"],"c":1,"e":"q² = 1/10000, so q = 0.01 and p = 0.99. Carrier frequency = 2pq = 2(0.99)(0.01) ≈ 0.0198, roughly 1 in 50."},
  {"i":"bio-b3-0532","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"A woman who is a carrier for haemophilia (X-linked recessive) marries a man with normal clotting. Considering ALL of their children together, what fraction is expected to be affected with haemophilia?","o":["1/2 of all children","1/4 of all children","All daughters","None"],"c":1,"e":"XᴴXʰ × XᴴY gives XᴴXᴴ, XᴴXʰ, XᴴY, XʰY. Only XʰY (one of four) is affected, so 1/4 of all children — all of them sons."},
  {"i":"bio-b3-0533","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"In a cross RrYy × rrYy (R/r and Y/y assort independently), what proportion of offspring are expected to show the R-dominant phenotype together with the Y-dominant phenotype?","o":["9/16","3/8","1/4","3/16"],"c":1,"e":"Rr × rr → 1/2 R_. Yy × Yy → 3/4 Y_. Combined = 1/2 × 3/4 = 3/8."},
  {"i":"bio-b3-0534","g":11,"u":"Genetics","d":"hard","t":"calculation","q":"A blood-type A father (genotype Iᴬi) and a blood-type B mother (genotype Iᴮi) have children. What is the probability that a given child has blood type O?","o":["0","1/4","1/2","3/4"],"c":1,"e":"Iᴬi × Iᴮi → IᴬIᴮ (AB), Iᴬi (A), Iᴮi (B), ii (O), each 1/4. Type O probability = 1/4."},
  {"i":"bio-b3-0535","g":11,"u":"Enzymes","d":"hard","t":"conceptual","q":"An enzyme is studied with and without a competitive inhibitor. Compared with the uninhibited reaction, the competitive inhibitor will most likely:","o":["Lower Vmax and leave Km unchanged","Raise the apparent Km and leave Vmax unchanged","Lower both Km and Vmax","Raise both Km and Vmax"],"c":1,"e":"A competitive inhibitor competes for the active site; adding more substrate overcomes it, so Vmax is unchanged but more substrate is needed to reach half-maximal velocity, raising the apparent Km."},
  {"i":"bio-b3-0536","g":11,"u":"Enzymes","d":"hard","t":"application","q":"A student measures an enzyme's activity and finds it nearly zero at 10 °C, peaks near 37 °C, then falls sharply to zero by 60 °C. The drop above 37 °C differs fundamentally from the low rate at 10 °C because:","o":["Both are caused by reversible loss of kinetic energy","At 60 °C the enzyme is denatured (shape permanently changed), while 10 °C only slows molecular collisions","At 10 °C the substrate is denatured, not the enzyme","Above 37 °C the pH rises and inactivates the enzyme"],"c":1,"e":"Low temperature reversibly reduces collision frequency, so warming restores activity; high temperature breaks the bonds holding tertiary structure, denaturing the active site permanently."},
  {"i":"bio-b3-0537","g":11,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"During strenuous exercise an athlete's muscles run short of oxygen and switch to anaerobic respiration. Compared with aerobic respiration of one glucose molecule, this anaerobic pathway in human muscle:","o":["Yields the same ATP but releases CO₂","Yields far less ATP (net 2) and produces lactic acid","Yields more ATP because glycolysis is faster","Produces ethanol and CO₂"],"c":1,"e":"Human muscle anaerobic respiration stops at glycolysis plus lactate formation, giving a net of only 2 ATP per glucose versus roughly 36–38 aerobically; it makes lactic acid, not ethanol."},
  {"i":"bio-b3-0538","g":11,"u":"The Human Body Systems","d":"hard","t":"application","q":"A person's blood plasma CO₂ rises sharply. The MOST direct homeostatic response coordinated by the medulla oblongata is to:","o":["Decrease breathing rate to retain CO₂","Increase breathing rate and depth to expel more CO₂","Increase urine production to remove CO₂","Constrict bronchioles to trap CO₂"],"c":1,"e":"Rising CO₂ lowers blood pH; chemoreceptors signal the medulla to raise the rate and depth of breathing, expelling CO₂ and restoring pH."},
  {"i":"bio-b3-0539","g":11,"u":"Characteristics of Animals","d":"hard","t":"conceptual","q":"When classifying animals, the presence of a true coelom (a body cavity fully lined by mesoderm) is significant mainly because it:","o":["Replaces the need for a circulatory system in all coelomates","Allows internal organs to be suspended, develop, and move independently of the body wall","Is found only in vertebrates","Prevents the formation of segmented bodies"],"c":1,"e":"A true coelom cushions and suspends organs, letting the gut and other organs grow and move independently of the body wall — a key feature distinguishing coelomates from acoelomate and pseudocoelomate animals."},
  {"i":"bio-b3-0540","g":11,"u":"Biology & Technology","d":"hard","t":"application","q":"A biotechnology lab wants to insert a human insulin gene into a bacterial plasmid so both can be joined. To ensure the gene and plasmid have matching 'sticky ends' for ligation, the technician should:","o":["Cut both the gene and the plasmid with the SAME restriction enzyme","Cut the gene and the plasmid with two different enzymes","Use DNA ligase to cut the DNA","Heat both DNAs to 95 °C to create the ends"],"c":0,"e":"A given restriction enzyme cuts a specific palindromic sequence, leaving complementary overhangs; using the same enzyme on both ensures their sticky ends are complementary so DNA ligase can join them."},
  {"i":"bio-b3-0541","g":11,"u":"Population & Natural Resources","d":"hard","t":"calculation","q":"A population of 5 000 follows logistic growth with carrying capacity K = 20 000 and intrinsic rate r = 0.1 per year. Using dN/dt = rN(1 − N/K), the instantaneous growth rate at this moment is approximately:","o":["375 individuals per year","500 individuals per year","1 000 individuals per year","50 individuals per year"],"c":0,"e":"dN/dt = 0.1 × 5000 × (1 − 5000/20000) = 0.1 × 5000 × 0.75 = 375 individuals per year."},
  {"i":"bio-b3-0542","g":11,"u":"Genetics","d":"impossible","t":"calculation","q":"In an Ethiopian highland cattle population at Hardy–Weinberg equilibrium, a recessive coat allele gives 16% of calves the recessive phenotype. Among the dominant-phenotype cattle only, what fraction are heterozygous carriers?","o":["1/2","4/9","2/3","8/14"],"c":3,"e":"q²=0.16 so q=0.4, p=0.6. Dominant phenotype = p²+2pq = 0.36+0.48 = 0.84; heterozygotes = 0.48. Fraction = 0.48/0.84 = 4/7 = 8/14."},
  {"i":"bio-b3-0543","g":11,"u":"Enzymes","d":"impossible","t":"conceptual","q":"A competitive inhibitor is added to an enzyme assay. Which statement about the apparent kinetic constants is correct for competitive inhibition?","o":["Vmax is reduced and Km is unchanged","Vmax is unchanged and apparent Km is increased","Both Vmax and Km fall","Km is unchanged and Vmax rises"],"c":1,"e":"A competitive inhibitor is outcompeted at saturating substrate, so Vmax is unchanged, while apparent Km rises because more substrate is needed to half-saturate."},
  {"i":"bio-b3-0544","g":11,"u":"Genetics","d":"impossible","t":"calculation","q":"A dihybrid teff cross AaBb × AaBb shows that the genotype aabb is lethal and dies before scoring. Among the surviving offspring, what is the ratio of plants showing both dominant traits to plants showing only the A-dominant trait?","o":["9 : 3","9 : 4","3 : 1","9 : 2"],"c":0,"e":"Standard 9:3:3:1; the lethal class is aabb (the 1), not affecting A_B_ (9) or A_bb (3). Surviving ratio of A_B_ to A_bb is 9:3."},
  {"i":"bio-b3-0545","g":11,"u":"The Human Body Systems","d":"impossible","t":"conceptual","q":"At high altitude on the Ethiopian plateau, sustained hyperventilation lowers arterial CO₂. By the bicarbonate buffer equilibrium, what is the effect on arterial blood pH and the renal compensation?","o":["pH rises; kidneys excrete more bicarbonate","pH falls; kidneys retain bicarbonate","pH rises; kidneys retain bicarbonate","pH falls; kidneys excrete more H⁺"],"c":0,"e":"Lower CO₂ shifts CO₂+H₂O⇌H⁺+HCO₃⁻ left, lowering H⁺ so pH rises (respiratory alkalosis); kidneys compensate by excreting bicarbonate."},
  {"i":"bio-b3-0546","g":11,"u":"Genetics","d":"impossible","t":"calculation","q":"In humans, red–green colour blindness is X-linked recessive. A carrier mother and an unaffected father have children. What proportion of ALL their children (both sexes pooled) are expected to be colour-blind?","o":["1/2","1/4","1/8","1/3"],"c":1,"e":"Sons: 1/2 affected; daughters: 0 affected (father normal). Pooling: 1/2 sons × 1/2 affected = 1/4 of all children."},
  {"i":"bio-b3-0547","g":11,"u":"Enzymes","d":"impossible","t":"application","q":"An enzyme has optimum activity at 40 °C. After brief exposure to 70 °C then cooling back to 40 °C it shows 30% of original activity. The best explanation consistent with enzyme biochemistry is:","o":["Denaturation is always fully reversible on cooling","A fraction of molecules refolded to the native state; the rest stayed denatured","The enzyme's optimum shifted permanently to 70 °C","Cofactor loss raised activity"],"c":1,"e":"Heat denaturation is often partly irreversible; some molecules refold to the native conformation on cooling while others aggregate or stay unfolded, giving partial recovered activity."},
  {"i":"bio-b3-0548","g":11,"u":"Characteristics of Animals","d":"impossible","t":"conceptual","q":"Across the major animal phyla, which sequence correctly orders these traits by first evolutionary appearance: true tissues, bilateral symmetry, a coelom?","o":["Coelom → bilateral symmetry → true tissues","True tissues → bilateral symmetry → coelom","Bilateral symmetry → true tissues → coelom","True tissues → coelom → bilateral symmetry"],"c":1,"e":"True tissues arose in cnidarians/eumetazoans first, bilateral symmetry in bilaterians next, and a true coelom appeared later in coelomate animals."},
  {"i":"bio-b3-0549","g":11,"u":"Genetics","d":"impossible","t":"calculation","q":"Two genes are 20 map units apart. A fully heterozygous individual in cis configuration (AB/ab) is test-crossed. What percentage of offspring are expected to be the recombinant genotype Ab/ab specifically?","o":["20%","10%","40%","5%"],"c":1,"e":"Recombinants total 20%, split equally between the two recombinant classes (Ab and aB), so Ab/ab = 10%."},
  {"i":"bio-b3-0550","g":11,"u":"Biology & Technology","d":"impossible","t":"application","q":"A PCR reaction starts with 5 target DNA molecules. Assuming ideal doubling each cycle, how many copies exist after 10 cycles?","o":["5120","1024","5125","2560"],"c":0,"e":"Copies = initial × 2ⁿ = 5 × 2¹⁰ = 5 × 1024 = 5120."},
  {"i":"bio-b3-0551","g":11,"u":"Population & Natural Resources","d":"impossible","t":"calculation","q":"A village population grows at a constant 3.5% per year. Using the rule of 70 as the standard approximation, the doubling time is closest to:","o":["35 years","20 years","14 years","7 years"],"c":1,"e":"Doubling time ≈ 70 / growth rate(%) = 70 / 3.5 = 20 years."},
  {"i":"bio-b3-0552","g":11,"u":"The Human Body Systems","d":"impossible","t":"conceptual","q":"During strenuous exercise, oxygen unloading to muscle is enhanced. Which combination of local changes shifts the oxygen–haemoglobin dissociation curve to the right?","o":["Lower CO₂, higher pH, lower temperature","Higher CO₂, lower pH, higher temperature","Lower CO₂, lower pH, higher temperature","Higher CO₂, higher pH, lower temperature"],"c":1,"e":"The Bohr effect: rising CO₂, falling pH, and rising temperature all shift the curve right, releasing more O₂ to active muscle."},
  {"i":"bio-b3-0553","g":11,"u":"Genetics","d":"impossible","t":"calculation","q":"In a tetrahybrid self-cross AaBbCcDd × AaBbCcDd with independent assortment and complete dominance, what fraction of offspring show all four recessive phenotypes?","o":["1/16","1/64","1/256","1/81"],"c":2,"e":"Each gene gives 1/4 recessive homozygous; independent so (1/4)⁴ = 1/256."},
  {"i":"bio-b3-0554","g":11,"u":"Enzymes","d":"impossible","t":"calculation","q":"An enzyme follows Michaelis–Menten kinetics with Km = 2 mmol/L and Vmax = 100 µmol/min. At a substrate concentration of 6 mmol/L, the reaction velocity is:","o":["50 µmol/min","75 µmol/min","60 µmol/min","25 µmol/min"],"c":1,"e":"v = Vmax[S]/(Km+[S]) = 100×6/(2+6) = 600/8 = 75 µmol/min."},
  {"i":"bio-b3-0555","g":11,"u":"The Human Body Systems","d":"impossible","t":"conceptual","q":"A person with type O blood is often called a universal red-cell donor. The immunological basis is that their erythrocytes:","o":["Carry both A and B antigens but no antibodies","Carry neither A nor B surface antigens","Carry the Rh antigen only","Lack all plasma antibodies"],"c":1,"e":"Type O red cells display neither A nor B antigens, so they are not agglutinated by anti-A or anti-B in a recipient's plasma."},
  {"i":"bio-b3-0556","g":11,"u":"Genetics","d":"impossible","t":"application","q":"A man with blood type AB marries a woman with type O. Considering ABO inheritance, which blood type is IMPOSSIBLE among their biological children?","o":["Type A","Type B","Type AB","Either A or B"],"c":2,"e":"AB (IᴬIᴮ) × O (ii) gives Iᴬi or Iᴮi = type A or B only; AB cannot occur."},
  {"i":"bio-b3-0557","g":11,"u":"Biology & Technology","d":"impossible","t":"conceptual","q":"In recombinant insulin production, a key reason bacterial expression of the human gene requires a cDNA (not genomic DNA) version is that bacteria:","o":["Cannot translate eukaryotic mRNA at all","Lack the spliceosome to remove introns","Use a different genetic code","Cannot replicate plasmids"],"c":1,"e":"Bacteria lack spliceosomes, so they cannot excise introns; cDNA made from mature mRNA is already intron-free and translatable."},
  {"i":"bio-b3-0558","g":11,"u":"Population & Natural Resources","d":"impossible","t":"calculation","q":"In a grassland food chain, primary producers fix 50,000 kJ/m². Applying the standard 10% ecological energy-transfer rule, the energy available to secondary consumers is:","o":["5,000 kJ/m²","500 kJ/m²","50 kJ/m²","2,500 kJ/m²"],"c":1,"e":"Producers→primary consumers: 50,000×0.1=5,000; primary→secondary: 5,000×0.1=500 kJ/m²."},
  {"i":"bio-b3-0559","g":11,"u":"Characteristics of Animals","d":"impossible","t":"conceptual","q":"Open and closed circulatory systems differ fundamentally. Which statement best captures an advantage of the closed system found in annelids and vertebrates?","o":["It uses less total fluid volume always","It allows higher pressure and faster, targeted delivery to tissues","It removes the need for any respiratory pigment","It eliminates the need for a heart"],"c":1,"e":"In a closed system blood stays in vessels, sustaining higher pressure and enabling faster, more precisely regulated distribution to specific tissues."},
  {"i":"bio-b3-0560","g":11,"u":"Genetics","d":"impossible","t":"calculation","q":"In epistasis, two genes control fruit colour: gene A is dominant epistatic (A_ masks B, giving white). A cross AaBb × AaBb yields what ratio of white : coloured (combined)?","o":["12 : 4","9 : 7","13 : 3","15 : 1"],"c":0,"e":"Dominant epistasis: A_ (9+3=12) all white; aaB_ and aabb (3+1=4) show colour. Ratio white:coloured = 12:4."},
  {"i":"bio-b3-0561","g":11,"u":"The Human Body Systems","d":"impossible","t":"application","q":"A nephron's glomerular filtration freely filters glucose, yet healthy urine contains none. The mechanism preventing glucose loss is:","o":["Glucose is too large to be filtered","Active reabsorption in the proximal tubule below the transport maximum","Secretion of glucose in the loop of Henle","Glucose precipitates in the collecting duct"],"c":1,"e":"Filtered glucose is fully reabsorbed by sodium-coupled active transport in the proximal tubule, as long as plasma glucose stays below the tubular transport maximum."},
  {"i":"bio-b3-0562","g":11,"u":"Biology & Technology","d":"impossible","t":"conceptual","q":"During the lytic versus lysogenic decision of a temperate bacteriophage, the lysogenic pathway is characterised by:","o":["Immediate host lysis and viral burst","Integration of viral DNA as a prophage replicated with the host genome","Synthesis of new virions without DNA replication","Destruction of the host chromosome at once"],"c":1,"e":"In lysogeny the phage genome integrates as a prophage and is copied passively with the host chromosome until induction triggers the lytic cycle."},
  {"i":"bio-b3-0563","g":11,"u":"Population & Natural Resources","d":"impossible","t":"conceptual","q":"A species introduced to Lake Tana shows an initial J-shaped exponential rise, then levels into an S-shaped curve. The flattening is best explained by:","o":["Carrying capacity reached as density-dependent factors intensify","Permanent removal of all predators","A sudden rise in the intrinsic growth rate","Disappearance of all competition"],"c":0,"e":"Logistic growth flattens as the population nears carrying capacity (K), where density-dependent factors like food limitation, competition and disease raise mortality."},
  {"i":"bio-b3-0564","g":11,"u":"Genetics","d":"impossible","t":"calculation","q":"In an Ethiopian highland community, oculocutaneous albinism (autosomal recessive) occurs in 1 in 10 000 newborns. Assuming Hardy–Weinberg equilibrium, what fraction of phenotypically normally pigmented individuals are heterozygous carriers?","o":["About 1 in 51","About 1 in 100","About 1 in 200","About 1 in 5 000"],"c":0,"e":"q² = 1/10000 so q = 0.01 and p = 0.99; carriers 2pq = 0.0198. Among unaffected people 2pq/(p²+2pq) = 0.0198/0.9999 ≈ 0.0198 ≈ 1/51."},
  {"i":"bio-b3-0565","g":11,"u":"Genetics","d":"impossible","t":"calculation","q":"A doubly heterozygous plant (AaBb), where the two genes are 20 map units apart on the same chromosome, is test-crossed to aabb. Of 1 000 offspring, how many are expected to show a recombinant (non-parental) combination of the two traits?","o":["200","100","250","500"],"c":0,"e":"Recombination frequency 20% means 20% of offspring are recombinant, split equally between the two recombinant classes; 0.20 × 1000 = 200 recombinants (100 + 100)."},
  {"i":"bio-b3-0566","g":11,"u":"The Human Body Systems","d":"impossible","t":"calculation","q":"A phenotypically normal woman whose father had haemophilia A (X-linked recessive) marries an unaffected man. Considering all of their children together (sons and daughters), what proportion is expected to be affected with haemophilia?","o":["1/4","1/2","1/8","0"],"c":0,"e":"The woman is an obligate carrier XᴴXʰ (her father gave her Xʰ); cross XᴴXʰ × XᴴY gives sons ½ affected, daughters 0 affected, so ¼ of all children are affected."},
  {"i":"bio-b3-0567","g":11,"u":"Enzymes","d":"impossible","t":"conceptual","q":"An enzyme is studied with and without a reversible competitive inhibitor at fixed total enzyme. Compared with the uninhibited reaction, the competitive inhibitor changes the kinetic constants in which way?","o":["Apparent Km increases while Vmax is unchanged","Vmax decreases while Km is unchanged","Both Km and Vmax decrease","Km decreases while Vmax increases"],"c":0,"e":"A competitive inhibitor competes for the active site, so more substrate is needed to reach half-maximal velocity (apparent Km rises), but at saturating substrate the inhibitor is outcompeted, leaving Vmax unchanged."},
  {"i":"bio-b3-0568","g":11,"u":"Biology & Technology","d":"impossible","t":"application","q":"In producing recombinant human insulin in bacteria, why is the insulin gene most often supplied as a cDNA copy synthesised from mRNA rather than as the genomic DNA sequence?","o":["Bacteria cannot splice out introns, so the intron-free cDNA yields the correct protein","Bacteria translate cDNA in the nucleus where splicing occurs","cDNA contains introns that bacteria need for expression","Genomic DNA cannot be cut by restriction enzymes"],"c":0,"e":"Prokaryotes lack the spliceosome machinery to remove introns; cDNA reverse-transcribed from mature mRNA is already intron-free, so the bacterium translates a correct insulin polypeptide."},
  {"i":"bio-b3-0569","g":11,"u":"The Human Body Systems","d":"impossible","t":"calculation","q":"A person oxidises glucose completely in aerobic respiration. If the volume of oxygen consumed equals the volume of carbon dioxide produced, what is the respiratory quotient (RQ), and what does it indicate about the substrate?","o":["RQ = 1.0, indicating carbohydrate is the respiratory substrate","RQ = 0.7, indicating fat is the substrate","RQ = 0.8, indicating protein is the substrate","RQ = 1.3, indicating anaerobic fermentation"],"c":0,"e":"For glucose, C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O, so CO₂ produced ÷ O₂ consumed = 6/6 = 1.0, the value characteristic of carbohydrate oxidation."},
  {"i":"bio-b3-0570","g":11,"u":"Population & Natural Resources","d":"impossible","t":"application","q":"A fish population in Lake Tana grows logistically with carrying capacity K. At what population size is the absolute growth rate (number of new individuals added per unit time) the greatest?","o":["At about K/2","Just below K","At very small population size near zero","Exactly at K"],"c":0,"e":"In the logistic model dN/dt = rN(1 − N/K), the rate is maximised when N = K/2, balancing a large reproducing population against still-abundant resources."},
  {"i":"bio-b3-0571","g":11,"u":"Genetics","d":"impossible","t":"calculation","q":"In a population at Hardy–Weinberg equilibrium for the ABO blood-group locus, the allele frequencies are Iᴬ = 0.3, Iᴮ = 0.1 and i = 0.6. What is the expected frequency of blood group A?","o":["0.45","0.09","0.36","0.30"],"c":0,"e":"Group A genotypes are IᴬIᴬ (p² = 0.09) and Iᴬi (2pr = 2 × 0.3 × 0.6 = 0.36); summing gives 0.09 + 0.36 = 0.45."},
  {"i":"bio-b3-0572","g":12,"u":"The Human Body Systems","d":"easy","t":"definition","q":"Which blood cells are mainly responsible for carrying oxygen from the lungs to body tissues?","o":["Red blood cells","White blood cells","Platelets","Plasma cells"],"c":0,"e":"Red blood cells (erythrocytes) contain haemoglobin, which binds oxygen and transports it to the tissues."},
  {"i":"bio-b3-0573","g":12,"u":"The Human Body Systems","d":"easy","t":"definition","q":"The functional unit of the kidney where blood is filtered to form urine is the:","o":["Alveolus","Nephron","Neuron","Villus"],"c":1,"e":"The nephron is the structural and functional unit of the kidney, carrying out filtration, reabsorption and secretion."},
  {"i":"bio-b3-0574","g":12,"u":"The Human Body Systems","d":"easy","t":"conceptual","q":"During inhalation in humans, the diaphragm:","o":["Relaxes and moves upward","Contracts and flattens downward","Stays completely still","Closes the trachea"],"c":1,"e":"On inhalation the diaphragm contracts and flattens, increasing thoracic volume and drawing air into the lungs."},
  {"i":"bio-b3-0575","g":12,"u":"The Human Body Systems","d":"easy","t":"definition","q":"The gap across which a nerve impulse is transmitted between two neurons is called the:","o":["Synapse","Axon","Dendrite","Node of Ranvier"],"c":0,"e":"A synapse is the junction between two neurons where neurotransmitters carry the signal across the gap."},
  {"i":"bio-b3-0576","g":12,"u":"The Human Body Systems","d":"easy","t":"definition","q":"Which chamber of the human heart pumps oxygenated blood into the aorta?","o":["Right atrium","Right ventricle","Left ventricle","Left atrium"],"c":2,"e":"The left ventricle has the thickest muscular wall and pumps oxygenated blood into the aorta to the whole body."},
  {"i":"bio-b3-0577","g":12,"u":"The Human Body Systems","d":"easy","t":"calculation","q":"In humans, a normal somatic (body) cell contains how many chromosomes?","o":["23","46","44","48"],"c":1,"e":"Human somatic cells are diploid with 46 chromosomes (23 pairs); gametes are haploid with 23."},
  {"i":"bio-b3-0578","g":12,"u":"The Human Body Systems","d":"easy","t":"calculation","q":"A man heterozygous for free earlobes (Ff) crosses with a woman with attached earlobes (ff). Free (F) is dominant. What fraction of children are expected to have attached earlobes?","o":["0","1/4","1/2","3/4"],"c":2,"e":"Ff × ff gives 1 Ff : 1 ff, so 1/2 are ff (attached earlobes)."},
  {"i":"bio-b3-0579","g":12,"u":"Microorganisms","d":"easy","t":"definition","q":"Bacteria are best classified as which type of cell?","o":["Eukaryotic","Prokaryotic","Viral","Fungal"],"c":1,"e":"Bacteria are prokaryotes: they lack a membrane-bound nucleus and membrane-bound organelles."},
  {"i":"bio-b3-0580","g":12,"u":"Microorganisms","d":"easy","t":"conceptual","q":"Which statement about viruses is correct?","o":["They are made of cells","They can reproduce only inside a host cell","They have their own ribosomes","They are larger than bacteria"],"c":1,"e":"Viruses are acellular and obligate intracellular parasites; they can replicate only by using a host cell's machinery."},
  {"i":"bio-b3-0581","g":12,"u":"Microorganisms","d":"easy","t":"definition","q":"In the production of injera dough and bread, the microorganism that ferments sugars to produce carbon dioxide is a:","o":["Yeast","Virus","Protozoan","Blue-green alga"],"c":0,"e":"Yeast (a fungus) ferments sugars, releasing CO₂ that makes injera batter and bread dough rise."},
  {"i":"bio-b3-0582","g":12,"u":"Microorganisms","d":"easy","t":"definition","q":"Penicillin, an antibiotic, is naturally produced mainly by which group of microorganisms?","o":["Bacteria","Fungi","Viruses","Algae"],"c":1,"e":"Penicillin is produced by the fungus Penicillium; antibiotics inhibit or kill bacteria."},
  {"i":"bio-b3-0583","g":12,"u":"Microorganisms","d":"easy","t":"conceptual","q":"Why is refrigerating food an effective way to slow spoilage by microorganisms?","o":["It kills all bacteria instantly","Low temperature slows microbial growth and enzyme activity","It removes all water from food","It adds preservatives to the food"],"c":1,"e":"Cold temperatures slow microbial metabolism and reproduction, delaying spoilage without necessarily killing the microbes."},
  {"i":"bio-b3-0584","g":12,"u":"Energy Transformation","d":"easy","t":"definition","q":"In which organelle does photosynthesis take place in plant cells?","o":["Mitochondrion","Chloroplast","Nucleus","Ribosome"],"c":1,"e":"Photosynthesis occurs in chloroplasts, which contain chlorophyll that absorbs light energy."},
  {"i":"bio-b3-0585","g":12,"u":"Energy Transformation","d":"easy","t":"conceptual","q":"Which gas is released as a by-product of the light reactions of photosynthesis?","o":["Carbon dioxide","Nitrogen","Oxygen","Methane"],"c":2,"e":"In the light reactions, water is split (photolysis), releasing oxygen as a by-product."},
  {"i":"bio-b3-0586","g":12,"u":"Energy Transformation","d":"easy","t":"definition","q":"The energy-carrying molecule produced during cellular respiration that cells use directly is:","o":["ATP","DNA","Glucose","Chlorophyll"],"c":0,"e":"ATP (adenosine triphosphate) is the immediate energy currency that cells use to power their activities."},
  {"i":"bio-b3-0587","g":12,"u":"Energy Transformation","d":"easy","t":"definition","q":"In aerobic respiration, glucose is completely broken down using which gas?","o":["Carbon dioxide","Oxygen","Hydrogen","Nitrogen"],"c":1,"e":"Aerobic respiration uses oxygen to fully oxidise glucose, yielding CO₂, water and a large amount of ATP."},
  {"i":"bio-b3-0588","g":12,"u":"Energy Transformation","d":"easy","t":"conceptual","q":"In a food chain, organisms that make their own food using sunlight are called:","o":["Producers","Primary consumers","Decomposers","Carnivores"],"c":0,"e":"Producers (autotrophs), such as green plants, convert light energy into chemical energy by photosynthesis, forming the base of the food chain."},
  {"i":"bio-b3-0589","g":12,"u":"Evolution","d":"easy","t":"definition","q":"According to Darwin, the main mechanism that drives evolutionary change is:","o":["Use and disuse of organs","Natural selection","Spontaneous generation","Inheritance of acquired blood"],"c":1,"e":"Darwin proposed natural selection: individuals with favourable heritable traits survive and reproduce more, so those traits spread."},
  {"i":"bio-b3-0590","g":12,"u":"Evolution","d":"easy","t":"definition","q":"Structures such as the human arm and a whale's flipper that share a common ancestral origin but differ in function are described as:","o":["Analogous structures","Homologous structures","Vestigial structures","Vector structures"],"c":1,"e":"Homologous structures have a common evolutionary origin (same basic plan) even when their functions differ, evidencing common ancestry."},
  {"i":"bio-b3-0591","g":12,"u":"Evolution","d":"easy","t":"calculation","q":"In a population at Hardy–Weinberg equilibrium, the frequency of the recessive allele (q) is 0.3. What is the frequency of the dominant allele (p)?","o":["0.3","0.49","0.7","0.09"],"c":2,"e":"Since p + q = 1, p = 1 − 0.3 = 0.7."},
  {"i":"bio-b3-0592","g":12,"u":"Applications of Biology","d":"easy","t":"application","q":"The biotechnology technique of making genetically identical copies of an organism is known as:","o":["Cloning","Fermentation","Vaccination","Pasteurization"],"c":0,"e":"Cloning produces organisms that are genetically identical to the original by copying its genetic material."},
  {"i":"bio-b3-0593","g":12,"u":"Climate Change","d":"easy","t":"conceptual","q":"Which gas is the main greenhouse gas released by burning fossil fuels and contributing to global warming?","o":["Oxygen","Carbon dioxide","Nitrogen","Argon"],"c":1,"e":"Carbon dioxide (CO₂) released by burning fossil fuels traps heat in the atmosphere, driving global warming and climate change."},
  {"i":"bio-b3-0594","g":12,"u":"The Human Body Systems","d":"easy","t":"definition","q":"In humans, the functional unit of the kidney that filters blood and forms urine is called the:","o":["Nephron","Alveolus","Neuron","Villus"],"c":0,"e":"The nephron is the microscopic filtering unit of the kidney; each kidney contains about one million of them."},
  {"i":"bio-b3-0595","g":12,"u":"The Human Body Systems","d":"easy","t":"conceptual","q":"Which blood vessel carries oxygenated blood from the lungs to the left atrium of the heart?","o":["Pulmonary vein","Pulmonary artery","Vena cava","Hepatic portal vein"],"c":0,"e":"The pulmonary vein is the exception that carries oxygen-rich blood; it returns blood from the lungs to the left atrium."},
  {"i":"bio-b3-0596","g":12,"u":"The Human Body Systems","d":"easy","t":"definition","q":"The hormone secreted by the beta cells of the pancreas that lowers blood glucose is:","o":["Insulin","Glucagon","Adrenaline","Thyroxine"],"c":0,"e":"Insulin from pancreatic beta cells promotes glucose uptake by cells, lowering blood glucose; glucagon raises it."},
  {"i":"bio-b3-0597","g":12,"u":"The Human Body Systems","d":"easy","t":"conceptual","q":"In the human gas-exchange system, oxygen and carbon dioxide are exchanged across the walls of the:","o":["Alveoli","Bronchi","Trachea","Pleura"],"c":0,"e":"The thin, moist alveolar walls provide a large surface area for gas exchange by diffusion with surrounding capillaries."},
  {"i":"bio-b3-0598","g":12,"u":"The Human Body Systems","d":"easy","t":"definition","q":"The liquid part of blood remaining after cells are removed, which transports dissolved nutrients and wastes, is called:","o":["Plasma","Serum clot","Lymph node","Platelets"],"c":0,"e":"Plasma is the straw-coloured fluid (about 55% of blood) that carries cells, nutrients, hormones and wastes."},
  {"i":"bio-b3-0599","g":12,"u":"Microorganisms","d":"easy","t":"definition","q":"Bacteria are best classified as which type of organism based on cell structure?","o":["Prokaryotic","Eukaryotic","Viral","Protozoan"],"c":0,"e":"Bacteria are prokaryotes: they lack a membrane-bound nucleus and membrane-bound organelles, with DNA free in the cytoplasm."},
  {"i":"bio-b3-0600","g":12,"u":"Microorganisms","d":"easy","t":"definition","q":"The group of microorganisms that lack cellular structure and can only reproduce inside a living host cell are the:","o":["Viruses","Fungi","Algae","Bacteria"],"c":0,"e":"Viruses are acellular obligate parasites; they have no cytoplasm or ribosomes and must hijack a host cell to replicate."},
  {"i":"bio-b3-0601","g":12,"u":"Microorganisms","d":"easy","t":"application","q":"In making traditional Ethiopian injera, the souring and rising of teff batter is mainly caused by the activity of:","o":["Microorganisms (yeasts and bacteria)","Mineral salts","Sunlight","Plant enzymes only"],"c":0,"e":"Fermenting microorganisms (yeasts and lactic acid bacteria) produce CO₂ and acids that leaven and sour the injera batter."},
  {"i":"bio-b3-0602","g":12,"u":"Microorganisms","d":"easy","t":"conceptual","q":"Which microorganism is a eukaryote with a cell wall made of chitin and is used in baking and brewing?","o":["Yeast","Cyanobacterium","Bacteriophage","Mycoplasma"],"c":0,"e":"Yeast is a single-celled fungus (eukaryote) with a chitin cell wall; it ferments sugars to ethanol and CO₂."},
  {"i":"bio-b3-0603","g":12,"u":"Applications of Biology","d":"easy","t":"definition","q":"The use of living organisms or their products to make useful goods, such as medicines and improved crops, is called:","o":["Biotechnology","Taxonomy","Histology","Ecology"],"c":0,"e":"Biotechnology applies biological systems and organisms (or their components) to develop products and processes useful to humans."},
  {"i":"bio-b3-0604","g":12,"u":"Applications of Biology","d":"easy","t":"definition","q":"The technique of cutting and joining DNA from different sources to create new gene combinations is known as:","o":["Recombinant DNA technology","Pasteurization","Distillation","Chromatography"],"c":0,"e":"Recombinant DNA (genetic engineering) uses restriction enzymes and ligase to splice DNA fragments from different organisms."},
  {"i":"bio-b3-0605","g":12,"u":"Applications of Biology","d":"easy","t":"application","q":"Producing many genetically identical plants from a few cells in sterile culture is an example of:","o":["Tissue culture","Crop rotation","Natural selection","Composting"],"c":0,"e":"Tissue (micropropagation) culture grows plant cells on nutrient media to produce many identical clones rapidly."},
  {"i":"bio-b3-0606","g":12,"u":"Energy Transformation","d":"easy","t":"definition","q":"In which organelle of a plant cell does photosynthesis occur?","o":["Chloroplast","Mitochondrion","Nucleus","Ribosome"],"c":0,"e":"Chloroplasts contain chlorophyll, which captures light energy to drive photosynthesis."},
  {"i":"bio-b3-0607","g":12,"u":"Energy Transformation","d":"easy","t":"conceptual","q":"The green pigment that absorbs light energy for photosynthesis is:","o":["Chlorophyll","Haemoglobin","Melanin","Carotene"],"c":0,"e":"Chlorophyll absorbs mainly red and blue light and reflects green, capturing the energy that powers photosynthesis."},
  {"i":"bio-b3-0608","g":12,"u":"Energy Transformation","d":"easy","t":"definition","q":"Aerobic respiration in cells releases energy that is stored in the short-term energy molecule:","o":["ATP","DNA","NaCl","Glucose"],"c":0,"e":"Respiration transfers energy from glucose to ATP (adenosine triphosphate), the cell's immediate energy currency."},
  {"i":"bio-b3-0609","g":12,"u":"Energy Transformation","d":"easy","t":"conceptual","q":"Which gas is released as a by-product when plants carry out photosynthesis?","o":["Oxygen","Nitrogen","Carbon dioxide","Methane"],"c":0,"e":"Photosynthesis uses CO₂ and water to make glucose, releasing oxygen from the splitting of water."},
  {"i":"bio-b3-0610","g":12,"u":"Evolution","d":"easy","t":"definition","q":"The process by which organisms better adapted to their environment tend to survive and reproduce more is called:","o":["Natural selection","Genetic drift only","Pollination","Diffusion"],"c":0,"e":"Natural selection, proposed by Darwin, is the differential survival and reproduction of individuals with favourable heritable traits."},
  {"i":"bio-b3-0611","g":12,"u":"Evolution","d":"easy","t":"definition","q":"Structures with a common evolutionary origin but different functions, such as a human arm and a bat wing, are described as:","o":["Homologous structures","Analogous structures","Vestigial organs","Fossils"],"c":0,"e":"Homologous structures share a common ancestral origin and basic plan, providing evidence for evolution by common descent."},
  {"i":"bio-b3-0612","g":12,"u":"Evolution","d":"easy","t":"calculation","q":"In a population at Hardy–Weinberg equilibrium, the frequency of the recessive allele (q) is 0.2. What is the frequency of the dominant allele (p)?","o":["0.8","0.2","0.4","0.04"],"c":0,"e":"Since p + q = 1, p = 1 − 0.2 = 0.8."},
  {"i":"bio-b3-0613","g":12,"u":"Evolution","d":"easy","t":"calculation","q":"A heterozygous tall pea plant (Tt) is self-crossed. What fraction of the offspring are expected to be short (tt)?","o":["1/4","1/2","3/4","1"],"c":0,"e":"Tt × Tt gives genotypes 1 TT : 2 Tt : 1 tt, so 1/4 of offspring are short (tt)."},
  {"i":"bio-b3-0614","g":12,"u":"Climate Change","d":"easy","t":"conceptual","q":"Which gas is the main greenhouse gas released by burning fossil fuels and contributes most to global warming?","o":["Carbon dioxide","Oxygen","Nitrogen","Argon"],"c":0,"e":"Carbon dioxide from burning fossil fuels traps heat in the atmosphere and is the major driver of human-caused global warming."},
  {"i":"bio-b3-0615","g":12,"u":"The Human Body Systems","d":"easy","t":"definition","q":"In a human cell, which organelle is the primary site of ATP production through aerobic respiration?","o":["Mitochondrion","Ribosome","Lysosome","Golgi apparatus"],"c":0,"e":"The mitochondrion carries out the Krebs cycle and oxidative phosphorylation, generating most of the cell's ATP."},
  {"i":"bio-b3-0616","g":12,"u":"The Human Body Systems","d":"easy","t":"definition","q":"Which part of the human nephron is the main site of ultrafiltration of blood?","o":["Glomerulus","Loop of Henle","Collecting duct","Distal tubule"],"c":0,"e":"The glomerulus is a capillary tuft where high pressure forces water and small solutes into Bowman's capsule, forming the filtrate."},
  {"i":"bio-b3-0617","g":12,"u":"The Human Body Systems","d":"easy","t":"definition","q":"Which blood cells are chiefly responsible for transporting oxygen in humans?","o":["Erythrocytes","Lymphocytes","Platelets","Neutrophils"],"c":0,"e":"Erythrocytes (red blood cells) contain haemoglobin, which binds oxygen for transport from the lungs to tissues."},
  {"i":"bio-b3-0618","g":12,"u":"The Human Body Systems","d":"easy","t":"definition","q":"The exchange of gases between alveoli and blood occurs mainly by which process?","o":["Diffusion","Active transport","Osmosis","Phagocytosis"],"c":0,"e":"Oxygen and carbon dioxide move down their concentration gradients across the thin alveolar wall by simple diffusion."},
  {"i":"bio-b3-0619","g":12,"u":"The Human Body Systems","d":"easy","t":"definition","q":"Which hormone, secreted by the pancreas, lowers blood glucose concentration?","o":["Insulin","Glucagon","Adrenaline","Thyroxine"],"c":0,"e":"Insulin from the beta cells of the islets of Langerhans promotes glucose uptake by cells, lowering blood glucose."},
  {"i":"bio-b3-0620","g":12,"u":"Energy Transformation","d":"easy","t":"definition","q":"In which structure of the chloroplast do the light-dependent reactions of photosynthesis occur?","o":["Thylakoid membrane","Stroma","Outer membrane","Intermembrane space"],"c":0,"e":"The light-dependent reactions occur on the thylakoid membranes, where chlorophyll and the electron transport chain are located."},
  {"i":"bio-b3-0621","g":12,"u":"Energy Transformation","d":"easy","t":"conceptual","q":"Which gas is released as a by-product of the light-dependent stage of photosynthesis?","o":["Oxygen","Carbon dioxide","Nitrogen","Hydrogen"],"c":0,"e":"Photolysis of water during the light reactions splits water, releasing oxygen as a by-product."},
  {"i":"bio-b3-0622","g":12,"u":"Energy Transformation","d":"easy","t":"definition","q":"During aerobic respiration in humans, what is the final electron acceptor of the electron transport chain?","o":["Oxygen","Carbon dioxide","Water","NAD⁺"],"c":0,"e":"Oxygen accepts electrons at the end of the chain and combines with hydrogen ions to form water."},
  {"i":"bio-b3-0623","g":12,"u":"Energy Transformation","d":"easy","t":"conceptual","q":"In which part of a eukaryotic cell does glycolysis take place?","o":["Cytoplasm","Mitochondrial matrix","Nucleus","Inner mitochondrial membrane"],"c":0,"e":"Glycolysis, the splitting of glucose into two pyruvate molecules, occurs in the cytoplasm and does not require oxygen."},
  {"i":"bio-b3-0624","g":12,"u":"Energy Transformation","d":"easy","t":"definition","q":"The Calvin cycle (light-independent reactions) takes place in which region of the chloroplast?","o":["Stroma","Thylakoid lumen","Grana","Outer membrane"],"c":0,"e":"The Calvin cycle uses ATP and NADPH in the stroma to fix carbon dioxide into carbohydrate."},
  {"i":"bio-b3-0625","g":12,"u":"Microorganisms","d":"easy","t":"definition","q":"Which feature distinguishes prokaryotic cells such as bacteria from eukaryotic cells?","o":["Absence of a membrane-bound nucleus","Presence of ribosomes","Presence of a cell membrane","Presence of DNA"],"c":0,"e":"Prokaryotes lack a true membrane-bound nucleus; their genetic material lies free in the cytoplasm as a nucleoid."},
  {"i":"bio-b3-0626","g":12,"u":"Microorganisms","d":"easy","t":"definition","q":"Which group of microorganisms is responsible for fermenting injera batter (teff) to make it rise?","o":["Yeasts and bacteria","Viruses","Protozoa","Algae"],"c":0,"e":"Wild yeasts and lactic acid bacteria ferment the teff batter, producing carbon dioxide and the characteristic sour flavour."},
  {"i":"bio-b3-0627","g":12,"u":"Microorganisms","d":"easy","t":"conceptual","q":"A virus can reproduce only when it is inside which of the following?","o":["A living host cell","Sterile nutrient broth","Distilled water","Dry soil"],"c":0,"e":"Viruses are obligate intracellular parasites that hijack the machinery of a living host cell to replicate."},
  {"i":"bio-b3-0628","g":12,"u":"Microorganisms","d":"easy","t":"definition","q":"Which enzyme is commonly used in genetic engineering to cut DNA at specific recognition sequences?","o":["Restriction endonuclease","DNA polymerase","Amylase","Lipase"],"c":0,"e":"Restriction endonucleases recognise specific base sequences and cut the DNA, a key step in making recombinant DNA."},
  {"i":"bio-b3-0629","g":12,"u":"Applications of Biology","d":"easy","t":"definition","q":"The transfer of a gene from one organism into the DNA of another to produce a recombinant organism is called what?","o":["Genetic engineering","Natural selection","Binary fission","Pollination"],"c":0,"e":"Genetic engineering deliberately inserts a gene into another organism's genome to give it a new characteristic."},
  {"i":"bio-b3-0630","g":12,"u":"Applications of Biology","d":"easy","t":"application","q":"Which biotechnology process uses microorganisms to convert sugars into ethanol for biofuel?","o":["Fermentation","Distillation only","Photosynthesis","Transpiration"],"c":0,"e":"Fermentation by yeast converts sugars anaerobically into ethanol and carbon dioxide, the basis of bioethanol production."},
  {"i":"bio-b3-0631","g":12,"u":"Evolution","d":"easy","t":"calculation","q":"A tall pea plant (Tt) is crossed with a short pea plant (tt). Tall (T) is dominant. What fraction of offspring is expected to be short?","o":["1/2","1/4","3/4","0"],"c":0,"e":"The cross Tt × tt gives genotypes Tt, Tt, tt, tt — so 2 of 4, i.e. 1/2, are short (tt)."},
  {"i":"bio-b3-0632","g":12,"u":"Evolution","d":"easy","t":"calculation","q":"In a monohybrid cross between two heterozygous parents (Aa × Aa), what is the expected phenotypic ratio of dominant to recessive?","o":["3 : 1","1 : 1","9 : 3 : 3 : 1","1 : 2 : 1"],"c":0,"e":"Aa × Aa yields 1 AA : 2 Aa : 1 aa; the three dominant-showing offspring to one recessive give a 3 : 1 phenotypic ratio."},
  {"i":"bio-b3-0633","g":12,"u":"Evolution","d":"easy","t":"conceptual","q":"In humans, red-green colour blindness is an X-linked recessive trait. From which parent does an affected son most commonly inherit the allele?","o":["His mother","His father","Both parents equally","Neither parent"],"c":0,"e":"A son receives his single X chromosome from his mother, so the recessive allele for colour blindness comes from her."},
  {"i":"bio-b3-0634","g":12,"u":"Evolution","d":"easy","t":"definition","q":"The gradual change in the inherited characteristics of a population over many generations is best described as what?","o":["Evolution","Respiration","Digestion","Diffusion"],"c":0,"e":"Evolution is the change in heritable traits of populations across successive generations, driven by mechanisms such as natural selection."},
  {"i":"bio-b3-0635","g":12,"u":"Climate Change","d":"easy","t":"conceptual","q":"Which gas, released largely by burning fossil fuels, is the main greenhouse gas contributing to global warming?","o":["Carbon dioxide","Oxygen","Nitrogen","Helium"],"c":0,"e":"Carbon dioxide traps infrared heat in the atmosphere; rising levels from fossil-fuel combustion drive global warming."},
  {"i":"bio-b3-0636","g":12,"u":"The Human Body Systems","d":"easy","t":"definition","q":"Which blood cells are mainly responsible for transporting oxygen in the human body?","o":["Red blood cells","White blood cells","Platelets","Plasma cells"],"c":0,"e":"Red blood cells contain haemoglobin, which binds oxygen and carries it from the lungs to body tissues."},
  {"i":"bio-b3-0637","g":12,"u":"The Human Body Systems","d":"easy","t":"definition","q":"Which part of the human brain controls balance and coordination of movement?","o":["Cerebellum","Cerebrum","Medulla oblongata","Hypothalamus"],"c":0,"e":"The cerebellum coordinates voluntary movements, posture and balance."},
  {"i":"bio-b3-0638","g":12,"u":"The Human Body Systems","d":"easy","t":"conceptual","q":"In which organ does most chemical digestion and absorption of nutrients occur?","o":["Small intestine","Stomach","Large intestine","Oesophagus"],"c":0,"e":"The small intestine completes digestion and absorbs most nutrients through its villi."},
  {"i":"bio-b3-0639","g":12,"u":"The Human Body Systems","d":"easy","t":"definition","q":"The hormone that lowers blood glucose level by promoting its uptake into cells is:","o":["Insulin","Glucagon","Adrenaline","Thyroxine"],"c":0,"e":"Insulin, secreted by the pancreas, lowers blood glucose by stimulating cells to absorb and store it."},
  {"i":"bio-b3-0640","g":12,"u":"Applications of Biology","d":"easy","t":"definition","q":"The use of living organisms or their products to make useful goods is called:","o":["Biotechnology","Taxonomy","Ecology","Histology"],"c":0,"e":"Biotechnology applies living systems and organisms to develop or make products such as foods, medicines and enzymes."},
  {"i":"bio-b3-0641","g":12,"u":"Applications of Biology","d":"easy","t":"application","q":"Which enzyme is commonly used in the production of injera and other fermented foods to break down sugars?","o":["Zymase (from yeast)","Amylase only","Lipase only","Catalase"],"c":0,"e":"Yeast produces zymase, which ferments sugars into ethanol and carbon dioxide, helping dough rise."},
  {"i":"bio-b3-0642","g":12,"u":"Applications of Biology","d":"easy","t":"definition","q":"Insulin used to treat diabetes is now mainly produced by:","o":["Genetically engineered bacteria","Extracting it from plants","Crushing animal bones","Chemical synthesis from salt"],"c":0,"e":"The human insulin gene is inserted into bacteria, which then mass-produce insulin through recombinant DNA technology."},
  {"i":"bio-b3-0643","g":12,"u":"Microorganisms","d":"easy","t":"definition","q":"Which group of microorganisms lacks a true membrane-bound nucleus?","o":["Bacteria","Fungi","Protozoa","Algae"],"c":0,"e":"Bacteria are prokaryotes; their genetic material is not enclosed in a membrane-bound nucleus."},
  {"i":"bio-b3-0644","g":12,"u":"Microorganisms","d":"easy","t":"definition","q":"Viruses can only reproduce when they are:","o":["Inside a living host cell","In sterile water","Exposed to sunlight","On a dry surface"],"c":0,"e":"Viruses are obligate parasites; they need the machinery of a living host cell to replicate."},
  {"i":"bio-b3-0645","g":12,"u":"Microorganisms","d":"easy","t":"application","q":"The process by which microorganisms convert sugars into alcohol and carbon dioxide in the absence of oxygen is:","o":["Fermentation","Photosynthesis","Transpiration","Nitrification"],"c":0,"e":"Anaerobic fermentation by yeast converts glucose into ethanol and carbon dioxide, used in tella and beverages."},
  {"i":"bio-b3-0646","g":12,"u":"Microorganisms","d":"easy","t":"definition","q":"Which of the following diseases is caused by a bacterium?","o":["Tuberculosis","Influenza","Measles","HIV/AIDS"],"c":0,"e":"Tuberculosis is caused by the bacterium Mycobacterium tuberculosis; the others are viral diseases."},
  {"i":"bio-b3-0647","g":12,"u":"Energy Transformation","d":"easy","t":"conceptual","q":"In photosynthesis, the gas released as a by-product when water is split is:","o":["Oxygen","Carbon dioxide","Nitrogen","Hydrogen"],"c":0,"e":"During the light reactions, water is split (photolysis), releasing oxygen as a by-product."},
  {"i":"bio-b3-0648","g":12,"u":"Energy Transformation","d":"easy","t":"definition","q":"The cell organelle where aerobic respiration mainly produces ATP is the:","o":["Mitochondrion","Chloroplast","Ribosome","Golgi body"],"c":0,"e":"The mitochondrion is the site of the Krebs cycle and oxidative phosphorylation, generating most ATP."},
  {"i":"bio-b3-0649","g":12,"u":"Energy Transformation","d":"easy","t":"calculation","q":"A messenger RNA contains 300 nucleotides. How many amino acids can it code for, given that one codon is three nucleotides?","o":["100","300","150","900"],"c":0,"e":"Each codon = 3 nucleotides, so 300 ÷ 3 = 100 codons, coding for 100 amino acids."},
  {"i":"bio-b3-0650","g":12,"u":"Energy Transformation","d":"easy","t":"definition","q":"The green pigment in plants that absorbs light energy for photosynthesis is:","o":["Chlorophyll","Haemoglobin","Melanin","Carotene"],"c":0,"e":"Chlorophyll absorbs light (mainly red and blue) and drives the light reactions of photosynthesis."},
  {"i":"bio-b3-0651","g":12,"u":"Evolution","d":"easy","t":"calculation","q":"In a population in Hardy–Weinberg equilibrium, the frequency of the homozygous recessive genotype is 0.09. What is the frequency of heterozygous carriers (2pq)?","o":["0.42","0.21","0.49","0.09"],"c":0,"e":"q² = 0.09 → q = 0.3, p = 0.7; 2pq = 2(0.7)(0.3) = 0.42."},
  {"i":"bio-b3-0652","g":12,"u":"Evolution","d":"easy","t":"calculation","q":"Two heterozygous tall pea plants (Tt) are crossed. What fraction of the offspring is expected to be short (tt)?","o":["1/4","1/2","3/4","1/1"],"c":0,"e":"Tt × Tt gives 1 TT : 2 Tt : 1 tt, so 1/4 of offspring are short (tt)."},
  {"i":"bio-b3-0653","g":12,"u":"Evolution","d":"easy","t":"definition","q":"Structures with a common evolutionary origin but different functions, such as a bat's wing and a human arm, are described as:","o":["Homologous structures","Analogous structures","Vestigial structures","Embryonic structures"],"c":0,"e":"Homologous structures share a common ancestral origin even though their functions differ."},
  {"i":"bio-b3-0654","g":12,"u":"Evolution","d":"easy","t":"calculation","q":"In a cross between blood groups Iᴬi and Iᴮi, what fraction of children is expected to have blood group O?","o":["1/4","1/2","3/4","0"],"c":0,"e":"Iᴬi × Iᴮi gives IᴬIᴮ, Iᴬi, Iᴮi, ii in equal parts; only ii (1/4) is group O."},
  {"i":"bio-b3-0655","g":12,"u":"Evolution","d":"easy","t":"conceptual","q":"The main idea of Charles Darwin's theory of evolution is:","o":["Natural selection of favourable inherited traits","Inheritance of acquired characteristics","Spontaneous generation of life","Constant unchanging species"],"c":0,"e":"Darwin proposed that organisms with favourable heritable traits survive and reproduce more, driving evolution by natural selection."},
  {"i":"bio-b3-0656","g":12,"u":"Climate Change","d":"easy","t":"definition","q":"Which gas is the major greenhouse gas released by burning fossil fuels and contributing to global warming?","o":["Carbon dioxide","Oxygen","Nitrogen","Helium"],"c":0,"e":"Carbon dioxide from burning fossil fuels traps heat in the atmosphere, driving global warming."},
  {"i":"bio-b3-0657","g":12,"u":"The Human Body Systems","d":"easy","t":"calculation","q":"In a Hardy–Weinberg population, a recessive condition appears in 9% of people (q² = 0.09). What percentage of the population is expected to be heterozygous carriers?","o":["21%","42%","49%","30%"],"c":1,"e":"q = √0.09 = 0.3 and p = 0.7, so carriers 2pq = 2(0.7)(0.3) = 0.42 = 42%."},
  {"i":"bio-b3-0658","g":12,"u":"Microorganisms","d":"easy","t":"definition","q":"A microorganism that lacks a true membrane-bound nucleus and membrane-bound organelles is best described as:","o":["Eukaryotic","Prokaryotic","Multicellular","Photosynthetic"],"c":1,"e":"Prokaryotes such as bacteria have no nuclear membrane; their genetic material lies free in the cytoplasm as a nucleoid."},
  {"i":"bio-b3-0659","g":12,"u":"Energy Transformation","d":"easy","t":"calculation","q":"If producers in a food chain store 10,000 kJ of energy, about how much is available to secondary consumers, assuming roughly 10% transfer at each trophic level?","o":["1,000 kJ","100 kJ","10 kJ","500 kJ"],"c":1,"e":"10,000 kJ × 10% = 1,000 kJ to primary consumers, then × 10% = 100 kJ to secondary consumers."},
  {"i":"bio-b3-0660","g":12,"u":"Evolution","d":"easy","t":"conceptual","q":"Which process describes the differential survival and reproduction of individuals whose inherited traits best fit the environment?","o":["Genetic drift","Natural selection","Gene flow","Mutation"],"c":1,"e":"Natural selection is the non-random survival and reproduction of better-adapted variants, gradually changing allele frequencies over generations."},
  {"i":"bio-b3-0661","g":12,"u":"Applications of Biology","d":"easy","t":"application","q":"In genetic engineering, the enzyme used to cut DNA at specific recognition sequences is a:","o":["DNA ligase","DNA polymerase","Restriction enzyme","Helicase"],"c":2,"e":"Restriction enzymes (endonucleases) recognize specific base sequences and cut the DNA there; ligase later joins fragments."},
  {"i":"bio-b3-0662","g":12,"u":"Climate Change","d":"easy","t":"conceptual","q":"Which gas released mainly by burning fossil fuels is the principal driver of the enhanced greenhouse effect?","o":["Oxygen","Nitrogen","Carbon dioxide","Helium"],"c":2,"e":"Carbon dioxide (CO₂) from fossil-fuel combustion traps outgoing infrared radiation, intensifying the greenhouse effect and warming."},
  {"i":"bio-b3-0663","g":12,"u":"The Human Body Systems","d":"medium","t":"application","q":"A woman who is a carrier for the X-linked recessive allele causing haemophilia marries a man with normal clotting. Considering only their sons, what fraction is expected to have haemophilia?","o":["All of the sons","Half of the sons","One quarter of the sons","None of the sons"],"c":1,"e":"Cross XᴴXʰ × XᴴY; sons receive Y from father and either Xᴴ or Xʰ from mother, giving XᴴY and XʰY in equal numbers, so half the sons are affected."},
  {"i":"bio-b3-0664","g":12,"u":"The Human Body Systems","d":"medium","t":"calculation","q":"In a population at Hardy–Weinberg equilibrium, an autosomal recessive trait appears in 4% of people. What percentage of the population are heterozygous carriers?","o":["16%","20%","32%","40%"],"c":2,"e":"q² = 0.04 so q = 0.2 and p = 0.8; carrier frequency 2pq = 2(0.8)(0.2) = 0.32, i.e. 32%."},
  {"i":"bio-b3-0665","g":12,"u":"The Human Body Systems","d":"medium","t":"calculation","q":"A father with blood group A (genotype Iᴬi) and a mother with blood group B (genotype Iᴮi) have children. What is the probability that a child has blood group O?","o":["0","1/4","1/2","3/4"],"c":1,"e":"Iᴬi × Iᴮi gives IᴬIᴮ, Iᴬi, Iᴮi, ii in a 1:1:1:1 ratio; only ii (group O) occurs, so the probability is 1/4."},
  {"i":"bio-b3-0666","g":12,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"During strenuous exercise in a highland Ethiopian runner, skeletal muscle lacking sufficient oxygen regenerates NAD⁺ mainly by which process, allowing glycolysis to continue?","o":["Conversion of pyruvate to lactate","Complete oxidation of pyruvate in the Krebs cycle","Reduction of oxygen at the electron transport chain","Conversion of glucose to glycogen"],"c":0,"e":"Without enough O₂, lactate fermentation reduces pyruvate to lactate, oxidising NADH back to NAD⁺ so glycolysis (and ATP supply) can continue."},
  {"i":"bio-b3-0667","g":12,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"A person's blood pH begins to fall slightly. Which immediate respiratory response best helps restore it toward normal?","o":["Increased breathing rate to expel more CO₂","Decreased breathing rate to retain more CO₂","Increased reabsorption of bicarbonate by the lungs","Reduced oxygen uptake at the alveoli"],"c":0,"e":"More CO₂ shifts the carbonic acid equilibrium to produce H⁺; breathing faster expels CO₂, lowering H⁺ and raising pH back toward normal."},
  {"i":"bio-b3-0668","g":12,"u":"The Human Body Systems","d":"medium","t":"application","q":"A nephron's filtrate has a higher glucose concentration than usual because blood glucose is very high, and glucose still appears in the urine. The best explanation is that:","o":["The glomerulus has stopped filtering glucose","The carrier proteins for glucose reabsorption are saturated","Glucose is actively secreted into the filtrate","The loop of Henle destroys excess glucose"],"c":1,"e":"Glucose is normally fully reabsorbed by active transport, but the carriers have a transport maximum; once saturated, excess glucose remains in the filtrate and is excreted."},
  {"i":"bio-b3-0669","g":12,"u":"Microorganisms","d":"medium","t":"calculation","q":"A single bacterium divides by binary fission every 30 minutes under ideal conditions. Starting from one cell, how many cells are present after 3 hours?","o":["32","64","128","256"],"c":1,"e":"Three hours is 6 generations of 30 minutes; cells = 2⁶ = 64."},
  {"i":"bio-b3-0670","g":12,"u":"Microorganisms","d":"medium","t":"definition","q":"Which statement best describes why viruses are generally NOT classified as living cells?","o":["They contain no genetic material","They lack cellular structure and cannot reproduce without a host cell","They are always larger than bacteria","They are unable to mutate or evolve"],"c":1,"e":"Viruses are acellular and obligate intracellular parasites; they have nucleic acid and a protein coat but must use a host cell's machinery to replicate."},
  {"i":"bio-b3-0671","g":12,"u":"Microorganisms","d":"medium","t":"application","q":"In producing traditional Ethiopian injera, the teff batter is left to ferment. Which microbial activity is mainly responsible for the sour taste and the bubbles in the batter?","o":["Aerobic respiration releasing only water","Fermentation producing organic acids and CO₂","Nitrogen fixation by root bacteria","Photosynthesis by algae in the batter"],"c":1,"e":"Yeasts and lactic acid bacteria ferment the batter, producing organic (lactic) acids that give sourness and CO₂ gas that forms the bubbles."},
  {"i":"bio-b3-0672","g":12,"u":"Microorganisms","d":"medium","t":"conceptual","q":"A patient stops taking an antibiotic after only two days because they feel better. Why does this practice promote antibiotic-resistant bacteria?","o":["It causes bacteria to produce new antibiotics","Surviving less-susceptible bacteria are left to multiply","It makes the antibiotic permanently stronger","It converts viruses into bacteria"],"c":1,"e":"Stopping early leaves the more resistant bacteria alive; these survivors reproduce, so the population becomes enriched for resistance."},
  {"i":"bio-b3-0673","g":12,"u":"Microorganisms","d":"medium","t":"application","q":"In genetic engineering, a human insulin gene is inserted into a bacterial plasmid. Which enzyme is used to join the cut human DNA to the cut plasmid DNA?","o":["DNA ligase","Restriction endonuclease","DNA helicase","RNA polymerase"],"c":0,"e":"Restriction enzymes cut the DNA at specific sites, and DNA ligase seals the sugar–phosphate backbone, joining the insert to the plasmid."},
  {"i":"bio-b3-0674","g":12,"u":"Energy Transformation","d":"medium","t":"calculation","q":"Balance the overall photosynthesis equation: 6CO₂ + 6H₂O → C₆H₁₂O₆ + xO₂. What is the value of x?","o":["3","6","12","18"],"c":1,"e":"One glucose contains 6 carbons; balancing carbon and oxygen gives six O₂ molecules released, so x = 6."},
  {"i":"bio-b3-0675","g":12,"u":"Energy Transformation","d":"medium","t":"conceptual","q":"In aerobic respiration, the largest amount of ATP is produced at which stage?","o":["Glycolysis in the cytoplasm","The link reaction","The Krebs cycle","Oxidative phosphorylation at the electron transport chain"],"c":3,"e":"The electron transport chain uses NADH and FADH₂ to drive chemiosmosis, producing far more ATP than glycolysis or the Krebs cycle."},
  {"i":"bio-b3-0676","g":12,"u":"Energy Transformation","d":"medium","t":"conceptual","q":"In the light-dependent reactions of photosynthesis, the oxygen released originates from which molecule?","o":["Carbon dioxide","Water","Glucose","Chlorophyll"],"c":1,"e":"Photolysis splits water (H₂O) into hydrogen ions, electrons and oxygen; the released O₂ comes from water, not from CO₂."},
  {"i":"bio-b3-0677","g":12,"u":"Energy Transformation","d":"medium","t":"application","q":"An enzyme catalysing a reaction in the human body works fastest at about 37 °C. Raising the temperature to 60 °C sharply reduces the reaction rate. The best explanation is that:","o":["The substrate evaporates at 60 °C","The enzyme's active site is denatured by the high temperature","The enzyme is converted into substrate","Higher temperature always lowers all reaction rates"],"c":1,"e":"High temperature disrupts the bonds maintaining the enzyme's tertiary shape, denaturing the active site so it can no longer bind substrate effectively."},
  {"i":"bio-b3-0678","g":12,"u":"Evolution","d":"medium","t":"calculation","q":"Two pea plants heterozygous for seed colour (Yy, yellow dominant to green) are crossed. What fraction of the offspring is expected to show the green (recessive) phenotype?","o":["1/4","1/2","3/4","All"],"c":0,"e":"Yy × Yy gives 1 YY : 2 Yy : 1 yy; only yy (1/4) is green, since yellow is dominant."},
  {"i":"bio-b3-0679","g":12,"u":"Evolution","d":"medium","t":"calculation","q":"In a dihybrid testcross AaBb × aabb (genes unlinked), what proportion of offspring are expected to be recessive for both traits (aabb)?","o":["1/16","1/8","1/4","1/2"],"c":2,"e":"A testcross of AaBb × aabb gives a 1:1:1:1 ratio of the four phenotypes; aabb is one of four, i.e. 1/4."},
  {"i":"bio-b3-0680","g":12,"u":"Evolution","d":"medium","t":"conceptual","q":"On the Ethiopian highlands, dark-coloured rock lizards survive better than light ones on dark lava fields because predators spot them less easily, and over generations the dark form becomes common. This change is best explained by:","o":["Use and disuse of body parts","Natural selection acting on inherited variation","Inheritance of acquired characteristics","Random change unrelated to survival"],"c":1,"e":"Camouflage gives dark lizards higher survival and reproduction; their heritable alleles increase in frequency, which is natural selection."},
  {"i":"bio-b3-0681","g":12,"u":"Evolution","d":"medium","t":"definition","q":"Two species of finch evolve from one ancestral species after populations become separated by a mountain range and can no longer interbreed. This is an example of:","o":["Convergent evolution","Allopatric speciation","Artificial selection","Genetic drift only"],"c":1,"e":"Geographic separation (allopatry) prevents gene flow; the isolated populations diverge until they become distinct species, defining allopatric speciation."},
  {"i":"bio-b3-0682","g":12,"u":"Applications of Biology","d":"medium","t":"application","q":"In a controlled cross, a tall pea plant of unknown genotype (Tt or TT) is crossed with a short plant (tt), and among the offspring half are tall and half are short. The unknown plant's genotype is:","o":["TT","Tt","tt","Cannot be determined"],"c":1,"e":"A 1:1 tall-to-short ratio in a testcross indicates the tall parent is heterozygous (Tt); a TT parent would give all tall offspring."},
  {"i":"bio-b3-0683","g":12,"u":"Applications of Biology","d":"medium","t":"application","q":"A farmer uses tissue culture to mass-produce disease-free enset (false banana) plantlets. The main advantage over growing from suckers is that tissue culture:","o":["Produces genetically varied plants for natural selection","Rapidly yields many uniform, disease-free plants","Removes the need for any nutrients","Changes the species into a new one"],"c":1,"e":"Micropropagation from healthy tissue gives large numbers of genetically identical, pathogen-free plantlets quickly, which growing from suckers cannot match."},
  {"i":"bio-b3-0684","g":12,"u":"Climate Change","d":"medium","t":"conceptual","q":"Clearing large areas of Ethiopian highland forest for farmland tends to increase atmospheric CO₂ for two combined reasons. Which pair is correct?","o":["More photosynthesis and more respiration","Fewer trees absorbing CO₂ and carbon released from burning or decaying wood","More carbon stored in soil and less rainfall","Increased ocean uptake and reduced sunlight"],"c":1,"e":"Removing trees lowers CO₂ uptake by photosynthesis, while burning and decomposition of the cleared wood release stored carbon as CO₂; both raise atmospheric CO₂."},
  {"i":"bio-b3-0685","g":12,"u":"The Human Body Systems","d":"medium","t":"calculation","q":"A man with blood group AB marries a woman with blood group O. Considering only the ABO system, what proportion of their children is expected to have blood group A?","o":["1/4","1/2","3/4","All of them"],"c":1,"e":"AB (IᴬIᴮ) × O (ii) gives 1/2 Iᴬi (group A) and 1/2 Iᴮi (group B). So 1/2 are group A."},
  {"i":"bio-b3-0686","g":12,"u":"The Human Body Systems","d":"medium","t":"application","q":"In humans, red-green colour blindness is X-linked recessive. A carrier woman marries a man with normal colour vision. What fraction of their SONS is expected to be colour blind?","o":["0","1/4","1/2","All sons"],"c":2,"e":"Mother XᴬXᵃ × father XᴬY. Sons get XᴬY or XᵃY in equal numbers, so 1/2 of sons are colour blind."},
  {"i":"bio-b3-0687","g":12,"u":"Evolution","d":"medium","t":"calculation","q":"In a large randomly mating population at Hardy–Weinberg equilibrium, 16% of individuals show a recessive trait. What percentage of the population are heterozygous carriers?","o":["24%","36%","48%","60%"],"c":2,"e":"q² = 0.16 so q = 0.4 and p = 0.6. Heterozygotes = 2pq = 2(0.6)(0.4) = 0.48, i.e. 48%."},
  {"i":"bio-b3-0688","g":12,"u":"Evolution","d":"medium","t":"calculation","q":"A recessive allele has frequency q = 0.3 in a population in Hardy–Weinberg equilibrium. What is the frequency of the dominant phenotype?","o":["0.09","0.49","0.51","0.91"],"c":3,"e":"Dominant phenotype = p² + 2pq = 1 − q² = 1 − 0.09 = 0.91."},
  {"i":"bio-b3-0689","g":12,"u":"Applications of Biology","d":"medium","t":"calculation","q":"A pure-breeding tall purple-flowered pea plant (TTPP) is crossed with a dwarf white one (ttpp). The F1 is selfed. What fraction of the F2 is expected to be dwarf AND white?","o":["1/16","3/16","9/16","1/4"],"c":0,"e":"In a 9:3:3:1 dihybrid ratio, the double-recessive (dwarf white, ttpp) is 1/16."},
  {"i":"bio-b3-0690","g":12,"u":"Applications of Biology","d":"medium","t":"calculation","q":"In a monohybrid cross between two heterozygotes (Rr × Rr) for round (R) versus wrinkled (r) seeds, what fraction of the offspring is expected to be homozygous dominant?","o":["1/4","1/2","3/4","1/3"],"c":0,"e":"Rr × Rr gives 1 RR : 2 Rr : 1 rr. Homozygous dominant (RR) = 1/4."},
  {"i":"bio-b3-0691","g":12,"u":"Energy Transformation","d":"medium","t":"calculation","q":"During aerobic respiration, the complete oxidation of one glucose molecule yields a net theoretical maximum of how many ATP molecules (textbook value)?","o":["2","4","36–38","30"],"c":2,"e":"Glycolysis (net 2) + Krebs cycle and oxidative phosphorylation together give a textbook maximum of about 36–38 ATP per glucose."},
  {"i":"bio-b3-0692","g":12,"u":"Energy Transformation","d":"medium","t":"conceptual","q":"In the light-dependent reactions of photosynthesis, the splitting of water (photolysis) directly provides which of the following?","o":["ATP only","Electrons, protons and O₂","CO₂ for the Calvin cycle","Glucose"],"c":1,"e":"Photolysis of water releases electrons (to replace those lost by P680), protons (H⁺), and oxygen as a by-product."},
  {"i":"bio-b3-0693","g":12,"u":"Energy Transformation","d":"medium","t":"conceptual","q":"In which part of the mitochondrion does the Krebs (citric acid) cycle take place?","o":["Outer membrane","Intermembrane space","Matrix","Inner membrane cristae"],"c":2,"e":"The enzymes of the Krebs cycle are located in the mitochondrial matrix; the electron transport chain is on the inner membrane."},
  {"i":"bio-b3-0694","g":12,"u":"Microorganisms","d":"medium","t":"conceptual","q":"Which feature distinguishes a typical bacterial (prokaryotic) cell from a fungal (eukaryotic) cell?","o":["Presence of a plasma membrane","Presence of ribosomes","Absence of a membrane-bound nucleus","Ability to carry out respiration"],"c":2,"e":"Bacteria are prokaryotes and lack a membrane-bound nucleus; fungi are eukaryotes with a true nucleus. Both have membranes and ribosomes."},
  {"i":"bio-b3-0695","g":12,"u":"Microorganisms","d":"medium","t":"application","q":"In traditional Ethiopian injera making, the souring of teff batter is mainly caused by microbial fermentation that produces which product?","o":["Ethanol only","Lactic acid","Methane","Citric acid"],"c":1,"e":"Lactic acid bacteria ferment the batter, lowering pH and giving injera its characteristic sour taste; some CO₂ also forms the holes."},
  {"i":"bio-b3-0696","g":12,"u":"Microorganisms","d":"medium","t":"definition","q":"A virus is best described as which of the following?","o":["A single-celled prokaryote","An obligate intracellular parasite that needs a host cell to replicate","A free-living decomposer","A type of fungus"],"c":1,"e":"Viruses are acellular obligate intracellular parasites; they can only replicate using the machinery of a living host cell."},
  {"i":"bio-b3-0697","g":12,"u":"Applications of Biology","d":"medium","t":"conceptual","q":"In genetic engineering, restriction endonucleases are used because they perform which function?","o":["Join DNA fragments together","Cut DNA at specific recognition sequences","Synthesise mRNA from DNA","Replicate the whole genome"],"c":1,"e":"Restriction enzymes recognise specific base sequences and cut DNA there; DNA ligase is what joins fragments."},
  {"i":"bio-b3-0698","g":12,"u":"Applications of Biology","d":"medium","t":"application","q":"In the polymerase chain reaction (PCR), the strands of DNA are separated by which step?","o":["Annealing at about 55 °C","Extension by Taq polymerase","Denaturation by heating to about 95 °C","Ligation"],"c":2,"e":"Heating to about 90–95 °C (denaturation) breaks the hydrogen bonds and separates the two DNA strands."},
  {"i":"bio-b3-0699","g":12,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"In the human nephron, most reabsorption of glucose and amino acids from the filtrate occurs in which region?","o":["Glomerulus","Proximal convoluted tubule","Loop of Henle","Collecting duct"],"c":1,"e":"The proximal convoluted tubule is the main site where glucose, amino acids and most water and salts are reabsorbed."},
  {"i":"bio-b3-0700","g":12,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"Which sequence correctly traces oxygenated blood from the lungs back into systemic circulation?","o":["Pulmonary artery → right atrium → right ventricle → aorta","Pulmonary vein → left atrium → left ventricle → aorta","Vena cava → left atrium → left ventricle → pulmonary artery","Pulmonary vein → right atrium → right ventricle → aorta"],"c":1,"e":"Oxygenated blood returns via the pulmonary vein to the left atrium, passes to the left ventricle, then leaves through the aorta."},
  {"i":"bio-b3-0701","g":12,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"At a chemical synapse, the arrival of a nerve impulse at the presynaptic terminal directly triggers which event?","o":["Influx of Ca²⁺ and release of neurotransmitter","Active transport of Na⁺ out of the axon","Synthesis of myelin","Reabsorption of the neurotransmitter only"],"c":0,"e":"Depolarisation opens voltage-gated Ca²⁺ channels; Ca²⁺ influx causes synaptic vesicles to fuse and release neurotransmitter."},
  {"i":"bio-b3-0702","g":12,"u":"The Human Body Systems","d":"medium","t":"application","q":"After a meal raises blood glucose, the pancreas secretes insulin. The MAIN effect of insulin is to do which of the following?","o":["Stimulate breakdown of glycogen to glucose","Promote uptake of glucose by cells and its storage as glycogen","Increase blood glucose further","Stimulate the kidney to excrete glucose"],"c":1,"e":"Insulin lowers blood glucose by promoting cellular glucose uptake and conversion to glycogen in the liver and muscle."},
  {"i":"bio-b3-0703","g":12,"u":"Evolution","d":"medium","t":"conceptual","q":"The presence of the pentadactyl (five-fingered) limb pattern in humans, whales and bats is best explained as which kind of evidence for evolution?","o":["Analogous structures from convergent evolution","Homologous structures from common ancestry","Vestigial structures","Acquired characteristics"],"c":1,"e":"These limbs share the same underlying bone plan despite different functions, indicating descent from a common ancestor (homology)."},
  {"i":"bio-b3-0704","g":12,"u":"Evolution","d":"medium","t":"application","q":"Overuse of antibiotics leads to populations of resistant bacteria. This is best explained by which mechanism?","o":["Bacteria deliberately mutating to survive","Natural selection of pre-existing resistant variants","Inheritance of resistance acquired during the host's lifetime","Antibiotics directly creating resistance genes"],"c":1,"e":"Random pre-existing resistant variants survive the antibiotic and reproduce, so resistance frequency rises by natural selection."},
  {"i":"bio-b3-0705","g":12,"u":"Climate Change","d":"medium","t":"application","q":"In a grassland food chain, if producers fix 10 000 kJ of energy, approximately how much energy is available to a secondary consumer, assuming the standard 10% ecological efficiency?","o":["1000 kJ","100 kJ","10 kJ","5000 kJ"],"c":1,"e":"Producers 10 000 kJ → primary consumer 1000 kJ (10%) → secondary consumer 100 kJ (another 10%)."},
  {"i":"bio-b3-0706","g":12,"u":"Climate Change","d":"medium","t":"conceptual","q":"Rising atmospheric CO₂ contributes to global warming mainly because CO₂ does which of the following?","o":["Destroys the ozone layer","Absorbs and re-emits long-wave (infrared) radiation from the Earth","Reflects incoming sunlight back to space","Blocks all ultraviolet radiation"],"c":1,"e":"As a greenhouse gas, CO₂ absorbs outgoing infrared radiation and re-emits it, trapping heat in the lower atmosphere."},
  {"i":"bio-b3-0707","g":12,"u":"The Human Body Systems","d":"medium","t":"application","q":"A woman who is a carrier for haemophilia (an X-linked recessive disorder) has children with a man who is not haemophilic. What fraction of ALL their children is expected to be haemophilic?","o":["1/2","1/4","1/8","0"],"c":1,"e":"Cross XᴴXʰ × XᴴY gives offspring XᴴXᴴ, XᴴXʰ, XᴴY, XʰY. Only XʰY (one of four) is affected, so 1/4 of all children."},
  {"i":"bio-b3-0708","g":12,"u":"The Human Body Systems","d":"medium","t":"calculation","q":"In a population at Hardy–Weinberg equilibrium, 4% of people show a recessive trait. What percentage of the population is expected to be heterozygous carriers?","o":["16%","20%","32%","64%"],"c":2,"e":"q² = 0.04 so q = 0.2 and p = 0.8. Carriers = 2pq = 2(0.8)(0.2) = 0.32 = 32%."},
  {"i":"bio-b3-0709","g":12,"u":"The Human Body Systems","d":"medium","t":"calculation","q":"Two plants heterozygous for two independently assorting genes (AaBb) are crossed. What fraction of the offspring is expected to be homozygous recessive for both genes (aabb)?","o":["1/16","3/16","9/16","1/4"],"c":0,"e":"For each gene Aa × Aa gives 1/4 recessive. Independent assortment: 1/4 × 1/4 = 1/16."},
  {"i":"bio-b3-0710","g":12,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"In humans, blood group is determined by alleles Iᴬ, Iᴮ (codominant) and i (recessive). A cross between a heterozygous group-A parent (Iᴬi) and a heterozygous group-B parent (Iᴮi) can produce children of how many different blood groups?","o":["1","2","3","4"],"c":3,"e":"Offspring genotypes are IᴬIᴮ (AB), Iᴬi (A), Iᴮi (B), and ii (O) — all four ABO groups."},
  {"i":"bio-b3-0711","g":12,"u":"The Human Body Systems","d":"medium","t":"application","q":"During strenuous exercise a sprinter's muscle cells run short of oxygen yet keep generating ATP for a short time. The accumulating product responsible for muscle fatigue is mainly:","o":["Ethanol","Lactic acid","Carbon dioxide","Pyruvate fully oxidised"],"c":1,"e":"Without enough oxygen, human muscle uses anaerobic respiration, reducing pyruvate to lactic acid (lactate), which accumulates and causes fatigue."},
  {"i":"bio-b3-0712","g":12,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"A person's blood pH starts to fall below normal during illness. Which immediate response best opposes this change?","o":["Decreased breathing rate to retain CO₂","Increased breathing rate to expel more CO₂","Kidneys reabsorbing more hydrogen ions","Increased production of carbonic acid"],"c":1,"e":"Falling pH (more acidic) signals breathing to increase, expelling CO₂ and shifting the carbonic-acid/bicarbonate buffer to raise pH back toward normal."},
  {"i":"bio-b3-0713","g":12,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"A neuron is at resting potential. Which statement best describes the distribution maintained by the sodium–potassium pump?","o":["High Na⁺ outside, high K⁺ inside","High Na⁺ inside, high K⁺ outside","Equal Na⁺ and K⁺ on both sides","High Na⁺ and K⁺ both outside"],"c":0,"e":"The Na⁺/K⁺ pump expels Na⁺ and imports K⁺, keeping Na⁺ concentrated outside and K⁺ inside, establishing the resting potential."},
  {"i":"bio-b3-0714","g":12,"u":"The Human Body Systems","d":"medium","t":"application","q":"A man with blood group AB marries a woman with blood group O. Regarding the ABO gene, what blood groups can their children have?","o":["A or B only","AB or O only","A, B, AB or O","O only"],"c":0,"e":"Father IᴬIᴮ × mother ii gives Iᴬi (group A) and Iᴮi (group B) only — no AB and no O children."},
  {"i":"bio-b3-0715","g":12,"u":"Energy Transformation","d":"medium","t":"calculation","q":"In the light-independent (Calvin) reactions, how many molecules of CO₂ must be fixed to synthesise one molecule of glucose?","o":["3","6","12","18"],"c":1,"e":"Glucose has 6 carbons, and each CO₂ supplies one carbon, so 6 CO₂ molecules are needed to build one glucose."},
  {"i":"bio-b3-0716","g":12,"u":"Energy Transformation","d":"medium","t":"calculation","q":"Glycolysis converts one glucose molecule into two pyruvate molecules. What is the NET yield of ATP from glycolysis alone?","o":["1 ATP","2 ATP","4 ATP","38 ATP"],"c":1,"e":"Glycolysis produces 4 ATP but uses 2 in the priming steps, giving a net gain of 2 ATP per glucose."},
  {"i":"bio-b3-0717","g":12,"u":"Energy Transformation","d":"medium","t":"conceptual","q":"In aerobic respiration, the final electron acceptor at the end of the electron transport chain is:","o":["NAD⁺","Pyruvate","Oxygen","Carbon dioxide"],"c":2,"e":"Oxygen accepts electrons at the end of the chain and combines with hydrogen to form water; without it the chain halts."},
  {"i":"bio-b3-0718","g":12,"u":"Energy Transformation","d":"medium","t":"application","q":"A leaf is exposed to light of increasing intensity while CO₂ and temperature are kept constant. The rate of photosynthesis rises then levels off. The plateau is best explained because:","o":["Light is now toxic to chloroplasts","Another factor such as CO₂ has become limiting","Chlorophyll has been destroyed","Respiration has stopped"],"c":1,"e":"Once light is plentiful, a different factor (here CO₂) limits the rate, so adding more light no longer increases photosynthesis."},
  {"i":"bio-b3-0719","g":12,"u":"Energy Transformation","d":"medium","t":"conceptual","q":"During the Krebs (citric acid) cycle, carbon atoms originally from glucose leave the cell mainly in the form of:","o":["Lactic acid","Carbon dioxide","Ethanol","Water"],"c":1,"e":"The Krebs cycle decarboxylates intermediates, releasing carbon as CO₂, which is then exhaled."},
  {"i":"bio-b3-0720","g":12,"u":"Microorganisms","d":"medium","t":"conceptual","q":"An enzyme works fastest at 40 °C and pH 7. At 70 °C its activity drops sharply and does not recover on cooling. The best explanation is that:","o":["The substrate was used up","The enzyme's active site was denatured","The pH became too acidic","More enzyme was produced"],"c":1,"e":"High temperature breaks the bonds holding the enzyme's shape, denaturing the active site permanently, so activity is lost even after cooling."},
  {"i":"bio-b3-0721","g":12,"u":"Microorganisms","d":"medium","t":"application","q":"In making 'injera', the batter is left to ferment for a few days. Yeasts and bacteria break down sugars without oxygen, producing the gas that gives injera its 'eyes'. That gas is:","o":["Oxygen","Carbon dioxide","Nitrogen","Hydrogen"],"c":1,"e":"Anaerobic fermentation by yeast converts sugars to ethanol and CO₂; the CO₂ bubbles form the characteristic holes in injera."},
  {"i":"bio-b3-0722","g":12,"u":"Microorganisms","d":"medium","t":"conceptual","q":"A bacterial cell differs from a typical human cell in that the bacterium:","o":["Has a membrane-bound nucleus","Lacks membrane-bound organelles","Contains no DNA","Has linear chromosomes only"],"c":1,"e":"Bacteria are prokaryotes: they have DNA but no membrane-bound nucleus or organelles, unlike eukaryotic human cells."},
  {"i":"bio-b3-0723","g":12,"u":"Applications of Biology","d":"medium","t":"application","q":"In producing genetically modified bacteria to make human insulin, the human insulin gene is inserted into a small circular DNA molecule used as a vector. This vector is a:","o":["Ribosome","Plasmid","Mitochondrion","Lysosome"],"c":1,"e":"Plasmids are small circular DNA molecules in bacteria; a gene of interest is spliced into a plasmid, which then carries it into the host bacterium."},
  {"i":"bio-b3-0724","g":12,"u":"Evolution","d":"medium","t":"application","q":"Overuse of an antibiotic on a farm leads, over several years, to a bacterial population that the antibiotic no longer kills. This is best explained by:","o":["Bacteria choosing to become resistant","Natural selection of pre-existing resistant variants","The antibiotic mutating the bacteria on purpose","Loss of all genetic variation"],"c":1,"e":"Random variation produces some resistant bacteria; the antibiotic kills the susceptible ones, so resistant survivors reproduce and dominate — natural selection."},
  {"i":"bio-b3-0725","g":12,"u":"Evolution","d":"medium","t":"conceptual","q":"The forelimbs of a human, a whale and a bat have the same basic bone arrangement but different functions. Such homologous structures are evidence of:","o":["Convergent evolution from unrelated ancestors","Common ancestry with divergent adaptation","Spontaneous generation","Acquired characteristics being inherited"],"c":1,"e":"Homologous structures share an inherited body plan from a common ancestor and were modified for different roles — evidence of divergent evolution."},
  {"i":"bio-b3-0726","g":12,"u":"Climate Change","d":"medium","t":"calculation","q":"In a grassland food chain, grass stores 10,000 kJ of energy. If only about 10% of energy passes to each next level, roughly how much energy reaches the secondary consumers?","o":["1,000 kJ","100 kJ","10 kJ","5,000 kJ"],"c":1,"e":"Grass 10,000 kJ → primary consumers ~1,000 kJ → secondary consumers ~100 kJ, applying the ~10% transfer at each step."},
  {"i":"bio-b3-0727","g":12,"u":"The Human Body Systems","d":"medium","t":"calculation","q":"A man with blood group AB marries a woman with blood group O. Ignoring rare exceptions, what fraction of their children are expected to be blood group B?","o":["1/4","1/2","All of them","None"],"c":1,"e":"AB (I^A I^B) × O (ii) gives genotypes 1/2 I^A i and 1/2 I^B i, so half the children are group A and half are group B."},
  {"i":"bio-b3-0728","g":12,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"In a healthy nephron, glucose normally does not appear in the urine because it is:","o":["Too large to enter the glomerular filtrate","Completely reabsorbed in the proximal convoluted tubule","Broken down by enzymes in the loop of Henle","Secreted back into the blood at the collecting duct"],"c":1,"e":"Glucose is freely filtered at the glomerulus but is actively reabsorbed in the proximal convoluted tubule, so under normal blood-glucose levels none reaches the urine."},
  {"i":"bio-b3-0729","g":12,"u":"The Human Body Systems","d":"medium","t":"application","q":"During strenuous exercise in a long-distance runner from the Ethiopian highlands, muscle cells lacking enough oxygen produce ATP and accumulate:","o":["Ethanol and carbon dioxide","Lactic acid","Pyruvate converted fully to CO₂ and water","Acetyl-CoA only"],"c":1,"e":"In human muscle, anaerobic respiration converts pyruvate to lactic acid (not ethanol, which occurs in yeast), regenerating NAD⁺ for continued glycolysis."},
  {"i":"bio-b3-0730","g":12,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"After a meal rich in injera and wot, the rise in blood glucose is corrected mainly by insulin, which promotes:","o":["Glycogen breakdown in the liver","Uptake of glucose by body cells and glycogen storage","Conversion of amino acids to glucose","Release of glucagon from the pancreas"],"c":1,"e":"Insulin lowers blood glucose by stimulating cellular glucose uptake and promoting glycogen synthesis (glycogenesis) in the liver and muscle."},
  {"i":"bio-b3-0731","g":12,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"Which sequence correctly traces an electrical impulse through the conducting system of the heart?","o":["AV node → SA node → bundle of His → Purkinje fibres","SA node → AV node → bundle of His → Purkinje fibres","Purkinje fibres → AV node → SA node → bundle of His","SA node → bundle of His → AV node → Purkinje fibres"],"c":1,"e":"The SA node (pacemaker) fires first, the impulse reaches the AV node, then passes down the bundle of His and spreads through the Purkinje fibres."},
  {"i":"bio-b3-0732","g":12,"u":"The Human Body Systems","d":"medium","t":"calculation","q":"In a dihybrid cross AaBb × AaBb (independent assortment, complete dominance), how many of the 16 boxes show the double-recessive phenotype?","o":["1","3","4","9"],"c":0,"e":"The 9:3:3:1 ratio means only 1 of 16 offspring is aabb (double recessive)."},
  {"i":"bio-b3-0733","g":12,"u":"Energy Transformation","d":"medium","t":"calculation","q":"In aerobic respiration, the complete oxidation of one glucose molecule yields a theoretical maximum of about how many ATP?","o":["2 ATP","4 ATP","38 ATP","12 ATP"],"c":2,"e":"Glycolysis (2) + Krebs cycle (2) + oxidative phosphorylation (≈34) gives a theoretical maximum of about 38 ATP per glucose."},
  {"i":"bio-b3-0734","g":12,"u":"Energy Transformation","d":"medium","t":"conceptual","q":"During the light-dependent reactions of photosynthesis, the oxygen released originates from:","o":["Carbon dioxide","Water","Glucose","RuBP"],"c":1,"e":"Photolysis of water (2H₂O → 4H⁺ + 4e⁻ + O₂) in the light reactions releases the oxygen gas, not from CO₂."},
  {"i":"bio-b3-0735","g":12,"u":"Energy Transformation","d":"medium","t":"conceptual","q":"In the Calvin cycle (light-independent reactions), CO₂ is first fixed when it combines with:","o":["NADPH","Ribulose bisphosphate (RuBP)","Glucose","Pyruvate"],"c":1,"e":"The enzyme RuBisCO catalyses the attachment of CO₂ to the 5-carbon RuBP, forming an unstable 6-carbon compound that splits into two 3-carbon molecules."},
  {"i":"bio-b3-0736","g":12,"u":"Energy Transformation","d":"medium","t":"application","q":"A leaf is kept in the dark for 24 hours before a starch test. The main reason for this de-starching step is to:","o":["Kill the chloroplasts","Ensure any starch detected is made during the experiment","Increase chlorophyll concentration","Open the stomata wider"],"c":1,"e":"De-starching empties existing starch stores so that any starch found afterward must have been produced during the actual investigation."},
  {"i":"bio-b3-0737","g":12,"u":"Energy Transformation","d":"medium","t":"conceptual","q":"In the mitochondrion, the proton gradient that drives ATP synthase is established across the:","o":["Outer mitochondrial membrane","Inner mitochondrial membrane","Nuclear membrane","Thylakoid membrane"],"c":1,"e":"The electron transport chain pumps protons across the inner mitochondrial membrane into the intermembrane space, and their return through ATP synthase produces ATP."},
  {"i":"bio-b3-0738","g":12,"u":"Microorganisms","d":"medium","t":"definition","q":"A key structural feature distinguishing a typical bacterial (prokaryotic) cell from a fungal cell is that the bacterium:","o":["Has a true membrane-bound nucleus","Lacks membrane-bound organelles such as mitochondria","Has cellulose in its cell wall","Reproduces only sexually"],"c":1,"e":"Prokaryotes lack a true nucleus and membrane-bound organelles; their DNA lies free in the cytoplasm as a single circular chromosome."},
  {"i":"bio-b3-0739","g":12,"u":"Microorganisms","d":"medium","t":"application","q":"In traditional Ethiopian preparation of injera, the souring of teff batter is mainly caused by:","o":["Aerobic respiration by molds","Lactic acid fermentation by bacteria and yeast","Photosynthesis by cyanobacteria","Protein digestion by viruses"],"c":1,"e":"Fermenting microorganisms, chiefly lactic acid bacteria together with yeast, produce acids and CO₂ that sour and leaven the teff batter."},
  {"i":"bio-b3-0740","g":12,"u":"Microorganisms","d":"medium","t":"conceptual","q":"Viruses are not classified as fully living cells mainly because they:","o":["Contain no genetic material","Cannot reproduce outside a host cell","Are larger than bacteria","Have their own ribosomes and mitochondria"],"c":1,"e":"Viruses lack the cellular machinery to metabolise and replicate independently; they can only reproduce using a living host cell's apparatus."},
  {"i":"bio-b3-0741","g":12,"u":"Microorganisms","d":"medium","t":"application","q":"Pasteurization of cow's milk in an Ethiopian dairy reduces disease risk primarily by:","o":["Sterilizing the milk completely so no microbes remain","Heating to kill most pathogenic microorganisms while preserving quality","Freezing the milk to stop all reactions","Adding antibiotics directly to the milk"],"c":1,"e":"Pasteurization uses controlled heating to destroy most pathogens and reduce spoilage organisms without fully sterilizing or ruining the milk."},
  {"i":"bio-b3-0742","g":12,"u":"Applications of Biology","d":"medium","t":"conceptual","q":"In the production of recombinant human insulin, the human insulin gene is most commonly inserted into a bacterial:","o":["Ribosome","Plasmid","Cell wall","Flagellum"],"c":1,"e":"A plasmid serves as the vector: the insulin gene is spliced into it, and the recombinant plasmid is taken up by bacteria that then produce insulin."},
  {"i":"bio-b3-0743","g":12,"u":"Applications of Biology","d":"medium","t":"application","q":"A farmer near Bahir Dar uses tissue culture to propagate disease-free banana plants. The main advantage of this method is that the offspring are:","o":["Genetically varied for natural selection","Genetically identical clones of a selected parent","Produced only through sexual reproduction","Always polyploid and sterile"],"c":1,"e":"Tissue culture (micropropagation) is asexual, producing many genetically identical clones of a chosen, disease-free parent plant."},
  {"i":"bio-b3-0744","g":12,"u":"Evolution","d":"medium","t":"conceptual","q":"The presence of similar bone arrangement in the forelimbs of a human, a bat, and a whale is best explained as evidence from:","o":["Analogous structures showing convergent evolution","Homologous structures showing common ancestry","Vestigial organs losing their function","Artificial selection by humans"],"c":1,"e":"These forelimbs share the same underlying bone plan despite different functions, making them homologous structures pointing to a common ancestor."},
  {"i":"bio-b3-0745","g":12,"u":"Climate Change","d":"medium","t":"application","q":"Reforestation programmes in the Ethiopian highlands help slow climate change mainly because growing trees:","o":["Release carbon dioxide during photosynthesis","Absorb carbon dioxide and store carbon in biomass","Increase atmospheric methane directly","Reflect all incoming sunlight back to space"],"c":1,"e":"Photosynthesis removes atmospheric CO₂ and fixes the carbon in wood and other biomass, acting as a carbon sink that mitigates warming."},
  {"i":"bio-b3-0746","g":12,"u":"Climate Change","d":"medium","t":"conceptual","q":"In a grassland food chain, only about 10% of energy passes from one trophic level to the next. This limits the number of trophic levels mainly because:","o":["Producers cannot capture any sunlight","Most energy is lost as heat through respiration at each level","Energy is recycled endlessly between levels","Consumers create new energy from food"],"c":1,"e":"At each transfer, most energy is dissipated as heat during respiration and in undigested material, so little remains to support many higher levels."},
  {"i":"bio-b3-0747","g":12,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"In a nephron, the glomerular filtrate becomes hypertonic to blood plasma at the bottom of the loop of Henle mainly because of the activity of which limb?","o":["Active pumping of Na⁺ out of the thick ascending limb, which is impermeable to water","Passive water entry into the descending limb only","Active K⁺ secretion in the distal convoluted tubule","Reabsorption of glucose in the proximal convoluted tubule"],"c":0,"e":"The thick ascending limb actively pumps out Na⁺/Cl⁻ but is impermeable to water, raising the medullary interstitium's osmolarity; this countercurrent multiplier makes the filtrate deep in the loop concentrated."},
  {"i":"bio-b3-0748","g":12,"u":"The Human Body Systems","d":"medium","t":"calculation","q":"A man with blood group AB marries a woman with group O. Ignoring rare exceptions, what proportion of their children is expected to have group O?","o":["0%","25%","50%","100%"],"c":0,"e":"AB parent is Iᴬ Iᴮ; O parent is ii. Children are Iᴬi (group A) or Iᴮi (group B) in a 1:1 ratio. No child can be ii, so 0% are group O."},
  {"i":"bio-b3-0749","g":12,"u":"Evolution","d":"medium","t":"calculation","q":"In a large randomly mating population at Hardy–Weinberg equilibrium, 4% of individuals show a recessive trait. What percentage of the population is expected to be heterozygous carriers?","o":["16%","20%","32%","64%"],"c":2,"e":"q² = 0.04 so q = 0.2 and p = 0.8. Heterozygotes = 2pq = 2(0.8)(0.2) = 0.32, i.e. 32%."},
  {"i":"bio-b3-0750","g":12,"u":"Evolution","d":"medium","t":"conceptual","q":"Two bird populations in the Ethiopian highlands diverge after a valley separates them; they later cannot interbreed even when reunited. This is best described as:","o":["Sympatric speciation by polyploidy","Allopatric speciation following geographic isolation","Convergent evolution","Genetic drift with no isolation"],"c":1,"e":"A physical barrier (the valley) splits the population, allowing independent genetic change until reproductive isolation forms — the defining sequence of allopatric speciation."},
  {"i":"bio-b3-0751","g":12,"u":"Microorganisms","d":"medium","t":"conceptual","q":"During industrial production of injera-souring cultures, lactic acid bacteria ferment carbohydrate without oxygen. Compared with aerobic respiration, this fermentation yields less ATP mainly because:","o":["The electron transport chain and oxidative phosphorylation are not used","Glycolysis is skipped entirely","More CO₂ is released","Water is consumed instead of produced"],"c":0,"e":"Fermentation regenerates NAD⁺ but does not pass electrons to an electron transport chain, so only the small ATP yield of glycolysis is obtained."},
  {"i":"bio-b3-0752","g":12,"u":"Microorganisms","d":"medium","t":"application","q":"A biotechnologist inserts a human insulin gene into a bacterial plasmid. The enzyme used to join the gene to the cut plasmid is:","o":["DNA polymerase","Restriction endonuclease","DNA ligase","Helicase"],"c":2,"e":"Restriction enzymes cut the DNA; DNA ligase seals the sugar–phosphate backbone, joining the insulin gene into the plasmid vector."},
  {"i":"bio-b3-0753","g":12,"u":"Energy Transformation","d":"medium","t":"calculation","q":"Balancing the overall equation of aerobic respiration of one glucose molecule, how many molecules of O₂ are consumed?","o":["2","6","12","36"],"c":1,"e":"C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O. Six O₂ molecules are consumed per glucose."},
  {"i":"bio-b3-0754","g":12,"u":"Energy Transformation","d":"medium","t":"conceptual","q":"In the light-dependent reactions of photosynthesis, the oxygen released originates from:","o":["Carbon dioxide","Water molecules split by photolysis","Glucose","ATP"],"c":1,"e":"Photolysis splits water (2H₂O → 4H⁺ + 4e⁻ + O₂), so the released O₂ comes from water, not CO₂."},
  {"i":"bio-b3-0755","g":12,"u":"The Human Body Systems","d":"medium","t":"calculation","q":"A colour-blind allele is X-linked recessive. A carrier woman (XᴮXᵇ) marries a man with normal vision (XᴮY). What fraction of their SONS is expected to be colour-blind?","o":["0","1/4","1/2","1"],"c":2,"e":"Sons get X from mother and Y from father. Mother gives Xᴮ or Xᵇ equally, so half the sons are XᵇY (colour-blind)."},
  {"i":"bio-b3-0756","g":12,"u":"Evolution","d":"medium","t":"calculation","q":"In a dihybrid cross AaBb × AaBb with independent assortment, what fraction of offspring is heterozygous at both loci (AaBb)?","o":["1/16","3/16","1/4","9/16"],"c":2,"e":"Aa × Aa gives 1/2 Aa; Bb × Bb gives 1/2 Bb. Combined: 1/2 × 1/2 = 1/4 are AaBb."},
  {"i":"bio-b3-0757","g":12,"u":"Applications of Biology","d":"medium","t":"application","q":"A farmer in Bahir Dar wants only the largest-grain teff plants to reproduce each generation to increase grain size over time. This deliberate practice is an example of:","o":["Natural selection","Artificial (selective) breeding","Genetic drift","Mutation pressure"],"c":1,"e":"Humans choosing which individuals breed for a desired trait is artificial selection (selective breeding), not a natural process."},
  {"i":"bio-b3-0758","g":12,"u":"Applications of Biology","d":"medium","t":"conceptual","q":"In a PCR reaction used for DNA fingerprinting, a heat-stable DNA polymerase (Taq) is essential because:","o":["It works only at 0 °C","It survives the repeated high-temperature denaturation steps","It replaces the need for primers","It synthesises RNA instead of DNA"],"c":1,"e":"PCR cycles include ~95 °C denaturation; an ordinary polymerase would be destroyed, so a thermostable polymerase from a thermophile is required."},
  {"i":"bio-b3-0759","g":12,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"After a meal raises blood glucose, the pancreas secretes insulin. Insulin lowers blood glucose chiefly by:","o":["Stimulating glycogen breakdown in the liver","Promoting glucose uptake by cells and glycogen synthesis","Increasing glucose absorption in the kidney tubule","Inhibiting the secretion of glucagon-producing cells only"],"c":1,"e":"Insulin increases cellular glucose uptake and drives glycogenesis (glucose → glycogen) in liver and muscle, lowering blood glucose."},
  {"i":"bio-b3-0760","g":12,"u":"The Human Body Systems","d":"medium","t":"calculation","q":"At a synapse, an action potential triggers Ca²⁺ influx into the presynaptic terminal. The immediate result of this Ca²⁺ entry is:","o":["Reuptake of neurotransmitter","Fusion of vesicles and release of neurotransmitter","Closure of voltage-gated Na⁺ channels in the axon","Hyperpolarisation of the presynaptic membrane"],"c":1,"e":"Ca²⁺ entering the presynaptic terminal causes synaptic vesicles to fuse with the membrane and release neurotransmitter into the cleft."},
  {"i":"bio-b3-0761","g":12,"u":"Energy Transformation","d":"medium","t":"calculation","q":"If glycolysis produces a net gain of 2 ATP and the rest of aerobic respiration adds about 34 ATP, what approximate total ATP is produced per glucose?","o":["About 2","About 18","About 36","About 72"],"c":2,"e":"Net 2 (glycolysis) + ~2 (Krebs/GTP) + ~32 (oxidative phosphorylation) ≈ 36 ATP per glucose in the commonly cited yield."},
  {"i":"bio-b3-0762","g":12,"u":"Microorganisms","d":"medium","t":"conceptual","q":"A virus is described as an obligate intracellular parasite. The best justification is that a virus:","o":["Has a cell wall but no membrane","Cannot replicate without using a host cell's machinery","Performs its own respiration","Reproduces only by binary fission outside cells"],"c":1,"e":"Viruses lack ribosomes and metabolic machinery, so they must enter a living host cell to replicate — making them obligate intracellular parasites."},
  {"i":"bio-b3-0763","g":12,"u":"Climate Change","d":"medium","t":"conceptual","q":"Rising atmospheric CO₂ contributes to global warming mainly because CO₂:","o":["Reflects all incoming sunlight back to space","Absorbs and re-emits outgoing infrared (heat) radiation","Destroys the ozone layer directly","Increases the Sun's energy output"],"c":1,"e":"Greenhouse gases such as CO₂ are transparent to incoming visible light but absorb outgoing infrared radiation, trapping heat in the lower atmosphere."},
  {"i":"bio-b3-0764","g":12,"u":"Climate Change","d":"medium","t":"application","q":"Large-scale reforestation is promoted as a climate mitigation strategy in Ethiopia largely because forests:","o":["Release stored CO₂ rapidly","Act as carbon sinks by fixing CO₂ during photosynthesis","Reduce rainfall and humidity","Increase atmospheric methane directly"],"c":1,"e":"Growing trees absorb atmospheric CO₂ and store the carbon in biomass, functioning as carbon sinks that reduce net greenhouse-gas levels."},
  {"i":"bio-b3-0765","g":12,"u":"Evolution","d":"medium","t":"calculation","q":"A plant of genotype Tt (tall, dominant) is test-crossed with a tt (short) plant. What phenotypic ratio of tall to short offspring is expected?","o":["3 tall : 1 short","1 tall : 1 short","1 tall : 3 short","All tall"],"c":1,"e":"Tt × tt gives 1/2 Tt (tall) and 1/2 tt (short), a 1:1 ratio — the classic test-cross result."},
  {"i":"bio-b3-0766","g":12,"u":"Applications of Biology","d":"medium","t":"conceptual","q":"In an aquatic food chain, energy transfer between trophic levels is roughly 10% efficient. This best explains why:","o":["Food chains rarely have more than 4–5 trophic levels","Producers are always the least abundant","Decomposers obtain no energy","Top predators store the most total energy"],"c":0,"e":"Because only ~10% of energy passes upward at each step, available energy runs out after a few levels, limiting food-chain length."},
  {"i":"bio-b3-0767","g":12,"u":"The Human Body Systems","d":"medium","t":"conceptual","q":"During strenuous exercise, breathing rate rises primarily in response to detection of:","o":["Decreased blood glucose","Increased blood CO₂ and falling pH","Increased blood Ca²⁺","Decreased body temperature"],"c":1,"e":"Chemoreceptors detect rising CO₂ and the resulting drop in blood pH; the respiratory centre then increases breathing rate to expel CO₂."},
  {"i":"bio-b3-0768","g":12,"u":"Evolution","d":"hard","t":"calculation","q":"In an isolated highland population in Bale, a recessive allele for a metabolic trait gives 16% of individuals the recessive phenotype. Assuming Hardy–Weinberg equilibrium, what proportion of the population are heterozygous carriers?","o":["0.16","0.48","0.32","0.24"],"c":1,"e":"q² = 0.16 so q = 0.4 and p = 0.6; heterozygotes = 2pq = 2(0.6)(0.4) = 0.48."},
  {"i":"bio-b3-0769","g":12,"u":"Evolution","d":"hard","t":"calculation","q":"For an X-linked recessive condition, the recessive allele frequency in a population is 0.2. Since males are hemizygous, the expected frequency of affected males compared with affected females is closest to which ratio?","o":["1 : 1","5 : 1","2 : 1","25 : 1"],"c":1,"e":"Affected males = q = 0.2; affected females = q² = 0.04; ratio 0.2 : 0.04 = 5 : 1."},
  {"i":"bio-b3-0770","g":12,"u":"Applications of Biology","d":"hard","t":"calculation","q":"A dihybrid cross AaBb × AaBb (genes assort independently) is performed. What fraction of the offspring are expected to show at least one dominant trait but NOT both dominant traits?","o":["9/16","6/16","7/16","3/16"],"c":1,"e":"Ratio 9 A_B_ : 3 A_bb : 3 aaB_ : 1 aabb; exactly one dominant trait = 3 + 3 = 6/16."},
  {"i":"bio-b3-0771","g":12,"u":"Applications of Biology","d":"hard","t":"calculation","q":"A test cross of a plant heterozygous for two linked genes yields 42% parental and 8% recombinant for one combination, with the recombinants split evenly. What is the map distance between the genes?","o":["8 map units","16 map units","42 map units","50 map units"],"c":1,"e":"Total recombinants = 8% + 8% = 16%; map distance equals recombination frequency = 16 map units."},
  {"i":"bio-b3-0772","g":12,"u":"Applications of Biology","d":"hard","t":"calculation","q":"In poultry, feather colour shows incomplete dominance: CC = black, CWCW = white, CCW = blue (Erminette). Crossing two blue birds, what fraction of surviving chicks are expected to be blue?","o":["1/4","1/2","3/4","All"],"c":1,"e":"CCW × CCW → 1 CC : 2 CCW : 1 CWCW, i.e. 1 black : 2 blue : 1 white; blue = 2/4 = 1/2."},
  {"i":"bio-b3-0773","g":12,"u":"Applications of Biology","d":"hard","t":"conceptual","q":"A woman with blood group AB marries a man with group O. Considering ABO codominance, which blood groups are possible among their children?","o":["A, B, AB and O","Only AB","A and B only","O only"],"c":2,"e":"AB (I^A I^B) × O (ii) gives I^A i (group A) and I^B i (group B) only; neither AB nor O is possible."},
  {"i":"bio-b3-0774","g":12,"u":"The Human Body Systems","d":"hard","t":"calculation","q":"A man with haemophilia (X-linked recessive) marries a carrier woman. What proportion of their daughters are expected to be haemophiliac?","o":["0","1/4","1/2","All"],"c":2,"e":"X^h Y × X^H X^h → daughters are X^H X^h or X^h X^h; half (1/2) receive the father's X^h and the mother's X^h, so half are affected."},
  {"i":"bio-b3-0775","g":12,"u":"The Human Body Systems","d":"hard","t":"application","q":"During strenuous exercise in an Addis Ababa athlete at altitude, plasma CO₂ rises. Which sequence best describes the homeostatic response that follows?","o":["Blood pH rises → breathing slows → CO₂ retained","Blood pH falls → chemoreceptors stimulated → breathing rate increases","Blood pH unchanged → heart rate falls → CO₂ stored","Blood pH rises → chemoreceptors inhibited → breathing increases"],"c":1,"e":"Rising CO₂ forms carbonic acid, lowering pH; medullary chemoreceptors detect this and raise ventilation to expel CO₂."},
  {"i":"bio-b3-0776","g":12,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"A patient's nephron shows glucose in the urine despite normal blood glucose. The most likely single explanation is a defect in which process?","o":["Glomerular filtration of glucose","Active reabsorption in the proximal convoluted tubule","Secretion in the distal tubule","Osmosis in the collecting duct"],"c":1,"e":"Glucose is freely filtered but normally fully reclaimed by active reabsorption (Na⁺-glucose cotransport) in the PCT; a transporter defect causes glucosuria at normal blood glucose."},
  {"i":"bio-b3-0777","g":12,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"In a reflex arc, signal conduction is fastest along which neuron feature, and why?","o":["Unmyelinated axon, because there is no insulation to slow it","Myelinated axon, because saltatory conduction jumps between nodes of Ranvier","The synaptic cleft, because chemical diffusion is instant","The dendrites, because they are shortest"],"c":1,"e":"Myelin forces the action potential to jump node-to-node (saltatory conduction), which is much faster than continuous conduction along bare membrane."},
  {"i":"bio-b3-0778","g":12,"u":"The Human Body Systems","d":"hard","t":"application","q":"A person loses a large volume of blood plasma. Which immediate hormonal response best restores blood volume?","o":["Decreased ADH and decreased aldosterone","Increased ADH and increased aldosterone","Increased insulin secretion","Decreased renin release"],"c":1,"e":"Low blood volume triggers ADH (water reabsorption) and the renin–angiotensin–aldosterone system (Na⁺ then water retention), both raising volume."},
  {"i":"bio-b3-0779","g":12,"u":"Energy Transformation","d":"hard","t":"calculation","q":"Complete oxidation of one glucose molecule via aerobic respiration yields a theoretical maximum of about how many ATP, and where is most generated?","o":["2 ATP, in glycolysis","About 30–32 ATP, mostly at oxidative phosphorylation","4 ATP, in the Krebs cycle","About 38 ATP, all in the cytoplasm"],"c":1,"e":"Modern estimates give ~30–32 ATP per glucose; the great majority comes from oxidative phosphorylation driven by the electron transport chain."},
  {"i":"bio-b3-0780","g":12,"u":"Energy Transformation","d":"hard","t":"calculation","q":"If the light reactions supply 18 ATP and 12 NADPH to fix carbon, and the Calvin cycle turns required to make one glucose use 18 ATP and 12 NADPH, how many CO₂ molecules and Calvin-cycle turns produce one glucose?","o":["3 CO₂, 3 turns","6 CO₂, 6 turns","12 CO₂, 12 turns","1 CO₂, 1 turn"],"c":1,"e":"Each Calvin turn fixes one CO₂ using 3 ATP and 2 NADPH; six turns fix 6 CO₂ (18 ATP, 12 NADPH) to build one 6-carbon glucose."},
  {"i":"bio-b3-0781","g":12,"u":"Energy Transformation","d":"hard","t":"conceptual","q":"A poison blocks the final electron acceptor of the mitochondrial electron transport chain. What is the most direct consequence?","o":["Glycolysis stops immediately","The proton gradient collapses and ATP synthesis by chemiosmosis halts","More ATP is produced by substrate-level phosphorylation","Water production increases"],"c":1,"e":"Without a terminal acceptor (O₂), electron flow stops, no protons are pumped, the gradient dissipates, and ATP synthase can no longer make ATP."},
  {"i":"bio-b3-0782","g":12,"u":"Microorganisms","d":"hard","t":"calculation","q":"A bacterial culture starts with 500 cells and divides every 20 minutes under ideal conditions. How many cells are present after 2 hours, assuming no death?","o":["3000","32000","16000","8000"],"c":1,"e":"2 hours = 120 min = 6 generations; 500 × 2⁶ = 500 × 64 = 32000 cells."},
  {"i":"bio-b3-0783","g":12,"u":"Microorganisms","d":"hard","t":"conceptual","q":"Gram-positive and Gram-negative bacteria differ chiefly in cell-wall structure. Which statement is correct?","o":["Gram-positive cells have an outer membrane and thin peptidoglycan","Gram-positive cells have a thick peptidoglycan layer and retain crystal violet","Gram-negative cells have no peptidoglycan at all","Gram-negative cells stain purple because of thick peptidoglycan"],"c":1,"e":"Gram-positive walls have thick peptidoglycan that traps crystal violet (purple); Gram-negatives have thin peptidoglycan plus an outer membrane and lose the stain, appearing pink."},
  {"i":"bio-b3-0784","g":12,"u":"Microorganisms","d":"hard","t":"application","q":"In traditional Ethiopian injera fermentation, the souring of teff batter is mainly driven by which microbial activity?","o":["Aerobic respiration producing CO₂ only","Lactic acid bacteria producing organic acids that lower pH","Photosynthesis by cyanobacteria","Protein digestion by fungal proteases"],"c":1,"e":"Lactic acid bacteria ferment sugars to lactic and other organic acids, lowering pH (souring) and helping preserve the batter; yeasts add CO₂ for texture."},
  {"i":"bio-b3-0785","g":12,"u":"Microorganisms","d":"hard","t":"conceptual","q":"A restriction enzyme cuts DNA at a specific palindromic site leaving 'sticky ends'. Why are sticky ends useful in genetic engineering?","o":["They prevent any DNA from rejoining","Their single-stranded overhangs base-pair with complementary overhangs, letting DNA ligase join fragments","They destroy the foreign gene","They make the DNA double-stranded for the first time"],"c":1,"e":"Complementary single-stranded overhangs from the same enzyme anneal by base pairing, allowing DNA ligase to seal an insert into a vector."},
  {"i":"bio-b3-0786","g":12,"u":"Microorganisms","d":"hard","t":"application","q":"In producing recombinant human insulin, why is a bacterial plasmid chosen as the vector?","o":["Plasmids cannot replicate, so the gene stays dormant","Plasmids replicate independently and carry the gene into rapidly dividing bacteria for mass expression","Plasmids are made of protein, not DNA","Plasmids prevent the host bacterium from dividing"],"c":1,"e":"Plasmids are small, self-replicating DNA circles that, once carrying the insulin gene, multiply with fast-growing bacteria to produce large protein yields."},
  {"i":"bio-b3-0787","g":12,"u":"Climate Change","d":"hard","t":"calculation","q":"In a grassland food chain, producers fix 10000 kJ. Applying the ~10% energy-transfer rule, how much energy is available to secondary consumers?","o":["1000 kJ","100 kJ","10 kJ","900 kJ"],"c":1,"e":"Primary consumers get ~10% of 10000 = 1000 kJ; secondary consumers get ~10% of that = 100 kJ."},
  {"i":"bio-b3-0788","g":12,"u":"Climate Change","d":"hard","t":"conceptual","q":"Reforestation programmes in the Ethiopian highlands are promoted as climate mitigation chiefly because trees:","o":["Release carbon dioxide that warms the soil","Act as carbon sinks, removing CO₂ from the air during photosynthesis","Increase atmospheric methane","Reflect all incoming sunlight back to space"],"c":1,"e":"Growing trees absorb atmospheric CO₂ and store carbon in biomass and soil, reducing the greenhouse gas that drives warming."},
  {"i":"bio-b3-0789","g":12,"u":"Climate Change","d":"hard","t":"application","q":"A lake near farmland develops dense algal blooms, then fish die at night. Which two-step explanation is correct?","o":["Fertiliser runoff causes eutrophication; decomposing algae deplete dissolved oxygen, suffocating fish","Drought raises oxygen; fish overheat","Pesticides add oxygen; algae starve fish of light only","Cooling water freezes the fish at night"],"c":0,"e":"Nutrient runoff (eutrophication) fuels algal blooms; at night and as algae die, respiration and bacterial decomposition consume dissolved oxygen, causing fish kills."},
  {"i":"bio-b3-0790","g":12,"u":"Evolution","d":"hard","t":"calculation","q":"In a large Ethiopian highland sheep population at Hardy–Weinberg equilibrium, 16% of animals show a recessive coat trait (genotype aa). What percentage of the population are expected to be heterozygous carriers (Aa)?","o":["16%","36%","48%","60%"],"c":2,"e":"q² = 0.16, so q = 0.4 and p = 0.6; heterozygotes = 2pq = 2(0.6)(0.4) = 0.48 = 48%."},
  {"i":"bio-b3-0791","g":12,"u":"Evolution","d":"hard","t":"calculation","q":"For an X-linked recessive allele in a population at equilibrium, the recessive allele frequency is q = 0.2. Assuming equal sex ratio, what fraction of MALES are expected to be affected, and is this higher or lower than affected females?","o":["0.04, higher than females","0.20, higher than females","0.20, lower than females","0.40, equal to females"],"c":1,"e":"Males are hemizygous, so affected-male frequency = q = 0.2; affected females = q² = 0.04, so males are affected far more often."},
  {"i":"bio-b3-0792","g":12,"u":"Evolution","d":"hard","t":"conceptual","q":"Two finch-like seedeater populations on opposite sides of the Great Rift Valley diverge until they can no longer interbreed even when brought together, due to incompatible courtship songs. This barrier to gene flow is best classified as:","o":["A postzygotic, geographic barrier","A prezygotic, behavioural isolating mechanism","Hybrid sterility","Genetic drift in a bottleneck"],"c":1,"e":"Courtship-song mismatch prevents mating before any zygote forms, so it is a prezygotic, behavioural reproductive isolating mechanism."},
  {"i":"bio-b3-0793","g":12,"u":"Evolution","d":"hard","t":"calculation","q":"A founder group of 8 individuals colonises an isolated island. One founder is heterozygous (Bb) for a rare allele; all others are BB. What is the frequency of the b allele in this founding population?","o":["1/8 = 0.125","1/16 = 0.0625","1/4 = 0.25","2/8 = 0.25"],"c":1,"e":"8 diploid individuals carry 16 alleles; only 1 is b, so frequency = 1/16 = 0.0625 — an example of the founder effect."},
  {"i":"bio-b3-0794","g":12,"u":"The Human Body Systems","d":"hard","t":"calculation","q":"A father with blood group AB and a mother with group O have children. Considering the ABO system only, what proportion of their children are expected to be group O?","o":["0%","25%","50%","100%"],"c":0,"e":"Father is I^A I^B, mother is ii; children are either I^A i (group A) or I^B i (group B). No child can be group O."},
  {"i":"bio-b3-0795","g":12,"u":"The Human Body Systems","d":"hard","t":"calculation","q":"A woman who is a carrier for haemophilia (X^H X^h) marries an unaffected man (X^H Y). What fraction of their SONS are expected to have haemophilia?","o":["0","1/4","1/2","All sons"],"c":2,"e":"Sons get X from mother: half receive X^H (unaffected), half X^h (affected). So 1/2 of sons are affected, though only 1/4 of all children."},
  {"i":"bio-b3-0796","g":12,"u":"The Human Body Systems","d":"hard","t":"calculation","q":"In a dihybrid cross AaBb × AaBb with independent assortment and complete dominance, what is the probability of an offspring showing the dominant trait for A but the recessive trait for B?","o":["9/16","3/16","6/16","1/16"],"c":1,"e":"P(A_) = 3/4 and P(bb) = 1/4; combined = 3/4 × 1/4 = 3/16."},
  {"i":"bio-b3-0797","g":12,"u":"The Human Body Systems","d":"hard","t":"calculation","q":"In a test cross between a dihybrid AaBb and a double-recessive aabb, what phenotypic ratio is expected among offspring (genes unlinked)?","o":["9:3:3:1","3:1","1:1:1:1","1:2:1"],"c":2,"e":"A test cross of a dihybrid to aabb yields the four genotypes AaBb, Aabb, aaBb, aabb in equal frequency: 1:1:1:1."},
  {"i":"bio-b3-0798","g":12,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"After a meal high in injera (carbohydrate), blood glucose rises. Which sequence correctly describes the homeostatic correction?","o":["Glucagon released → liver releases glucose → glucose falls","Insulin from beta cells → cells take up glucose, liver stores glycogen → glucose falls","Adrenaline released → glycogen broken down → glucose rises","Insulin from alpha cells → liver releases glucose → glucose rises"],"c":1,"e":"High blood glucose stimulates pancreatic beta cells to secrete insulin, increasing cellular uptake and hepatic glycogen storage, lowering glucose by negative feedback."},
  {"i":"bio-b3-0799","g":12,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"During strenuous exercise at high altitude on the Ethiopian plateau, a person breathes faster. The primary chemical stimulus detected by chemoreceptors driving this increase is mainly:","o":["A fall in blood oxygen alone","A rise in blood CO₂ / fall in blood pH","A rise in blood pH","A rise in blood glucose"],"c":1,"e":"Central and peripheral chemoreceptors respond most strongly to rising CO₂ and the associated drop in blood pH; O₂ becomes a major driver only when it falls substantially."},
  {"i":"bio-b3-0800","g":12,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"A toxin blocks the reabsorption of water in the collecting duct by preventing aquaporin insertion. Which hormone's action is being blocked, and what is the immediate effect on urine?","o":["Aldosterone; less salt in urine","ADH (vasopressin); large volume of dilute urine","Insulin; glucose in urine","ADH; small volume of concentrated urine"],"c":1,"e":"ADH inserts aquaporins for water reabsorption in the collecting duct; blocking it produces a large volume of dilute urine (as in diabetes insipidus)."},
  {"i":"bio-b3-0801","g":12,"u":"The Human Body Systems","d":"hard","t":"application","q":"A motor neuron is stimulated and an action potential occurs. Which event corresponds to depolarisation of the membrane?","o":["K⁺ channels open and K⁺ leaves the cell","Na⁺ channels open and Na⁺ rushes into the cell","The Na⁺/K⁺ pump restores the gradient","Cl⁻ enters making the inside more negative"],"c":1,"e":"Depolarisation is caused by voltage-gated Na⁺ channels opening, letting Na⁺ flow in and making the inside less negative (toward +30 mV)."},
  {"i":"bio-b3-0802","g":12,"u":"Energy Transformation","d":"hard","t":"calculation","q":"In aerobic respiration, the complete oxidation of one glucose molecule yields a maximum theoretical net total of how many ATP, and where is most of it generated?","o":["2 ATP; in glycolysis","38 ATP; mostly by oxidative phosphorylation on the inner mitochondrial membrane","4 ATP; in the Krebs cycle","36 ATP; entirely in the cytoplasm"],"c":1,"e":"The classic textbook maximum is about 38 ATP per glucose, the great majority produced by the electron transport chain / oxidative phosphorylation on the inner mitochondrial membrane."},
  {"i":"bio-b3-0803","g":12,"u":"Energy Transformation","d":"hard","t":"conceptual","q":"In the light-dependent reactions of photosynthesis, water is split (photolysis). Which three products result directly from photolysis of water?","o":["Glucose, O₂ and H₂O","O₂, electrons (e⁻) and protons (H⁺)","CO₂, ATP and NADPH","O₂, CO₂ and ATP"],"c":1,"e":"Photolysis (2H₂O → 4H⁺ + 4e⁻ + O₂) supplies electrons to replace those lost by chlorophyll, protons for the gradient, and releases oxygen gas."},
  {"i":"bio-b3-0804","g":12,"u":"Energy Transformation","d":"hard","t":"application","q":"A plant is supplied with CO₂ labelled with the isotope ¹⁴C. In the Calvin cycle, the labelled carbon will FIRST appear in which stable compound?","o":["RuBP (ribulose bisphosphate)","A 3-carbon compound (3-phosphoglycerate, 3-PGA)","Glucose","Rubisco enzyme"],"c":1,"e":"CO₂ is fixed by Rubisco onto RuBP, and the unstable 6-carbon intermediate immediately splits into two 3-carbon molecules of 3-PGA — the first stable product."},
  {"i":"bio-b3-0805","g":12,"u":"Energy Transformation","d":"hard","t":"conceptual","q":"During vigorous exercise an athlete's muscles run short of oxygen. The function of lactic acid fermentation that allows glycolysis to continue is to:","o":["Produce extra ATP directly from pyruvate","Regenerate NAD⁺ by reducing pyruvate to lactate","Release oxygen for the electron transport chain","Convert lactate into glucose in the muscle"],"c":1,"e":"Without O₂ the electron transport chain stops; reducing pyruvate to lactate reoxidises NADH back to NAD⁺, allowing glycolysis (the only ATP source) to keep running."},
  {"i":"bio-b3-0806","g":12,"u":"Microorganisms","d":"hard","t":"conceptual","q":"A Gram stain is performed on a bacterial sample. Gram-positive bacteria appear purple while Gram-negative appear pink. The structural feature mainly responsible for this difference is:","o":["Presence or absence of a nucleus","Thickness of the peptidoglycan layer in the cell wall","Possession of flagella","Whether the organism is aerobic"],"c":1,"e":"Gram-positive cells have a thick peptidoglycan layer that retains the crystal-violet–iodine complex (purple); Gram-negatives have thin peptidoglycan and stain pink with the counterstain."},
  {"i":"bio-b3-0807","g":12,"u":"Microorganisms","d":"hard","t":"calculation","q":"A bacterium divides by binary fission every 20 minutes. Starting from a single cell under ideal conditions, how many cells are present after 2 hours?","o":["6","12","64","128"],"c":2,"e":"2 hours = 120 min = 6 generations; cells = 1 × 2⁶ = 64."},
  {"i":"bio-b3-0808","g":12,"u":"Microorganisms","d":"hard","t":"application","q":"In producing injera, teff batter is left to ferment by wild microorganisms before baking. The sour taste and bubbles in the batter are mainly due to microbial production of:","o":["Lactic acid and CO₂","Ethanol and oxygen","Citric acid and nitrogen","Methane and water"],"c":0,"e":"Fermenting microbes (yeasts and lactic-acid bacteria) produce CO₂ gas (giving the bubbles/'eyes') and organic acids such as lactic acid that give injera its characteristic sour flavour."},
  {"i":"bio-b3-0809","g":12,"u":"Microorganisms","d":"hard","t":"conceptual","q":"In genetic engineering to make human insulin, a human gene is inserted into a bacterial plasmid. The enzymes that respectively cut the DNA and join the pieces are:","o":["DNA polymerase and helicase","Restriction enzymes and DNA ligase","Ligase and reverse transcriptase","Amylase and protease"],"c":1,"e":"Restriction endonucleases cut DNA at specific sites (often leaving sticky ends), and DNA ligase seals the human gene into the plasmid vector to form recombinant DNA."},
  {"i":"bio-b3-0810","g":12,"u":"Applications of Biology","d":"hard","t":"application","q":"A farmer in the Rift Valley wants many genetically identical, disease-free banana plants quickly from one elite parent. The most appropriate biotechnology is:","o":["Sexual cross-breeding over several seasons","Plant tissue culture (micropropagation)","Genetic modification with a Bt gene","Random mutation breeding using radiation"],"c":1,"e":"Tissue culture (micropropagation) grows many genetically identical, often pathogen-free clones rapidly from a small explant of a chosen elite plant — ideal for uniform, disease-free planting material."},
  {"i":"bio-b3-0811","g":12,"u":"Climate Change","d":"hard","t":"calculation","q":"In an Ethiopian grassland food chain, grass fixes 50,000 kJ m⁻² yr⁻¹. Assuming about 10% energy transfer between successive trophic levels, roughly how much energy is available to a secondary consumer (e.g. a serval) per m² per year?","o":["5,000 kJ","2,500 kJ","500 kJ","50 kJ"],"c":2,"e":"10% to primary consumers = 5,000 kJ; another 10% to secondary consumers = 500 kJ m⁻² yr⁻¹, illustrating energy loss at each trophic level."},
  {"i":"bio-b3-0812","g":12,"u":"Evolution","d":"hard","t":"calculation","q":"In an isolated highland sheep population, a recessive allele a causes a wool defect. 16 in every 100 sheep show the defect. Assuming Hardy–Weinberg equilibrium, what fraction of the phenotypically normal sheep are heterozygous carriers?","o":["4/7","8/21","1/2","4/25"],"c":0,"e":"q²=0.16 so q=0.4, p=0.6. Carriers 2pq=0.48; normal=p²+2pq=0.36+0.48=0.84. Carrier fraction of normals=0.48/0.84=4/7."},
  {"i":"bio-b3-0813","g":12,"u":"Evolution","d":"hard","t":"calculation","q":"A plant population has genotype counts AA=90, Aa=60, aa=50 (total 200). What is the frequency of allele a, and is the population in Hardy–Weinberg equilibrium?","o":["a=0.40; yes, in equilibrium","a=0.40; no, not in equilibrium","a=0.25; yes, in equilibrium","a=0.60; no, not in equilibrium"],"c":1,"e":"a=(2·50+60)/400=160/400=0.40. Expected AA under HWE=0.6²·200=72, but observed is 90, so the genotype counts deviate — not in equilibrium."},
  {"i":"bio-b3-0814","g":12,"u":"The Human Body Systems","d":"hard","t":"calculation","q":"A man with blood type AB marries a woman who is heterozygous type B (I^B i). What proportion of their children are expected to be type B?","o":["1/4","1/2","3/4","1/8"],"c":1,"e":"Cross I^A I^B × I^B i gives 1/4 I^A I^B (AB), 1/4 I^A i (A), 1/4 I^B I^B (B), 1/4 I^B i (B). Type B = 1/4+1/4 = 1/2."},
  {"i":"bio-b3-0815","g":12,"u":"The Human Body Systems","d":"hard","t":"calculation","q":"Haemophilia is X-linked recessive. A carrier mother (X^H X^h) marries an unaffected father (X^H Y). What fraction of ALL their children are expected to be affected, and what fraction of their sons are affected?","o":["1/4 of all children; 1/2 of sons","1/2 of all children; 1/2 of sons","1/4 of all children; 1/4 of sons","1/2 of all children; all sons"],"c":0,"e":"Offspring: X^H X^H, X^H X^h, X^H Y, X^h Y. Only X^h Y is affected = 1/4 of all children. Among sons, half (X^h Y) are affected = 1/2 of sons."},
  {"i":"bio-b3-0816","g":12,"u":"The Human Body Systems","d":"hard","t":"calculation","q":"In a dihybrid cross RrYy × RrYy (R round and Y yellow are dominant), what proportion of offspring are round AND green?","o":["9/16","3/16","1/16","3/4"],"c":1,"e":"Round = 3/4, green (yy) = 1/4. Round and green = 3/4 × 1/4 = 3/16."},
  {"i":"bio-b3-0817","g":12,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"In a test cross of a tall purple-flowered plant (genotype unknown) with a short white plant (ttpp), the offspring are 1/4 tall purple, 1/4 tall white, 1/4 short purple, 1/4 short white. What is the genotype of the tall purple parent?","o":["TTPP","TtPp","TtPP","TTPp"],"c":1,"e":"A 1:1:1:1 test-cross ratio means the parent makes four equally frequent gamete types (TP, Tp, tP, tp), so it is heterozygous for both genes: TtPp."},
  {"i":"bio-b3-0818","g":12,"u":"The Human Body Systems","d":"hard","t":"calculation","q":"Two parents with normal skin pigmentation have a child with albinism (autosomal recessive). If they have three more children, what is the probability that all three are unaffected?","o":["27/64","9/16","3/4","1/64"],"c":0,"e":"Both parents must be Aa, so each child is unaffected with probability 3/4. For three independent children: (3/4)³ = 27/64."},
  {"i":"bio-b3-0819","g":12,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"During which phase of the cardiac cycle are BOTH the atrioventricular valves and the semilunar valves closed, allowing ventricular pressure to build without any change in blood volume?","o":["Atrial systole","Isovolumetric ventricular contraction","Ventricular ejection","Ventricular filling"],"c":1,"e":"In isovolumetric contraction the ventricles contract with all four valves shut, so pressure rises sharply while ventricular volume stays constant until the semilunar valves open."},
  {"i":"bio-b3-0820","g":12,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"A person hyperventilates, blowing off large amounts of CO₂. What is the most direct effect on blood pH and on the oxygen–haemoglobin dissociation curve?","o":["pH falls; curve shifts right","pH rises; curve shifts left","pH rises; curve shifts right","pH falls; curve shifts left"],"c":1,"e":"Losing CO₂ lowers carbonic acid, so blood pH rises (alkalosis). By the Bohr effect, higher pH raises haemoglobin's O₂ affinity, shifting the dissociation curve left."},
  {"i":"bio-b3-0821","g":12,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"In the nephron, a substance is freely filtered, not reabsorbed, AND actively secreted into the tubule. How does the amount excreted in urine compare with the amount filtered?","o":["Less than filtered, because some is reabsorbed","Equal to the amount filtered","Greater than the amount filtered, because secretion adds more","It cannot appear in urine at all"],"c":2,"e":"Filtration delivers part of the substance; tubular secretion adds extra from peritubular blood, and with no reabsorption all of it leaves, so the excreted amount exceeds the filtered amount."},
  {"i":"bio-b3-0822","g":12,"u":"The Human Body Systems","d":"hard","t":"application","q":"A neuron has a resting potential of −70 mV. A stimulus opens its voltage-gated Na⁺ channels. Which change occurs at the membrane at that instant?","o":["Hyperpolarisation as Cl⁻ enters","Depolarisation toward +30 mV as Na⁺ enters","Repolarisation as K⁺ enters","No change because Na⁺ leaves the cell"],"c":1,"e":"Open voltage-gated Na⁺ channels let Na⁺ rush in down its electrochemical gradient, making the inside less negative and driving depolarisation toward about +30 mV — the rising phase of the action potential."},
  {"i":"bio-b3-0823","g":12,"u":"Energy Transformation","d":"hard","t":"calculation","q":"In aerobic respiration of one glucose molecule in a prokaryote, net glycolysis yields 2 ATP and the total is about 38 ATP. What percentage of total ATP comes from substrate-level phosphorylation in glycolysis alone (net)?","o":["About 5%","About 25%","About 50%","About 11%"],"c":0,"e":"Net glycolysis = 2 ATP of about 38 total → 2/38 ≈ 0.053 ≈ 5%, showing most ATP comes from oxidative phosphorylation."},
  {"i":"bio-b3-0824","g":12,"u":"Energy Transformation","d":"hard","t":"conceptual","q":"In the light-dependent reactions, water is split by photolysis. Which set of products does the photolysis of water directly provide?","o":["CO₂, ATP and NADPH","Electrons, protons (H⁺) and oxygen","Glucose and oxygen","NADP⁺ and ADP only"],"c":1,"e":"Photolysis (2H₂O → 4H⁺ + 4e⁻ + O₂) replaces electrons lost by photosystem II, releases protons that build the gradient for ATP synthesis, and gives off O₂ as a by-product."},
  {"i":"bio-b3-0825","g":12,"u":"Energy Transformation","d":"hard","t":"calculation","q":"Each turn of the Calvin cycle fixes one CO₂, and three turns yield one net G3P. How many turns and how many CO₂ molecules are needed to build one glucose (from two G3P)?","o":["3 turns, 3 CO₂","6 turns, 6 CO₂","2 turns, 2 CO₂","12 turns, 12 CO₂"],"c":1,"e":"One net G3P needs 3 turns (3 CO₂); glucose needs two G3P, so 6 turns and 6 CO₂ total."},
  {"i":"bio-b3-0826","g":12,"u":"Energy Transformation","d":"hard","t":"application","q":"A poison blocks the electron transport chain at the final step where electrons are passed to oxygen. What is the most immediate consequence for ATP production?","o":["Glycolysis stops immediately as well","The proton gradient collapses and chemiosmotic ATP synthesis halts","The Krebs cycle makes extra ATP to compensate","Oxygen consumption increases sharply"],"c":1,"e":"Blocking the terminal oxidase stops electron flow, so protons are no longer pumped; the gradient dissipates and ATP synthase can no longer drive oxidative phosphorylation, the main ATP source."},
  {"i":"bio-b3-0827","g":12,"u":"Energy Transformation","d":"hard","t":"conceptual","q":"Enzyme activity rises with temperature up to an optimum, then falls sharply above it. Which explanation correctly accounts for BOTH the rise and the fall?","o":["Below: more substrate is made; above: pH change","Below: more kinetic energy and collisions; above: denaturation alters the active site","Below: the enzyme is denatured; above: cofactors are lost","Both changes are due to competitive inhibition"],"c":1,"e":"Below the optimum, higher temperature increases kinetic energy and enzyme–substrate collisions. Above it, heat disrupts the bonds holding tertiary structure, denaturing the enzyme and destroying active-site shape."},
  {"i":"bio-b3-0828","g":12,"u":"Microorganisms","d":"hard","t":"conceptual","q":"In the lac operon of E. coli, lactose is absent and glucose is also absent (so cAMP-CAP is high). What is the transcription state of the structural genes?","o":["High transcription, because cAMP-CAP is high","No transcription, because the active repressor blocks the operator","Constitutive maximum transcription","Only the repressor gene is transcribed"],"c":1,"e":"Without lactose there is no allolactose to inactivate the repressor, so it stays bound to the operator and blocks RNA polymerase — the structural genes are off regardless of cAMP-CAP."},
  {"i":"bio-b3-0829","g":12,"u":"Microorganisms","d":"hard","t":"calculation","q":"A single bacterium divides by binary fission every 20 minutes under ideal conditions. Starting from one cell, how many cells are present after 3 hours, assuming no death?","o":["512","1024","256","180"],"c":0,"e":"3 hours = 180 min; divisions = 180/20 = 9. Cells = 2⁹ = 512."},
  {"i":"bio-b3-0830","g":12,"u":"Microorganisms","d":"hard","t":"application","q":"In recombinant DNA technology a human gene is inserted into a bacterial plasmid. Which enzymes are essential, in order, to cut the DNA at specific sites and then join the gene into the plasmid?","o":["DNA polymerase, then helicase","Restriction endonuclease, then DNA ligase","Ligase, then restriction enzyme","Reverse transcriptase, then primase"],"c":1,"e":"A restriction endonuclease cuts both plasmid and gene at specific recognition sequences (often making sticky ends), then DNA ligase seals the phosphodiester backbone to join the gene into the plasmid."},
  {"i":"bio-b3-0831","g":12,"u":"Applications of Biology","d":"hard","t":"application","q":"In Ethiopian fermented-milk (ergo) and injera making, lactic acid bacteria act on the milk and dough. What metabolic process do they use, and what main product lowers the pH?","o":["Aerobic respiration producing CO₂","Anaerobic fermentation producing lactic acid","Photosynthesis producing oxygen","Nitrogen fixation producing ammonia"],"c":1,"e":"Lactic acid bacteria carry out anaerobic fermentation, converting sugars to lactic acid; the accumulating acid lowers pH, preserving the food and giving the characteristic sour taste."},
  {"i":"bio-b3-0832","g":12,"u":"Climate Change","d":"hard","t":"application","q":"An Ethiopian grassland has 10,000 kg of producer biomass supporting herbivores, which support carnivores. Using the standard 10% ecological energy-transfer rule, how much biomass is available at the carnivore (secondary consumer) level?","o":["1000 kg","100 kg","10 kg","500 kg"],"c":1,"e":"Each trophic step transfers about 10%: producers 10,000 kg → herbivores 1000 kg → carnivores 100 kg, so about 100 kg reaches the secondary consumers."},
  {"i":"bio-b3-0833","g":12,"u":"The Human Body Systems","d":"hard","t":"calculation","q":"In a Sidama family, a man with normal colour vision marries a woman who is a carrier for the X-linked recessive red-green colour-blindness allele. What fraction of their SONS is expected to be colour-blind?","o":["0","1/4","1/2","3/4"],"c":2,"e":"Father XᴮY × carrier mother XᴮXᵇ. Sons receive Y from father and either Xᴮ or Xᵇ from mother, so half of sons are XᵇY (colour-blind): 1/2."},
  {"i":"bio-b3-0834","g":12,"u":"Applications of Biology","d":"hard","t":"calculation","q":"Two heterozygous tall pea plants (Tt) are crossed, producing 480 offspring. Assuming complete dominance and ideal Mendelian ratios, how many offspring are expected to be homozygous recessive (short)?","o":["120","160","240","360"],"c":0,"e":"Tt × Tt gives 1 TT : 2 Tt : 1 tt, so 1/4 are tt. 480 × 1/4 = 120 short plants."},
  {"i":"bio-b3-0835","g":12,"u":"Applications of Biology","d":"hard","t":"calculation","q":"In a population of insects at Hardy–Weinberg equilibrium, the recessive allele for an enzyme deficiency has frequency q = 0.3. What percentage of the population is expected to be heterozygous carriers?","o":["9%","21%","42%","49%"],"c":2,"e":"With q = 0.3, p = 0.7. Heterozygote frequency = 2pq = 2(0.7)(0.3) = 0.42 = 42%."},
  {"i":"bio-b3-0836","g":12,"u":"Energy Transformation","d":"hard","t":"calculation","q":"The complete oxidation of one glucose molecule via glycolysis, the Krebs cycle and oxidative phosphorylation yields a commonly cited theoretical maximum of how many ATP, and where is the largest share generated?","o":["38 ATP, most by substrate-level phosphorylation in glycolysis","38 ATP, most by oxidative phosphorylation across the inner mitochondrial membrane","2 ATP, all by the Krebs cycle","4 ATP, most in the cytoplasm by fermentation"],"c":1,"e":"The theoretical maximum is about 38 ATP per glucose; only 4 come from substrate-level phosphorylation, while roughly 34 are produced by oxidative phosphorylation driven by the electron transport chain on the inner mitochondrial membrane."},
  {"i":"bio-b3-0837","g":12,"u":"Energy Transformation","d":"hard","t":"conceptual","q":"In photosynthesis, a student claims the oxygen released as O₂ comes from CO₂. Which statement best corrects this, consistent with the Ethiopian curriculum?","o":["O₂ comes from CO₂, split during the Calvin cycle","O₂ comes from the photolysis of water at photosystem II","O₂ comes from glucose breakdown in the stroma","O₂ comes from ATP hydrolysis in the thylakoid"],"c":1,"e":"The O₂ released originates from the light-driven splitting (photolysis) of water at photosystem II, not from CO₂. CO₂ is fixed into carbohydrate in the Calvin cycle."},
  {"i":"bio-b3-0838","g":12,"u":"Microorganisms","d":"hard","t":"calculation","q":"A single bacterium contaminating injera batter divides every 20 minutes under ideal conditions. Starting from one cell, how many cells are present after 3 hours, assuming unlimited resources?","o":["256","512","1 024","2 048"],"c":1,"e":"180 minutes / 20 = 9 divisions. Cells = 2⁹ = 512."},
  {"i":"bio-b3-0839","g":12,"u":"Microorganisms","d":"hard","t":"application","q":"In producing recombinant human insulin using bacteria, which sequence of steps is correct?","o":["Cut insulin gene and plasmid with the same restriction enzyme → join with DNA ligase → transform bacterium → bacterium expresses insulin","Translate insulin protein first → reverse-translate to plasmid → inject into human cells","Use DNA ligase to cut the gene → restriction enzyme to seal the plasmid → grow on agar","Extract insulin from bacterial ribosomes → insert into a virus → infect yeast"],"c":0,"e":"The same restriction enzyme cuts both the insulin gene and the plasmid to give complementary sticky ends; DNA ligase joins them into recombinant DNA, which the bacterium takes up (transformation) and then transcribes and translates to make insulin."},
  {"i":"bio-b3-0840","g":12,"u":"Evolution","d":"hard","t":"calculation","q":"In a herd of Boran cattle at Hardy–Weinberg equilibrium, 16% show a recessive coat phenotype. What is the frequency of the dominant allele?","o":["0.16","0.40","0.60","0.84"],"c":2,"e":"q² = 0.16 → q = 0.4, so p = 1 − 0.4 = 0.6 for the dominant allele."},
  {"i":"bio-b3-0841","g":12,"u":"Evolution","d":"hard","t":"conceptual","q":"Antibiotic resistance spreading among bacteria is used to illustrate natural selection. Which statement most accurately describes the mechanism?","o":["Antibiotics induce individual bacteria to mutate toward resistance on demand","Pre-existing resistant variants survive and reproduce while susceptible cells die, raising resistance frequency","All bacteria gradually acquire resistance by using the antibiotic as a nutrient","Resistance appears only because bacteria consciously adapt to the drug"],"c":1,"e":"Resistance arises from pre-existing variation (mutation or horizontal gene transfer). The antibiotic selectively kills susceptible cells, so resistant cells survive and reproduce and resistance frequency rises — selection, not directed adaptation."},
  {"i":"bio-b3-0842","g":12,"u":"The Human Body Systems","d":"hard","t":"conceptual","q":"A person hyperventilates, blowing off large amounts of CO₂. Using the relationship CO₂ + H₂O ⇌ H⁺ + HCO₃⁻, what is the most likely immediate effect on arterial blood pH and why?","o":["pH falls, because losing CO₂ adds H⁺","pH rises, because losing CO₂ shifts the equilibrium left, lowering H⁺","pH is unchanged, because CO₂ does not affect blood pH","pH rises, because CO₂ loss increases H⁺ concentration"],"c":1,"e":"Removing CO₂ pulls CO₂ + H₂O ⇌ H⁺ + HCO₃⁻ to the left, consuming H⁺ and lowering H⁺ concentration, so blood pH rises (respiratory alkalosis)."},
  {"i":"bio-b3-0843","g":12,"u":"The Human Body Systems","d":"hard","t":"application","q":"A man of blood genotype IᴬIᴮ (type AB) and a woman of genotype Iᴬi (type A) have children. What proportion of their children can have blood type O?","o":["0","1/4","1/2","3/4"],"c":0,"e":"Father's gametes Iᴬ or Iᴮ; mother's Iᴬ or i. Offspring are IᴬIᴬ, Iᴬi, IᴬIᴮ, Iᴮi (types A, A, AB, B). No ii is possible since the father carries no i allele, so 0 can be type O."},
  {"i":"bio-b3-0844","g":12,"u":"Climate Change","d":"hard","t":"application","q":"In a highland grassland food chain — grass → grasshopper → bird → hawk — about 10% of energy transfers between trophic levels. If the grass fixes 200 000 kJ, approximately how much energy reaches the hawk?","o":["20 000 kJ","2 000 kJ","200 kJ","20 kJ"],"c":2,"e":"Applying 10% over three transfers: 200 000 → 20 000 → 2 000 → 200 kJ. The hawk receives about 200 kJ."},
  {"i":"bio-b3-0845","g":12,"u":"The Human Body Systems","d":"impossible","t":"calculation","q":"In a population at Hardy–Weinberg equilibrium, a recessive autosomal metabolic disorder affects 1 in 10 000 newborns. What is the approximate ratio of heterozygous carriers to affected individuals?","o":["About 50 : 1","About 99 : 1","About 198 : 1","About 99 : 100"],"c":2,"e":"q²=1/10000 so q=0.01, p=0.99; carriers 2pq=0.0198 and affected q²=0.0001, giving 2pq/q²=2p/q=2(0.99)/0.01≈198."},
  {"i":"bio-b3-0846","g":12,"u":"Evolution","d":"impossible","t":"calculation","q":"Two genes are 18 map units apart. A dihybrid AaBb (cis arrangement, AB/ab) is testcrossed. Of 1000 offspring, how many are expected to show the recombinant AaBb-type combinations (Ab and aB phenotypes combined)?","o":["90","180","410","820"],"c":1,"e":"Recombination frequency 18% means 18% of offspring are recombinant; 0.18×1000=180 split between the two recombinant classes."},
  {"i":"bio-b3-0847","g":12,"u":"The Human Body Systems","d":"impossible","t":"calculation","q":"A woman whose father was red–green colour-blind marries a man with normal colour vision. What fraction of their sons is expected to be colour-blind?","o":["0","1/4","1/2","All"],"c":2,"e":"The woman is an obligate carrier (XᶜX); her sons receive either Xᶜ or X from her, so 1/2 of sons are colour-blind regardless of the father's X."},
  {"i":"bio-b3-0848","g":12,"u":"Microorganisms","d":"impossible","t":"conceptual","q":"During the lag phase of a bacterial growth curve in fresh medium, which statement best describes the cells?","o":["Cell number falls as toxins accumulate","Cells are metabolically active synthesising enzymes but not yet dividing rapidly","Division rate equals death rate giving constant numbers","Cells double at the maximum constant rate"],"c":1,"e":"In lag phase cells adapt and synthesise enzymes/ribosomes for the new substrate; numbers are nearly constant because rapid division has not yet begun."},
  {"i":"bio-b3-0849","g":12,"u":"Energy Transformation","d":"impossible","t":"calculation","q":"Complete aerobic oxidation of one glucose molecule via glycolysis, the Krebs cycle and oxidative phosphorylation yields a commonly cited net maximum of how many ATP, and where is most produced?","o":["About 38, most in glycolysis","About 38, most at the electron transport chain","About 4, most in the Krebs cycle","About 2, most in fermentation"],"c":1,"e":"The traditional maximum net yield is about 36–38 ATP, the great majority generated by oxidative phosphorylation at the electron transport chain via chemiosmosis."},
  {"i":"bio-b3-0850","g":12,"u":"The Human Body Systems","d":"impossible","t":"conceptual","q":"In a dihybrid cross AaBb × AaBb where the two genes assort independently, what fraction of offspring are homozygous at both loci (any homozygous genotype)?","o":["1/16","1/8","1/4","9/16"],"c":2,"e":"At each locus P(homozygous)=1/2 (AA or aa); for two independent loci (1/2)(1/2)=1/4."},
  {"i":"bio-b3-0851","g":12,"u":"Evolution","d":"impossible","t":"conceptual","q":"A trait is controlled by alleles where heterozygotes express both phenotypes simultaneously (e.g. AB blood type). This inheritance pattern is best termed:","o":["Incomplete dominance","Codominance","Epistasis","Pleiotropy"],"c":1,"e":"Codominance occurs when both alleles are fully and independently expressed in the heterozygote, as in IᴬIᴮ giving type AB blood."},
  {"i":"bio-b3-0852","g":12,"u":"The Human Body Systems","d":"impossible","t":"calculation","q":"At the glomerulus, plasma is filtered but plasma proteins are retained. If inulin is freely filtered, neither reabsorbed nor secreted, and its clearance equals 125 mL/min, this value most directly estimates:","o":["Renal plasma flow","Glomerular filtration rate","Tubular reabsorption rate","Urine production rate"],"c":1,"e":"Because inulin is freely filtered and neither reabsorbed nor secreted, its clearance equals the glomerular filtration rate (GFR)."},
  {"i":"bio-b3-0853","g":12,"u":"Microorganisms","d":"impossible","t":"application","q":"In producing recombinant human insulin, a restriction enzyme cuts both the plasmid and the insulin-gene DNA to create matching sticky ends, which are then joined. The enzyme that seals the sugar–phosphate backbone is:","o":["DNA polymerase","DNA ligase","Reverse transcriptase","Helicase"],"c":1,"e":"DNA ligase forms phosphodiester bonds joining the insert to the plasmid; restriction enzymes only cut, polymerase extends, and reverse transcriptase makes cDNA."},
  {"i":"bio-b3-0854","g":12,"u":"Energy Transformation","d":"impossible","t":"conceptual","q":"In C₃ plants under hot, dry conditions with closed stomata, rubisco increasingly fixes O₂ instead of CO₂. The wasteful process this initiates is:","o":["Photophosphorylation","Photorespiration","Chemiosmosis","The Calvin cycle"],"c":1,"e":"When O₂/CO₂ ratio rises, rubisco's oxygenase activity drives photorespiration, consuming energy and releasing CO₂ without net sugar gain."},
  {"i":"bio-b3-0855","g":12,"u":"Evolution","d":"impossible","t":"calculation","q":"In a Hardy–Weinberg population, the dominant allele frequency p=0.7. What percentage of individuals are expected to show the recessive phenotype?","o":["9%","21%","49%","30%"],"c":0,"e":"q=1−0.7=0.3; recessive phenotype frequency q²=0.09=9%."},
  {"i":"bio-b3-0856","g":12,"u":"The Human Body Systems","d":"impossible","t":"conceptual","q":"A rise in blood CO₂ is detected and ventilation increases to restore normal levels. This regulatory arrangement is an example of:","o":["Positive feedback","Negative feedback","Feed-forward amplification","Open-loop control"],"c":1,"e":"The response (increased ventilation) opposes and corrects the initial change (high CO₂), the defining feature of negative feedback homeostasis."},
  {"i":"bio-b3-0857","g":12,"u":"Applications of Biology","d":"impossible","t":"application","q":"A farmer uses Bacillus thuringiensis (Bt) protein engineered into a crop to control insect pests. The Bt toxin's selectivity for certain insects arises mainly because:","o":["It is only active in the alkaline insect midgut and binds specific gut receptors","It blocks photosynthesis only in insects","It is a broad poison killing all animals equally","It works only after activation by sunlight"],"c":0,"e":"The Cry protoxin is solubilised and activated in the alkaline insect midgut and binds receptors specific to susceptible insects, sparing mammals with acidic stomachs."},
  {"i":"bio-b3-0858","g":12,"u":"Microorganisms","d":"impossible","t":"calculation","q":"A single bacterium with a generation time of 20 minutes divides under ideal conditions. How many cells are present after 2 hours?","o":["32","64","128","256"],"c":1,"e":"2 hours = 120 min / 20 min = 6 generations; 2⁶ = 64 cells."},
  {"i":"bio-b3-0859","g":12,"u":"Climate Change","d":"impossible","t":"conceptual","q":"Rising atmospheric CO₂ dissolves into seawater, lowering ocean pH and reducing carbonate availability. The clearest direct consequence for marine life is:","o":["Increased coral and shellfish calcification","Impaired shell and skeleton formation in calcifying organisms","Higher dissolved oxygen levels","Faster photosynthesis in all algae"],"c":1,"e":"Ocean acidification reduces carbonate ions, hindering CaCO₃ shell and skeleton formation in corals, molluscs and some plankton."},
  {"i":"bio-b3-0860","g":12,"u":"Energy Transformation","d":"impossible","t":"conceptual","q":"In an energy pyramid, only about 10% of energy passes from one trophic level to the next. The main reason most energy is NOT transferred is that it is:","o":["Stored permanently as biomass in the next level","Lost largely as heat through respiration and incomplete consumption","Converted back to sunlight","Recycled directly to producers as glucose"],"c":1,"e":"Most assimilated energy is dissipated as metabolic heat during respiration, with further losses from uneaten/undigested material, leaving roughly 10% available upward."},
  {"i":"bio-b3-0861","g":12,"u":"The Human Body Systems","d":"impossible","t":"calculation","q":"A man of blood group AB marries a woman of group O. Ignoring rare exceptions, which blood groups are possible among their children?","o":["Only AB","A and B only","O only","A, B, AB and O"],"c":1,"e":"Father IᴬIᴮ × mother ii gives Iᴬi (group A) and Iᴮi (group B) only; neither AB nor O can appear."},
  {"i":"bio-b3-0862","g":12,"u":"Evolution","d":"impossible","t":"conceptual","q":"Two insect populations of the same species become separated by a newly formed rift lake and diverge until they can no longer interbreed when reunited. This illustrates:","o":["Sympatric speciation","Allopatric speciation","Convergent evolution","Genetic drift bottleneck only"],"c":1,"e":"Geographic separation (the lake) preventing gene flow, followed by reproductive isolation, defines allopatric speciation."},
  {"i":"bio-b3-0863","g":12,"u":"The Human Body Systems","d":"impossible","t":"calculation","q":"In a monohybrid cross of two heterozygotes (Tt × Tt) for a fully dominant trait, what is the probability that exactly two of three offspring show the dominant phenotype?","o":["27/64","9/64","27/256","3/4"],"c":0,"e":"P(dominant)=3/4, P(recessive)=1/4; exactly two of three = C(3,2)(3/4)²(1/4)=3×9/16×1/4=27/64."},
  {"i":"bio-b3-0864","g":12,"u":"Microorganisms","d":"impossible","t":"conceptual","q":"A virus uses reverse transcriptase to make DNA from its RNA genome, which then integrates into the host chromosome. Such a virus is best classified as a:","o":["Bacteriophage","Retrovirus","Lytic DNA virus","Prion"],"c":1,"e":"Retroviruses carry reverse transcriptase to convert their RNA genome into DNA that integrates as a provirus, e.g. HIV."},
  {"i":"bio-b3-0865","g":12,"u":"Applications of Biology","d":"impossible","t":"application","q":"In a polymerase chain reaction (PCR), the step that separates the double-stranded DNA into single strands requires:","o":["Cooling to about 50 °C","Heating to about 95 °C (denaturation)","Adding DNA ligase","Exposure to ultraviolet light"],"c":1,"e":"Denaturation at roughly 94–95 °C breaks the hydrogen bonds separating the two strands before primer annealing at a lower temperature."},
  {"i":"bio-b3-0866","g":12,"u":"The Human Body Systems","d":"impossible","t":"calculation","q":"In a human population, an autosomal recessive form of albinism affects 1 in 10 000 individuals and the population is in Hardy–Weinberg equilibrium. A clinically unaffected (normally pigmented) man is chosen at random. What is the probability that he is a heterozygous carrier of the albinism allele?","o":["About 0.0198 (≈ 2.0%)","About 0.0099 (≈ 1.0%)","About 0.0001 (≈ 0.01%)","About 0.99 (≈ 99%)"],"c":0,"e":"q²=1/10000 so q=0.01, p=0.99, carrier freq 2pq=0.0198. Among the unaffected (p²+2pq), carriers = 2pq/(p²+2pq)=0.0198/0.9999≈0.0198."},
  {"i":"bio-b3-0867","g":12,"u":"The Human Body Systems","d":"impossible","t":"calculation","q":"A woman heterozygous at two unlinked autosomal loci (genotype AaBb) is crossed with a man of genotype Aabb. Considering all offspring, what fraction are expected to show the dominant A phenotype together with the recessive bb phenotype?","o":["3/8","1/4","1/16","9/16"],"c":0,"e":"Aa×Aa gives 3/4 dominant A_; Bb×bb gives 1/2 bb. Independent loci multiply: 3/4 × 1/2 = 3/8."},
  {"i":"bio-b3-0868","g":12,"u":"The Human Body Systems","d":"impossible","t":"calculation","q":"A phenotypically normal woman whose father was colour-blind marries a man with normal colour vision. Colour blindness is X-linked recessive. Of all the children this couple may have, what proportion are expected to be colour-blind?","o":["1/4","1/2","1/8","0"],"c":0,"e":"The woman is an obligate carrier (XᴴXʰ) since her father gave her Xʰ; husband is XᴴY. Offspring: ¼ XᴴXᴴ, ¼ XᴴXʰ, ¼ XᴴY, ¼ XʰY. Only XʰY (¼ of all children) is colour-blind."},
  {"i":"bio-b3-0869","g":12,"u":"Energy Transformation","d":"impossible","t":"calculation","q":"During complete aerobic respiration of one glucose molecule, electron carriers are re-oxidised at the inner mitochondrial membrane. Counting the carriers generated across glycolysis, the link reaction and the Krebs cycle, and using the curriculum's theoretical yield (3 ATP per NADH, 2 ATP per FADH₂), what is the maximum theoretical ATP yield per glucose?","o":["38","36","30","2"],"c":0,"e":"Per glucose: 10 NADH × 3 = 30, 2 FADH₂ × 2 = 4, plus 4 ATP by substrate-level phosphorylation = 38 ATP (theoretical maximum)."},
  {"i":"bio-b3-0870","g":12,"u":"Microorganisms","d":"impossible","t":"calculation","q":"A culture is inoculated with 500 bacterial cells that divide by binary fission with a constant generation time of 20 minutes under ideal conditions. Assuming uninterrupted exponential (log-phase) growth, how many cells are present after exactly 4 hours?","o":["2 048 000","1 024 000","6 000","240 000"],"c":0,"e":"In 4 h (240 min) there are 240/20 = 12 generations. N = N₀ × 2¹² = 500 × 4096 = 2 048 000 cells."},
  {"i":"bio-b3-0871","g":12,"u":"Applications of Biology","d":"impossible","t":"conceptual","q":"In producing recombinant human insulin in Escherichia coli, the human insulin gene is introduced as a cDNA copy synthesised from mRNA rather than as the gene cut directly from human genomic DNA. The principal reason is that the bacterial host:","o":["cannot remove introns, so a pre-processed intron-free coding sequence is required","cannot translate eukaryotic codons because its genetic code differs","would degrade any DNA containing the human promoter sequence","lacks ribosomes capable of reading a poly-A tailed transcript"],"c":0,"e":"Prokaryotes lack the spliceosome machinery to excise introns. cDNA made by reverse transcription of mature mRNA is already intron-free, so the bacterium can transcribe and translate it into functional insulin chains."},
  {"i":"bio-b3-0872","g":12,"u":"Climate Change","d":"impossible","t":"application","q":"In a grassland food chain, producers fix 45 000 kJ m⁻² yr⁻¹ of energy. Applying the curriculum's ~10% ecological efficiency between successive trophic levels, approximately how much energy is available to a tertiary consumer (the predator that eats the secondary consumer)?","o":["≈ 45 kJ m⁻² yr⁻¹","≈ 450 kJ m⁻² yr⁻¹","≈ 4 500 kJ m⁻² yr⁻¹","≈ 4.5 kJ m⁻² yr⁻¹"],"c":0,"e":"Tertiary consumer is the 4th trophic level. 45000 × 0.1³ = 45000 × 0.001 = 45 kJ m⁻² yr⁻¹."},
  {"i":"bio-b3-0873","g":12,"u":"Evolution","d":"impossible","t":"calculation","q":"In a large random-mating population, a recessive allele is lethal in the homozygous state (homozygotes die before reproducing) and its current frequency is q = 0.5. With no mutation or migration, what is the allele's frequency after one generation of selection?","o":["1/3","1/4","1/2","2/3"],"c":0,"e":"For a fully recessive lethal, q′ = q/(1+q) = 0.5/1.5 = 1/3. Lethal homozygotes are removed each generation, so the allele declines but is not eliminated in one step."},
  {"i":"bio-b3-0874","g":12,"u":"Microorganisms","d":"impossible","t":"conceptual","q":"Penicillin is bactericidal against actively dividing Gram-positive bacteria but does not harm human cells and is far less effective against dormant (non-dividing) bacteria. The best unifying explanation is that penicillin:","o":["inhibits cross-linking of peptidoglycan during cell-wall synthesis, a structure and process absent in human cells and inactive in dormant bacteria","binds bacterial 70S ribosomes, which human cells lack and dormant cells switch off","disrupts the bacterial plasma membrane only while the membrane is being newly assembled","blocks bacterial DNA gyrase, an enzyme used only during active replication"],"c":0,"e":"Penicillin inhibits transpeptidase, blocking peptidoglycan cross-linking. Human cells have no peptidoglycan wall (so are spared), and dormant cells are not building wall, so they are largely unaffected."}
];
